const NETWORK_ACCESS_MODE = String(process.env.NETWORK_ACCESS_MODE || 'localhost').trim().toLowerCase();
const NETWORK_WIFI_CIDR = String(process.env.NETWORK_WIFI_CIDR || '').trim();
const NETWORK_TRUST_PROXY = /^(1|true|yes|on)$/i.test(String(process.env.NETWORK_TRUST_PROXY || '').trim());
const NETWORK_EXTRA_ALLOWLIST = String(process.env.NETWORK_EXTRA_ALLOWLIST || '')
  .split(',')
  .map((s) => String(s || '').trim())
  .filter(Boolean);

function normalizeIp(raw) {
  let ip = String(raw || '').trim();
  if (!ip) return '';
  if (ip.startsWith('::ffff:')) ip = ip.slice(7);
  if (ip.startsWith('[') && ip.endsWith(']')) ip = ip.slice(1, -1);
  return ip;
}

function isLoopbackIp(ip) {
  const v = normalizeIp(ip).toLowerCase();
  return v === '127.0.0.1' || v === '::1';
}

function parseIpv4(ip) {
  const s = normalizeIp(ip);
  if (!/^\d{1,3}(?:\.\d{1,3}){3}$/.test(s)) return null;
  const parts = s.split('.').map((n) => Number(n));
  if (parts.some((n) => !Number.isInteger(n) || n < 0 || n > 255)) return null;
  return parts;
}

function ipv4ToInt(ip) {
  const p = parseIpv4(ip);
  if (!p) return null;
  return (((p[0] << 24) >>> 0) + (p[1] << 16) + (p[2] << 8) + p[3]) >>> 0;
}

function parseIpv4Cidr(cidr) {
  const txt = String(cidr || '').trim();
  const m = txt.match(/^(\d{1,3}(?:\.\d{1,3}){3})\/(\d{1,2})$/);
  if (!m) return null;
  const base = ipv4ToInt(m[1]);
  const prefix = Number(m[2]);
  if (base == null || !Number.isInteger(prefix) || prefix < 0 || prefix > 32) return null;
  const mask = prefix === 0 ? 0 : (0xffffffff << (32 - prefix)) >>> 0;
  return { base: base & mask, mask };
}

function isIpv4InCidr(ip, cidr) {
  const x = ipv4ToInt(ip);
  const c = parseIpv4Cidr(cidr);
  if (x == null || !c) return false;
  return (x & c.mask) === c.base;
}

function isPrivateIpv4(ip) {
  const p = parseIpv4(ip);
  if (!p) return false;
  const [a, b] = p;
  if (a === 10) return true;
  if (a === 172 && b >= 16 && b <= 31) return true;
  if (a === 192 && b === 168) return true;
  return false;
}

function isPrivateIpv6(ip) {
  const v = normalizeIp(ip).toLowerCase();
  return v.startsWith('fc') || v.startsWith('fd') || v.startsWith('fe80:');
}

function detectDefaultWifiCidr24() {
  try {
    const interfaces = os.networkInterfaces() || {};
    for (const name of Object.keys(interfaces)) {
      const rows = Array.isArray(interfaces[name]) ? interfaces[name] : [];
      for (const row of rows) {
        const fam = String(row?.family || '').toUpperCase();
        if (row?.internal) continue;
        if (fam !== 'IPV4' && fam !== '4') continue;
        const ip = normalizeIp(row?.address || '');
        if (!isPrivateIpv4(ip)) continue;
        const p = parseIpv4(ip);
        if (!p) continue;
        return `${p[0]}.${p[1]}.${p[2]}.0/24`;
      }
    }
  } catch {}
  return '';
}

function detectPrimaryLanIpv4() {
  try {
    const interfaces = os.networkInterfaces() || {};
    for (const name of Object.keys(interfaces)) {
      const rows = Array.isArray(interfaces[name]) ? interfaces[name] : [];
      for (const row of rows) {
        const fam = String(row?.family || '').toUpperCase();
        if (row?.internal) continue;
        if (fam !== 'IPV4' && fam !== '4') continue;
        const ip = normalizeIp(row?.address || '');
        if (!isPrivateIpv4(ip)) continue;
        return ip;
      }
    }
  } catch {}
  return '';
}

const EFFECTIVE_WIFI_CIDR = NETWORK_WIFI_CIDR || detectDefaultWifiCidr24();
const PRIMARY_LAN_IPV4 = detectPrimaryLanIpv4();

function ipAllowedByPolicy(ip) {
  const x = normalizeIp(ip);
  if (!x) return false;
  if (isLoopbackIp(x)) return true;
  if (NETWORK_EXTRA_ALLOWLIST.includes(x)) return true;
  if (NETWORK_ACCESS_MODE === 'open') return true;
  if (NETWORK_ACCESS_MODE === 'localhost') return false;
  if (NETWORK_ACCESS_MODE === 'wifi_only') {
    if (EFFECTIVE_WIFI_CIDR && isIpv4InCidr(x, EFFECTIVE_WIFI_CIDR)) return true;
    return false;
  }
  if (NETWORK_ACCESS_MODE === 'lan_private') {
    if (isPrivateIpv4(x) || isPrivateIpv6(x)) return true;
    return false;
  }
  return false;
}

function originAllowedByPolicy(origin) {
  if (!origin) return true;
  try {
    const u = new URL(origin);
    const h = normalizeIp(u.hostname);
    if (h === 'localhost') return true;
    return ipAllowedByPolicy(h);
  } catch {
    return false;
  }
}

function getRequestClientIp(req) {
  if (NETWORK_TRUST_PROXY) {
    const xfwd = String(req.headers['x-forwarded-for'] || '').trim();
    if (xfwd) {
      const first = xfwd.split(',')[0];
      const ip = normalizeIp(first);
      if (ip) return ip;
    }
  }
  return normalizeIp(req.ip || req.socket?.remoteAddress || '');
}

app.set('trust proxy', NETWORK_TRUST_PROXY ? 1 : false);
app.use(cors({
  origin(origin, cb) {
    return cb(null, originAllowedByPolicy(origin));
  },
}));
app.use((req, res, next) => {
  const ip = getRequestClientIp(req);
  if (ipAllowedByPolicy(ip)) return next();
  if (DEBUG_ANALYST) {
    console.warn(`[NETWORK_GUARD] blocked ip=${ip} method=${req.method} path=${req.path}`);
  }
  return res.status(403).json({
    success: false,
    error: 'network_access_denied',
    mode: NETWORK_ACCESS_MODE,
  });
});
app.use(express.json({ limit: '50mb' }));

// ============================================================
// HELPERS
// ============================================================

function debugTextPreview(input, maxChars = 180) {
  const txt = String(input || '').replace(/\s+/g, ' ').trim();
  if (txt.length <= maxChars) return txt;
  return `${txt.slice(0, maxChars).trim()}...`;
}

function textSha1(input) {
  return crypto.createHash('sha1').update(String(input || ''), 'utf8').digest('hex');
}

function logAnalystDebug(event, payload = {}) {
  if (!DEBUG_ANALYST) return;
  try {
    const row = {
      at: new Date().toISOString(),
      event: String(event || 'unknown'),
      ...payload,
    };
    console.log(`[DEBUG_ANALYST] ${JSON.stringify(row)}`);
  } catch (err) {
    console.log(`[DEBUG_ANALYST] ${String(event || 'unknown')} ${(err && err.message) ? err.message : ''}`.trim());
  }
}

function bindAnalystRequestTrace(req, res, endpointName) {
  if (!DEBUG_ANALYST) return () => {};
  const startedAt = Date.now();
  const requestId = `${String(endpointName || 'endpoint')}:${crypto.randomBytes(4).toString('hex')}`;
  const body = req?.body || {};
  let finished = false;
  let aborted = false;
  logAnalystDebug('request.start', {
    requestId,
    endpoint: endpointName,
    method: String(req?.method || 'unknown'),
    activeModule: body?.activeModule == null ? null : String(body.activeModule),
    hasActiveModuleField: Object.prototype.hasOwnProperty.call(body, 'activeModule'),
    strategy: body?.strategy == null ? null : String(body.strategy),
    preferCachedLive: body?.preferCachedLive === true,
    voiceMode: body?.voiceMode === true,
    streaming: false,
    message: debugTextPreview(body?.message || '', 200),
  });
  res.on('finish', () => {
    finished = true;
    logAnalystDebug('request.finish', {
      requestId,
      endpoint: endpointName,
      statusCode: Number(res.statusCode || 0),
      durationMs: Date.now() - startedAt,
      writableEnded: res.writableEnded === true,
    });
  });
  req.on('aborted', () => {
    aborted = true;
    logAnalystDebug('request.aborted', {
      requestId,
      endpoint: endpointName,
      durationMs: Date.now() - startedAt,
      finished: false,
      writableEnded: false,
      connectionClosedEarly: true,
    });
  });
  res.on('close', () => {
    logAnalystDebug('request.close', {
      requestId,
      endpoint: endpointName,
      durationMs: Date.now() - startedAt,
      finished,
      aborted,
      writableEnded: res.writableEnded === true,
      connectionClosedEarly: aborted || !finished,
    });
  });
  return (meta = {}) => {
    logAnalystDebug('request.meta', {
      requestId,
      endpoint: endpointName,
      ...meta,
    });
  };
}

function ensureRequestTraceId(rawTraceId, prefix = 'jarvis') {
  const existing = String(rawTraceId || '').trim();
  if (existing) return existing;
  return `${String(prefix || 'jarvis').toLowerCase().replace(/[^a-z0-9]+/g, '').slice(0, 12) || 'jarvis'}-${crypto.randomBytes(8).toString('hex')}`;
}

function enforceVoiceJarvisEndpointGuard(req, res, endpointName, traceFn) {
  if (req?.body?.voiceMode !== true) return false;
  const traceId = ensureRequestTraceId(req?.body?.traceId, 'voiceguard');
  const message = 'Voice must use Jarvis endpoint';
  const routePathTag = 'voice_endpoint_guard';
  const stageRecord = buildJarvisTraceRecord({
    stage: 'voice_endpoint_guard_block',
    traceId,
    endpoint: String(endpointName || 'unknown'),
    intent: 'voice_routing_guard',
    toolsUsed: ['JarvisGuard'],
    precedenceMode: null,
    voiceMode: true,
    voiceBriefMode: String(req?.body?.voiceBriefMode || '').trim().toLowerCase() || null,
    routePathTag,
    source: 'jarvis_voice_guard',
    formatterUsed: null,
    didFinalize: null,
    invariantsPass: true,
    failedRules: [],
    replyPreview: message,
    spokenTextPreview: null,
    serverEqualsReply: null,
    routePath: String(endpointName || 'unknown'),
    mode: 'guard',
    sessionId: String(req?.body?.sessionId || req?.body?.clientId || '').trim() || null,
    sessionKey: null,
  });
  jarvisTraceStore.set(stageRecord, {
    sessionId: stageRecord.sessionId || null,
  });
  if (typeof traceFn === 'function') {
    traceFn({
      branch: 'voice_endpoint_guard_block',
      traceId,
      endpoint: endpointName,
      replyPreview: message,
    });
  }
  logJarvisAudit('voice_endpoint_guard_block', stageRecord);
  res.status(409).json({
    success: false,
    source: 'jarvis_voice_guard',
    error: 'voice_endpoint_rejected',
    message,
    reply: message,
    requiredEndpoint: '/api/jarvis/query',
    endpoint: String(endpointName || 'unknown'),
    traceId,
  });
  return true;
}

const SESSION_DATA_CACHE_TTL_MS = Math.max(30 * 1000, Number(process.env.SESSION_DATA_CACHE_TTL_MS || 2 * 60 * 1000));
let sessionDataCache = {
  fetchedAt: 0,
  sessions: null,
  sessionCount: 0,
  candleCount: 0,
};

function invalidateSessionDataCache() {
  sessionDataCache = {
    fetchedAt: 0,
    sessions: null,
    sessionCount: 0,
    candleCount: 0,
  };
}

function loadAllSessions() {
  const now = Date.now();
  if (
    sessionDataCache.sessions
    && (now - sessionDataCache.fetchedAt) < SESSION_DATA_CACHE_TTL_MS
  ) {
    return sessionDataCache.sessions;
  }

  const db = getDB();
  const rows = db.prepare(`
    SELECT
      s.date AS session_date,
      c.timestamp,
      c.open,
      c.high,
      c.low,
      c.close,
      c.volume
    FROM candles c
    JOIN sessions s ON s.id = c.session_id
    WHERE c.timeframe = '5m'
    ORDER BY s.date ASC, c.timestamp ASC
  `).all();

  const result = {};
  for (const r of rows) {
    const d = r.session_date;
    if (!result[d]) result[d] = [];
    const ts = String(r.timestamp || '');
    let datePart = d;
    let timePart = '00:00:00';
    if (ts.includes(' ')) {
      const split = ts.split(' ');
      datePart = split[0] || d;
      timePart = split[1] || '00:00:00';
    } else if (ts.includes('T')) {
      const split = ts.split('T');
      datePart = split[0] || d;
      const right = String(split[1] || '');
      const trimmed = right
        .replace(/Z$/i, '')
        .replace(/[+-]\d{2}:?\d{2}$/i, '');
      timePart = (trimmed || '00:00:00').split('.')[0] || '00:00:00';
    }
    result[d].push({
      timestamp: ts,
      date: datePart,
      time: timePart,
      open: r.open,
      high: r.high,
      low: r.low,
      close: r.close,
      volume: r.volume,
    });
  }

  sessionDataCache = {
    fetchedAt: now,
    sessions: result,
    sessionCount: Object.keys(result).length,
    candleCount: rows.length,
  };
  return result;
}

function ensureDir(dirPath) {
  if (!fs.existsSync(dirPath)) fs.mkdirSync(dirPath, { recursive: true });
}

function pruneRuntimeBackups(maxBackups = MAX_DB_BACKUPS) {
  ensureDir(DB_BACKUP_DIR);
  const cap = Math.max(5, Number(maxBackups || MAX_DB_BACKUPS));
  const files = fs.readdirSync(DB_BACKUP_DIR)
    .filter((name) => name.startsWith('mcnair-') && name.endsWith('.db'))
    .map((name) => {
      const fullPath = path.join(DB_BACKUP_DIR, name);
      let mtimeMs = 0;
      try { mtimeMs = Number(fs.statSync(fullPath).mtimeMs || 0); } catch {}
      return { fullPath, mtimeMs };
    })
    .sort((a, b) => b.mtimeMs - a.mtimeMs);

  let removedCount = 0;
  for (let i = cap; i < files.length; i += 1) {
    try {
      fs.unlinkSync(files[i].fullPath);
      removedCount += 1;
    } catch {}
  }
  return {
    maxBackups: cap,
    totalBackups: files.length,
    removedCount,
    retainedCount: Math.max(0, files.length - removedCount),
  };
}

function createRuntimeBackup(reason = 'manual') {
  const safeReason = String(reason || 'manual')
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, '_')
    .slice(0, 48) || 'manual';
  ensureDir(DB_BACKUP_DIR);
  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const backupPath = path.join(DB_BACKUP_DIR, `mcnair-${safeReason}-${stamp}.db`);
  const withPrune = (result) => {
    try {
      return { ...result, prune: pruneRuntimeBackups() };
    } catch (err) {
      return { ...result, prune: { error: String(err?.message || 'backup_prune_failed') } };
    }
  };
  if (!fs.existsSync(DB_FILE)) {
    return withPrune({ ok: false, method: 'none', path: backupPath, error: 'db_file_missing' });
  }
  try {
    execFileSync('sqlite3', [DB_FILE, `.backup ${backupPath}`], {
      stdio: 'ignore',
      timeout: 30_000,
    });
    return withPrune({ ok: true, method: 'sqlite_backup', path: backupPath });
  } catch (err) {
    try {
      fs.copyFileSync(DB_FILE, backupPath);
      return withPrune({ ok: true, method: 'copy_fallback', path: backupPath, warn: String(err?.message || 'sqlite_backup_failed') });
    } catch (copyErr) {
      return withPrune({
        ok: false,
        method: 'failed',
        path: backupPath,
        error: String(copyErr?.message || err?.message || 'backup_failed'),
      });
    }
  }
}

function fileSha256(filePath) {
  const h = crypto.createHash('sha256');
  h.update(fs.readFileSync(filePath));
  return h.digest('hex');
}

function parseDateRangeFromFilename(filename) {
  const txt = String(filename || '');
  const matches = txt.match(/\d{8}/g) || [];
  if (matches.length < 2) return { start: null, end: null };
  const asIso = (v) => `${v.slice(0, 4)}-${v.slice(4, 6)}-${v.slice(6, 8)}`;
  return { start: asIso(matches[0]), end: asIso(matches[1]) };
}

function addIsoDays(isoDate, days) {
  const ms = toUtcDayMs(isoDate);
  if (!Number.isFinite(ms)) return null;
  const next = new Date(ms + (Number(days || 0) * 86400000));
  return next.toISOString().slice(0, 10);
}

function intersectsIsoRange(aStart, aEnd, bStart, bEnd) {
  const x1 = toUtcDayMs(aStart);
  const x2 = toUtcDayMs(aEnd);
  const y1 = toUtcDayMs(bStart);
  const y2 = toUtcDayMs(bEnd);
  if (![x1, x2, y1, y2].every(Number.isFinite)) return false;
  return x1 <= y2 && x2 >= y1;
}

function getImportedFilenames(db = getDB()) {
  const rows = db.prepare(`
    SELECT filename
    FROM imports
    WHERE status IN ('success', 'partial')
      AND (
        COALESCE(total_rows, 0) > 0
        OR COALESCE(total_candles, 0) > 0
        OR COALESCE(sessions_added, 0) > 0
      )
  `).all();
  return new Set(rows.map((r) => String(r.filename || '').trim()).filter(Boolean));
}

function expandHomePath(inputPath) {
  const raw = String(inputPath || '').trim();
  if (!raw) return '';
  if (raw === '~') return os.homedir();
  if (raw.startsWith('~/')) return path.join(os.homedir(), raw.slice(2));
  return raw;
}

function looksLikeDatabentoCsv(filename) {
  const name = String(filename || '').toLowerCase();
  if (!name.endsWith('.csv')) return false;
  return /^glbx-mdp3-\d{8}-\d{8}\./.test(name);
}

function collectDatabentoCsvFiles(rootDir, maxDepth = 1) {
  const out = [];
  const root = expandHomePath(rootDir);
  if (!root || !fs.existsSync(root)) return out;
  const walk = (dir, depth) => {
    if (depth > maxDepth) return;
    let entries = [];
    try {
      entries = fs.readdirSync(dir, { withFileTypes: true });
    } catch {
      return;
    }
    for (const entry of entries) {
      const full = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        walk(full, depth + 1);
        continue;
      }
      if (!entry.isFile()) continue;
      if (!looksLikeDatabentoCsv(entry.name)) continue;
      let stat = null;
      try {
        stat = fs.statSync(full);
      } catch {
        continue;
      }
      if (!stat || !stat.isFile()) continue;
      const range = parseDateRangeFromFilename(entry.name);
      out.push({
        name: entry.name,
        fullPath: full,
        size: stat.size,
        mtimeMs: Number(stat.mtimeMs || 0),
        rangeStart: range.start,
        rangeEnd: range.end,
      });
    }
  };
  walk(root, 0);
  return out;
}

function persistImportedSessions(result, options = {}) {
  const db = getDB();
  const insertSession = db.prepare(`
    INSERT OR IGNORE INTO sessions (date, candle_count, day_of_week)
    VALUES (?, ?, ?)
  `);
  const insertCandle = db.prepare(`
    INSERT OR IGNORE INTO candles (session_id, timestamp, timeframe, open, high, low, close, volume)
    VALUES (?, ?, '5m', ?, ?, ?, ?, ?)
  `);
  const getSessionId = db.prepare('SELECT id FROM sessions WHERE date = ?');

  let sessionsAdded = 0;
  let candlesAdded = 0;
  db.transaction(() => {
    for (const date of result.validSessions || []) {
      const candles = result.sessions?.[date] || [];
      const d = new Date(`${date}T12:00:00`);
      const dow = d.getDay();
      const adjDow = dow === 0 ? 6 : dow - 1;
      const insertedSession = insertSession.run(date, candles.length, adjDow);
      const session = getSessionId.get(date);
      if (!session) continue;
      if (Number(insertedSession?.changes || 0) > 0) sessionsAdded += 1;
      for (const c of candles) {
        const insertedCandle = insertCandle.run(session.id, c.timestamp, c.open, c.high, c.low, c.close, c.volume);
        if (Number(insertedCandle?.changes || 0) > 0) candlesAdded += 1;
      }
    }
  })();

  const filename = String(options.filename || result.file || 'import.csv');
  const totalRows = Number(result.totalRows || 0);
  const totalCandles = Number(result.stats?.totalCandles || 0);
  const emptyImport = totalRows <= 0 || totalCandles <= 0 || (result.validSessions || []).length <= 0;
  const status = emptyImport
    ? 'failed'
    : (result.invalidSessions || []).length > 0 ? 'partial' : 'success';
  const errors = (result.invalidSessions || []).slice(0, 20);
  if (emptyImport) {
    errors.push({ reason: 'empty_or_no_valid_rows' });
  }
  db.prepare(`
    INSERT INTO imports (filename, total_rows, total_candles, sessions_added, date_range_start, date_range_end, status, errors)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    filename,
    totalRows,
    totalCandles,
    sessionsAdded,
    result.stats?.dateRange?.first || null,
    result.stats?.dateRange?.last || null,
    status,
    JSON.stringify(errors)
  );

  return { sessionsAdded, candlesAdded, status, totalRows, totalCandles };
}

function validateRecentSessionDataCoverage(options = {}) {
  const lookbackSessions = Math.max(3, Math.min(30, Number(options.lookbackSessions || 8)));
  const minCandlesPerSession = Math.max(60, Number(options.minCandlesPerSession || 280));
  const db = getDB();
  const rows = db.prepare(`
    SELECT date, candle_count
    FROM sessions
    ORDER BY date DESC
    LIMIT ?
  `).all(lookbackSessions);
  const sessions = loadAllSessions();
  const checks = [];
  let issues = 0;

  for (const r of rows) {
    const date = String(r.date || '');
    const candles = sessions[date] || [];
    const validation = validateSession(candles);
    const tooFew = Number(candles.length) < minCandlesPerSession;
    if (!validation.valid || tooFew) issues += 1;
    checks.push({
      date,
      candles: Number(candles.length),
      tooFewCandles: tooFew,
      valid: !!validation.valid,
      errors: (validation.errors || []).slice(0, 4),
    });
  }

  return {
    checkedSessions: checks.length,
    issueCount: issues,
    minCandlesPerSession,
    checks,
  };
}

function listDatabentoCsvCandidates() {
  ensureDir(DATABENTO_SYNC_DIR);
  const primary = collectDatabentoCsvFiles(DATABENTO_SYNC_DIR, 0);
  const extras = DATABENTO_EXTRA_DIRS
    .filter((dir) => path.resolve(expandHomePath(dir || '')) !== path.resolve(DATABENTO_SYNC_DIR))
    .flatMap((dir) => collectDatabentoCsvFiles(dir, DATABENTO_SCAN_MAX_DEPTH));
  const merged = new Map();
  for (const c of primary.concat(extras)) {
    const key = String(c.name || '').trim().toLowerCase();
    if (!key) continue;
    const prev = merged.get(key);
    if (!prev) {
      merged.set(key, c);
      continue;
    }
    const prevScore = Number(prev.size || 0) + Number(prev.mtimeMs || 0);
    const nextScore = Number(c.size || 0) + Number(c.mtimeMs || 0);
    if (nextScore > prevScore) merged.set(key, c);
  }
  return Array.from(merged.values());
}

function runAutomatedDataSync(options = {}) {
  const triggerSource = String(options.triggerSource || 'manual_sync');
  const maxFiles = Math.max(1, Math.min(24, Number(options.maxFiles || 6)));
  const db = getDB();
  const freshnessBefore = getSessionFreshnessSummary('America/New_York');
  const importedNames = getImportedFilenames(db);
  const today = dateInTimezone('America/New_York');
  const targetStart = freshnessBefore.lastSessionDate ? addIsoDays(freshnessBefore.lastSessionDate, 1) : null;
  const candidates = listDatabentoCsvCandidates()
    .filter((f) => !importedNames.has(f.name))
    .filter((f) => {
      if (!targetStart) return true;
      if (f.rangeStart && f.rangeEnd) return intersectsIsoRange(f.rangeStart, f.rangeEnd, targetStart, today);
      return f.mtimeMs >= (Date.now() - (72 * 60 * 60 * 1000));
    })
    .sort((a, b) => {
      const aKey = toUtcDayMs(a.rangeStart) || 0;
      const bKey = toUtcDayMs(b.rangeStart) || 0;
      if (aKey !== bKey) return aKey - bKey;
      return a.mtimeMs - b.mtimeMs;
    })
    .slice(0, maxFiles);

  const imported = [];
  const skipped = [];
  const failures = [];
  let sessionsAdded = 0;
  let candlesAdded = 0;

  for (const f of candidates) {
    try {
      if (Number(f.size || 0) < DATABENTO_MIN_FILE_BYTES) {
        skipped.push({ file: f.name, reason: 'file_too_small', size: Number(f.size || 0) });
        continue;
      }
      const result = importTradingViewCSV(f.fullPath);
      const persisted = persistImportedSessions(result, { filename: f.name });
      if (String(persisted.status || '').toLowerCase() === 'failed') {
        skipped.push({
          file: f.name,
          reason: 'empty_or_invalid_rows',
          totalRows: Number(persisted.totalRows || 0),
          totalCandles: Number(persisted.totalCandles || 0),
        });
        continue;
      }
      sessionsAdded += persisted.sessionsAdded;
      candlesAdded += persisted.candlesAdded;
      imported.push({
        file: f.name,
        importStatus: persisted.status,
        sessionsAdded: persisted.sessionsAdded,
        candlesAdded: persisted.candlesAdded,
        dateRange: result.stats?.dateRange || null,
        invalidSessions: (result.invalidSessions || []).length,
      });
    } catch (err) {
      failures.push({ file: f.name, error: String(err.message || 'sync_import_failed') });
    }
  }

  if (candidates.length === 0) {
    skipped.push({ reason: 'no_new_files', directory: DATABENTO_SYNC_DIR });
  }

  if (imported.length > 0) {
    invalidateAltCache();
    invalidateDailyPlanCache();
    invalidateSessionControlPanelCache();
    eliteBriefCache.clear();
  }

  const freshnessAfter = getSessionFreshnessSummary('America/New_York');
  const coverage = validateRecentSessionDataCoverage({ lookbackSessions: 8, minCandlesPerSession: 280 });
  const status = failures.length > 0
    ? (imported.length > 0 ? 'partial' : 'error')
    : (imported.length > 0 ? 'ok' : 'noop');

  db.prepare(`
    INSERT INTO data_sync_runs (
      trigger_source, scanned_files, imported_files, sessions_added, candles_added,
      stale_before, stale_after, freshness_json, validation_json, details_json, status
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    triggerSource,
    candidates.length,
    imported.length,
    sessionsAdded,
    candlesAdded,
    freshnessBefore.isStale ? 1 : 0,
    freshnessAfter.isStale ? 1 : 0,
    JSON.stringify({ before: freshnessBefore, after: freshnessAfter }),
    JSON.stringify(coverage),
    JSON.stringify({ imported, skipped, failures }),
    status
  );

  db.prepare('INSERT INTO activity_log (module, message, severity, data) VALUES (?, ?, ?, ?)')
    .run(
      'data',
      `Data sync ${status}: ${imported.length}/${candidates.length} file(s), +${sessionsAdded} sessions.`,
      status === 'ok' ? 'success' : status === 'noop' ? 'info' : 'warning',
      JSON.stringify({ triggerSource, imported, skipped, failures, coverage, freshnessAfter })
    );

  return {
    status,
    triggerSource,
    scannedFiles: candidates.length,
    importedFiles: imported.length,
    sessionsAdded,
    candlesAdded,
    freshnessBefore,
    freshnessAfter,
    coverage,
    imported,
    skipped,
    failures,
  };
}

function loadRegimes(sessions) {
  const regimes = {};
  const dates = Object.keys(sessions).sort();
  for (let i = 0; i < dates.length; i++) {
    const date = dates[i];
    const candles = sessions[date];
    const orbCandles = candles.filter(c => {
      const [h, m] = c.time.split(':').map(Number);
      return h === 9 && m >= 30 && m < 45;
    });
    const orbHigh = orbCandles.length > 0 ? Math.max(...orbCandles.map(c => c.high)) : null;
    const orbLow = orbCandles.length > 0 ? Math.min(...orbCandles.map(c => c.low)) : null;
    const orb = orbHigh && orbLow ? { high: orbHigh, low: orbLow, range_ticks: Math.round((orbHigh - orbLow) * 4) } : null;

    const prevDate = i > 0 ? dates[i - 1] : null;
    const prevCandles = prevDate ? sessions[prevDate] : null;
    const prevClose = prevCandles ? prevCandles[prevCandles.length - 1].close : null;

    regimes[date] = classifyRegime(candles, orb, prevClose ? { close: prevClose } : null);
  }
  return regimes;
}

