let altCache = null;
let altCacheTime = 0;
const ALT_CACHE_TTL = 30000; // 30 seconds
const ECON_CACHE_TTL_MS = 5 * 60 * 1000;
let econCalendarCache = { fetchedAt: 0, events: [], source: 'none', error: null };
const ELITE_BRIEF_TTL_MS = 60 * 1000;
const eliteBriefCache = new Map();
const eliteBriefInFlight = new Map();
const COACH_SNAPSHOT_TTL_MS = 45 * 1000;
const coachSnapshotCache = new Map();
const DAILY_PLAN_TTL_MS = 30 * 1000;
const dailyPlanCache = new Map();
const SESSION_PANEL_TTL_MS = 3 * 1000;
const sessionControlPanelCache = new Map();
const COMMAND_SNAPSHOT_TTL_MS = 20 * 1000;
const COMMAND_SNAPSHOT_STALE_TTL_MS = 2 * 60 * 1000;
const commandSnapshotCache = new Map();
const commandSnapshotInFlight = new Map();
const STRATEGY_LAYER_TTL_MS = Math.max(15_000, Number(process.env.STRATEGY_LAYER_TTL_MS || (2 * 60 * 1000)));
const strategyLayerCache = new Map();
const strategyLayerInFlight = new Map();
const STRATEGY_TRACKING_TTL_MS = Math.max(15_000, Number(process.env.STRATEGY_TRACKING_TTL_MS || (120 * 1000)));
