function getLogicGuardSummary(hours = 72) {
  const db = getDB();
  const lookback = Math.max(1, Math.min(720, Number(hours || 72)));
  const agg = db.prepare(`
    SELECT
      COUNT(*) as total,
      COALESCE(SUM(CASE WHEN status = 'steady' THEN 1 ELSE 0 END), 0) as steady_count,
      COALESCE(SUM(CASE WHEN status = 'tightened' THEN 1 ELSE 0 END), 0) as tightened_count,
      COALESCE(SUM(CASE WHEN status = 'relaxed' THEN 1 ELSE 0 END), 0) as relaxed_count,
      COALESCE(SUM(CASE WHEN status = 'error' THEN 1 ELSE 0 END), 0) as error_count
    FROM logic_guard_events
    WHERE created_at >= datetime('now', ?)
  `).get(`-${lookback} hours`);
  const latest = db.prepare(`
    SELECT id, status, sample_size, win_rate, loss_streak, action_json, details_json, created_at
    FROM logic_guard_events
    ORDER BY id DESC
    LIMIT 1
  `).get() || null;
  const currentThresholds = getActiveScoreThresholds('global');
  const currentAutonomy = getExecutionAutonomySettings(db);
  const state = db.prepare(`
    SELECT id, lock_expires_at, last_run_at, last_status, last_error,
           consecutive_healthy_runs, last_boundary_change_date,
           last_change_direction, last_change_at, updated_at
    FROM logic_guard_state
    WHERE id = 1
  `).get() || null;
  return {
    windowHours: lookback,
    total: Number(agg?.total || 0),
    steady: Number(agg?.steady_count || 0),
    tightened: Number(agg?.tightened_count || 0),
    relaxed: Number(agg?.relaxed_count || 0),
    errors: Number(agg?.error_count || 0),
    activeBoundary: {
      minSetupProbability: Number(currentAutonomy.minSetupProbability || 0),
      minConfidencePct: Number(currentAutonomy.minConfidencePct || 0),
      waitThreshold: Number(currentThresholds.waitThreshold || 0),
      goThreshold: Number(currentThresholds.goThreshold || 0),
    },
    state: state ? {
      lockExpiresAt: state.lock_expires_at || null,
      lastRunAt: state.last_run_at || null,
      lastStatus: state.last_status || null,
      lastError: state.last_error || null,
      consecutiveHealthyRuns: Number(state.consecutive_healthy_runs || 0),
      lastBoundaryChangeDate: state.last_boundary_change_date || null,
      lastChangeDirection: state.last_change_direction || null,
      lastChangeAt: state.last_change_at || null,
      updatedAt: state.updated_at || null,
    } : null,
    latest: latest ? {
      id: latest.id,
      status: latest.status,
      sampleSize: Number(latest.sample_size || 0),
      winRate: latest.win_rate == null ? null : Number(latest.win_rate),
      lossStreak: Number(latest.loss_streak || 0),
      action: safeParseJson(latest.action_json, {}),
      details: safeParseJson(latest.details_json, {}),
      createdAt: latest.created_at,
    } : null,
  };
}

function getLatestLogicGuardCalibrationState() {
  const db = getDB();
  const row = db.prepare(`
    SELECT id, status, action_json, details_json, created_at
    FROM logic_guard_events
    ORDER BY id DESC
    LIMIT 1
  `).get();
  if (!row) {
    return {
      available: false,
      calibrating: false,
      reason: '',
      latestStatus: null,
      createdAt: null,
    };
  }
  const action = safeParseJson(row.action_json, {});
  const details = safeParseJson(row.details_json, {});
  const metrics = details.metrics || {};
  const decisive = Number(metrics.decisive || 0);
  const decisiveDays = Number(metrics.decisiveDays || 0);
  const minDecisiveSample = Number(details.minDecisiveSample || 0);
  const minDecisiveDays = Number(details.minDecisiveDays || 0);
  const reasonText = String(action.reason || '').toLowerCase();
  const calibrating = reasonText.includes('insufficient decisive')
    || (minDecisiveSample > 0 && decisive < minDecisiveSample)
    || (minDecisiveDays > 0 && decisiveDays < minDecisiveDays);
  return {
    available: true,
    calibrating,
    reason: String(action.reason || ''),
    latestStatus: row.status || null,
    createdAt: row.created_at || null,
    metrics: {
      decisive,
      decisiveDays,
      minDecisiveSample,
      minDecisiveDays,
    },
  };
}

function buildBoundarySummary(hours = 24) {
  const selfHeal = getSelfHealSummary(hours);
  const logicGuard = getLogicGuardSummary(Math.max(24, Math.min(720, Number(hours || 24) * 3)));
  const latestStatus = String(logicGuard?.latest?.status || 'steady').toLowerCase();
  const hasRuntimeFailures = Number(selfHeal?.failed || 0) > 0;
  const hasLogicErrors = Number(logicGuard?.errors || 0) > 0;
  const metrics = logicGuard?.latest?.details?.metrics || {};
  const decisive = Number(metrics?.decisive || 0);
  const decisiveDays = Number(metrics?.decisiveDays || 0);
  const minDecisiveDays = Number(logicGuard?.latest?.details?.minDecisiveDays || 0);
  const weightedWinRate = Number(metrics?.weightedWinRate ?? metrics?.winRate ?? 0);
  const recencyDelta = Number(metrics?.recencyDelta ?? 0);
  const clampPct = (n) => Math.max(0, Math.min(100, Number.isFinite(Number(n)) ? Number(n) : 0));
  const baseConfidence = clampPct((decisive * 7) + (weightedWinRate * 0.45) - (Math.max(0, -recencyDelta) * 1.3));
  const confidence = hasRuntimeFailures || hasLogicErrors ? Math.min(baseConfidence, 25) : baseConfidence;

  let boundaryMode = 'NORMAL';
  let directive = 'TRADE';
  let why = 'System healthy and guardrails stable.';

  if (latestStatus === 'tightened') {
    boundaryMode = 'DEFENSIVE';
    directive = 'WAIT';
    why = 'Recent outcomes weakened; filters tightened to reduce false starts.';
  } else if (latestStatus === 'relaxed') {
    boundaryMode = 'OPPORTUNISTIC';
    directive = 'TRADE';
    why = 'Recent outcomes strong; filters relaxed carefully within safety limits.';
  } else if (latestStatus === 'error' || hasRuntimeFailures || hasLogicErrors) {
    boundaryMode = 'ALERT';
    directive = "DON'T TRADE";
    why = 'System issue detected; wait for recovery confirmation before action.';
  } else if (decisive < 6 || (minDecisiveDays > 0 && decisiveDays < minDecisiveDays)) {
    boundaryMode = 'CALIBRATING';
    directive = 'WAIT';
    why = 'Decisive sample is still shallow; treat edge confidence as provisional.';
  }

  const line = `[${directive}] ${why}`;
  return {
    generatedAt: new Date().toISOString(),
    boundaryMode,
    directive,
    line,
    confidence: round2(confidence),
    activeBoundary: logicGuard?.activeBoundary || {
      minSetupProbability: 0,
      minConfidencePct: 0,
      waitThreshold: 0,
      goThreshold: 0,
    },
    health: {
      runtimeFailures: Number(selfHeal?.failed || 0),
      runtimeRemediated: Number(selfHeal?.remediated || 0),
      logicErrors: Number(logicGuard?.errors || 0),
    },
    latest: {
      selfHeal: selfHeal?.latest || null,
      logicGuard: logicGuard?.latest || null,
    },
  };
}

async function buildReadinessSummary(strategy = 'original') {
  const safeStrategy = strategy === 'alt' ? 'alt' : 'original';
  const health = buildHealthSnapshot();
  const boundary = buildBoundarySummary(24);
  const cmd = await buildTradingCommandSnapshot(safeStrategy).catch(() => null);
  const decision = cmd?.decision || null;
  const sig = buildDecisionSignalSummary(decision || {});
  const dataFreshness = getSessionFreshnessSummary('America/New_York');
  const now = Date.now();
  const lastMs = runtimeGuard.lastTriggerAt ? Date.parse(runtimeGuard.lastTriggerAt) : 0;
  const cooldownRemainingMs = lastMs > 0 ? Math.max(0, runtimeGuard.cooldownMs - (now - lastMs)) : 0;

  const reasons = [];
  if (health.status !== 'ok') reasons.push('system_health_degraded');
  if (boundary.directive === "DON'T TRADE") reasons.push('boundary_alert_mode');
  if (boundary.directive === 'WAIT') reasons.push('boundary_calibration_or_defensive_mode');
  if (runtimeGuard.inFlight) reasons.push('runtime_guard_healing_in_progress');
  if (runtimeGuard.lastError) reasons.push('runtime_guard_last_trigger_error');
  if ((decision?.blockers || []).length > 0) reasons.push('active_decision_blockers');
  if (dataFreshness.error) reasons.push('data_freshness_unavailable');
  if (dataFreshness.isStale) reasons.push('session_data_stale');
  if (!dataFreshness.lastSessionDate) reasons.push('session_data_missing');

  let readiness = 'READY';
  if (boundary.directive === "DON'T TRADE" || health.status !== 'ok') readiness = 'NOT_READY';
  else if (boundary.directive === 'WAIT' || runtimeGuard.inFlight || (decision?.blockers || []).length > 0) readiness = 'CAUTION';
  if (!dataFreshness.lastSessionDate) {
    readiness = 'NOT_READY';
  } else if (dataFreshness.isStale) {
    readiness = dataFreshness.staleDays > (dataFreshness.staleThresholdDays + 2) ? 'NOT_READY' : (readiness === 'READY' ? 'CAUTION' : readiness);
  }

  let line = readiness === 'READY'
    ? '[TRADE] System is healthy and decision gates are supportive.'
    : readiness === 'CAUTION'
      ? '[WAIT] System is running, but guardrails suggest patience.'
      : '[DON\'T TRADE] System or boundary state requires stand-down.';
  if (!dataFreshness.lastSessionDate) {
    line = '[DON\'T TRADE] No session data is loaded yet; import data first.';
  } else if (dataFreshness.isStale) {
    line = readiness === 'NOT_READY'
      ? '[DON\'T TRADE] Session data is too stale; resync before trading.'
      : '[WAIT] Session data is stale; verify current regime before trading.';
  }

  return {
    generatedAt: new Date().toISOString(),
    strategy: safeStrategy,
    readiness,
    line,
    signal: sig.signalLabel,
    boundaryDirective: boundary.directive,
    boundaryLine: boundary.line,
    decision: {
      verdict: decision?.verdict || null,
      confidence: decision?.confidence ?? null,
      blockers: decision?.blockers || [],
      topSetup: decision?.topSetups?.[0]?.name || null,
    },
    runtimeGuard: {
      inFlight: runtimeGuard.inFlight,
      lastTriggerAt: runtimeGuard.lastTriggerAt,
      lastReason: runtimeGuard.lastReason,
      lastError: runtimeGuard.lastError,
      cooldownRemainingMs,
      totalTriggers: runtimeGuard.totalTriggers,
      suppressed: runtimeGuard.suppressed,
    },
    dataFreshness,
    health,
    reasons,
  };
}

function ageHoursFromSqliteTimestamp(sqliteTs) {
  const d = sqliteToUtcDate(sqliteTs);
  if (!d) return null;
  return round2((Date.now() - d.getTime()) / (60 * 60 * 1000));
}

async function buildSteadyStateStatus(strategy = 'original') {
  const safeStrategy = strategy === 'alt' ? 'alt' : 'original';
  const now = nowInTimezone('America/New_York');
  const db = getDB();
  const readiness = await buildReadinessSummary(safeStrategy).catch(() => null);
  const freshness = getSessionFreshnessSummary('America/New_York');
  const latestSync = db.prepare('SELECT * FROM data_sync_runs ORDER BY id DESC LIMIT 1').get() || null;
  const latestEval = db.prepare('SELECT * FROM model_eval_runs ORDER BY id DESC LIMIT 1').get() || null;
  const recentLifecycleReview = db.prepare(`
    SELECT id, created_at, message, severity
    FROM activity_log
    WHERE module = 'lab' AND message LIKE 'Live lifecycle review%'
    ORDER BY id DESC
    LIMIT 1
  `).get() || null;
  const feedback7d = db.prepare(`
    SELECT COUNT(*) as n
    FROM trade_outcome_feedback
    WHERE trade_date >= date('now', '-7 days')
      AND source NOT IN ('deep_reliability','stability_test','system_probe','synthetic')
      AND setup_id NOT LIKE 'deep_reliability_%'
  `).get();
  const todayOutcome = summarizeFeedbackForDate(now.date);
  const todayClosure = buildOutcomeClosureStatusForDate(now.date);
  const outstandingClosure = findOutstandingOutcomeClosure({
    referenceDate: now.date,
    maxLookbackSessions: 7,
  });
  const weekday = new Date(`${now.date}T12:00:00`).getDay();

  const actions = [];
  const warnings = [];
  if (!readiness) {
    actions.push('REFRESH_COMMAND_SNAPSHOT');
  } else if (readiness.readiness === 'NOT_READY') {
    actions.push('RESOLVE_SYSTEM_NOT_READY');
  } else if (readiness.readiness === 'CAUTION') {
    warnings.push('SYSTEM_IN_CAUTION_MODE');
  }
  if (freshness.isStale) actions.push('RUN_DATA_SYNC');
  const syncAge = ageHoursFromSqliteTimestamp(latestSync?.created_at);
  if (!latestSync || !Number.isFinite(syncAge) || syncAge > 36) warnings.push('DATA_SYNC_STALE');
  const evalAge = ageHoursFromSqliteTimestamp(latestEval?.created_at);
  if (!latestEval || latestEval.status !== 'passed') actions.push('RUN_MODEL_EVAL');
  else if (!Number.isFinite(evalAge) || evalAge > 36) warnings.push('MODEL_EVAL_OLD');
  if (!recentLifecycleReview || (ageHoursFromSqliteTimestamp(recentLifecycleReview.created_at) || 999) > 36) {
    warnings.push('LIFECYCLE_REVIEW_OLD');
  }
  if (Number(feedback7d?.n || 0) <= 0) warnings.push('NO_RECENT_REAL_OUTCOMES');
  if (outstandingClosure.required && !outstandingClosure.complete) {
    actions.push('COMPLETE_OUTCOME_CLOSURE');
    if (outstandingClosure.stale) warnings.push('OUTCOME_CLOSURE_STALE');
  }
  if (weekday >= 1 && weekday <= 5 && now.time >= '16:45' && todayClosure.required && !todayClosure.complete) {
    actions.push('LOG_TODAY_OUTCOME');
  }

  const uniqueActions = Array.from(new Set(actions));
  const uniqueWarnings = Array.from(new Set(warnings));
  let status = 'READY';
  if (uniqueActions.length > 0) status = 'ACTION_REQUIRED';
  else if (uniqueWarnings.length > 0) status = 'ATTENTION';

  const line = status === 'READY'
    ? '[READY] System is in steady-state. Keep feeding real outcomes.'
    : status === 'ACTION_REQUIRED'
      ? '[ACTION REQUIRED] Complete required maintenance items before relying on signals.'
      : '[ATTENTION] System running, but maintenance drift was detected.';

  return {
    generatedAt: new Date().toISOString(),
    strategy: safeStrategy,
    status,
    line,
    requiredActions: uniqueActions,
    warnings: uniqueWarnings,
    readiness: readiness ? {
      state: readiness.readiness,
      line: readiness.line,
    } : null,
    dataFreshness: freshness,
    dataSync: latestSync ? {
      id: latestSync.id,
      status: latestSync.status,
      importedFiles: Number(latestSync.imported_files || 0),
      sessionsAdded: Number(latestSync.sessions_added || 0),
      ageHours: syncAge,
      createdAt: latestSync.created_at,
    } : null,
    modelEval: latestEval ? {
      id: latestEval.id,
      status: latestEval.status,
      interpreterPassed: !!latestEval.interpreter_passed,
      decisionPassed: !!latestEval.decision_passed,
      ageHours: evalAge,
      createdAt: latestEval.created_at,
    } : null,
    lifecycleReview: recentLifecycleReview ? {
      id: recentLifecycleReview.id,
      severity: recentLifecycleReview.severity,
      ageHours: ageHoursFromSqliteTimestamp(recentLifecycleReview.created_at),
      createdAt: recentLifecycleReview.created_at,
      message: recentLifecycleReview.message,
    } : null,
    outcomes: {
      todayDate: now.date,
      todaySamples: Number(todayOutcome.samples || 0),
      weekSamples: Number(feedback7d?.n || 0),
      todayWins: Number(todayOutcome.wins || 0),
      todayLosses: Number(todayOutcome.losses || 0),
      todayBreakeven: Number(todayOutcome.breakeven || 0),
      closure: {
        required: !!todayClosure.required,
        complete: !!todayClosure.complete,
        reason: todayClosure.reason || null,
        missingSetups: todayClosure.missingSetups || [],
      },
      outstandingClosure: {
        tradeDate: outstandingClosure.tradeDate || null,
        required: !!outstandingClosure.required,
        complete: !!outstandingClosure.complete,
        reason: outstandingClosure.reason || null,
        missingSetups: outstandingClosure.missingSetups || [],
        stale: !!outstandingClosure.stale,
        ageDays: Number.isFinite(Number(outstandingClosure.ageDays)) ? Number(outstandingClosure.ageDays) : null,
      },
    },
  };
}

async function runSteadyStateEnforcement(options = {}) {
  const strategy = options.strategy === 'alt' ? 'alt' : 'original';
  const triggerSource = String(options.triggerSource || 'api_manual_steady_enforce');
  const dataSync = runAutomatedDataSync({ triggerSource, maxFiles: options.maxFiles || 4 });
  const reconcile = runAutoReconciliationIngest({ maxFiles: 6 });
  const modelEval = await runModelEvalHarness({ triggerSource });
  const lifecycle = runLiveStrategyLifecycleReview(triggerSource);
  await buildTradingCommandSnapshot(strategy, { forceFresh: true }).catch(() => null);
  const steady = await buildSteadyStateStatus(strategy);
  return {
    status: 'ok',
    triggerSource,
    tasks: { dataSync, reconcile, modelEval, lifecycle },
    steadyState: steady,
  };
}

function getActiveScoreWeights(scope = 'global') {
  const db = getDB();
  const scoped = String(scope || 'global').trim() || 'global';
  let row = db.prepare(`
    SELECT *
    FROM score_weights
    WHERE scope = ? AND status = 'active'
    ORDER BY id DESC
    LIMIT 1
  `).get(scoped);
  if (!row && scoped !== 'global') {
    row = db.prepare(`
      SELECT *
      FROM score_weights
      WHERE scope = 'global' AND status = 'active'
      ORDER BY id DESC
      LIMIT 1
    `).get();
  }
  let wd = Number(row?.w_discovery ?? 0.34);
  let wi = Number(row?.w_intel ?? 0.33);
  let we = Number(row?.w_execution ?? 0.33);
  if (!Number.isFinite(wd) || !Number.isFinite(wi) || !Number.isFinite(we)) {
    wd = 0.34; wi = 0.33; we = 0.33;
  }
  wd = Math.max(0, wd);
  wi = Math.max(0, wi);
  we = Math.max(0, we);
  const sum = wd + wi + we;
  if (sum <= 0) {
    wd = 0.34; wi = 0.33; we = 0.33;
  }
  const denom = (wd + wi + we) || 1;
  return {
    scope: row?.scope || scoped,
    source: row ? 'db' : 'default',
    id: row?.id || null,
    proposedBy: row?.proposed_by || 'system',
    wDiscovery: round2((wd / denom) * 10000) / 10000,
    wIntel: round2((wi / denom) * 10000) / 10000,
    wExecution: round2((we / denom) * 10000) / 10000,
  };
}

function getActiveScoreThresholds(scope = 'global') {
  const db = getDB();
  const scoped = String(scope || 'global').trim() || 'global';
  let row = db.prepare(`
    SELECT *
    FROM score_thresholds
    WHERE scope = ? AND active = 1
    ORDER BY id DESC
    LIMIT 1
  `).get(scoped);
  if (!row && scoped !== 'global') {
    row = db.prepare(`
      SELECT *
      FROM score_thresholds
      WHERE scope = 'global' AND active = 1
      ORDER BY id DESC
      LIMIT 1
    `).get();
  }
  let waitThreshold = clampNumber(Number(row?.wait_threshold ?? 50), 0, 95);
  let goThreshold = clampNumber(Number(row?.go_threshold ?? 72), waitThreshold + 1, 100);
  if (goThreshold <= waitThreshold) {
    waitThreshold = 50;
    goThreshold = 72;
  }
  return {
    scope: row?.scope || scoped,
    source: row ? 'db' : 'default',
    id: row?.id || null,
    waitThreshold: round2(waitThreshold),
    goThreshold: round2(goThreshold),
  };
}

function updateActiveScoreConfig(input = {}) {
  const db = getDB();
  const scope = String(input.scope || 'global').trim() || 'global';
  const currentW = getActiveScoreWeights(scope);
  const currentT = getActiveScoreThresholds(scope);
  const proposedBy = String(input.proposedBy || input.proposed_by || 'owner').trim() || 'owner';
  const notes = input.notes == null ? null : String(input.notes).slice(0, 1000);

  const hasWeightInput = ['wDiscovery', 'wIntel', 'wExecution', 'w_discovery', 'w_intel', 'w_execution']
    .some((k) => input[k] != null);
  if (hasWeightInput) {
    let wd = Number(input.wDiscovery ?? input.w_discovery ?? currentW.wDiscovery);
    let wi = Number(input.wIntel ?? input.w_intel ?? currentW.wIntel);
    let we = Number(input.wExecution ?? input.w_execution ?? currentW.wExecution);
    if (!Number.isFinite(wd)) wd = currentW.wDiscovery;
    if (!Number.isFinite(wi)) wi = currentW.wIntel;
    if (!Number.isFinite(we)) we = currentW.wExecution;
    wd = Math.max(0, wd);
    wi = Math.max(0, wi);
    we = Math.max(0, we);
    const sum = wd + wi + we;
    if (sum <= 0) {
      wd = 0.34; wi = 0.33; we = 0.33;
    }
    const denom = (wd + wi + we) || 1;
    wd = wd / denom;
    wi = wi / denom;
    we = we / denom;
    db.prepare(`
      INSERT INTO score_weights (
        scope, w_discovery, w_intel, w_execution, status, proposed_by, notes, created_at
      ) VALUES (?, ?, ?, ?, 'active', ?, ?, datetime('now'))
      ON CONFLICT(scope, status) DO UPDATE SET
        w_discovery = excluded.w_discovery,
        w_intel = excluded.w_intel,
        w_execution = excluded.w_execution,
        proposed_by = excluded.proposed_by,
        notes = excluded.notes,
        created_at = datetime('now')
    `).run(scope, wd, wi, we, proposedBy, notes);
  }

  const hasThresholdInput = ['goThreshold', 'waitThreshold', 'go_threshold', 'wait_threshold']
    .some((k) => input[k] != null);
  if (hasThresholdInput) {
    let waitThreshold = Number(input.waitThreshold ?? input.wait_threshold ?? currentT.waitThreshold);
    let goThreshold = Number(input.goThreshold ?? input.go_threshold ?? currentT.goThreshold);
    if (!Number.isFinite(waitThreshold)) waitThreshold = currentT.waitThreshold;
    if (!Number.isFinite(goThreshold)) goThreshold = currentT.goThreshold;
    waitThreshold = clampNumber(waitThreshold, 0, 95);
    goThreshold = clampNumber(goThreshold, waitThreshold + 1, 100);
    const tx = db.transaction(() => {
      db.prepare('UPDATE score_thresholds SET active = 0 WHERE scope = ?').run(scope);
      db.prepare(`
        INSERT INTO score_thresholds (scope, go_threshold, wait_threshold, active, created_at)
        VALUES (?, ?, ?, 1, datetime('now'))
      `).run(scope, goThreshold, waitThreshold);
    });
    tx();
  }

  return {
    scope,
    weights: getActiveScoreWeights(scope),
    thresholds: getActiveScoreThresholds(scope),
  };
}

function recordDiscoveryKnowledge(report = {}, runId = null) {
  try {
    const runKey = Number.isFinite(Number(runId)) ? `discovery:run:${Number(runId)}` : `discovery:run:${Date.now()}`;
    const runEntity = kgEnsureEntity({
      entityKey: runKey,
      entityType: 'discovery_run',
      label: `Discovery Run #${runId || 'unknown'}`,
      metadata: {
        mode: report?.mode || null,
        summary: report?.summary || {},
      },
    });
    const candidates = Array.isArray(report?.candidates) ? report.candidates : [];
    for (const c of candidates) {
      const setupKeyPart = normalizeGraphKeyPart(c?.key || c?.name || `candidate_${Date.now()}`);
      const setupEntity = kgEnsureEntity({
        entityKey: `setup:${setupKeyPart}`,
        entityType: 'setup',
        label: c?.name || setupKeyPart,
        metadata: {
          strategyKey: c?.key || null,
          status: c?.status || null,
          family: c?.rules?.family || null,
        },
      });
      if (!setupEntity) continue;
      if (runEntity) {
        kgUpsertRelation({
          fromEntityId: runEntity.id,
          toEntityId: setupEntity.id,
          relationType: 'discovered_candidate',
          strength: clampNumber(Number(c?.robustnessScore || 0) / 100, 0, 1),
          metadata: {
            status: c?.status || null,
            score: c?.robustnessScore || 0,
          },
        });
      }
      kgAddObservation({
        entityId: setupEntity.id,
        obsType: 'discovery_candidate',
        sourceModule: 'discovery',
        tradeDate: dateInTimezone('America/New_York'),
        valueText: `${String(c?.status || 'candidate').toUpperCase()} candidate from discovery run.`,
        valueNumeric: Number(c?.robustnessScore || 0),
        valueJson: {
          runId,
          key: c?.key || null,
          status: c?.status || null,
          robustnessScore: Number(c?.robustnessScore || 0),
          testMetrics: c?.splits?.test || {},
          overallMetrics: c?.splits?.overall || {},
        },
        confidence: clampNumber(Number(c?.robustnessScore || 0) / 100, 0, 1),
      });
      if (String(c?.status || '').toLowerCase() === 'live_eligible') {
        kgUpsertInsight({
          insightKey: `discovery:live_eligible:${dateInTimezone('America/New_York')}:${setupKeyPart}`,
          scope: 'discovery',
          signal: 'WAIT',
          confidencePct: clampPercent(c?.robustnessScore || 0, 0, 100),
          blockerCount: 0,
          reason: `Live-eligible setup discovered: ${c?.name || setupKeyPart}.`,
          detailsJson: {
            runId,
            setupKey: c?.key || null,
            testWinRate: Number(c?.splits?.test?.winRate || 0),
            testProfitFactor: Number(c?.splits?.test?.profitFactor || 0),
          },
          tradeDate: dateInTimezone('America/New_York'),
          sourceModule: 'discovery',
        });
      }
    }
  } catch (err) {
    console.error('[Unified Intelligence] Discovery write failed:', err.message);
  }
}

function recordTradeFeedbackKnowledge(entry = {}) {
  try {
    const setupId = String(entry.setupId || '').trim().toLowerCase();
    const setupName = String(entry.setupName || '').trim();
    const outcome = String(entry.outcome || '').trim().toLowerCase();
    if (!setupId || !setupName || !outcome) return;

    const entityKey = `setup:${normalizeGraphKeyPart(setupId)}`;
    const updated = kgUpdateEntityOutcome({
      entityKey,
      entityType: 'setup',
      label: setupName,
      outcome,
      metadata: { setupId, setupName },
    });
    if (!updated) return;

    kgAddObservation({
      entityId: updated.id,
      obsType: 'trade_outcome',
      sourceModule: 'feedback',
      tradeDate: entry.tradeDate || dateInTimezone('America/New_York'),
      valueText: `Outcome logged: ${outcome.toUpperCase()}.`,
      valueNumeric: Number.isFinite(Number(entry.pnlDollars)) ? Number(entry.pnlDollars) : null,
      valueJson: {
        setupId,
        setupName,
        outcome,
        source: entry.source || 'manual',
        notes: entry.notes || null,
      },
      confidence: 1,
      isVerified: 1,
    });
    if (String(entry.notes || '').trim()) {
      kgAddObservation({
        entityId: updated.id,
        obsType: 'journal_note',
        sourceModule: 'feedback',
        tradeDate: entry.tradeDate || dateInTimezone('America/New_York'),
        valueText: String(entry.notes).slice(0, 1000),
        valueJson: {
          setupId,
          source: entry.source || 'manual',
        },
        confidence: 0.8,
      });
    }
  } catch (err) {
    console.error('[Unified Intelligence] Feedback write failed:', err.message);
  }
}

function recordCommandSnapshotKnowledge(snapshot = null) {
  try {
    if (!snapshot || !snapshot.decision) return;
    const decision = snapshot.decision || {};
    const tradeDate = snapshot.marketDate || dateInTimezone('America/New_York');
    const strategy = snapshot.strategy || 'original';
    const sessionEntity = kgEnsureEntity({
      entityKey: `session:${tradeDate}`,
      entityType: 'session',
      label: `Session ${tradeDate}`,
      metadata: {
        strategy,
      },
    });
    const topSetups = Array.isArray(decision.topSetups) ? decision.topSetups : [];
    for (const setup of topSetups) {
      const setupId = String(setup.setupId || setup.name || 'setup_unknown');
      const setupEntity = kgEnsureEntity({
        entityKey: `setup:${normalizeGraphKeyPart(setupId)}`,
        entityType: 'setup',
        label: setup.name || setupId,
        metadata: {
          setupId,
          source: 'decision',
        },
      });
      if (sessionEntity && setupEntity) {
        kgUpsertRelation({
          fromEntityId: sessionEntity.id,
          toEntityId: setupEntity.id,
          relationType: 'top_setup',
          strength: clampNumber(Number(setup.probability || 0) / 100, 0, 1),
          metadata: {
            rank: Number(setup.rank || null),
            expectedValueDollars: Number(setup.expectedValueDollars || 0),
            annualizedTrades: Number(setup.annualizedTrades || 0),
          },
        });
      }
      if (setupEntity) {
        kgAddObservation({
          entityId: setupEntity.id,
          obsType: 'setup_ranked',
          sourceModule: 'execution',
          tradeDate,
          sessionDate: tradeDate,
          valueText: `Ranked setup #${setup.rank || '?'} for ${tradeDate}.`,
          valueNumeric: Number(setup.probability || 0),
          valueJson: {
            rank: Number(setup.rank || null),
            grade: setup.grade || null,
            expectedValueDollars: Number(setup.expectedValueDollars || 0),
            liveWinRate: Number(setup.liveWinRate || 0),
            liveSamples: Number(setup.liveSamples || 0),
          },
          confidence: clampNumber(Number(setup.probability || 0) / 100, 0, 1),
        });
      }
    }
    if (sessionEntity) {
      kgAddObservation({
        entityId: sessionEntity.id,
        obsType: 'unified_decision',
        sourceModule: 'execution',
        tradeDate,
        sessionDate: tradeDate,
        valueText: buildDecisionSignalSummary(decision).line,
        valueNumeric: Number(decision.confidence || 0),
        valueJson: {
          signal: normalizeDecisionSignal(decision.signal || decision.verdict),
          blockers: decision.blockers || [],
          warnings: decision.warnings || [],
          setupScore: Number(decision.setupScoreEffective || 0),
        },
        confidence: clampNumber(Number(decision.confidence || 0) / 100, 0, 1),
      });
    }
    kgUpsertInsight({
      insightKey: `decision:${strategy}:${tradeDate}`,
      scope: 'global',
      signal: normalizeDecisionSignal(decision.signal || decision.verdict),
      confidencePct: clampPercent(decision.confidence || 0),
      blockerCount: Array.isArray(decision.blockers) ? decision.blockers.length : 0,
      reason: String(decision.why10Words || buildTenWordWhy({
        signal: normalizeDecisionSignal(decision.signal || decision.verdict),
        blockers: decision.blockers || [],
      })),
      detailsJson: {
        marketDate: tradeDate,
        strategy,
        blockers: decision.blockers || [],
        warnings: decision.warnings || [],
        topSetups: (decision.topSetups || []).slice(0, 3),
      },
      tradeDate,
      sourceModule: 'execution',
    });
  } catch (err) {
    console.error('[Unified Intelligence] Decision write failed:', err.message);
  }
}

function extractXmlTag(block, tag) {
  const m = String(block || '').match(new RegExp(`<${tag}>\\s*(?:<!\\[CDATA\\[([\\s\\S]*?)\\]\\]>|([^<]*))\\s*<\\/${tag}>`, 'i'));
  return String((m && (m[1] ?? m[2])) || '').trim();
}

function parseForexFactoryWeeklyXml(xmlText) {
  const xml = String(xmlText || '');
  const events = [];
  const re = /<event>([\s\S]*?)<\/event>/gi;
  let m;
  while ((m = re.exec(xml)) !== null) {
    const block = m[1];
    events.push({
      title: extractXmlTag(block, 'title'),
      country: extractXmlTag(block, 'country'),
      date: extractXmlTag(block, 'date'),
      time: extractXmlTag(block, 'time'),
      impact: extractXmlTag(block, 'impact'),
      forecast: extractXmlTag(block, 'forecast'),
      previous: extractXmlTag(block, 'previous'),
      url: extractXmlTag(block, 'url'),
    });
  }
  return events;
}

function dateYmdToMdY(ymd) {
  const parts = String(ymd || '').split('-');
  if (parts.length !== 3) return '';
  return `${parts[1]}-${parts[2]}-${parts[0]}`;
}

function parseTimeToMinutes(timeText) {
  const txt = String(timeText || '').trim().toLowerCase();
  if (!txt || txt === 'all day' || txt === 'tentative' || txt.includes('day')) return null;
  const m = txt.match(/^(\d{1,2}):(\d{2})\s*(am|pm)$/);
  if (!m) return null;
  let hour = Number(m[1]) % 12;
  const min = Number(m[2]);
  if (m[3] === 'pm') hour += 12;
  return hour * 60 + min;
}

function impactRank(impact) {
  const txt = String(impact || '').toLowerCase();
  if (txt.includes('high')) return 3;
  if (txt.includes('medium')) return 2;
  if (txt.includes('low')) return 1;
  return 0;
}

function currencyAllowed(country, allowed = []) {
  if (!allowed.length) return true;
  return allowed.includes(String(country || '').toUpperCase());
}

function readNewsCacheFromDisk() {
  try {
    const cachePath = path.join(__dirname, '..', 'data', 'news-calendar-cache.json');
    if (!fs.existsSync(cachePath)) return null;
    const raw = JSON.parse(fs.readFileSync(cachePath, 'utf8'));
    const events = Array.isArray(raw?.events) ? raw.events : [];
    if (!events.length) return null;
    return {
      fetchedAt: Number(raw.fetchedAt || 0),
      events,
      source: raw.source || 'disk_cache',
      error: null,
    };
  } catch {
    return null;
  }
}

function writeNewsCacheToDisk(payload) {
  try {
    const cachePath = path.join(__dirname, '..', 'data', 'news-calendar-cache.json');
    const out = {
      fetchedAt: Number(payload?.fetchedAt || Date.now()),
      source: payload?.source || 'forexfactory_weekly_xml',
      events: Array.isArray(payload?.events) ? payload.events : [],
      updatedAt: new Date().toISOString(),
    };
    fs.writeFileSync(cachePath, JSON.stringify(out, null, 2));
  } catch {}
}

async function fetchEconomicCalendarEvents() {
  const now = Date.now();
  if (now - econCalendarCache.fetchedAt < ECON_CACHE_TTL_MS && Array.isArray(econCalendarCache.events) && econCalendarCache.events.length) {
    return econCalendarCache;
  }
  const newsCfg = config.news || {};
  if (newsCfg.enabled === false) {
    return { fetchedAt: now, events: [], source: 'disabled', error: null };
  }
  const url = newsCfg.calendarUrl || 'https://nfs.faireconomy.media/ff_calendar_thisweek.xml';
  const timeoutMs = Math.max(3000, Number(newsCfg.timeoutMs || 9000));
  try {
    const response = await fetch(url, { signal: AbortSignal.timeout(timeoutMs) });
    if (!response.ok) {
      throw new Error(`calendar fetch failed (${response.status})`);
    }
    const xml = await response.text();
    const events = parseForexFactoryWeeklyXml(xml);
    econCalendarCache = {
      fetchedAt: now,
      events,
      source: 'forexfactory_weekly_xml',
      error: null,
    };
    writeNewsCacheToDisk(econCalendarCache);
    return econCalendarCache;
  } catch (err) {
    const disk = readNewsCacheFromDisk();
    if (disk && Array.isArray(disk.events) && disk.events.length) {
      econCalendarCache = {
        fetchedAt: now,
        events: disk.events,
        source: `stale_${disk.source || 'disk_cache'}`,
        error: err.message || 'calendar fetch failed',
      };
      return econCalendarCache;
    }
    econCalendarCache = {
      fetchedAt: now,
      events: Array.isArray(econCalendarCache.events) ? econCalendarCache.events : [],
      source: econCalendarCache.source || 'error',
      error: err.message || 'calendar fetch failed',
    };
    return econCalendarCache;
  }
}

function betaSmoothedRate(wins, total, priorP = 0.5, priorN = 14) {
  const w = Number(wins || 0);
  const n = Number(total || 0);
  if (n <= 0) return priorP;
  return (w + (priorP * priorN)) / (n + priorN);
}

function quantileFromSorted(arr, q) {
  if (!arr.length) return 0;
  const p = clampNumber(q, 0, 1);
  const idx = (arr.length - 1) * p;
  const lo = Math.floor(idx);
  const hi = Math.ceil(idx);
  if (lo === hi) return arr[lo];
  const mix = idx - lo;
  return arr[lo] + ((arr[hi] - arr[lo]) * mix);
}

function sigmoid(x) {
  const z = clampNumber(x, -30, 30);
  return 1 / (1 + Math.exp(-z));
}

function logit(p) {
  const pp = clampNumber(p, 1e-4, 1 - 1e-4);
  return Math.log(pp / (1 - pp));
}

function buildRateMap(rows, keyFn, priorRate = 0.5, priorN = 12) {
  const buckets = new Map();
  for (const row of rows) {
    const key = keyFn(row);
    if (!key) continue;
    const cur = buckets.get(key) || { n: 0, wins: 0 };
    cur.n += 1;
    if (row.result === 'win') cur.wins += 1;
    buckets.set(key, cur);
  }
  const out = new Map();
  for (const [key, b] of buckets.entries()) {
    const rate = betaSmoothedRate(b.wins, b.n, priorRate, priorN);
    out.set(key, { n: b.n, wins: b.wins, rate });
  }
  return out;
}

function getRateFromMap(map, key, fallbackRate = 0.5) {
  const row = map.get(key);
  if (!row) return { n: 0, rate: fallbackRate };
  return { n: Number(row.n || 0), rate: Number(row.rate || fallbackRate) };
}

function buildRegimeTradeRows(snapshot) {
  const bt = snapshot?.bt || {};
  const trades = Array.isArray(bt.trades) ? bt.trades : [];
  const regimes = snapshot?.regimes || {};
  return trades
    .filter((t) => !!t.date)
    .map((t, idx) => {
      const r = regimes[t.date] || {};
      return {
        ...t,
        idx,
        dayName: dayNameFromDate(t.date),
        orb: String(r.regime_orb_size || 'unknown').toLowerCase(),
        vol: String(r.regime_vol || 'unknown').toLowerCase(),
        trend: String(r.regime_trend || 'unknown').toLowerCase(),
      };
    });
}

function buildContextModel(rows, overallRate) {
  return {
    overallRate,
    totalN: rows.length,
    byDay: buildRateMap(rows, (r) => r.dayName, overallRate, 12),
    byOrb: buildRateMap(rows, (r) => r.orb, overallRate, 12),
    byVol: buildRateMap(rows, (r) => r.vol, overallRate, 12),
    byTrend: buildRateMap(rows, (r) => r.trend, overallRate, 12),
    byCombo: buildRateMap(rows, (r) => `${r.dayName}|${r.orb}|${r.vol}`, overallRate, 14),
  };
}

function scoreRawWinProbabilityFromContext(ctx, contextModel, options = {}) {
  const priorRate = clampNumber(Number(contextModel?.overallRate || 0.5), 0.05, 0.95);
  const day = getRateFromMap(contextModel.byDay, ctx.dayName, priorRate);
  const orb = getRateFromMap(contextModel.byOrb, ctx.orb, priorRate);
  const vol = getRateFromMap(contextModel.byVol, ctx.vol, priorRate);
  const trend = getRateFromMap(contextModel.byTrend, ctx.trend, priorRate);
  const combo = getRateFromMap(contextModel.byCombo, `${ctx.dayName}|${ctx.orb}|${ctx.vol}`, priorRate);
  const recentRate = clampNumber(Number(options.recentRate || priorRate), 0.05, 0.95);
  const recentN = Number(options.recentN || 0);

  const components = [
    { name: 'overall', n: Number(contextModel?.totalN || 0), rate: priorRate * 100, base: 1.0 },
    { name: 'day_of_week', n: day.n, rate: day.rate * 100, base: 0.95 },
    { name: 'orb_profile', n: orb.n, rate: orb.rate * 100, base: 0.9 },
    { name: 'volatility', n: vol.n, rate: vol.rate * 100, base: 0.85 },
    { name: 'trend', n: trend.n, rate: trend.rate * 100, base: 0.65 },
    { name: 'regime_combo', n: combo.n, rate: combo.rate * 100, base: 1.15 },
    { name: 'recent_form', n: recentN, rate: recentRate * 100, base: 0.8 },
  ].map((x) => {
    const sampleScale = clampNumber(x.n / 35, 0.1, 1.0);
    return { ...x, weight: x.base * sampleScale };
  });

  const weightedSum = components.reduce((s, x) => s + (x.rate * x.weight), 0);
  const weightTotal = components.reduce((s, x) => s + x.weight, 0) || 1;
  let point = weightedSum / weightTotal;

  const setupScore = clampNumber(options.setupScore ?? 50, 0, 100);
  const setupAdj = (setupScore - 50) * 0.08;
  const pfAdj = (Number(options.profitFactor || 1) - 1) * 2.4;
  point += setupAdj + pfAdj;
  if (String(options.action || '').toLowerCase().includes('defensive')) point -= 1.5;

  point = clampNumber(point, 25, 82);
  const effectiveN = components.reduce((s, x) => s + Math.min(40, x.n) * (x.weight / (x.base || 1)), 0);

  return {
    point,
    probability: point / 100,
    effectiveN,
    components: components.map((c) => ({ name: c.name, n: c.n, rate: round2(c.rate), weight: round2(c.weight) })),
  };
}

function fitPlattCalibrator(samples = []) {
  const clean = samples
    .map((s) => ({ p: clampNumber(Number(s.p || 0.5), 1e-4, 1 - 1e-4), y: Number(s.y ? 1 : 0) }))
    .filter((s) => Number.isFinite(s.p));
  if (clean.length < 40) {
    return { a: 1, b: 0, sampleSize: clean.length, mode: 'identity', logLossRaw: null, logLossCal: null, brierRaw: null, brierCal: null };
  }

  let a = 1;
  let b = 0;
  const n = clean.length;
  const lr = 0.08;
  const reg = 0.02;

  for (let iter = 0; iter < 260; iter += 1) {
    let gradA = 0;
    let gradB = 0;
    for (const s of clean) {
      const z = logit(s.p);
      const ph = sigmoid((a * z) + b);
      const err = ph - s.y;
      gradA += err * z;
      gradB += err;
    }
    gradA = (gradA / n) + (reg * (a - 1));
    gradB = (gradB / n) + (reg * b);
    a -= lr * gradA;
    b -= lr * gradB;
  }

  const logLoss = (pp, y) => -((y * Math.log(clampNumber(pp, 1e-6, 1 - 1e-6))) + ((1 - y) * Math.log(clampNumber(1 - pp, 1e-6, 1 - 1e-6))));
  let llRaw = 0;
  let llCal = 0;
  let brRaw = 0;
  let brCal = 0;
  for (const s of clean) {
    const pRaw = s.p;
    const pCal = sigmoid((a * logit(s.p)) + b);
    llRaw += logLoss(pRaw, s.y);
    llCal += logLoss(pCal, s.y);
    brRaw += Math.pow(pRaw - s.y, 2);
    brCal += Math.pow(pCal - s.y, 2);
  }

  return {
    a: round2(a),
    b: round2(b),
    sampleSize: n,
    mode: 'platt',
    logLossRaw: round2(llRaw / n),
    logLossCal: round2(llCal / n),
    brierRaw: round2(brRaw / n),
    brierCal: round2(brCal / n),
  };
}

function applyCalibrator(prob, calibrator) {
  const p = clampNumber(Number(prob || 0.5), 1e-4, 1 - 1e-4);
  if (!calibrator || calibrator.mode !== 'platt') return p;
  return sigmoid((Number(calibrator.a || 1) * logit(p)) + Number(calibrator.b || 0));
}

function parseAnnualizedTrades(freqText) {
  const m = String(freqText || '').match(/~\s*(\d+)\s*\/\s*yr/i);
  return m ? Number(m[1]) : null;
}

function gradeProbability(pct) {
  const p = Number(pct || 0);
  if (p >= 60) return 'A';
  if (p >= 55) return 'B';
  if (p >= 50) return 'C';
  return 'D';
}

function buildSetupProbabilityCards(plan, winModel, focusSetups = [], metrics = {}) {
  const avgWin = Math.abs(Number(metrics.avgWinDollars || 260));
  const avgLoss = Math.abs(Number(metrics.avgLossDollars || 220));
  const base = Number(winModel?.point || 50);
  return focusSetups.map((s, idx) => {
    const name = String(s.name || s.title || `Setup ${idx + 1}`);
    let p = base;
    const conf = String(s.confidence || '').toLowerCase();
    if (conf.includes('high')) p += 2.5;
    if (conf.includes('low')) p -= 2;
    if (/closer tp/i.test(name)) p += 1.5;
    if (/filter:/i.test(name) || /vulnerab/i.test(String(s.rationale || ''))) p -= 4;
    if (Number.isFinite(Number(s.testWR))) p = (0.55 * p) + (0.45 * Number(s.testWR));
    if (Number.isFinite(Number(s.testPF)) && Number(s.testPF) > 1.5) p += 1.2;
    p = clampNumber(p, 25, 85);
    const winP = p / 100;
    const ev = (winP * avgWin) - ((1 - winP) * avgLoss);
    const annualizedTrades = Number.isFinite(s.annualizedTrades) ? Number(s.annualizedTrades) : parseAnnualizedTrades(s.frequency || s.confidence);
    return {
      name,
      source: s.source || 'coach',
      probability: round2(p),
      grade: gradeProbability(p),
      expectedValueDollars: round2(ev),
      annualizedTrades: Number.isFinite(annualizedTrades) ? annualizedTrades : null,
      confidence: s.confidence || 'moderate',
      rationale: s.rationale || '',
    };
  }).sort((a, b) => b.probability - a.probability);
}

function buildSessionStrategyRanking(phasePlan = {}, setupCards = []) {
  const cardsByName = new Map(setupCards.map((c) => [String(c.name || '').toLowerCase(), c]));
  const rankFor = (focusNames = []) => {
    const focused = focusNames
      .map((n) => cardsByName.get(String(n || '').toLowerCase()))
      .filter(Boolean);
    const backup = setupCards.filter((c) => !focused.find((f) => f.name === c.name));
    const top = [...focused, ...backup].slice(0, 3);
    return top.map((c, idx) => ({
      rank: idx + 1,
      name: c.name,
      probability: c.probability,
      grade: c.grade,
      expectedValueDollars: c.expectedValueDollars,
    }));
  };
  return {
    preMarket: rankFor(phasePlan.preMarket?.focus || []),
    postORB: rankFor(phasePlan.postORB?.focus || []),
    midday: rankFor(phasePlan.midday?.focus || []),
  };
}

function loadLearningState() {
  try {
    if (!fs.existsSync(LEARNING_STATE_PATH)) {
      return { version: 1, records: [], updatedAt: null };
    }
    const raw = JSON.parse(fs.readFileSync(LEARNING_STATE_PATH, 'utf8'));
    return {
      version: Number(raw?.version || 1),
      records: Array.isArray(raw?.records) ? raw.records : [],
      updatedAt: raw?.updatedAt || null,
    };
  } catch {
    return { version: 1, records: [], updatedAt: null };
  }
}

function saveLearningState(state) {
  try {
    const out = {
      version: 1,
      records: Array.isArray(state?.records) ? state.records.slice(-600) : [],
      updatedAt: new Date().toISOString(),
    };
    fs.writeFileSync(LEARNING_STATE_PATH, JSON.stringify(out, null, 2));
  } catch {}
}

function summarizeLearningState(state) {
  const rows = Array.isArray(state?.records) ? state.records : [];
  const completed = rows.filter((r) => r?.outcome);
  if (!completed.length) {
    return { completedDays: 0, hitRate: null, avgPredictionError: null, avgPnlDollars: null, lastOutcomeDate: null };
  }
  let hits = 0;
  let errAbs = 0;
  let pnl = 0;
  for (const r of completed) {
    const wr = Number(r.outcome?.winRate ?? 50);
    if (wr >= Number(r.rangeLow || 0) && wr <= Number(r.rangeHigh || 100)) hits += 1;
    errAbs += Math.abs(Number(r.point || 50) - wr);
    pnl += Number(r.outcome?.pnlDollars || 0);
  }
  completed.sort((a, b) => String(b.date || '').localeCompare(String(a.date || '')));
  return {
    completedDays: completed.length,
    hitRate: round2((hits / completed.length) * 100),
    avgPredictionError: round2(errAbs / completed.length),
    avgPnlDollars: round2(pnl / completed.length),
    lastOutcomeDate: completed[0]?.date || null,
  };
}

function updateLearningLoop(brief) {
  const db = getDB();
  const state = loadLearningState();
  const date = String(brief?.marketDate || '');
  const strategy = String(brief?.strategy || 'original');
  if (date) {
    const exists = state.records.find((r) => r.date === date && r.strategy === strategy);
    if (!exists) {
      state.records.push({
        date,
        strategy,
        point: Number(brief?.winModel?.point || 50),
        rangeLow: Number(brief?.winModel?.rangeLow || 45),
        rangeHigh: Number(brief?.winModel?.rangeHigh || 55),
        modelVersion: brief?.modelVersion || 'elite',
        createdAt: new Date().toISOString(),
        outcome: null,
      });
    }
  }

  const today = dateInTimezone('America/New_York');
  for (const rec of state.records) {
    if (rec.outcome) continue;
    if (!rec.date || rec.date >= today) continue;
    const manual = db.prepare(`
      SELECT COUNT(*) as n,
             COALESCE(SUM(CASE WHEN result = 'win' THEN 1 ELSE 0 END), 0) as wins,
             COALESCE(SUM(COALESCE(pnl_dollars, 0)), 0) as pnl
      FROM trades
      WHERE source = 'manual' AND date = ?
    `).get(rec.date);
    const feedback = summarizeFeedbackForDate(rec.date);
    const useFeedback = Number(feedback.samples || 0) > 0;
    const n = useFeedback ? Number(feedback.samples || 0) : Number(manual?.n || 0);
    if (n <= 0) continue;
    const wins = useFeedback ? Number(feedback.wins || 0) : Number(manual?.wins || 0);
    const pnl = useFeedback ? Number(feedback.pnlDollars || 0) : Number(manual?.pnl || 0);
    const winRate = n > 0 ? (wins / n) * 100 : 0;
    rec.outcome = {
      trades: n,
      wins,
      winRate: round2(winRate),
      pnlDollars: round2(pnl),
      source: useFeedback ? 'trade_outcome_feedback' : 'manual_trades',
      withinRange: winRate >= Number(rec.rangeLow || 0) && winRate <= Number(rec.rangeHigh || 100),
      completedAt: new Date().toISOString(),
    };
  }

  state.records.sort((a, b) => String(a.date || '').localeCompare(String(b.date || '')));
  saveLearningState(state);
  return summarizeLearningState(state);
}

function estimateWinProbability(snapshot, plan) {
  const bt = snapshot?.bt || {};
  const metrics = bt.metrics || {};
  const rows = buildRegimeTradeRows(snapshot);
  const totalTrades = Number(metrics.totalTrades || rows.length || 0);
  const totalWins = Number(metrics.wins || rows.filter((t) => t.result === 'win').length || 0);
  const overallRate = betaSmoothedRate(totalWins, totalTrades, 0.5, 18);
  const contextModel = buildContextModel(rows, overallRate);

  const recentRows = rows.slice(-24);
  const recentWins = recentRows.filter((t) => t.result === 'win').length;
  const recentRate = betaSmoothedRate(recentWins, recentRows.length, overallRate, 8);
  const currentContext = {
    dayName: String(plan?.dayName || ''),
    orb: String(plan?.regime?.orbSize || 'unknown').toLowerCase(),
    vol: String(plan?.regime?.volatility || 'unknown').toLowerCase(),
    trend: String(plan?.regime?.trend || 'unknown').toLowerCase(),
  };

  const rawNow = scoreRawWinProbabilityFromContext(currentContext, contextModel, {
    recentRate,
    recentN: recentRows.length,
    setupScore: clampNumber(plan?.setupQuality?.score ?? 50, 0, 100),
    profitFactor: Number(metrics.profitFactor || 1),
    action: String(plan?.action || ''),
  });

  const samples = rows.map((r, idx) => {
    const recentHist = rows.slice(Math.max(0, idx - 24), idx);
    const recentHistWins = recentHist.filter((t) => t.result === 'win').length;
    const pRaw = scoreRawWinProbabilityFromContext({
      dayName: r.dayName,
      orb: r.orb,
      vol: r.vol,
      trend: r.trend,
    }, contextModel, {
      recentRate: betaSmoothedRate(recentHistWins, recentHist.length, overallRate, 8),
      recentN: recentHist.length,
      setupScore: 50,
      profitFactor: Number(metrics.profitFactor || 1),
      action: 'CONTROLLED EXECUTION',
    }).probability;
    return { p: pRaw, y: r.result === 'win' ? 1 : 0 };
  });

  const calibrator = fitPlattCalibrator(samples);
  const calibratedProb = applyCalibrator(rawNow.probability, calibrator);
  const point = calibratedProb * 100;
  const effectiveN = Math.max(8, Number(rawNow.effectiveN || 20));
  const confidence = clampNumber((Math.min(effectiveN, 320) / 320) * 0.72 + 0.24, 0.25, 0.96);
  const p = clampNumber(calibratedProb, 0.05, 0.95);
  const stdPct = Math.sqrt((p * (1 - p)) / effectiveN) * 100;
  const volPenalty = currentContext.vol === 'extreme' ? 2.5 : currentContext.vol === 'high' ? 1.3 : 0.7;
  const modelNoise = calibrator.mode === 'platt' && Number.isFinite(calibrator.brierCal)
    ? (Math.sqrt(Math.max(0.0001, calibrator.brierCal)) * 12)
    : 2.5;
  const band = Math.max(4, (stdPct * 1.96) + volPenalty + modelNoise);
  const rangeLow = clampNumber(point - band, 8, 95);
  const rangeHigh = clampNumber(point + band, 8, 95);

  return {
    point: round2(point),
    rawPoint: round2(rawNow.point),
    rangeLow: round2(rangeLow),
    rangeHigh: round2(rangeHigh),
    confidencePct: Math.round(confidence * 100),
    confidenceLevel: confidence >= 0.75 ? 'high' : confidence >= 0.55 ? 'medium' : 'low',
    modelInputs: {
      totalTrades,
      totalWins,
      setupScore: Math.round(clampNumber(plan?.setupQuality?.score ?? 50, 0, 100)),
      profitFactor: round2(metrics.profitFactor || 1),
      components: rawNow.components,
      calibration: calibrator,
    },
  };
}

function estimateOutcomeEnvelope(snapshot, plan, winModel) {
  const bt = snapshot?.bt || {};
  const metrics = bt.metrics || {};
  const trades = Array.isArray(bt.trades) ? bt.trades : [];
  const maxTrades = Math.max(1, Math.min(4, Number(plan?.riskPlan?.maxTrades ?? 2)));
  const stopAfterLosses = Math.max(1, Math.min(4, Number(plan?.riskPlan?.stopAfterConsecutiveLosses ?? 2)));
  const sizeGuidance = String(plan?.riskPlan?.sizeGuidance || '').toLowerCase();
  const sizeMultiplier = sizeGuidance.includes('half') ? 0.5 : sizeGuidance.includes('small') ? 0.7 : 1.0;

  const winSamples = trades.filter(t => t.result === 'win').map(t => Math.abs(Number(t.pnl_dollars || 0)) * sizeMultiplier).filter(v => Number.isFinite(v) && v > 0);
  const lossSamples = trades.filter(t => t.result === 'loss').map(t => Math.abs(Number(t.pnl_dollars || 0)) * sizeMultiplier).filter(v => Number.isFinite(v) && v > 0);

  const avgWin = Math.max(10, Math.abs(Number(metrics.avgWinDollars || 260)) * sizeMultiplier);
  const avgLoss = Math.max(10, Math.abs(Number(metrics.avgLossDollars || 220)) * sizeMultiplier);
  const winP = clampNumber(Number(winModel?.point || 50) / 100, 0.05, 0.95);
  const runs = 4000;

  const sampleVal = (arr, fallback) => {
    if (!Array.isArray(arr) || !arr.length) return fallback;
    return arr[Math.floor(Math.random() * arr.length)];
  };

  const outcomes = [];
  for (let i = 0; i < runs; i += 1) {
    let pnlDay = 0;
    let lossStreak = 0;
    for (let j = 0; j < maxTrades; j += 1) {
      const isWin = Math.random() < winP;
      if (isWin) {
        pnlDay += sampleVal(winSamples, avgWin);
        lossStreak = 0;
      } else {
        pnlDay -= sampleVal(lossSamples, avgLoss);
        lossStreak += 1;
        if (lossStreak >= stopAfterLosses) break;
      }
    }
    outcomes.push(pnlDay);
  }

  outcomes.sort((a, b) => a - b);
  const mean = outcomes.reduce((s, v) => s + v, 0) / (outcomes.length || 1);
  const p10 = quantileFromSorted(outcomes, 0.1);
  const p25 = quantileFromSorted(outcomes, 0.25);
  const p50 = quantileFromSorted(outcomes, 0.5);
  const p75 = quantileFromSorted(outcomes, 0.75);
  const p90 = quantileFromSorted(outcomes, 0.9);
  const probGreen = (outcomes.filter(v => v > 0).length / (outcomes.length || 1)) * 100;

  return {
    maxTrades,
    stopAfterLosses,
    sizeMultiplier,
    expectancyPerTrade: round2(Number(metrics.expectancyDollars || 0) * sizeMultiplier),
    expectedDayDollars: round2(mean),
    defensiveDollars: round2(p25),
    optimisticDollars: round2(p75),
    distribution: {
      p10: round2(p10),
      p50: round2(p50),
      p90: round2(p90),
      probGreen: round2(probGreen),
    },
  };
}

function buildSessionFocusPlan(plan, newsEvents, focusSetups) {
  const volatility = String(plan?.regime?.volatility || '').toLowerCase();
  const action = String(plan?.action || 'CONTROLLED EXECUTION');
  const aroundOpen = (newsEvents || []).filter((e) => Number.isFinite(e.minutes) && e.minutes >= 555 && e.minutes <= 645);
  const morningHigh = aroundOpen.filter((e) => impactRank(e.impact) >= 3);
  const firstSetup = focusSetups?.[0]?.name || 'Primary ORB setup';
  const secondSetup = focusSetups?.[1]?.name || 'Companion setup';
  const thirdSetup = focusSetups?.[2]?.name || 'High-selectivity fallback';

  return {
    preMarket: {
      objective: morningHigh.length ? 'Capital preservation into event risk window' : 'Structured preparation and selective first execution',
      focus: [firstSetup, secondSetup],
      checklist: [
        `Action state: ${action}`,
        morningHigh.length
          ? `High-impact event near open: ${morningHigh.map(e => `${e.time} ${e.country} ${e.title}`).join(' | ')}`
          : 'No high-impact event in the open-risk window.',
        `Regime: ORB ${plan?.regime?.orbSize || 'unknown'} | Vol ${plan?.regime?.volatility || 'unknown'} | Trend ${plan?.regime?.trend || 'unknown'}`,
      ],
    },
    postORB: {
      objective: 'Execute only if post-ORB structure confirms your edge',
      focus: [firstSetup, thirdSetup],
      checklist: [
        volatility === 'extreme'
          ? 'Extreme volatility gate: one-and-done unless setup quality is clearly A/B.'
          : 'Standard volatility gate: max two attempts if quality remains valid.',
        'Require clean trigger + acceptable risk/reward before entry.',
        `Respect max trades ${plan?.riskPlan?.maxTrades ?? 2} and stop-after-losses ${plan?.riskPlan?.stopAfterConsecutiveLosses ?? 2}.`,
      ],
    },
    midday: {
      objective: 'Protect capital and avoid forcing low-quality trades',
      focus: [secondSetup, thirdSetup],
      checklist: [
        'If morning execution failed quality gates, stand down instead of forcing catch-up trades.',
        'Prioritize highest-frequency setup only if structure is clean.',
        `Maintain ${plan?.riskPlan?.mode || 'CONTROLLED'} risk profile through close.`,
      ],
    },
  };
}

async function buildEliteMorningBrief(strategy = 'original') {
  const now = Date.now();
  const marketDate = dateInTimezone('America/New_York');
  const cacheKey = `${strategy}:${marketDate}`;
  const cached = eliteBriefCache.get(cacheKey);
  if (cached && (now - cached.fetchedAt) < ELITE_BRIEF_TTL_MS) {
    return cached.brief;
  }
  const inFlight = eliteBriefInFlight.get(cacheKey);
  if (inFlight) return inFlight;

  const pending = (async () => {
    const snapshot = buildCoachSnapshot(strategy);
    if (!snapshot) return null;
    const plan = buildDailyTradingPlan(strategy, { snapshot, forceFresh: true });
    if (!plan) return null;

    const todayYmd = marketDate;
    const todayMdY = dateYmdToMdY(todayYmd);
    const newsCfg = config.news || {};
    const allowedCurrencies = Array.isArray(newsCfg.focusCurrencies) && newsCfg.focusCurrencies.length
      ? newsCfg.focusCurrencies
      : ['USD'];
    const minImpact = String(newsCfg.minImpact || 'Medium').toLowerCase();
    const minImpactRank = minImpact.includes('high') ? 3 : minImpact.includes('low') ? 1 : 2;

    const calendar = await fetchEconomicCalendarEvents();
    const allTodayEvents = (calendar.events || [])
      .filter((e) => e.date === todayMdY)
      .map((e) => ({ ...e, minutes: parseTimeToMinutes(e.time) }))
      .sort((a, b) => {
        const am = a.minutes === null ? 10_000 : a.minutes;
        const bm = b.minutes === null ? 10_000 : b.minutes;
        if (am !== bm) return am - bm;
        return impactRank(b.impact) - impactRank(a.impact);
      });
    const todayEvents = allTodayEvents
      .filter((e) => currencyAllowed(e.country, allowedCurrencies))
      .filter((e) => impactRank(e.impact) >= minImpactRank)
      .slice(0, 24);

    const winModel = estimateWinProbability(snapshot, plan);
    const outcome = estimateOutcomeEnvelope(snapshot, plan, winModel);
    const discoveryFocus = getLatestOpportunitiesForDiscord(3);
    const focusSetups = [
      ...(plan.primarySetups || []).map(s => ({
        name: s.title,
        source: 'coach',
        confidence: s.confidence || 'moderate',
        rationale: s.rationale || 'Primary setup from coach model.',
        expectedImpact: Number(s.expectedImpact || 0),
      })),
      ...discoveryFocus.map(d => ({
        name: d.name,
        source: 'discovery',
        confidence: d.frequency || 'mid',
        rationale: `Live-eligible discovery candidate (score ${d.score}, test WR ${d.testWR}%, PF ${d.testPF}).`,
        expectedImpact: 0,
        testWR: Number(d.testWR || 0),
        testPF: Number(d.testPF || 0),
        annualizedTrades: Number(d.annualizedTrades || 0),
        frequencyBucket: d.frequencyBucket || null,
        frequency: d.frequency || null,
      })),
    ].slice(0, 4);
    const setupProbabilities = buildSetupProbabilityCards(plan, winModel, focusSetups, snapshot?.bt?.metrics || {});
    const phasePlan = buildSessionFocusPlan(plan, todayEvents, focusSetups);
    const strategyRanking = buildSessionStrategyRanking(phasePlan, setupProbabilities);
    const riskWindows = todayEvents
      .filter((e) => Number.isFinite(e.minutes) && e.minutes >= 555 && e.minutes <= 960)
      .slice(0, 5)
      .map((e) => ({
        time: e.time,
        country: e.country,
        impact: e.impact,
        title: e.title,
        window: e.minutes <= 630 ? 'open' : e.minutes <= 720 ? 'mid_morning' : 'midday',
      }));

    const brief = {
      generatedAt: new Date().toISOString(),
      strategy,
      marketDate: todayYmd,
      plan,
      winModel,
      outcome,
      modelVersion: 'elite-v3',
      news: {
        source: calendar.source,
        error: calendar.error,
        timezone: 'America/New_York',
        focusCurrencies: allowedCurrencies,
        minImpact,
        events: allTodayEvents.slice(0, 30),
        eventCount: allTodayEvents.length,
        focusEvents: todayEvents.slice(0, 16),
        focusEventCount: todayEvents.length,
        riskWindows,
      },
      focusSetups,
      setupProbabilities,
      phasePlan,
      strategyRanking,
      executionRules: [
        `Action state: ${plan.action}`,
        `Risk mode: ${plan.riskPlan?.mode || 'NORMAL'} | Max trades ${plan.riskPlan?.maxTrades ?? 2} | Size ${plan.riskPlan?.sizeGuidance || 'half-size'}`,
        `Bias: ${plan.bias?.dayBias || 'No strong day bias.'}`,
        `Regime playbook: ${(plan.bias?.orbPlaybook || [])[0] || 'Run core playbook.'}`,
      ],
    };
    brief.learning = updateLearningLoop(brief);
    eliteBriefCache.set(cacheKey, { fetchedAt: Date.now(), brief });
    if (eliteBriefCache.size > 8) {
      for (const [k] of eliteBriefCache.entries()) {
        if (k !== cacheKey) {
          eliteBriefCache.delete(k);
          if (eliteBriefCache.size <= 4) break;
        }
      }
    }
    return brief;
  })();

  eliteBriefInFlight.set(cacheKey, pending);
  try {
    return await pending;
  } finally {
    eliteBriefInFlight.delete(cacheKey);
  }
}

async function buildEliteMorningBriefText(strategy = 'original') {
  const brief = await buildEliteMorningBrief(strategy);
  if (!brief) return 'No elite brief is available yet. Import session data and run sync before requesting the morning brief.';

  const newsLines = (brief.news?.events || []).slice(0, 5)
    .map((e, i) => `${i + 1}. ${e.time || 'TBD'} ET | ${e.country} ${String(e.impact || '').toUpperCase()} | ${e.title}`)
    .join('\n') || 'No medium/high-impact focus-currency events scheduled today.';

  const focusLines = (brief.focusSetups || []).slice(0, 4)
    .map((s, i) => `${i + 1}. ${s.name} (${String(s.confidence || 'moderate').toUpperCase()})`)
    .join('\n') || 'No setup priorities identified.';
  const setupProbLines = (brief.setupProbabilities || []).slice(0, 3)
    .map((s, i) => `${i + 1}. ${s.name} — ${s.probability}% (${s.grade}) EV $${s.expectedValueDollars}`)
    .join('\n') || 'No setup probability cards available.';
  const phase = brief.phasePlan || {};
  const preMarketLine = (phase.preMarket?.focus || []).join(' | ') || 'not available';
  const postOrbLine = (phase.postORB?.focus || []).join(' | ') || 'not available';
  const middayLine = (phase.midday?.focus || []).join(' | ') || 'not available';
  const learn = brief.learning || {};

  return [
    `3130 Elite Morning Brief (${brief.plan.dayName})`,
    `Action: ${brief.plan.action} | Setup: ${brief.plan.setupQuality?.score || 0}/${brief.plan.setupQuality?.grade || 'D'}`,
    `Win Chance Today: ${brief.winModel?.point}% (range ${brief.winModel?.rangeLow}-${brief.winModel?.rangeHigh}%, confidence ${String(brief.winModel?.confidenceLevel || 'low').toUpperCase()})`,
    `Outcome Est.: mean $${brief.outcome?.expectedDayDollars} | P10 $${brief.outcome?.distribution?.p10} | P50 $${brief.outcome?.distribution?.p50} | P90 $${brief.outcome?.distribution?.p90} | Green ${brief.outcome?.distribution?.probGreen}%`,
    '',
    'News (ET):',
    newsLines,
    '',
    'Focus Setups:',
    focusLines,
    '',
    'Setup Odds:',
    setupProbLines,
    '',
    `Phase Focus — Pre: ${preMarketLine}`,
    `Phase Focus — Post-ORB: ${postOrbLine}`,
    `Phase Focus — Midday: ${middayLine}`,
    learn.completedDays > 0
      ? `Learning: ${learn.completedDays} completed day(s) | Hit-rate ${learn.hitRate}% | Avg abs error ${learn.avgPredictionError}% | Avg day PnL $${learn.avgPnlDollars}`
      : 'Learning: collecting real-trade outcomes from journal to calibrate predictions.',
    '',
    'Execution:',
    ...(brief.executionRules || []),
  ].join('\n');
}

function buildUnifiedExecutionDecision({ plan, elite, panel, opportunities = [] }) {
  const GOLDEN_ZONE_MAX = 220;
  const FRIDAY_EXHAUSTION_LIMIT = 380;
  const GLOBAL_EXHAUSTION_LIMIT = 400;
  const ROLLING3_VOLATILITY_ALERT = 450;
  const ROLLING3_VOLATILITY_MSG = 'High Volatility Regime Detected: Probability of fakeouts increased. Tighten stops or increase blocker sensitivity.';
  const GOLDEN_ZONE_MIN = 70;
  const blockers = [];
  const warnings = [];
  const addBlocker = (name) => {
    if (!name) return;
    if (!blockers.includes(name)) blockers.push(name);
  };
  const addWarning = (msg) => {
    if (!msg) return;
    if (!warnings.includes(msg)) warnings.push(msg);
  };
  const guardCalibration = getLatestLogicGuardCalibrationState();
  const action = String(plan?.action || '').toUpperCase();
  const winPoint = Number(elite?.winModel?.point || 0);
  const probGreen = Number(elite?.outcome?.distribution?.probGreen || 0);
  const scoreWeights = getActiveScoreWeights('global');
  const scoreThresholds = getActiveScoreThresholds('global');
  const dataFreshness = getSessionFreshnessSummary('America/New_York');
  const orbCandidates = [
    plan?.regime?.orbRangeTicks,
    opportunities?.orb?.range_ticks,
    ...(Array.isArray(opportunities) ? opportunities.map((o) => o?.orb?.range_ticks) : []),
  ];
  let orbRangeTicks = null;
  for (const c of orbCandidates) {
    const n = Number(c);
    if (Number.isFinite(n)) {
      orbRangeTicks = n;
      break;
    }
  }
  const hasOrbRangeTicks = Number.isFinite(orbRangeTicks);
  const rolling3OrbAvgTicks = Number(plan?.regime?.rolling3OrbAvgTicks);
  const hasRolling3OrbAvgTicks = Number.isFinite(rolling3OrbAvgTicks);
  const baseSetupScore = Number(plan?.setupQuality?.score || 0);
  let setupScore = baseSetupScore;
  let goldenZoneBonusApplied = false;
  if (hasOrbRangeTicks && orbRangeTicks >= GOLDEN_ZONE_MIN && orbRangeTicks <= GOLDEN_ZONE_MAX) {
    setupScore = clampNumber(baseSetupScore + 15, 0, 100);
    goldenZoneBonusApplied = true;
    if (plan?.setupQuality && Number.isFinite(Number(plan.setupQuality.score))) {
      plan.setupQuality.score = setupScore;
      plan.setupQuality.grade = gradeSetupQuality(setupScore);
      if (Array.isArray(plan.setupQuality.drivers)) {
        const bonusDriver = `Golden-zone bonus applied (+15): ORB ${Math.round(orbRangeTicks)}t within 70-${GOLDEN_ZONE_MAX}t.`;
        if (!plan.setupQuality.drivers.includes(bonusDriver)) {
          plan.setupQuality.drivers = [bonusDriver, ...plan.setupQuality.drivers].slice(0, 6);
        }
      }
    }
  }
  const todayName = String(plan?.dayName || '').toLowerCase();
  const isFriday = todayName === 'friday';
  if (isFriday && hasOrbRangeTicks && orbRangeTicks > FRIDAY_EXHAUSTION_LIMIT) {
    addBlocker('FRIDAY_VOLATILITY_EXHAUSTION');
  }
  if (hasOrbRangeTicks && orbRangeTicks > GLOBAL_EXHAUSTION_LIMIT) {
    addBlocker('RANGE_OVEREXTENDED');
    addWarning('Historical Exhaustion Risk: Range exceeds 5-year win average.');
  }
  if (hasRolling3OrbAvgTicks && rolling3OrbAvgTicks > ROLLING3_VOLATILITY_ALERT) {
    addWarning(ROLLING3_VOLATILITY_MSG);
  }
  if (guardCalibration.calibrating) {
    addBlocker('INSUFFICIENT_DECISIVE_SAMPLE');
    addWarning('Calibration active: decisive trade sample is still too shallow.');
  }
  const openRisk = (elite?.news?.riskWindows || []).filter((w) => w.window === 'open');
  const liveBlocked = (panel?.execution?.blockedReasons || []).map((b) => String(b || '').trim()).filter(Boolean);
  const executionAdvisoryOnly = new Set([
    'TOPSTEP_READ_ONLY_MODE',
    'TOPSTEP_API_NOT_ENABLED',
    'TOPSTEP_API_KEY_MISSING',
    'TOPSTEP_MANUAL_CONFIRM_REQUIRED',
    'TOPSTEP_AUTOMATION_DISABLED',
    'TOPSTEP_MANUAL_CONFIRMATION_ONLY',
  ]);
  const liveBlockedHard = [];
  for (const b of liveBlocked) {
    const key = String(b || '').toUpperCase();
    if (executionAdvisoryOnly.has(key)) {
      addWarning(`Execution compliance: ${humanizeDecisionBlocker(key)}.`);
    } else {
      liveBlockedHard.push(b);
    }
  }
  if (panel?.execution?.newsLockout?.blocked) {
    addBlocker('NEWS_LOCKOUT_ACTIVE');
    addWarning('High-impact news lockout window is active now.');
  }
  if (dataFreshness.isStale) {
    addBlocker('STALE_SESSION_DATA');
    addWarning(`Session data stale (${dataFreshness.staleDays}d). Sync fresh data before execution.`);
  }
  const outcomeClosure = findOutstandingOutcomeClosure({ maxLookbackSessions: 7 });
  if (outcomeClosure.required && !outcomeClosure.complete) {
    addBlocker('OUTCOME_LOG_INCOMPLETE');
    const missing = (outcomeClosure.missingSetups || []).slice(0, 3).join(', ');
    addWarning(
      `Outcome log required for ${outcomeClosure.tradeDate}${missing ? ` (missing setup logs: ${missing})` : ''}.`
    );
  }
  const discoveryRawScores = (Array.isArray(opportunities) ? opportunities : [])
    .map((o) => Number(o?.score ?? o?.robustnessScore ?? o?.testWR))
    .filter((n) => Number.isFinite(n))
    .map((n) => clampNumber(n, 0, 100));
  const discoveryScore = discoveryRawScores.length
    ? round2(discoveryRawScores.reduce((sum, n) => sum + n, 0) / discoveryRawScores.length)
    : 50;
  const intelScore = round2(clampNumber((winPoint * 0.55) + (probGreen * 0.45), 0, 100));
  let executionScore = clampNumber(setupScore, 0, 100);
  if (action.includes('DEFENSIVE')) executionScore -= 10;
  if (openRisk.length > 0) executionScore -= 8;
  if (liveBlockedHard.length > 0) executionScore -= 12;
  executionScore = round2(clampNumber(executionScore, 0, 100));
  const unifiedScore = round2(clampNumber(
    (discoveryScore * Number(scoreWeights.wDiscovery || 0.34))
      + (intelScore * Number(scoreWeights.wIntel || 0.33))
      + (executionScore * Number(scoreWeights.wExecution || 0.33)),
    0,
    100
  ));

  if (action.includes('DEFENSIVE')) addBlocker('defensive_action_state');
  if (setupScore < 50) addBlocker('setup_quality_below_50');
  if (winPoint < 50) addBlocker('win_prob_below_50');
  if (probGreen < 50) addBlocker('prob_green_below_50');
  if (openRisk.length > 0) addBlocker('open_news_risk');
  if (liveBlockedHard.length > 0) {
    for (const b of liveBlockedHard.slice(0, 2)) addBlocker(b);
  }

  const topSetups = (elite?.setupProbabilities || []).slice(0, 3).map((s, i) => ({
    rank: i + 1,
    setupId: normalizeSetupKey(s.name) || 'setup_unknown',
    name: s.name,
    probability: s.probability,
    grade: s.grade,
    expectedValueDollars: s.expectedValueDollars,
    annualizedTrades: s.annualizedTrades,
  }));
  const setupScorecards = buildTopSetupScorecards(topSetups);
  const scorecardBySetup = new Map(setupScorecards.map((c) => [c.setupId, c]));
  for (const s of topSetups) {
    s.scorecard = scorecardBySetup.get(s.setupId) || null;
  }
  topSetups.sort((a, b) => {
    const aScore = Number(a?.scorecard?.reliabilityScore || 50) * 0.55 + Number(a?.probability || 0) * 0.45;
    const bScore = Number(b?.scorecard?.reliabilityScore || 50) * 0.55 + Number(b?.probability || 0) * 0.45;
    return bScore - aScore;
  });
  topSetups.forEach((s, i) => { s.rank = i + 1; });
  const leadSetupScorecard = topSetups[0]?.scorecard || null;
  if (leadSetupScorecard?.signal === 'VERY_WEAK') {
    addBlocker('TOP_SETUP_VERY_WEAK_20_60');
    addWarning(`Top setup underperforming: ${leadSetupScorecard.rationale}`);
  } else if (leadSetupScorecard?.signal === 'WEAK') {
    addBlocker('TOP_SETUP_WEAK_20_60');
    addWarning(`Top setup weak in recent scorecard: ${leadSetupScorecard.rationale}`);
  } else if (leadSetupScorecard?.signal === 'INSUFFICIENT') {
    addWarning('Top setup scorecard is sample-limited; reduce confidence and size.');
  }

  const blockerUpper = blockers.map((b) => String(b || '').toUpperCase());
  const hasBlocker = (...keys) => blockerUpper.some((b) => keys.includes(b));
  const hasTopstepHardBlocker = blockerUpper.some((b) =>
    b === 'TOPSTEP_ENTRY_WINDOW_CLOSED'
      || b === 'TOPSTEP_FLATTEN_REQUIRED'
      || b === 'TOPSTEP_REMOTE_RUNTIME_DISALLOWED'
      || b === 'TOPSTEP_DAILY_LOSS_LIMIT_REACHED'
      || b === 'TOPSTEP_DRAWDOWN_BUFFER_LOW'
  );
  const hasTopstepSoftBlocker = blockerUpper.some((b) => b.startsWith('TOPSTEP_')) && !hasTopstepHardBlocker;
  if (hasTopstepSoftBlocker) {
    addWarning('Topstep compliance limits automation/execution mode; manual workflow required.');
  }
  const hardNoTrade = hasBlocker(
    'EXECUTION_DISABLED',
    'KILL_SWITCH_ACTIVE',
    'DAILY_LOSS_LIMIT_REACHED',
    'MAX_ORDERS_PER_DAY_REACHED',
    'TOP_SETUP_VERY_WEAK_20_60'
  );
  const hardWait = blockerUpper.some((b) =>
    b === 'RANGE_OVEREXTENDED'
      || b === 'FRIDAY_VOLATILITY_EXHAUSTION'
      || b === 'INSUFFICIENT_DECISIVE_SAMPLE'
      || b === 'STALE_SESSION_DATA'
      || b === 'NEWS_LOCKOUT_ACTIVE'
      || b === 'OUTCOME_LOG_INCOMPLETE'
      || b === 'TOP_SETUP_WEAK_20_60'
      || b === 'ORDER_COOLDOWN_ACTIVE'
      || b === 'TOPSTEP_LIVE_SYNC_UNHEALTHY'
  );

  let verdict = 'NO_TRADE';
  if (hardNoTrade || hasTopstepHardBlocker) verdict = 'NO_TRADE';
  else if (hardWait) verdict = 'WAIT';
  else if (blockers.length === 0 && unifiedScore >= Number(scoreThresholds.goThreshold || 72)) verdict = 'GO';
  else if (unifiedScore >= Number(scoreThresholds.waitThreshold || 50)) verdict = 'WAIT';
  else verdict = 'NO_TRADE';

  const ranked = elite?.strategyRanking?.preMarket || [];
  const orbLine = hasOrbRangeTicks
    ? `ORB 15m range: ${Math.round(orbRangeTicks)}t${goldenZoneBonusApplied ? ` (golden zone bonus +15, setup ${Math.round(baseSetupScore)} → ${Math.round(setupScore)})` : ''}.`
    : 'ORB 15m range: unavailable.';
  const rolling3Line = hasRolling3OrbAvgTicks
    ? `Recent 3-session ORB avg: ${Math.round(rolling3OrbAvgTicks)}t${rolling3OrbAvgTicks > ROLLING3_VOLATILITY_ALERT ? ' (high-vol regime)' : ''}.`
    : 'Recent 3-session ORB avg: unavailable.';
  const actionablePlan = [
    verdict === 'GO'
      ? 'Execute top-ranked setup only when trigger + structure align.'
      : verdict === 'WAIT'
        ? 'Wait for cleaner structure; no forced entries.'
        : 'No-trade bias unless setup quality materially improves.',
    `Unified score ${unifiedScore}/100 (thresholds: execute >= ${scoreThresholds.goThreshold}, monitor >= ${scoreThresholds.waitThreshold}).`,
    orbLine,
    rolling3Line,
    ...warnings,
    leadSetupScorecard
      ? `Top setup scorecard ${leadSetupScorecard.signal}: WR20 ${leadSetupScorecard.windows.w20.winRate}% (${leadSetupScorecard.windows.w20.samples} samples), WR60 ${leadSetupScorecard.windows.w60.winRate}% (${leadSetupScorecard.windows.w60.samples} samples).`
      : 'Top setup scorecard unavailable.',
    outcomeClosure.required && !outcomeClosure.complete
      ? `Outcome closure required for ${outcomeClosure.tradeDate}: ${outcomeClosure.reason}.`
      : 'Outcome closure check passed.',
    guardCalibration.calibrating
      ? `Calibration gate: ${guardCalibration.reason || 'decisive sample insufficient for full confidence.'}`
      : null,
    `Risk mode ${plan?.riskPlan?.mode || 'NORMAL'} with max ${plan?.riskPlan?.maxTrades ?? 2} trade(s).`,
    openRisk.length
      ? `Delay entries around open event risk (${openRisk.slice(0, 2).map((e) => `${e.time} ${e.country}`).join(' | ')}).`
      : 'No open-window event blockers.',
    ranked.length
      ? `Primary sequence: ${ranked.slice(0, 3).map((r) => `${r.rank}) ${r.name}`).join(' | ')}`
      : ((opportunities[0]?.name || opportunities[0]?.title) ? `Primary candidate: ${opportunities[0].name || opportunities[0].title}` : 'No ranked sequence available.'),
  ].filter(Boolean);
  const signal = normalizeDecisionSignal(verdict);
  const signalLabel = decisionSignalLabel(signal);
  const why10Words = buildTenWordWhy({ signal, blockers });

  const blockerPenalty = (blockers.length * 7) + (hardWait ? 8 : 0) + (hardNoTrade ? 14 : 0);
  return {
    verdict,
    signal,
    signalLabel,
    why10Words,
    signalLine: `[${signalLabel}] ${why10Words}`,
    confidence: round2(clampNumber((unifiedScore * 0.72) + (setupScore * 0.28) - blockerPenalty, 5, 98)),
    blockers,
    warnings,
    dataFreshness,
    orbRangeTicks: hasOrbRangeTicks ? round2(orbRangeTicks) : null,
    rolling3OrbAvgTicks: hasRolling3OrbAvgTicks ? round2(rolling3OrbAvgTicks) : null,
    setupScoreBase: round2(baseSetupScore),
    setupScoreEffective: round2(setupScore),
    unifiedScore,
    subScores: {
      discovery: discoveryScore,
      intel: intelScore,
      execution: executionScore,
    },
    setupScorecards: setupScorecards.slice(0, 3),
    outcomeClosure,
    scoreConfig: {
      weights: scoreWeights,
      thresholds: scoreThresholds,
    },
    hardGateTriggered: {
      hardNoTrade,
      hardWait,
    },
    topSetups,
    actionablePlan,
  };
}

function listTradeOutcomeFeedback(limit = 100, options = {}) {
  const includeSynthetic = asBool(options.includeSynthetic, false);
  const rows = getDB().prepare(`
    SELECT id, trade_id, trade_date, setup_id, setup_name, outcome, pnl_dollars, notes, source, created_at
    FROM trade_outcome_feedback
    ORDER BY id DESC
    LIMIT ?
  `).all(Math.max(1, Math.min(1000, Number(limit || 100))));
  return rows
    .filter((r) => includeSynthetic || !isSyntheticFeedback({ source: r.source, setupId: r.setup_id }))
    .map((r) => ({
    id: r.id,
    tradeId: r.trade_id,
    tradeDate: r.trade_date,
    setupId: r.setup_id,
    setupName: r.setup_name,
    outcome: r.outcome,
    pnlDollars: r.pnl_dollars,
    notes: r.notes,
    source: r.source,
    createdAt: r.created_at,
  }));
}

function normalizeOutcomeCounts(input = {}) {
  const wins = Math.max(0, Math.floor(Number(input.wins ?? input.winsCount ?? 0)));
  const losses = Math.max(0, Math.floor(Number(input.losses ?? input.lossesCount ?? 0)));
  const breakeven = Math.max(0, Math.floor(Number(input.breakeven ?? input.breakevenCount ?? 0)));
  const total = wins + losses + breakeven;
  return { wins, losses, breakeven, total };
}

const SYNTHETIC_FEEDBACK_SOURCES = new Set(['deep_reliability', 'stability_test', 'system_probe', 'synthetic']);
function isSyntheticFeedback({ source, setupId }) {
  const src = String(source || '').trim().toLowerCase();
  const sid = String(setupId || '').trim().toLowerCase();
  return SYNTHETIC_FEEDBACK_SOURCES.has(src) || sid.startsWith('deep_reliability_');
}

function deriveFeedbackTestIdeas(rows = []) {
  const noteRows = rows.filter((r) => String(r.notes || '').trim());
  const noteText = noteRows.map((r) => String(r.notes || '').toLowerCase()).join('\n');
  const ideas = [];
  if (/\bfirst\b.*\bloss\b|\bfirst trade\b.*\bloss\b/.test(noteText)) {
    ideas.push('Test first-entry quality gate: require cleaner trigger or reduce first entry size by one step.');
  }
  if (/\bslipp|spread|fill\b/.test(noteText)) {
    ideas.push('Track slippage by session window and avoid entries during widening spread conditions.');
  }
  if (/\bovertrade|revenge|force|chase\b/.test(noteText)) {
    ideas.push('Add behavioral guardrail: stop after first invalid setup and enforce cooldown before next entry.');
  }
  if (/\bstop\b.*\bbigger\b|\bloss\b.*\bbigger\b/.test(noteText)) {
    ideas.push('Test asymmetric stop handling: tighter initial stop or time-based stop on first attempt.');
  }
  if (ideas.length === 0 && noteRows.length > 0) {
    ideas.push('Convert repeated journal notes into a formal filter and validate it in paper-forward testing.');
  }
  return {
    latestNotes: noteRows.slice(0, 6).map((r) => String(r.notes || '').slice(0, 180)),
    testIdeas: ideas.slice(0, 6),
  };
}

function logTradeOutcomeFeedback(input = {}) {
  const db = getDB();
  const setupId = String(input.setupId || '').trim().toLowerCase();
  const setupName = String(input.setupName || '').trim();
  const outcome = String(input.outcome || '').trim().toLowerCase();
  if (!setupId || !setupName) throw new Error('setupId and setupName are required.');
  if (!['win', 'loss', 'breakeven', 'mixed'].includes(outcome)) throw new Error('outcome must be win/loss/breakeven/mixed.');
  const tradeDate = String(input.tradeDate || dateInTimezone('America/New_York'));
  const pnlDollars = input.pnlDollars == null ? null : Number(input.pnlDollars);
  const notes = input.notes == null ? null : String(input.notes);
  const tradeId = input.tradeId == null ? null : Number(input.tradeId);
  const source = String(input.source || 'manual').trim().toLowerCase();
  const synthetic = isSyntheticFeedback({ source, setupId });
  const normalizedCounts = normalizeOutcomeCounts(input);

  const insertOne = db.prepare(`
    INSERT INTO trade_outcome_feedback (trade_id, trade_date, setup_id, setup_name, outcome, pnl_dollars, notes, source)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `);
  const logActivity = db.prepare('INSERT INTO activity_log (module, message, severity, data) VALUES (?, ?, ?, ?)');

  if (outcome === 'mixed') {
    if (normalizedCounts.total <= 0) throw new Error('mixed outcome requires wins/losses/breakeven counts.');
    const entries = [];
    const batchSummary = `${normalizedCounts.wins}W/${normalizedCounts.losses}L/${normalizedCounts.breakeven}BE`;
    const baseNotes = [notes, `Batch outcome: ${batchSummary}`, Number.isFinite(pnlDollars) ? `Net PnL: $${Number(pnlDollars).toFixed(2)}` : null]
      .filter(Boolean)
      .join(' | ');
    const tx = db.transaction(() => {
      const pushRows = (tag, count) => {
        for (let i = 0; i < count; i += 1) {
          const row = insertOne.run(
            tradeId,
            tradeDate,
            setupId,
            setupName,
            tag,
            null,
            normalizedCounts.total > 1 ? `${baseNotes} | Leg ${entries.length + 1}/${normalizedCounts.total}` : baseNotes,
            source
          );
          entries.push({
            id: row.lastInsertRowid,
            setupId,
            setupName,
            outcome: tag,
            tradeDate,
            pnlDollars: null,
            notes: baseNotes,
            source,
          });
        }
      };
      pushRows('win', normalizedCounts.wins);
      pushRows('loss', normalizedCounts.losses);
      pushRows('breakeven', normalizedCounts.breakeven);
      logActivity.run(
        'feedback',
        `${synthetic ? '[synthetic] ' : ''}Mixed trade outcome logged for ${setupName} (${batchSummary}).`,
        'info',
        JSON.stringify({ setupId, tradeDate, source, batch: normalizedCounts, entries: entries.length, synthetic })
      );
    });
    tx();
    if (!synthetic) {
      for (const entry of entries) {
        recordTradeFeedbackKnowledge(entry);
      }
    }
    invalidateCommandSnapshotCache();
    resetAnalystContext('trade_feedback_updated', { clearHistory: false });
    return {
      mixed: true,
      setupId,
      setupName,
      tradeDate,
      source,
      batch: normalizedCounts,
      entriesCreated: entries.length,
      entries,
    };
  }

  if (!['win', 'loss', 'breakeven'].includes(outcome)) throw new Error('outcome must be win/loss/breakeven/mixed.');

  const row = insertOne.run(tradeId, tradeDate, setupId, setupName, outcome, pnlDollars, notes, source);

  logActivity.run(
    'feedback',
    `${synthetic ? '[synthetic] ' : ''}Trade outcome feedback logged for ${setupName} (${outcome}).`,
    'info',
    JSON.stringify({ id: row.lastInsertRowid, setupId, outcome, tradeDate, source, synthetic })
  );
  if (!synthetic) {
    recordTradeFeedbackKnowledge({
      id: row.lastInsertRowid,
      setupId,
      setupName,
      outcome,
      tradeDate,
      pnlDollars: Number.isFinite(pnlDollars) ? pnlDollars : null,
      notes,
      source,
    });
  }

  invalidateCommandSnapshotCache();
  resetAnalystContext('trade_feedback_updated', { clearHistory: false });
  return {
    id: row.lastInsertRowid,
    setupId,
    setupName,
    outcome,
    tradeDate,
    pnlDollars: Number.isFinite(pnlDollars) ? pnlDollars : null,
    notes,
    source,
  };
}

async function logTradeOutcomeFromDiscord(input = {}) {
  const cmd = await buildTradingCommandSnapshot('original');
  const top = cmd?.decision?.topSetups?.[0] || null;
  const fallbackSetupId = String(top?.setupId || 'setup_unknown');
  const fallbackSetupName = String(top?.name || 'Unknown setup');
  const statusRaw = String(input.outcome || '').trim().toLowerCase();
  const outcome = ['win', 'loss', 'breakeven'].includes(statusRaw)
    ? statusRaw
    : (statusRaw.includes('win') || statusRaw.includes('tp'))
      ? 'win'
      : (statusRaw.includes('loss') || statusRaw.includes('sl') || statusRaw.includes('stop'))
        ? 'loss'
        : 'breakeven';
  return logTradeOutcomeFeedback({
    setupId: String(input.setupId || fallbackSetupId),
    setupName: String(input.setupName || fallbackSetupName),
    outcome,
    tradeDate: input.tradeDate || dateInTimezone('America/New_York'),
    pnlDollars: input.pnlDollars,
    notes: input.notes,
    source: input.source || 'discord',
  });
}

function buildFeedbackSummary(rows = [], topSetupIds = []) {
  const bySetup = {};
  for (const row of rows) {
    const sid = String(row.setupId || 'unknown');
    if (!bySetup[sid]) bySetup[sid] = { setupId: sid, setupName: row.setupName || sid, samples: 0, wins: 0, losses: 0, breakeven: 0 };
    bySetup[sid].samples += 1;
    if (row.outcome === 'win') bySetup[sid].wins += 1;
    else if (row.outcome === 'loss') bySetup[sid].losses += 1;
    else bySetup[sid].breakeven += 1;
  }
  const summarized = Object.values(bySetup).map((s) => ({
    ...s,
    winRate: round2((s.wins / Math.max(1, s.samples)) * 100),
  })).sort((a, b) => b.samples - a.samples);

  const topFocus = topSetupIds
    .map((sid) => summarized.find((s) => s.setupId === sid))
    .filter(Boolean);

  const totals = rows.reduce((acc, row) => {
    acc.samples += 1;
    if (row.outcome === 'win') acc.wins += 1;
    if (row.outcome === 'loss') acc.losses += 1;
    if (row.outcome === 'breakeven') acc.breakeven += 1;
    return acc;
  }, { samples: 0, wins: 0, losses: 0, breakeven: 0 });
  const notesIntel = deriveFeedbackTestIdeas(rows);

  return {
    totalSamples: totals.samples,
    totalWinRate: round2((totals.wins / Math.max(1, totals.samples)) * 100),
    totals,
    bySetup: summarized.slice(0, 30),
    topFocus,
    latestNotes: notesIntel.latestNotes,
    testIdeas: notesIntel.testIdeas,
  };
}

function normalizeSetupKey(input) {
  return String(input || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 96);
}

function buildSetupWindowStats(rows = []) {
  const stats = {
    samples: rows.length,
    wins: 0,
    losses: 0,
    breakeven: 0,
    winRate: 0,
    avgPnlDollars: 0,
    totalPnlDollars: 0,
  };
  if (!rows.length) return stats;
  let pnlCount = 0;
  for (const row of rows) {
    const outcome = String(row.outcome || '').toLowerCase();
    if (outcome === 'win') stats.wins += 1;
    else if (outcome === 'loss') stats.losses += 1;
    else stats.breakeven += 1;
    if (Number.isFinite(Number(row.pnl_dollars))) {
      stats.totalPnlDollars += Number(row.pnl_dollars);
      pnlCount += 1;
    }
  }
  stats.winRate = round2((stats.wins / Math.max(1, stats.samples)) * 100);
  stats.totalPnlDollars = round2(stats.totalPnlDollars);
  stats.avgPnlDollars = pnlCount > 0 ? round2(stats.totalPnlDollars / pnlCount) : 0;
  return stats;
}

function buildSetupOutcomeScorecard(setupId, setupName = null, options = {}) {
  const sid = normalizeSetupKey(setupId);
  if (!sid) {
    return {
      setupId: sid || 'setup_unknown',
      setupName: setupName || setupId || 'Unknown setup',
      reliabilityScore: 50,
      signal: 'INSUFFICIENT',
      windows: { w20: buildSetupWindowStats([]), w60: buildSetupWindowStats([]) },
      rationale: 'No setup ID available for scorecard.',
    };
  }
  const lookback = Math.max(80, Number(options.lookback || 220));
  const rows = getDB().prepare(`
    SELECT setup_id, setup_name, outcome, pnl_dollars, source, created_at
    FROM trade_outcome_feedback
    WHERE setup_id = ?
    ORDER BY id DESC
    LIMIT ?
  `).all(sid, lookback).filter((r) => !isSyntheticFeedback({ source: r.source, setupId: r.setup_id }));
  const w20 = buildSetupWindowStats(rows.slice(0, 20));
  const w60 = buildSetupWindowStats(rows.slice(0, 60));
  const weightedWr = round2((w20.winRate * 0.62) + (w60.winRate * 0.38));
  const weightedPnl = round2((w20.avgPnlDollars * 0.55) + (w60.avgPnlDollars * 0.45));
  const sampleQuality = clampNumber((Math.min(w20.samples, 20) * 0.55) + (Math.min(w60.samples, 60) * 0.45), 0, 60);
  let reliabilityScore = round2(clampNumber(weightedWr * 0.55 + (weightedPnl > 0 ? 18 : weightedPnl < 0 ? 4 : 10) + sampleQuality * 0.25, 0, 100));
  let signal = 'NEUTRAL';
  let rationale = 'Balanced recent setup performance.';

  const weak20 = w20.samples >= 8 && w20.winRate < 45;
  const weak60 = w60.samples >= 20 && w60.winRate < 47;
  const veryWeak20 = w20.samples >= 8 && w20.winRate < 40;
  const veryWeak60 = w60.samples >= 20 && w60.winRate < 43;
  const negativePnlBias = w20.samples >= 8 && w20.avgPnlDollars < 0 && w60.samples >= 20 && w60.avgPnlDollars < 0;
  const strong20 = w20.samples >= 10 && w20.winRate >= 58 && w20.avgPnlDollars > 0;
  const strong60 = w60.samples >= 24 && w60.winRate >= 55 && w60.avgPnlDollars > 0;
  const insufficient = w20.samples < 6 && w60.samples < 14;

  if (insufficient) {
    signal = 'INSUFFICIENT';
    reliabilityScore = round2(Math.max(42, reliabilityScore));
    rationale = 'Not enough live samples for stable setup scoring yet.';
  } else if (veryWeak20 || veryWeak60 || negativePnlBias) {
    signal = 'VERY_WEAK';
    reliabilityScore = round2(clampNumber(reliabilityScore - 26, 0, 100));
    rationale = 'Recent and medium-window outcomes both show setup underperformance.';
  } else if (weak20 || weak60) {
    signal = 'WEAK';
    reliabilityScore = round2(clampNumber(reliabilityScore - 14, 0, 100));
    rationale = 'Setup win rate in rolling windows is below acceptable threshold.';
  } else if (strong20 && strong60) {
    signal = 'STRONG';
    reliabilityScore = round2(clampNumber(reliabilityScore + 12, 0, 100));
    rationale = 'Setup shows strong consistency across recent and medium windows.';
  }

  return {
    setupId: sid,
    setupName: rows[0]?.setup_name || setupName || sid,
    reliabilityScore,
    signal,
    windows: { w20, w60 },
    rationale,
    updatedAt: rows[0]?.created_at || null,
  };
}

function buildTopSetupScorecards(topSetups = []) {
  const out = [];
  for (const s of (topSetups || [])) {
    const setupId = normalizeSetupKey(s?.setupId || s?.name);
    const card = buildSetupOutcomeScorecard(setupId, s?.name || setupId);
    out.push(card);
  }
  return out;
}

function pruneCommandSnapshotCache(cacheKey) {
  if (commandSnapshotCache.size <= 10) return;
  for (const [k] of commandSnapshotCache.entries()) {
    if (k !== cacheKey) {
      commandSnapshotCache.delete(k);
      if (commandSnapshotCache.size <= 6) break;
    }
  }
}

function updateCommandSnapshotCache(cacheKey, snapshot) {
  if (!snapshot) return;
  commandSnapshotCache.set(cacheKey, { fetchedAt: Date.now(), snapshot });
  pruneCommandSnapshotCache(cacheKey);
}

async function buildTradingCommandSnapshotPayload(strategy = 'original', marketDate, options = {}) {
  const coachSnapshot = buildCoachSnapshot(strategy, { forceFresh: !!options.forceFresh });
  if (!coachSnapshot) return null;

  const plan = buildDailyTradingPlan(strategy, { snapshot: coachSnapshot, forceFresh: !!options.forceFresh });
  const elite = await buildEliteMorningBrief(strategy);
  const agents = buildAgentsBriefing(coachSnapshot);
  const history = loadAgentsBriefingHistory(strategy, 14);
  const intel = coachSnapshot.intel || {};
  const opportunities = getLatestOpportunitiesForDiscord(5);
  const panel = strategy === 'original'
    ? buildSessionControlPanel({ strategy: 'original', plan: strategy === 'original' ? plan : undefined, forceFresh: !!options.forceFresh })
    : null;
  const topstepLive = panel?.execution?.topstepLive || getTopstepLiveSnapshot({ fillLimit: 20 });

  const decision = buildUnifiedExecutionDecision({
    plan,
    elite,
    panel,
    opportunities,
  });
  const feedbackRows = listTradeOutcomeFeedback(250);
  const feedback = buildFeedbackSummary(feedbackRows, (decision.topSetups || []).map((s) => s.setupId));
  const feedbackMap = new Map((feedback.bySetup || []).map((s) => [s.setupId, s]));
  for (const ts of (decision.topSetups || [])) {
    const f = feedbackMap.get(ts.setupId);
    if (f) {
      ts.liveSamples = f.samples;
      ts.liveWinRate = f.winRate;
    }
  }

  const snapshot = {
    generatedAt: new Date().toISOString(),
    marketDate,
    strategy,
    plan,
    elite,
    agents,
    intel,
    panel,
    history,
    opportunities,
    decision,
    autonomy: getExecutionAutonomySettings(),
    topstepLive,
    marketDataFreshness: buildMarketDataFreshnessSnapshot({
      timezone: 'America/New_York',
    }),
    feedback,
  };
  recordCommandSnapshotKnowledge(snapshot);
  return snapshot;
}

function startCommandSnapshotRefresh(strategy = 'original', marketDate, options = {}) {
  const cacheKey = `${strategy}:${marketDate}`;
  const inFlight = commandSnapshotInFlight.get(cacheKey);
  if (inFlight) return inFlight;

  const pending = buildTradingCommandSnapshotPayload(strategy, marketDate, options)
    .then((snapshot) => {
      updateCommandSnapshotCache(cacheKey, snapshot);
      return snapshot;
    })
    .catch((err) => {
      if (options.background) {
        console.warn(`[Command Snapshot] Background refresh failed (${strategy}):`, err.message);
      }
      throw err;
    })
    .finally(() => {
      commandSnapshotInFlight.delete(cacheKey);
    });

  commandSnapshotInFlight.set(cacheKey, pending);
  return pending;
}

async function buildTradingCommandSnapshot(strategy = 'original', options = {}) {
  const marketDate = dateInTimezone('America/New_York');
  const cacheKey = `${strategy}:${marketDate}`;
  const now = Date.now();
  const forceFresh = !!options.forceFresh;
  const cached = commandSnapshotCache.get(cacheKey);
  const inFlight = commandSnapshotInFlight.get(cacheKey);

  if (!forceFresh && cached) {
    const ageMs = now - cached.fetchedAt;
    if (ageMs < COMMAND_SNAPSHOT_TTL_MS) return cached.snapshot;
    if (ageMs < COMMAND_SNAPSHOT_STALE_TTL_MS) {
      if (!inFlight) {
        startCommandSnapshotRefresh(strategy, marketDate, { forceFresh: false, background: true }).catch(() => {});
      }
      return cached.snapshot;
    }
  }

  if (inFlight && !forceFresh) return inFlight;
  return startCommandSnapshotRefresh(strategy, marketDate, { forceFresh, background: false });
}

function deriveCommandCenterSessionPhase(nowEt) {
  const hour = Number(nowEt?.time?.slice(0, 2));
  const minute = Number(nowEt?.time?.slice(3, 5));
  if (!Number.isFinite(hour) || !Number.isFinite(minute)) return 'unknown';
  const mins = (hour * 60) + minute;
  if (mins < 570) return 'pre_open';
  if (mins < 585) return 'orb_window';
  if (mins < 615) return 'momentum_window';
  if (mins <= 659) return 'entry_window';
  return 'outside_window';
}

