async function buildRegimeDetectionCached(options = {}) {
  const marketDate = dateInTimezone('America/New_York');
  const nowEt = options.nowEt && typeof options.nowEt === 'object'
    ? {
      date: String(options.nowEt.date || marketDate).trim() || marketDate,
      time: String(options.nowEt.time || '00:00').trim().slice(0, 5) || '00:00',
    }
    : nowInTimezone('America/New_York');
  const targetDate = String(options.targetDate || nowEt.date || marketDate).trim() || marketDate;
  const sessionPhase = String(options.sessionPhase || deriveCommandCenterSessionPhase(nowEt)).trim() || 'unknown';
  const includeEvidence = options.includeEvidence !== false;
  const cacheKey = [
    marketDate,
    `ctx:${targetDate}:${sessionPhase}`,
    includeEvidence ? 'evidence:1' : 'evidence:0',
  ].join('|');
  const now = Date.now();
  const forceFresh = options.forceFresh === true;

  if (!forceFresh) {
    const cached = regimeDetectionCache.get(cacheKey);
    if (cached && (now - cached.fetchedAt) < REGIME_DETECTION_TTL_MS) return cached.snapshot;
    if (regimeDetectionInFlight.has(cacheKey)) return regimeDetectionInFlight.get(cacheKey);
  }

  const pending = Promise.resolve().then(() => {
    const sessions = options.sessions && typeof options.sessions === 'object'
      ? options.sessions
      : loadAllSessions();
    const regimeByDate = options.regimeByDate && typeof options.regimeByDate === 'object'
      ? options.regimeByDate
      : loadRegimes(sessions);
    const allDates = Object.keys(sessions).sort();
    let latestDate = String(options.latestDate || '').trim();
    if (!latestDate || !sessions[latestDate]) {
      const eligible = allDates.filter((d) => d <= targetDate);
      latestDate = eligible.length > 0
        ? eligible[eligible.length - 1]
        : (allDates.length > 0 ? allDates[allDates.length - 1] : '');
    }
    return buildRegimeDetection({
      sessions,
      regimeByDate,
      latestDate,
      sessionPhase,
      includeEvidence,
    });
  }).then((snapshot) => {
    regimeDetectionCache.set(cacheKey, {
      fetchedAt: Date.now(),
      snapshot,
    });
    pruneRegimeDetectionCache(cacheKey);
    return snapshot;
  }).finally(() => {
    regimeDetectionInFlight.delete(cacheKey);
  });

  regimeDetectionInFlight.set(cacheKey, pending);
  return pending;
}

