        schemaName: config.databento?.api?.schemaName || DEFAULT_DATABENTO_SCHEMA,
        stypeIn: config.databento?.api?.stypeIn || DEFAULT_DATABENTO_STYPE_IN,
        symbols: config.databento?.api?.symbols || DEFAULT_DATABENTO_SYMBOLS,
