        nowDate: options.snapshotDate || options.nowEt?.date || dateInTimezone('America/New_York'),
        lookbackDays: config.databento?.api?.lookbackDays || DEFAULT_DATABENTO_LOOKBACK_DAYS,
        symbols: config.databento?.api?.symbols || DEFAULT_DATABENTO_SYMBOLS,
        dataset: config.databento?.api?.dataset || DEFAULT_DATABENTO_DATASET,
