function sqliteToUtcDate(sqliteTs) {
  const text = String(sqliteTs || '').trim();
  if (!text) return null;
  const d = new Date(text.replace(' ', 'T') + 'Z');
  return Number.isFinite(d.getTime()) ? d : null;
}

function getRecentConfirmedOrderStats(timezone = 'America/New_York') {
  const db = getDB();
  const today = dateInTimezone(timezone);
  const rows = db.prepare(`
    SELECT id, created_at, symbol, side, qty
    FROM execution_order_intents
    WHERE status = 'confirmed'
    ORDER BY id DESC
    LIMIT 600
  `).all();
  let confirmedToday = 0;
  let lastConfirmedAt = null;
  const recent = [];
  for (const row of rows) {
    const dt = sqliteToUtcDate(row.created_at);
    if (!dt) continue;
    const day = dateInTimezone(timezone, dt);
    if (day === today) confirmedToday += 1;
    if (!lastConfirmedAt) lastConfirmedAt = dt.toISOString();
    recent.push({
      at: dt.toISOString(),
      symbol: String(row.symbol || '').toUpperCase(),
      side: String(row.side || '').toLowerCase(),
      qty: Number(row.qty || 0),
    });
  }
  return { confirmedToday, lastConfirmedAt, recent };
}

function evaluateNewsLockoutNow(guardrails, timezone = 'America/New_York') {
  const events = Array.isArray(econCalendarCache?.events) ? econCalendarCache.events : [];
  const todayMdY = dateYmdToMdY(dateInTimezone(timezone));
  const now = nowInTimezone(timezone);
  const nowMinutes = parseMinutesFromHHMM(now.time, null);
  if (!Number.isFinite(nowMinutes) || events.length === 0) {
    return { blocked: false, activeEvent: null, checked: 0 };
  }
  const focusCurrencies = Array.isArray(config.news?.focusCurrencies) && config.news.focusCurrencies.length
    ? config.news.focusCurrencies
    : ['USD'];
  const candidates = events
    .filter((e) => e.date === todayMdY)
    .filter((e) => currencyAllowed(e.country, focusCurrencies))
    .filter((e) => impactRank(e.impact) >= 3)
    .map((e) => ({ ...e, minutes: parseTimeToMinutes(e.time) }))
    .filter((e) => Number.isFinite(e.minutes));

  for (const e of candidates) {
    const start = e.minutes - Number(guardrails.newsLockoutMinutesBefore || 0);
    const end = e.minutes + Number(guardrails.newsLockoutMinutesAfter || 0);
    if (nowMinutes >= start && nowMinutes <= end) {
      return {
        blocked: true,
        checked: candidates.length,
        activeEvent: {
          time: e.time,
          country: e.country,
          impact: e.impact,
          title: e.title,
          windowStart: start,
          windowEnd: end,
        },
      };
    }
  }
  return { blocked: false, activeEvent: null, checked: candidates.length };
}

function saveExecutionControls(input = {}) {
  const db = getDB();
  const current = getExecutionControls(db);
  const topstepCompliance = buildTopstepComplianceSnapshot();
  const next = {
    enabled: asBool(input.enabled, current.enabled),
    killSwitch: asBool(input.killSwitch, current.killSwitch),
    maxPositionSize: Math.max(1, Math.min(20, Number(input.maxPositionSize || current.maxPositionSize))),
    maxDailyLossDollars: Math.max(50, Math.min(100000, Number(input.maxDailyLossDollars || current.maxDailyLossDollars))),
    allowedSymbols: Array.isArray(input.allowedSymbols) && input.allowedSymbols.length > 0
      ? input.allowedSymbols.map(s => String(s).toUpperCase().trim()).filter(Boolean)
      : current.allowedSymbols,
    requireTwoStepConfirm: asBool(input.requireTwoStepConfirm, current.requireTwoStepConfirm),
  };
  if (topstepCompliance.strictMode && topstepCompliance.requireManualConfirm) {
    next.requireTwoStepConfirm = true;
  }
  db.prepare(`
    INSERT INTO execution_controls (id, enabled, kill_switch, max_position_size, max_daily_loss_dollars, allowed_symbols, require_two_step_confirm, updated_at)
    VALUES (1, ?, ?, ?, ?, ?, ?, datetime('now'))
    ON CONFLICT(id) DO UPDATE SET
      enabled = excluded.enabled,
      kill_switch = excluded.kill_switch,
      max_position_size = excluded.max_position_size,
      max_daily_loss_dollars = excluded.max_daily_loss_dollars,
      allowed_symbols = excluded.allowed_symbols,
      require_two_step_confirm = excluded.require_two_step_confirm,
      updated_at = datetime('now')
  `).run(
    next.enabled ? 1 : 0,
    next.killSwitch ? 1 : 0,
    next.maxPositionSize,
    next.maxDailyLossDollars,
    JSON.stringify(next.allowedSymbols),
    next.requireTwoStepConfirm ? 1 : 0
  );
  invalidateSessionControlPanelCache();
  return getExecutionControls(db);
}

