/**
 * Run backtest with conflict resolutions applied.
 * Returns corrected metrics if any resolutions exist.
 */
function runBacktestWithResolutions(sessions, options = {}) {
  const bt = runBacktest(sessions, options);

  // Apply any stored resolutions
  const db = getDB();
  const resolutions = db.prepare('SELECT * FROM conflict_resolutions').all();
  if (resolutions.length === 0) return bt;

  const resMap = {};
  for (const r of resolutions) {
    resMap[`${r.trade_date}|${r.direction}|${r.entry_price}`] = r;
  }

  let modified = false;
  for (const t of bt.trades) {
    const key = `${t.date}|${t.direction}|${t.entry_price}`;
    const res = resMap[key];
    if (res) {
      t.result = res.resolved_result;
      t.exit_reason = res.resolved_exit;
      t.pnl_ticks = res.resolved_pnl_ticks;
      t.pnl_dollars = res.resolved_pnl_dollars;
      t.exit_price = res.resolved_result === 'win' ? t.tp_price : t.sl_price;
      t._resolved = true;
      modified = true;
    }
  }

  // Recalculate all metrics if any trades were modified
  if (modified) {
    bt.metrics = calcMetrics(bt.trades);
    bt.equityCurve = calcEquityCurve(bt.trades, options.startingBalance || 50000);
    bt.drawdown = calcDrawdown(bt.trades, options.startingBalance || 50000);
    bt.sharpe = calcSharpe(bt.trades);
    bt.sortino = calcSortino(bt.trades);
    bt.monthly = monthlyBreakdown(bt.trades);
    bt.dayOfWeek = dayOfWeekBreakdown(bt.trades);

    // Exit reasons
    bt.exitReasons = {};
    for (const t of bt.trades) {
      bt.exitReasons[t.exit_reason] = (bt.exitReasons[t.exit_reason] || 0) + 1;
    }

    // Monte Carlo
    bt.monteCarlo = monteCarlo(bt.trades, 10000, {
      balance: options.startingBalance || 50000,
      maxDrawdown: options.topstepMaxDD || 2000,
      payoutTarget: options.topstepTarget || 3000,
    });
  }

  return bt;
}

app.get('/api/bridge', (req, res) => {
  const db = getDB();
  const sessions = loadAllSessions();
  const dates = Object.keys(sessions).sort();
  const topstepLive = getTopstepLiveSnapshot({ fillLimit: 25 });

  if (dates.length === 0) {
    return res.json({ status: 'no_data', message: 'Import TradingView data first' });
  }

  // Check for alt strategy mode
  if (req.query.strategy === 'alt') {
    const alt = getAltData();
    const latestDate = dates[dates.length - 1];
    const latestSession = processSession(sessions[latestDate]);

    return res.json({
      status: 'active',
      strategyMode: 'alt',
      strategyLabel: 'ORB 3130 — Closer TP',
      summary: alt.summary || {
        strategy: 'ORB 3130 — Closer TP',
        instrument: 'MNQ',
        dateRange: { start: dates[0], end: latestDate },
        totalSessions: dates.length,
        sessionsWithTrade: alt.trades.length,
        tradeFrequency: Math.round((alt.trades.length / dates.length) * 1000) / 10,
      },
      metrics: alt.metrics,
      drawdown: alt.drawdown,
      sharpe: alt.sharpe,
      sortino: alt.sortino,
      monteCarlo: alt.monteCarlo,
      equityCurve: alt.equityCurve,
      latestSession: {
        date: latestDate,
        orb: latestSession.orb,
        trade: latestSession.trade,
        noTradeReason: latestSession.no_trade_reason,
      },
      topstep: db.prepare('SELECT * FROM topstep_account ORDER BY date DESC LIMIT 1').get() || {
        balance: 50000, trailing_dd: 0, max_dd_buffer: 2000,
      },
      topstepLive,
      recentActivity: [],
      decay: alt.decay,
      changeSummary: alt.changeSummary,
    });
  }

  // Original strategy
  const bt = runBacktestWithResolutions(sessions, {
    startingBalance: config.topstep.startingBalance,
    topstepMaxDD: config.topstep.maxDrawdown,
    topstepTarget: config.topstep.profitTarget,
  });

  // Latest session analysis
  const latestDate = dates[dates.length - 1];
  const latestSession = processSession(sessions[latestDate]);

  // Recent activity
  const recentActivity = db.prepare(
    'SELECT * FROM activity_log ORDER BY created_at DESC LIMIT 20'
  ).all();

  // Topstep account latest
  const topstep = db.prepare(
    'SELECT * FROM topstep_account ORDER BY date DESC LIMIT 1'
  ).get();

  res.json({
    status: 'active',
    summary: bt.summary,
    metrics: bt.metrics,
    drawdown: bt.drawdown,
    sharpe: bt.sharpe,
    sortino: bt.sortino,
    monteCarlo: bt.monteCarlo,
    equityCurve: bt.equityCurve,
    latestSession: {
      date: latestDate,
      orb: latestSession.orb,
      trade: latestSession.trade,
      noTradeReason: latestSession.no_trade_reason,
    },
    topstep: topstep || {
      balance: config.topstep.startingBalance,
      trailing_dd: 0,
      max_dd_buffer: config.topstep.maxDrawdown,
    },
    topstepLive,
    recentActivity,
    decay: bt.decay,
  });
});

