app.post('/api/import', upload.single('file'), (req, res) => {
  if (!req.file) return res.status(400).json({ error: 'No file uploaded' });

  try {
    const backup = createRuntimeBackup('pre_import');
    if (!backup.ok) {
      return res.status(500).json({ error: `Pre-import backup failed: ${backup.error || 'unknown_error'}` });
    }

    const result = importTradingViewCSV(req.file.path);
    const db = getDB();

    const insertSession = db.prepare(`
      INSERT OR IGNORE INTO sessions (date, candle_count, day_of_week)
      VALUES (?, ?, ?)
    `);
    const insertCandle = db.prepare(`
      INSERT OR IGNORE INTO candles (session_id, timestamp, timeframe, open, high, low, close, volume)
      VALUES (?, ?, '5m', ?, ?, ?, ?, ?)
    `);
    const getSessionId = db.prepare('SELECT id FROM sessions WHERE date = ?');

    let sessionsAdded = 0, candlesAdded = 0;

    db.transaction(() => {
      for (const date of result.validSessions) {
        const candles = result.sessions[date];
        const d = new Date(date + 'T12:00:00');
        const dow = d.getDay();
        const adjDow = dow === 0 ? 6 : dow - 1;
        try {
          insertSession.run(date, candles.length, adjDow);
        } catch (e) { continue; }
        const session = getSessionId.get(date);
        if (!session) continue;
        sessionsAdded++;
        for (const c of candles) {
          insertCandle.run(session.id, c.timestamp, c.open, c.high, c.low, c.close, c.volume);
          candlesAdded++;
        }
      }
    })();

    // Invalidate caches first so recalculations use imported data.
    invalidateAltCache();
    invalidateDailyPlanCache();
    invalidateSessionControlPanelCache();
    eliteBriefCache.clear();

    // Run backtest on fresh data
    const sessions = loadAllSessions();
    const bt = runBacktest(sessions);

    // Log activity
    db.prepare(`INSERT INTO activity_log (module, message, severity, data)
      VALUES ('import', ?, 'success', ?)`
    ).run(
      `Imported ${sessionsAdded} sessions (${result.stats.dateRange.first} → ${result.stats.dateRange.last})`,
      JSON.stringify({ file: result.file, sessions: sessionsAdded, candles: candlesAdded })
    );

    // Clean up uploaded file
    fs.unlinkSync(req.file.path);

    setTimeout(() => {
      buildTradingCommandSnapshot('original', { forceFresh: true }).catch((warmErr) => {
        console.warn('[Import] command snapshot warm-up failed:', warmErr.message);
      });
    }, 0);

    res.json({
      backup,
      import: result.stats,
      sessionsAdded,
      candlesAdded,
      backtest: {
        totalTrades: bt.metrics.totalTrades,
        winRate: bt.metrics.winRate,
        profitFactor: bt.metrics.profitFactor,
        pnl: bt.metrics.totalPnlDollars,
      },
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

