// Conversation history per session (in-memory, resets on restart)
let analystHistory = [];
const ANALYST_CONTEXT_MAX_AGE_MS = Math.max(60 * 1000, Number(process.env.ANALYST_CONTEXT_MAX_AGE_MS || 8 * 60 * 1000));
let analystContextState = {
  systemPrompt: null,
  fingerprint: null,
  builtAt: 0,
  refreshCount: 0,
  lastReason: 'init',
  dataSummary: null,
};

function buildAnalystDataFingerprint(db = getDB()) {
  const scalar = (sql, fallback = '') => {
    try {
      const row = db.prepare(sql).get() || {};
      const value = row.v;
      return value == null ? fallback : String(value);
    } catch {
      return String(fallback);
    }
  };
  const fileMtime = (filePath) => {
    try {
      return String(Math.round(Number(fs.statSync(filePath).mtimeMs || 0)));
    } catch {
      return '0';
    }
  };
  const sessionRow = db.prepare(`
    SELECT
      COUNT(*) AS session_count,
      MIN(date) AS first_date,
      MAX(date) AS last_date
    FROM sessions
  `).get() || {};
  const importRow = db.prepare(`
    SELECT
      MAX(id) AS max_import_id,
      MAX(created_at) AS last_import_at
    FROM imports
  `).get() || {};
  const conflictRow = db.prepare(`
    SELECT
      MAX(id) AS max_resolution_id
    FROM conflict_resolutions
  `).get() || {};
  return [
    Number(sessionRow?.session_count || 0),
    sessionRow?.first_date || '',
    sessionRow?.last_date || '',
    Number(importRow?.max_import_id || 0),
    importRow?.last_import_at || '',
    Number(conflictRow?.max_resolution_id || 0),
    scalar('SELECT MAX(id) AS v FROM trade_outcome_feedback', '0'),
    scalar('SELECT MAX(created_at) AS v FROM trade_outcome_feedback', ''),
    scalar('SELECT MAX(updated_at) AS v FROM execution_autonomy', ''),
    scalar('SELECT MAX(id) AS v FROM discovery_runs', '0'),
    scalar('SELECT MAX(created_at) AS v FROM discovery_runs', ''),
    scalar('SELECT MAX(id) AS v FROM discovery_candidates', '0'),
    scalar('SELECT MAX(updated_at) AS v FROM discovery_candidates', ''),
    scalar('SELECT MAX(id) AS v FROM discovery_validations', '0'),
    scalar('SELECT MAX(updated_at) AS v FROM discovery_validations', ''),
    scalar('SELECT MAX(id) AS v FROM discovery_promotions', '0'),
    scalar('SELECT MAX(id) AS v FROM strategy_proposals', '0'),
    scalar('SELECT MAX(updated_at) AS v FROM strategy_proposals', ''),
    scalar('SELECT MAX(id) AS v FROM proposal_validations', '0'),
    scalar('SELECT MAX(updated_at) AS v FROM proposal_validations', ''),
    fileMtime(DAILY_VERDICT_PATH),
    fileMtime(LEARNING_STATE_PATH),
  ].join('|');
}

function resetAnalystContext(reason = 'manual_reset', options = {}) {
  const clearHistory = options.clearHistory !== false;
  if (clearHistory) analystHistory = [];
  analystContextState.systemPrompt = null;
  analystContextState.fingerprint = null;
  analystContextState.builtAt = 0;
  analystContextState.lastReason = reason;
  analystContextState.dataSummary = null;
}

async function rebuildAnalystContext(reason = 'rebuild_requested', fingerprintOverride = null, options = {}) {
  const sessions = loadAllSessions();
  const bt = runBacktestWithResolutions(sessions);
  const regimes = loadRegimes(sessions);
  const dates = Object.keys(sessions).sort();
  const latestDate = dates[dates.length - 1] || null;
  const intel = generateIntel(bt, regimes, latestDate);
  const tp = runTPSensitivity(bt.trades, sessions);
  const fingerprint = fingerprintOverride || buildAnalystDataFingerprint();
  const forceFresh = options.forceFresh === true;

  let commandSnapshot = null;
  try {
    commandSnapshot = await buildTradingCommandSnapshot('original', { forceFresh });
  } catch (err) {
    console.warn('[Analyst] command snapshot unavailable for context:', err.message);
  }
  const dailyVerdict = readDailyVerdictPayload();
  const dataFreshness = getSessionFreshnessSummary('America/New_York');

  analystContextState.systemPrompt = buildAnalystContext(
    bt,
    intel,
    tp,
    regimes,
    latestDate,
    { commandSnapshot, dailyVerdict, dataFreshness }
  );
  analystContextState.fingerprint = fingerprint;
  analystContextState.builtAt = Date.now();
  analystContextState.refreshCount += 1;
  analystContextState.lastReason = reason;
  analystContextState.dataSummary = {
    sessions: dates.length,
    firstDate: dates[0] || null,
    lastDate: latestDate,
    tradeCount: Number(bt?.metrics?.totalTrades || 0),
    commandSignal: commandSnapshot?.decision?.signalLabel || commandSnapshot?.decision?.verdict || null,
    commandTopSetup: commandSnapshot?.decision?.topSetups?.[0]?.name || null,
    feedbackSamples: Number(commandSnapshot?.feedback?.totalSamples || 0),
    freshnessLastSession: dataFreshness?.lastSessionDate || null,
  };

  return analystContextState;
}

async function ensureAnalystContext(options = {}) {
  const force = options.force === true;
  const reason = String(options.reason || 'chat_request');
  const fingerprint = buildAnalystDataFingerprint();
  const missing = !analystContextState.systemPrompt;
  const drifted = analystContextState.fingerprint !== fingerprint;
  const expired = analystContextState.builtAt > 0
    && (Date.now() - analystContextState.builtAt) > ANALYST_CONTEXT_MAX_AGE_MS;
  const refreshNeeded = force || missing || drifted || expired;
  if (!refreshNeeded) return analystContextState;

  const refreshReason = force
    ? `${reason}:forced`
    : drifted
      ? `${reason}:dataset_changed`
      : expired
        ? `${reason}:ttl_expired`
        : `${reason}:missing_context`;
  return rebuildAnalystContext(refreshReason, fingerprint, { forceFresh: force || drifted });
}

