function truncateAgentText(input, maxChars = 600) {
  const txt = String(input == null ? '' : input);
  if (txt.length <= maxChars) return txt;
  return `${txt.slice(0, maxChars)}...`;
}

function extractChartSignalFromText(text) {
  const raw = String(text || '').trim();
  if (!raw) return null;
  const m = raw.match(/(?:^|\n)\s*(?:\d+\)\s*)?signal\s*:\s*([A-Z' -]{3,24})/i);
  if (!m) return null;
  const normalized = String(m[1] || '').trim().toUpperCase();
  if (normalized.includes("DON'T")) return "DON'T TRADE";
  if (normalized.includes('DO NOT')) return "DON'T TRADE";
  if (normalized.includes('NO TRADE')) return "DON'T TRADE";
  if (normalized.includes('WAIT')) return 'WAIT';
  if (normalized.includes('TRADE')) return 'TRADE';
  return normalized;
}

function extractChartWhyFromText(text) {
  const raw = String(text || '').trim();
  if (!raw) return null;
  const m = raw.match(/(?:^|\n)\s*(?:\d+\)\s*)?why\s*:\s*(.+)/i);
  if (!m) return null;
  return truncateAgentText(String(m[1] || '').trim(), 180) || null;
}

function extractChartConfidenceFromText(text) {
  const raw = String(text || '');
  const m = raw.match(/(?:^|\n)\s*(?:\d+\)\s*)?confidence[^0-9]*([0-9]{1,3})/i);
  if (!m) return null;
  const n = Number(m[1]);
  if (!Number.isFinite(n)) return null;
  return clampNumber(n, 0, 100);
}

function setAnalystChartContextState(input = {}) {
  const response = String(input.response || '').trim();
  if (!response) return;
  analystChartContextState = {
    updatedAt: Date.now(),
    provider: String(input.provider || 'unknown'),
    prompt: truncateAgentText(String(input.prompt || '').trim(), 240) || null,
    response: truncateAgentText(response, 1600),
    signal: extractChartSignalFromText(response),
    why: extractChartWhyFromText(response),
    confidence: extractChartConfidenceFromText(response),
  };
}

function getAnalystChartContextState(options = {}) {
  const maxAgeMs = Math.max(30_000, Number(options.maxAgeMs || ANALYST_CHART_CONTEXT_TTL_MS));
  if (!Number(analystChartContextState?.updatedAt || 0)) return null;
  const ageMs = Date.now() - Number(analystChartContextState.updatedAt || 0);
  if (!Number.isFinite(ageMs) || ageMs < 0 || ageMs > maxAgeMs) return null;
  return {
    ...analystChartContextState,
    ageSeconds: Math.max(0, Math.floor(ageMs / 1000)),
  };
}

function buildAnalystChartContextLine(options = {}) {
  const ctx = getAnalystChartContextState(options);
  if (!ctx) return null;
  const parts = ['Chart context loaded'];
  if (ctx.signal) parts.push(`signal ${ctx.signal}`);
  if (Number.isFinite(Number(ctx.confidence))) parts.push(`confidence ${Math.round(Number(ctx.confidence))}%`);
  if (ctx.why) parts.push(ctx.why);
  parts.push(`updated ${Math.max(0, Number(ctx.ageSeconds || 0))}s ago`);
  return `${parts[0]}: ${parts.slice(1).join(' | ')}.`;
}

function safeUnlink(targetPath) {
  if (!targetPath) return;
  try { fs.unlinkSync(targetPath); } catch {}
}

function makeAssistantTempPath(ext = 'wav') {
  ensureDir(ASSISTANT_AUDIO_TMP_DIR);
  const stamp = Date.now();
  const nonce = crypto.randomBytes(4).toString('hex');
  const safeExt = String(ext || 'wav').replace(/[^a-z0-9]/gi, '').toLowerCase() || 'wav';
  return path.join(ASSISTANT_AUDIO_TMP_DIR, `voice-${stamp}-${nonce}.${safeExt}`);
}

function checkCommandAvailable(command) {
  const cmd = String(command || '').trim();
  if (!cmd) return false;
  const key = `cmd:${cmd}`;
  const now = Date.now();
  const cached = assistantToolAvailabilityCache[key];
  if (cached && (now - cached.checkedAt) < ASSISTANT_TOOL_AVAIL_CACHE_MS) return cached.available;

  let available = false;
  try {
    if (cmd.includes(path.sep)) {
      available = fs.existsSync(cmd);
    } else {
      execFileSync('which', [cmd], { stdio: 'ignore' });
      available = true;
    }
  } catch {
    available = false;
  }
  assistantToolAvailabilityCache[key] = { available, checkedAt: now };
  return available;
}

function assistantLocalVoiceState() {
  const piperBinAvailable = checkCommandAvailable(ASSISTANT_PIPER_BIN);
  const piperModelAvailable = !!ASSISTANT_PIPER_MODEL_PATH && fs.existsSync(ASSISTANT_PIPER_MODEL_PATH);
  const piperConfigAvailable = !ASSISTANT_PIPER_CONFIG_PATH || fs.existsSync(ASSISTANT_PIPER_CONFIG_PATH);
  const piperConfigured = piperBinAvailable && piperModelAvailable && piperConfigAvailable;
  const xttsConfigured = !!ASSISTANT_XTTS_URL;
  const edgeTtsAvailable = checkCommandAvailable(ASSISTANT_EDGE_TTS_BIN);
  const ffmpegAvailable = checkCommandAvailable(ASSISTANT_FFMPEG_BIN);
  return {
    piper: {
      configured: piperConfigured,
      binAvailable: piperBinAvailable,
      modelAvailable: piperModelAvailable,
      configAvailable: piperConfigAvailable,
    },
    xtts: {
      configured: xttsConfigured,
      endpoint: ASSISTANT_XTTS_URL || null,
    },
    edgeTts: {
      configured: edgeTtsAvailable,
      bin: ASSISTANT_EDGE_TTS_BIN || null,
      voice: ASSISTANT_EDGE_TTS_VOICE || null,
    },
    ffmpegAvailable,
  };
}

function normalizeRequestedVoiceProvider(input) {
  const raw = String(input || '').trim().toLowerCase();
  if (!raw) return 'auto';
  if (raw === 'default') return 'auto';
  const aliases = {
    'edge-tts': 'edge_tts',
    edge: 'edge_tts',
  };
  const normalized = aliases[raw] || raw;
  if (['auto', 'local', 'openai', 'piper', 'xtts', 'edge_tts', 'elevenlabs', 'browser'].includes(normalized)) return normalized;
  return 'auto';
}

function buildVoiceProviderOrder(preferred = 'auto') {
  const requested = normalizeRequestedVoiceProvider(preferred);
  const localOrder = ASSISTANT_LOCAL_TTS_PROVIDER === 'xtts'
    ? ['xtts', 'piper']
    : ['piper', 'xtts'];
  const fastLocalOrder = ['edge_tts', ...localOrder.filter((p) => p !== 'edge_tts')];

  let order = [];
  if (requested === 'piper') order = ['piper', 'xtts', 'edge_tts', 'elevenlabs', 'openai', 'browser'];
  else if (requested === 'xtts') order = ['xtts', 'piper', 'edge_tts', 'elevenlabs', 'openai', 'browser'];
  else if (requested === 'edge_tts') order = ['edge_tts', 'piper', 'xtts', 'elevenlabs', 'openai', 'browser'];
  else if (requested === 'openai') order = ['openai', 'elevenlabs', 'edge_tts', ...localOrder, 'browser'];
  else if (requested === 'elevenlabs') order = ['elevenlabs', 'openai', 'edge_tts', ...localOrder, 'browser'];
  else if (requested === 'local') order = ASSISTANT_VOICE_LATENCY_MODE === 'fast'
    ? [...fastLocalOrder, 'browser']
    : [...localOrder, 'edge_tts', 'elevenlabs', 'openai', 'browser'];
  else if (ASSISTANT_VOICE_MODE === 'local') order = ASSISTANT_VOICE_LATENCY_MODE === 'fast'
    ? [...fastLocalOrder, 'browser']
    : [...localOrder, 'browser'];
  else if (ASSISTANT_VOICE_MODE === 'openai') order = ['openai', 'elevenlabs', 'edge_tts', ...localOrder, 'browser'];
  else if (ASSISTANT_VOICE_MODE === 'quality') order = ASSISTANT_VOICE_LATENCY_MODE === 'fast'
    ? [...fastLocalOrder, 'elevenlabs', 'openai', 'browser']
    : ['elevenlabs', 'openai', 'edge_tts', ...localOrder, 'browser'];
  else order = ASSISTANT_VOICE_LATENCY_MODE === 'fast'
    ? [...fastLocalOrder, 'elevenlabs', 'openai', 'browser']
    : [...localOrder, 'edge_tts', 'elevenlabs', 'openai', 'browser'];

  if (ASSISTANT_VOICE_MODE === 'local' && !['openai', 'elevenlabs', 'edge_tts'].includes(requested)) {
    order = order.filter((provider) => provider !== 'openai' && provider !== 'elevenlabs' && provider !== 'edge_tts');
    if (!order.includes('browser')) order.push('browser');
  }

  const deduped = [];
  for (const provider of order) {
    if (!deduped.includes(provider)) deduped.push(provider);
  }
  if (requested === 'auto' || requested === 'local') {
    const lastGood = String(assistantVoiceRuntime.lastSuccessProvider || '').trim().toLowerCase();
    if (lastGood && deduped.includes(lastGood)) {
      deduped.splice(deduped.indexOf(lastGood), 1);
      deduped.unshift(lastGood);
    }
  }
  return deduped;
}

function listLocalVoiceProfiles() {
  return Object.values(LOCAL_VOICE_PROFILE_CATALOG).map((item) => ({
    id: item.id,
    name: item.name,
    description: item.description,
  }));
}

function resolveLocalVoiceProfileId(requested) {
  const candidate = String(requested || '').trim().toLowerCase();
  if (candidate && LOCAL_VOICE_PROFILE_CATALOG[candidate]) return candidate;
  if (LOCAL_VOICE_PROFILE_CATALOG[ASSISTANT_LOCAL_VOICE_PROFILE]) return ASSISTANT_LOCAL_VOICE_PROFILE;
  return 'jarvis_prime';
}

function resolveEnhancementFilter(profileId) {
  const resolvedId = resolveLocalVoiceProfileId(profileId);
  return LOCAL_VOICE_PROFILE_CATALOG[resolvedId]?.filter || ASSISTANT_AUDIO_ENHANCE_FILTER;
}

function makeVoiceCacheKey({ text, providerHint = 'auto', profile = 'jarvis_prime' }) {
  const normalizedText = String(text || '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase()
    .replace(/[.!?]+$/g, '');
  const payload = [
    String(providerHint || 'auto').toLowerCase(),
    String(profile || 'jarvis_prime').toLowerCase(),
    ASSISTANT_VOICE_MODE,
    ASSISTANT_VOICE_LATENCY_MODE,
    normalizedText,
  ].join('::');
  return crypto.createHash('sha1').update(payload).digest('hex');
}

function getCachedVoiceAudio(key) {
  const entry = assistantVoiceCache.get(key);
  if (!entry) return null;
  if ((Date.now() - Number(entry.cachedAt || 0)) > ASSISTANT_VOICE_CACHE_TTL_MS) {
    assistantVoiceCache.delete(key);
    return null;
  }
  entry.lastHitAt = Date.now();
  return entry.payload;
}

function setCachedVoiceAudio(key, payload) {
  if (!payload || typeof payload !== 'object') return;
  assistantVoiceCache.set(key, {
    cachedAt: Date.now(),
    lastHitAt: Date.now(),
    payload,
  });
  if (assistantVoiceCache.size <= ASSISTANT_VOICE_CACHE_MAX_ITEMS) return;
  const items = Array.from(assistantVoiceCache.entries())
    .sort((a, b) => Number(a[1]?.lastHitAt || 0) - Number(b[1]?.lastHitAt || 0));
  while (items.length > ASSISTANT_VOICE_CACHE_MAX_ITEMS) {
    const drop = items.shift();
    if (drop) assistantVoiceCache.delete(drop[0]);
  }
}

function analystCacheKey(message, fingerprint = '') {
  const payload = `${String(message || '').trim().toLowerCase()}::${String(fingerprint || '')}`;
  return crypto.createHash('sha1').update(payload).digest('hex');
}

function getCachedAnalystReply(key) {
  const entry = analystReplyCache.get(key);
  if (!entry) return null;
  if ((Date.now() - Number(entry.cachedAt || 0)) > ANALYST_REPLY_CACHE_TTL_MS) {
    analystReplyCache.delete(key);
    return null;
  }
  return String(entry.reply || '');
}

function setCachedAnalystReply(key, reply) {
  const text = String(reply || '').trim();
  if (!key || !text) return;
  analystReplyCache.set(key, { cachedAt: Date.now(), reply: text });
  if (analystReplyCache.size <= 80) return;
  const items = Array.from(analystReplyCache.entries())
    .sort((a, b) => Number(a[1]?.cachedAt || 0) - Number(b[1]?.cachedAt || 0));
  while (items.length > 80) {
    const drop = items.shift();
    if (drop) analystReplyCache.delete(drop[0]);
  }
}

function isWeakAnalystReply(text) {
  const msg = String(text || '').trim();
  if (!msg) return true;
  if (msg.length < 80) return true;
  return /\b(i'm not sure|cannot|can't|unable|no data available)\b/i.test(msg);
}

function compactAnalystHistoryForModel(history = [], maxItems = ANALYST_MODEL_HISTORY_MESSAGES) {
  const safeMax = Math.max(2, Number(maxItems || ANALYST_MODEL_HISTORY_MESSAGES));
  const filtered = Array.isArray(history) ? history.filter((m) => m && m.role) : [];
  if (filtered.length <= safeMax) return filtered;
  return filtered.slice(filtered.length - safeMax);
}

function normalizeAnalystReplyStyle(input) {
  let txt = String(input || '').trim();
  if (!txt) return txt;
  txt = txt
    .replace(/\bNOOP\b/gi, 'no new update')
    .replace(/\bN\/A\b/g, 'not available')
    .replace(/\bMNQ last 1-minute close:\s*([0-9.,]+)\s*at\s*([^\.\n]+)\.?/i, 'MNQ is around $1. Last update was $2.')
    .replace(/\bLive sync status:\s*no new update\b/i, 'Live sync is up to date.')
    .replace(/\bOpen positions:\s*0\b/i, 'You are currently flat.');
  if (txt.length > ANALYST_REPLY_MAX_CHARS) {
    txt = `${txt.slice(0, ANALYST_REPLY_MAX_CHARS).trim()}...`;
  }
  return txt;
}

function normalizeAssistantUserFacingReply(input, options = {}) {
  const stripCompletion = options.stripCompletion === true;
  const flattenPipes = options.flattenPipes !== false;
  const voiceMode = options.voiceMode === true;
  let txt = normalizeAnalystReplyStyle(input);
  if (!txt) return txt;

  if (stripCompletion) {
    txt = txt.replace(/\n{0,2}Completed:\n(?:- .*(?:\n|$))+/gi, '').trim();
  }

  txt = txt
    .replace(/\bTopstep sync\s+no new update\b/gi, 'Topstep sync is up to date')
    .replace(/\bLive sync status:\s*ok\b/gi, 'Live sync is healthy')
    .replace(/\bLive sync status:\s*error\b/gi, 'Live sync needs attention')
    .replace(/\bStatus:\s*API OK\b/gi, 'Status: system online')
    .replace(/\bTopstep sync status:\s*ok\b/gi, 'Live sync status is healthy')
    .replace(/\bTopstep sync status:\s*noop\b/gi, 'Live sync status is up to date')
    .replace(/\bTopstep sync status:\s*error\b/gi, 'Live sync status needs attention')
    .replace(/\bTopstep mode:\s*execution[_\s-]*assist\b/gi, 'Trading mode is execution assist')
    .replace(/\bTopstep mode:\s*read[_\s-]*only\b/gi, 'Trading mode is read only')
    .replace(/\bAccount:\s*([^|.\n]+)\s*\|\s*Open positions:\s*(\d+)\.?/gi, (_, acct, count) => {
      const safeName = assistantAccountSubject(acct);
      const n = Number(count);
      const qty = Number.isFinite(n) ? n : 0;
      return `${safeName} has ${qty} open position${qty === 1 ? '' : 's'}.`;
    })
    .replace(/\bLast sync time:\s*([^\.\n]+)\.?/gi, (_, ts) => {
      const t = formatAssistantClockTime(ts);
      return t ? `Last sync update was ${t}.` : 'Last sync update time is not available.';
    });

  if (flattenPipes && txt.includes('|')) {
    const parts = txt
      .split('|')
      .map((s) => String(s || '').trim())
      .filter(Boolean);
    if (parts.length > 1) {
      txt = parts.join('. ');
      if (!/[.!?]$/.test(txt)) txt += '.';
    }
  }

  txt = txt
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  if (voiceMode) {
    const parts = txt
      .split(/\n+/)
      .map((s) => String(s || '').trim().replace(/:\s*$/g, ''))
      .filter(Boolean);
    txt = parts.join('. ');
    txt = txt
      .replace(/^\[(TRADE|WAIT|DON'T TRADE)\]\s*/i, '$1. ')
      .replace(/\[(TRADE|WAIT|DON'T TRADE)\]/gi, '$1')
      .replace(/\s*\|\s*/g, ', ')
      .replace(/\bWR\b/g, 'win rate')
      .replace(/~(\d+)\/yr\b/gi, 'about $1 trades per year')
      .replace(/(^|[.]\s+)([1-4])\)\s+/g, (m, prefix, n) => {
        const labels = {
          '1': 'Top setup one: ',
          '2': 'Top setup two: ',
          '3': 'Top setup three: ',
          '4': 'Top setup four: ',
        };
        return `${prefix}${labels[String(n)] || ''}`;
      })
      .replace(/\.\s*\./g, '.')
      .replace(/([:;,])\./g, '$1')
      .replace(/[\[\]]/g, '')
      .replace(/\s{2,}/g, ' ')
      .trim();
    if (txt && !/[.!?]$/.test(txt)) txt += '.';
  }
  return txt;
}

function lowercaseFirstAlpha(text) {
  const src = String(text || '');
  for (let i = 0; i < src.length; i += 1) {
    const ch = src[i];
    if (/[A-Z]/.test(ch)) return `${src.slice(0, i)}${ch.toLowerCase()}${src.slice(i + 1)}`;
    if (/[a-z]/.test(ch)) return src;
  }
  return src;
}

function ensureSentenceEnd(text) {
  const src = String(text || '').trim();
  if (!src) return src;
  if (/[.!?]$/.test(src)) return src;
  return `${src}.`;
}

function normalizeAnalystNarrativeOnlyReply(input) {
  let txt = String(input || '').trim();
  if (!txt) return txt;

  // Remove bracketed rigid markers and bracket-heavy setup suffixes.
  txt = txt.replace(/\[([^\]]+)\]/g, '($1)');

  const lines = txt
    .split(/\n+/)
    .map((line) => String(line || '').trim())
    .filter(Boolean)
    .map((line) => {
      let out = line;
      const labelMatch = out.match(/^(?:(?:\((TRADE|WAIT|DON['’]T TRADE|NO-TRADE)\))|(TRADE|WAIT|DON['’]T TRADE|NO-TRADE))\s*(?:[:.\-]\s*)?(.*)$/i);
      if (labelMatch) {
        const rawLabel = String(labelMatch[1] || labelMatch[2] || '').replace(/’/g, '\'').toUpperCase();
        const rest = String(labelMatch[3] || '').trim();
        if (rawLabel === 'WAIT') {
          out = rest
            ? `Also, ${lowercaseFirstAlpha(rest)}`
            : 'I would wait for cleaner structure.';
        } else if (rawLabel === 'TRADE') {
          out = rest
            ? `This is a tradable environment if your trigger confirms. ${rest}`
            : 'This is a tradable environment if your trigger confirms.';
        } else {
          out = rest
            ? `Right now the better move is to stand down. ${rest}`
            : 'Right now the better move is to stand down.';
        }
      }

      out = out
        .replace(/\bWAIT:\s*/g, 'Also, ')
        .replace(/\bTRADE:\s*/g, 'This is a tradable environment if your trigger confirms; ')
        .replace(/\bDON['’]T TRADE:\s*/g, 'Right now the better move is to stand down because ')
        .replace(/\bNO-TRADE:\s*/g, 'Right now the better move is to stand down because ')
        .replace(/^TRADE\.\s*/g, 'This is a tradable environment if your trigger confirms. ')
        .replace(/\bDON['’]T TRADE\b/g, 'stand down')
        .replace(/\bNO-TRADE\b/g, 'stand down')
        .replace(/\s{2,}/g, ' ')
        .trim();

      return ensureSentenceEnd(out);
    });

  return lines.join('\n').replace(/\n{3,}/g, '\n\n').trim();
}

function buildAnalystVoiceEarbudBrief(input, snapshot = {}) {
  return buildEarbudCoachBrief({
    ...(snapshot && typeof snapshot === 'object' ? snapshot : {}),
    replyText: String(input || ''),
  });
}

function buildEarbudRuntimeSnapshot(seed = {}, replyText = '') {
  const base = (seed && typeof seed === 'object') ? { ...seed } : {};
  const explicitPosition = base.positionState && typeof base.positionState === 'object'
    ? { ...base.positionState }
    : {};
  let nowEt = null;
  let topstepLive = null;
  let liveState = null;
  try {
    nowEt = nowInTimezone('America/New_York');
  } catch {}
  try {
    topstepLive = getTopstepLiveSnapshot({ fillLimit: 20 });
  } catch {}
  try {
    liveState = getLiveTradeState();
  } catch {}
  const positions = Array.isArray(topstepLive?.positions) ? topstepLive.positions : [];
  const openPositions = positions.filter((p) => Number(p?.qty || 0) > 0);
  const preferredSymbol = String(config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase();
  const primary = openPositions.find((p) => String(p?.symbol || '').toUpperCase() === preferredSymbol) || openPositions[0] || null;
  const derivedQty = Number(primary?.qty ?? liveState?.qty ?? 0);
  const derivedQtyAbs = Number.isFinite(derivedQty) ? Math.abs(derivedQty) : 0;
  const derivedSideRaw = String(primary?.side || liveState?.side || '').toLowerCase();
  const derivedSide = (derivedSideRaw === 'long' || derivedSideRaw === 'short') ? derivedSideRaw : null;
  const pnlCandidates = [primary?.unrealizedPnl, liveState?.pnlDollars, liveState?.unrealizedPnl];
  let derivedUnrealized = null;
  for (const v of pnlCandidates) {
    const n = Number(v);
    if (Number.isFinite(n)) {
      derivedUnrealized = n;
      break;
    }
  }
  const volatilityHintText = `${String(replyText || '')} ${String(base.replyText || '')}`.trim();
  const derivedVolatilityExpanding = /\b(volatility\s+(?:is\s+)?(?:high|expanding|elevated)|expanding volatility|high volatility)\b/i.test(volatilityHintText);
  const derivedHasOpenPosition = openPositions.length > 0 || liveState?.inPosition === true || derivedQtyAbs > 0;

  return {
    ...base,
    nowEtTime: base.nowEtTime || nowEt?.time || null,
    positionState: {
      hasOpenPosition: derivedHasOpenPosition,
      openPositions: openPositions.length,
      side: derivedSide,
      qty: derivedQtyAbs,
      symbol: String(primary?.symbol || liveState?.symbol || '').toUpperCase() || null,
      unrealizedPnl: derivedUnrealized,
      volatilityExpanding: derivedVolatilityExpanding,
      ...explicitPosition,
    },
  };
}

function normalizeAssistantModuleReply(input, options = {}) {
  const base = normalizeAssistantUserFacingReply(input, options);
  const activeModule = normalizeDashboardModuleId(options.activeModule);
  if (activeModule === 'analyst') return normalizeAnalystNarrativeOnlyReply(base);
  return base;
}

function finalizeAssistantReplyForDelivery(input, options = {}) {
  const activeModule = normalizeDashboardModuleId(options.activeModule);
  const voiceMode = options.voiceMode === true;
  const voiceBriefMode = String(options.voiceBriefMode || '').trim().toLowerCase();
  const skipEarbudBrief = options.skipEarbudBrief === true;
  const applyUserFacingNormalize = options.applyUserFacingNormalize !== false;
  let txt = String(input || '');
  if (applyUserFacingNormalize) {
    txt = normalizeAssistantUserFacingReply(txt, {
      stripCompletion: voiceMode,
      voiceMode,
      activeModule,
    });
  }
  if (activeModule === 'analyst') {
    const before = String(txt || '');
    const beforeLen = before.length;
    const countRigidTokens = (raw) => {
      const src = String(raw || '');
      const patterns = [
        /\bDON['’]T\s*TRADE\b/gi,
        /\bDONT\s*TRADE\b/gi,
        /\bDO\s*NOT\s*TRADE\b/gi,
        /\bWAIT:\s*/gi,
        /\bTRADE\.\s*/gi,
        /\[(?:WAIT|TRADE|DON['’]T\s*TRADE|DONT\s*TRADE|DO\s*NOT\s*TRADE)\]/gi,
        /\bSTANCE:\s*/gi,
      ];
      let total = 0;
      for (const re of patterns) {
        const hits = src.match(re);
        if (Array.isArray(hits)) total += hits.length;
      }
      return total;
    };
    const beforeCount = countRigidTokens(before);
    txt = sanitizeAnalystReply(before);
    const after = String(txt || '');
    const afterLen = after.length;
    const afterCount = countRigidTokens(after);
    const removedTokens = Math.max(0, beforeCount - afterCount);
    const applied = before !== after;
    if (DEBUG_ANALYST) {
      console.log(`[ANALYST_SANITIZER] applied=${applied} beforeLen=${beforeLen} afterLen=${afterLen} removedTokens=${removedTokens}`);
    }
    if (voiceMode && (voiceBriefMode === 'earbud' || voiceBriefMode === 'earpiece') && !skipEarbudBrief) {
      const runtimeEarbudSnapshot = buildEarbudRuntimeSnapshot(options.earbudSnapshot || {}, txt);
      txt = buildAnalystVoiceEarbudBrief(txt, runtimeEarbudSnapshot);
    }
  }
  return String(txt || '').trim();
}

function applyAnalystSanitizedHeader(res, activeModule) {
  const normalized = normalizeDashboardModuleId(activeModule);
  const value = normalized === 'analyst' ? '1' : '0';
  try {
    res.set('X-Analyst-Sanitized', value);
  } catch {}
  return value;
}

function getAnalystProviderCooldownUntil(provider) {
  return Number(analystProviderRuntime?.cooldownUntilByProvider?.[provider] || 0);
}

function isAnalystProviderOnCooldown(provider) {
  return getAnalystProviderCooldownUntil(provider) > Date.now();
}

function markAnalystProviderCooldown(provider, reason = '') {
  const msg = String(reason || '').toLowerCase();
  let cooldownMs = ANALYST_PROVIDER_COOLDOWN_MS;
  if (/\bquota|429|insufficient\b/.test(msg)) cooldownMs = ANALYST_PROVIDER_QUOTA_COOLDOWN_MS;
  else if (/\babort|timeout|timed out\b/.test(msg)) cooldownMs = ANALYST_PROVIDER_TIMEOUT_COOLDOWN_MS;
  const until = Date.now() + cooldownMs;
  analystProviderRuntime = {
    ...analystProviderRuntime,
    cooldownUntilByProvider: {
      ...(analystProviderRuntime.cooldownUntilByProvider || {}),
      [provider]: until,
    },
    lastErrors: (analystProviderRuntime.lastErrors || []).concat([`${provider}:${truncateAgentText(msg, 120)}`]).slice(-10),
  };
}

function clearAnalystProviderCooldown(provider) {
  const next = { ...(analystProviderRuntime.cooldownUntilByProvider || {}) };
  if (!(provider in next)) return;
  delete next[provider];
  analystProviderRuntime = {
    ...analystProviderRuntime,
    cooldownUntilByProvider: next,
  };
}

function getAnalystProviderOrder(options = {}) {
  const openaiConfigured = options.openaiConfigured !== false;
  const anthropicConfigured = options.anthropicConfigured !== false;
  const openaiBlocked = Number(dashboardPlannerRuntime.openaiBlockedUntil || 0) > Date.now();
  const requested = ANALYST_PROVIDER_PRIORITY
    .split(',')
    .map((x) => String(x || '').trim().toLowerCase())
    .filter((x) => x === 'openai' || x === 'anthropic');
  const ordered = [];
  for (const provider of requested) {
    if (provider === 'openai' && !openaiConfigured) continue;
    if (provider === 'openai' && openaiBlocked && anthropicConfigured) continue;
    if (provider === 'anthropic' && !anthropicConfigured) continue;
    if (!ordered.includes(provider)) ordered.push(provider);
  }
  if (openaiConfigured && !ordered.includes('openai') && (!openaiBlocked || !anthropicConfigured)) ordered.push('openai');
  if (anthropicConfigured && !ordered.includes('anthropic')) ordered.push('anthropic');
  return ordered;
}

async function runAnalystProviderOpenAI({ apiKey, system, convo }) {
  if (!apiKey) throw new Error('openai_api_key_missing');
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), ANALYST_OPENAI_TIMEOUT_MS);
  try {
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: DASHBOARD_AGENT_MODEL_OPENAI,
        max_tokens: 1200,
        temperature: 0.15,
        messages: [{ role: 'system', content: system }].concat(
          convo.map((m) => ({
            role: m.role === 'assistant' ? 'assistant' : 'user',
            content: String(m.content || ''),
          }))
        ),
      }),
      signal: controller.signal,
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) {
      const msg = truncateAgentText(
        data?.error?.message || data?.error || `openai_http_${response.status}`,
        280
      );
      throw new Error(msg);
    }
    const out = extractOpenAiMessageText(data?.choices?.[0]?.message || {});
    if (!out) throw new Error('openai_empty_response');
    return {
      provider: 'openai',
      text: out,
    };
  } finally {
    clearTimeout(timeout);
  }
}

