function getProviderCooldownUntil(provider) {
  return Number(assistantVoiceRuntime?.cooldownUntilByProvider?.[provider] || 0);
}

function isProviderOnCooldown(provider) {
  const until = getProviderCooldownUntil(provider);
  return until > Date.now();
}

function markProviderCooldown(provider, errorText = '') {
  const err = String(errorText || '').toLowerCase();
  let cooldownMs = ASSISTANT_PROVIDER_COOLDOWN_MS;
  if (err.includes('insufficient_quota') || err.includes('quota')) {
    cooldownMs = ASSISTANT_PROVIDER_COOLDOWN_QUOTA_MS;
  } else if (err.includes('not_configured')) {
    cooldownMs = ASSISTANT_PROVIDER_COOLDOWN_NOT_CONFIGURED_MS;
  }
  const until = Date.now() + cooldownMs;
  assistantVoiceRuntime = {
    ...assistantVoiceRuntime,
    cooldownUntilByProvider: {
      ...(assistantVoiceRuntime.cooldownUntilByProvider || {}),
      [provider]: until,
    },
  };
}

function clearProviderCooldown(provider) {
  const current = { ...(assistantVoiceRuntime.cooldownUntilByProvider || {}) };
  if (!(provider in current)) return;
  delete current[provider];
  assistantVoiceRuntime = {
    ...assistantVoiceRuntime,
    cooldownUntilByProvider: current,
  };
}

function assistantVoiceProviderStatus() {
  const openaiKey = String(process.env.OPENAI_API_KEY || '').trim();
  const openaiConfigured = openaiKey.length > 0;
  const elevenLabsConfigured = !!(ASSISTANT_ELEVENLABS_API_KEY && ASSISTANT_ELEVENLABS_VOICE_ID);
  const local = assistantLocalVoiceState();
  const defaultVoiceProfile = resolveLocalVoiceProfileId(ASSISTANT_LOCAL_VOICE_PROFILE);
  const providerOrder = buildVoiceProviderOrder('auto');
  const predictedProvider = providerOrder.find((name) => {
    if (name === 'piper') return local.piper.configured;
    if (name === 'xtts') return local.xtts.configured;
    if (name === 'edge_tts') return local.edgeTts.configured;
    if (name === 'elevenlabs') return elevenLabsConfigured;
    if (name === 'openai') return openaiConfigured;
    return name === 'browser';
  }) || 'browser';
  const activeProvider = assistantVoiceRuntime.lastSuccessProvider || predictedProvider;
  return {
    provider: activeProvider,
    predictedProvider,
    mode: ASSISTANT_VOICE_MODE,
    browserFallbackEnabled: ASSISTANT_BROWSER_FALLBACK_ENABLED,
    openaiConfigured,
    localConfigured: local.piper.configured || local.xtts.configured,
    localProvider: activeProvider === 'piper' || activeProvider === 'xtts' ? activeProvider : null,
    providers: {
      piper: local.piper,
      xtts: local.xtts,
      edge_tts: local.edgeTts,
      elevenlabs: {
        configured: elevenLabsConfigured,
        voiceId: ASSISTANT_ELEVENLABS_VOICE_ID ? `${ASSISTANT_ELEVENLABS_VOICE_ID.slice(0, 5)}…` : null,
        model: ASSISTANT_ELEVENLABS_MODEL_ID || null,
      },
      openai: { configured: openaiConfigured },
      browser: { configured: true },
    },
    enhancement: {
      enabled: ASSISTANT_AUDIO_ENHANCE_ENABLED,
      ffmpegAvailable: local.ffmpegAvailable,
      format: ASSISTANT_AUDIO_OUTPUT_FORMAT,
    },
    piperTuning: {
      lengthScale: ASSISTANT_PIPER_LENGTH_SCALE,
      noiseScale: ASSISTANT_PIPER_NOISE_SCALE,
      noiseWScale: ASSISTANT_PIPER_NOISE_W_SCALE,
      sentenceSilence: ASSISTANT_PIPER_SENTENCE_SILENCE,
      volume: ASSISTANT_PIPER_VOLUME,
      noNormalize: ASSISTANT_PIPER_NO_NORMALIZE,
    },
    prosody: {
      enabled: ASSISTANT_NEURAL_PROSODY_ENABLED,
    },
    runtime: {
      lastSuccessAt: assistantVoiceRuntime.lastSuccessAt,
      lastSuccessProvider: assistantVoiceRuntime.lastSuccessProvider,
      lastLatencyMs: assistantVoiceRuntime.lastLatencyMs,
      lastErrorAt: assistantVoiceRuntime.lastErrorAt,
      lastErrors: assistantVoiceRuntime.lastErrors,
      cooldownUntilByProvider: assistantVoiceRuntime.cooldownUntilByProvider,
    },
    defaultVoiceProfile,
    voiceProfiles: listLocalVoiceProfiles(),
    model: ASSISTANT_TTS_MODEL,
    voice: ASSISTANT_TTS_VOICE,
  };
}

function runSpawn(command, args = [], options = {}) {
  const timeoutMs = Math.max(1000, Number(options.timeoutMs || 15000));
  const stdinText = typeof options.stdinText === 'string' ? options.stdinText : null;
  return new Promise((resolve, reject) => {
    let settled = false;
    let stdout = '';
    let stderr = '';
    let timer = null;
    const child = spawn(command, args, {
      stdio: ['pipe', 'pipe', 'pipe'],
      cwd: options.cwd || process.cwd(),
      env: options.env || process.env,
    });

    const finalize = (err, result) => {
      if (settled) return;
      settled = true;
      if (timer) clearTimeout(timer);
      if (err) return reject(err);
      return resolve(result);
    };

    timer = setTimeout(() => {
      try { child.kill('SIGKILL'); } catch {}
      finalize(new Error(`process_timeout:${command}`));
    }, timeoutMs);

    child.stdout.on('data', (chunk) => { stdout += chunk.toString(); });
    child.stderr.on('data', (chunk) => { stderr += chunk.toString(); });
    child.on('error', (err) => finalize(err));
    child.on('close', (code) => {
      if (code === 0) {
        return finalize(null, { code, stdout, stderr });
      }
      return finalize(new Error(`process_exit_${code}:${truncateAgentText(stderr || stdout || command, 260)}`));
    });

    if (stdinText != null) {
      try { child.stdin.write(stdinText); } catch {}
    }
    try { child.stdin.end(); } catch {}
  });
}

async function maybeEnhanceAudio(inputPath, extHint = 'wav', options = {}) {
  const local = assistantLocalVoiceState();
  if (ASSISTANT_VOICE_LATENCY_MODE === 'fast' && ASSISTANT_AUDIO_ENHANCE_FAST_SKIP) return null;
  if (!ASSISTANT_AUDIO_ENHANCE_ENABLED || !local.ffmpegAvailable) return null;
  const profileId = resolveLocalVoiceProfileId(options.profile);
  const profile = LOCAL_VOICE_PROFILE_CATALOG[profileId];
  const filter = resolveEnhancementFilter(profileId);
  const outputExt = ASSISTANT_AUDIO_OUTPUT_FORMAT === 'wav' ? 'wav' : 'mp3';
  const outputPath = makeAssistantTempPath(outputExt);
  const args = [
    '-y',
    '-hide_banner',
    '-loglevel',
    'error',
    '-i',
    inputPath,
    '-af',
    filter,
    '-ar',
    '44100',
    '-ac',
    '1',
  ];
  if (outputExt === 'mp3') args.push('-b:a', '128k');
  args.push(outputPath);
  try {
    await runSpawn(ASSISTANT_FFMPEG_BIN, args, { timeoutMs: ASSISTANT_LOCAL_TTS_TIMEOUT_MS });
    const audioBuffer = fs.readFileSync(outputPath);
    return {
      success: true,
      provider: options.providerTag || (extHint === 'wav' ? 'local_piper' : 'local_xtts'),
      mimeType: outputExt === 'mp3' ? 'audio/mpeg' : 'audio/wav',
      audioBase64: audioBuffer.toString('base64'),
      enhanced: true,
      voiceProfile: profileId,
      voiceProfileName: profile?.name || null,
      outputPath,
    };
  } catch {
    safeUnlink(outputPath);
    return null;
  }
}

async function synthesizeWithPiper(input, options = {}) {
  const local = assistantLocalVoiceState();
  if (!local.piper.configured) {
    return { success: false, provider: 'local_piper', error: 'piper_not_configured' };
  }
  const profileId = resolveLocalVoiceProfileId(options.profile);
  const profile = LOCAL_VOICE_PROFILE_CATALOG[profileId];
  const lengthScale = clampNumber(
    Number(options.lengthScale ?? ASSISTANT_PIPER_LENGTH_SCALE),
    0.7,
    1.4
  );
  const noiseScale = clampNumber(
    Number(options.noiseScale ?? ASSISTANT_PIPER_NOISE_SCALE),
    0.1,
    2.0
  );
  const noiseWScale = clampNumber(
    Number(options.noiseWScale ?? ASSISTANT_PIPER_NOISE_W_SCALE),
    0.1,
    2.0
  );
  const sentenceSilence = clampNumber(
    Number(options.sentenceSilence ?? ASSISTANT_PIPER_SENTENCE_SILENCE),
    0,
    1.2
  );
  const volume = clampNumber(
    Number(options.volume ?? ASSISTANT_PIPER_VOLUME),
    0.5,
    2.0
  );
  const noNormalize = options.noNormalize == null
    ? ASSISTANT_PIPER_NO_NORMALIZE
    : String(options.noNormalize).toLowerCase() === 'true';
  const outputPath = makeAssistantTempPath('wav');
  const args = [
    '--model',
    ASSISTANT_PIPER_MODEL_PATH,
    '--output_file',
    outputPath,
  ];
  if (ASSISTANT_PIPER_CONFIG_PATH) args.push('--config', ASSISTANT_PIPER_CONFIG_PATH);
  if (ASSISTANT_PIPER_SPEAKER && /^\d+$/.test(ASSISTANT_PIPER_SPEAKER)) {
    args.push('--speaker', ASSISTANT_PIPER_SPEAKER);
  }
  args.push('--length-scale', String(lengthScale));
  args.push('--noise-scale', String(noiseScale));
  args.push('--noise-w-scale', String(noiseWScale));
  args.push('--sentence-silence', String(sentenceSilence));
  args.push('--volume', String(volume));
  if (noNormalize) args.push('--no-normalize');

  const piperDir = path.dirname(ASSISTANT_PIPER_BIN);
  const dyldParts = [
    piperDir,
    '/opt/homebrew/lib',
    '/usr/local/lib',
    String(process.env.DYLD_LIBRARY_PATH || '').trim(),
  ].filter(Boolean);
  const env = {
    ...process.env,
    DYLD_LIBRARY_PATH: dyldParts.join(':'),
    DYLD_FALLBACK_LIBRARY_PATH: dyldParts.join(':'),
  };

  try {
    await runSpawn(ASSISTANT_PIPER_BIN, args, {
      timeoutMs: ASSISTANT_LOCAL_TTS_TIMEOUT_MS,
      stdinText: `${input}\n`,
      cwd: piperDir,
      env,
    });
    if (!fs.existsSync(outputPath)) {
      return { success: false, provider: 'local_piper', error: 'piper_output_missing' };
    }

    const enhanced = await maybeEnhanceAudio(outputPath, 'wav', {
      profile: profileId,
      providerTag: 'local_piper',
    });
    if (enhanced?.success) {
      safeUnlink(outputPath);
      const tmp = enhanced.outputPath;
      delete enhanced.outputPath;
      safeUnlink(tmp);
      return enhanced;
    }

    const audioBuffer = fs.readFileSync(outputPath);
    safeUnlink(outputPath);
    return {
      success: true,
      provider: 'local_piper',
      mimeType: 'audio/wav',
      audioBase64: audioBuffer.toString('base64'),
      enhanced: false,
      voiceProfile: profileId,
      voiceProfileName: profile?.name || null,
    };
  } catch (err) {
    safeUnlink(outputPath);
    return {
      success: false,
      provider: 'local_piper',
      error: truncateAgentText(String(err?.message || 'piper_failed'), 260),
    };
  }
}

function parseJsonAudioPayload(payload) {
  if (!payload || typeof payload !== 'object') return null;
  const fields = ['audioBase64', 'audio_base64', 'audio', 'wav', 'data'];
  for (const key of fields) {
    const value = payload[key];
    if (typeof value !== 'string' || !value.trim()) continue;
    const txt = value.trim();
    if (txt.startsWith('data:audio')) {
      const idx = txt.indexOf('base64,');
      if (idx > -1) return { base64: txt.slice(idx + 7), mimeType: txt.slice(5, txt.indexOf(';')) || null };
    }
    if (/^[A-Za-z0-9+/=\s]+$/.test(txt)) {
      return { base64: txt.replace(/\s+/g, ''), mimeType: null };
    }
  }
  return null;
}

async function synthesizeWithXtts(input, options = {}) {
  if (!ASSISTANT_XTTS_URL) {
    return { success: false, provider: 'local_xtts', error: 'xtts_not_configured' };
  }
  const profileId = resolveLocalVoiceProfileId(options.profile);
  const profile = LOCAL_VOICE_PROFILE_CATALOG[profileId];
  const body = {
    text: input,
    language: ASSISTANT_XTTS_LANGUAGE,
  };
  if (ASSISTANT_XTTS_MODEL) body.model = ASSISTANT_XTTS_MODEL;
  if (ASSISTANT_XTTS_SPEAKER_WAV && fs.existsSync(ASSISTANT_XTTS_SPEAKER_WAV)) {
    body.speaker_wav = ASSISTANT_XTTS_SPEAKER_WAV;
  }

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), ASSISTANT_LOCAL_TTS_TIMEOUT_MS);
  try {
    const response = await fetch(ASSISTANT_XTTS_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
      signal: controller.signal,
    });
    clearTimeout(timer);
    if (!response.ok) {
      const errText = truncateAgentText(await response.text().catch(() => ''), 260);
      return {
        success: false,
        provider: 'local_xtts',
        error: errText || `xtts_http_${response.status}`,
      };
    }
    const contentType = String(response.headers.get('content-type') || '').toLowerCase();
    let audioBuffer = null;
    let mimeType = contentType.includes('audio/') ? contentType.split(';')[0] : 'audio/wav';

    if (contentType.includes('application/json')) {
      const json = await response.json().catch(() => null);
      const parsed = parseJsonAudioPayload(json);
      if (!parsed?.base64) {
        return { success: false, provider: 'local_xtts', error: 'xtts_json_missing_audio' };
      }
      audioBuffer = Buffer.from(parsed.base64, 'base64');
      if (parsed.mimeType) mimeType = parsed.mimeType;
    } else {
      audioBuffer = Buffer.from(await response.arrayBuffer());
    }

    if (!audioBuffer || audioBuffer.length === 0) {
      return { success: false, provider: 'local_xtts', error: 'xtts_empty_audio' };
    }

    if (ASSISTANT_AUDIO_ENHANCE_ENABLED && assistantLocalVoiceState().ffmpegAvailable) {
      const inputPath = makeAssistantTempPath('wav');
      fs.writeFileSync(inputPath, audioBuffer);
      const enhanced = await maybeEnhanceAudio(inputPath, 'xtts', {
        profile: profileId,
        providerTag: 'local_xtts',
      });
      safeUnlink(inputPath);
      if (enhanced?.success) {
        const tmp = enhanced.outputPath;
        delete enhanced.outputPath;
        safeUnlink(tmp);
        return enhanced;
      }
    }

    return {
      success: true,
      provider: 'local_xtts',
      mimeType,
      audioBase64: audioBuffer.toString('base64'),
      enhanced: false,
      voiceProfile: profileId,
      voiceProfileName: profile?.name || null,
    };
  } catch (err) {
    clearTimeout(timer);
    return {
      success: false,
      provider: 'local_xtts',
      error: truncateAgentText(String(err?.message || 'xtts_failed'), 260),
    };
  }
}

