function applySpeechContractions(input) {
  let out = String(input || '');
  const replacements = [
    [/\bdo not\b/gi, "don't"],
    [/\bdoes not\b/gi, "doesn't"],
    [/\bdid not\b/gi, "didn't"],
    [/\bcannot\b/gi, "can't"],
    [/\bcan not\b/gi, "can't"],
    [/\bwill not\b/gi, "won't"],
    [/\bwe are\b/gi, "we're"],
    [/\byou are\b/gi, "you're"],
    [/\bi am\b/gi, "I'm"],
    [/\bit is\b/gi, "it's"],
    [/\bthat is\b/gi, "that's"],
    [/\bwe will\b/gi, "we'll"],
    [/\bi have\b/gi, "I've"],
  ];
  for (const [pattern, value] of replacements) out = out.replace(pattern, value);
  return out;
}

function buildAssistantProsodyInput(rawText) {
  const original = truncateAgentText(String(rawText || '').trim(), ASSISTANT_TTS_MAX_CHARS);
  if (!original || !ASSISTANT_NEURAL_PROSODY_ENABLED) {
    return {
      text: original,
      piper: {
        lengthScale: ASSISTANT_PIPER_LENGTH_SCALE,
      },
    };
  }

  let text = original
    .replace(/\s+/g, ' ')
    .trim();
  text = applySpeechContractions(text);

  // Small processing pauses around technical labels and conclusions.
  text = text
    .replace(/\b(ORB|TP|SL|PnL|CPI|FOMC|NFP)\b(?![,\-.:;!?])/g, '$1,')
    .replace(/\b(final verdict|bottom line|recommendation|warning)\b/gi, '... $1');

  if (!/[.!?]$/.test(text)) text += '.';

  const isListLike = (
    /(?:^|\n)\s*(?:[-*]|\d+\.)\s+/.test(rawText)
    || ((text.match(/,/g) || []).length >= 3)
    || /\b(first|second|third)\b/i.test(text)
  );
  const isWarningLike = /\b(warning|risk|caution|avoid|defensive|don't trade|no-trade|wait)\b/i.test(text);

  // Non-linear tempo target: faster for data lists, slower for recommendations/warnings.
  let speedMultiplier = 1.0;
  if (isListLike) speedMultiplier = 1.1;
  if (isWarningLike) speedMultiplier = 0.9;
  const piperLengthScale = clampNumber(ASSISTANT_PIPER_LENGTH_SCALE / speedMultiplier, 0.7, 1.4);

  return {
    text,
    piper: {
      lengthScale: piperLengthScale,
    },
  };
}

async function synthesizeAssistantVoiceAudio(text, options = {}) {
  const requestedProvider = normalizeRequestedVoiceProvider(options.provider);
  const effectiveMaxChars = ASSISTANT_VOICE_LATENCY_MODE === 'fast'
    ? Math.min(ASSISTANT_TTS_MAX_CHARS, ASSISTANT_TTS_FAST_MAX_CHARS)
    : ASSISTANT_TTS_MAX_CHARS;
  const input = truncateAgentText(String(text || '').trim(), effectiveMaxChars);
  if (!input) return { success: false, provider: 'browser', error: 'empty_tts_input' };

  const profileId = resolveLocalVoiceProfileId(options.profile);
  const speech = buildAssistantProsodyInput(input);
  const speechText = speech.text || input;
  const cacheEligible = speechText.length <= ASSISTANT_VOICE_CACHE_MAX_TEXT_CHARS;
  const cacheKey = cacheEligible ? makeVoiceCacheKey({
    text: speechText,
    providerHint: requestedProvider,
    profile: profileId,
  }) : null;
  if (cacheKey) {
    const cached = getCachedVoiceAudio(cacheKey);
    if (cached) {
      return {
        ...cached,
        cached: true,
        latencyMs: 1,
      };
    }
  }
  const providers = buildVoiceProviderOrder(options.provider);
  const startedAt = Date.now();
  const attempts = [];

  for (const provider of providers) {
    const forcedProvider = requestedProvider !== 'auto' && requestedProvider !== 'local';
    if (!forcedProvider && isProviderOnCooldown(provider)) {
      attempts.push({
        provider,
        error: 'cooldown_skip',
      });
      continue;
    }
    if (provider === 'browser') {
      const last = attempts[attempts.length - 1];
      return {
        success: false,
        provider: 'browser',
        error: last?.error || 'local_and_openai_unavailable',
        attempts,
      };
    }
    const out = provider === 'piper'
      ? await synthesizeWithPiper(speechText, {
        profile: profileId,
        ...(speech.piper || {}),
      })
      : provider === 'xtts'
        ? await synthesizeWithXtts(speechText, { profile: profileId })
        : provider === 'edge_tts'
          ? await synthesizeWithEdgeTts(speechText, { profile: profileId })
        : provider === 'elevenlabs'
          ? await synthesizeWithElevenLabs(speechText)
          : await synthesizeWithOpenAI(speechText);
    if (out?.success) {
      clearProviderCooldown(provider);
      const latencyMs = Date.now() - startedAt;
      assistantVoiceRuntime = {
        ...assistantVoiceRuntime,
        lastSuccessAt: new Date().toISOString(),
        lastSuccessProvider: out.provider || provider,
        lastLatencyMs: latencyMs,
        lastErrorAt: attempts.length ? new Date().toISOString() : assistantVoiceRuntime.lastErrorAt,
        lastErrors: attempts.slice(-4),
      };
      const result = {
        ...out,
        latencyMs,
      };
      if (cacheKey && result.success) {
        setCachedVoiceAudio(cacheKey, {
          success: true,
          provider: result.provider,
          mimeType: result.mimeType,
          audioBase64: result.audioBase64,
          enhanced: !!result.enhanced,
          voiceProfile: result.voiceProfile || profileId,
          voiceProfileName: result.voiceProfileName || null,
        });
      }
      return result;
    }
    markProviderCooldown(provider, out?.error || `${provider}_failed`);
    attempts.push({
      provider: out?.provider || provider,
      error: truncateAgentText(out?.error || `${provider}_failed`, 180),
    });
  }

  assistantVoiceRuntime = {
    ...assistantVoiceRuntime,
    lastErrorAt: new Date().toISOString(),
    lastErrors: attempts.slice(-6),
  };

  return {
    success: false,
    provider: 'browser',
    error: attempts[attempts.length - 1]?.error || 'voice_unavailable',
    attempts,
  };
}

async function prewarmAssistantVoiceCache() {
  if (!ASSISTANT_VOICE_PREWARM_ENABLED) return;
  if (!Array.isArray(ASSISTANT_VOICE_PREWARM_LINES) || ASSISTANT_VOICE_PREWARM_LINES.length === 0) return;
  for (const line of ASSISTANT_VOICE_PREWARM_LINES) {
    const text = String(line || '').trim();
    if (!text) continue;
    try {
      await Promise.race([
        synthesizeAssistantVoiceAudio(text, {
          provider: 'local',
          profile: resolveLocalVoiceProfileId(),
        }),
        new Promise((resolve) => setTimeout(resolve, Math.min(ASSISTANT_LOCAL_TTS_TIMEOUT_MS, 3500))),
      ]);
    } catch {}
  }
}

async function prewarmAssistantQueryCache() {
  if (!ASSISTANT_QUERY_PREWARM_ENABLED) return;
  if (!Array.isArray(ASSISTANT_QUERY_PREWARM_LINES) || ASSISTANT_QUERY_PREWARM_LINES.length === 0) return;
  for (const line of ASSISTANT_QUERY_PREWARM_LINES) {
    const msg = String(line || '').trim();
    if (!msg) continue;
    try {
      await Promise.race([
        runAssistantUnifiedQuery({
          message: msg,
          strategy: 'original',
          activeModule: 'analyst',
          preferCachedLive: true,
          voiceMode: true,
        }),
        new Promise((resolve) => setTimeout(resolve, 2500)),
      ]);
    } catch {}
  }
}

async function prewarmAssistantIntelCache() {
  if (!ASSISTANT_INTEL_PREWARM_ENABLED) return;
  try {
    const cmd = await buildTradingCommandSnapshot('original');
    await Promise.race([
      buildAssistantIntelligenceSnapshot({
        strategy: 'original',
        cmdSnapshot: cmd,
        preferCachedLive: true,
        forceFresh: true,
      }),
      new Promise((resolve) => setTimeout(resolve, 2500)),
    ]);
  } catch {}
}

function normalizeDashboardModuleId(input) {
  const raw = String(input || '').trim().toLowerCase().replace(/\s+/g, '_');
  if (!raw) return null;
  const alias = {
    dashboard: 'bridge',
    command_intel: 'briefing',
    command: 'briefing',
    intel: 'briefing',
    ai: 'analyst',
    ai_analyst: 'analyst',
    codex: 'analyst',
    codex_console: 'analyst',
    system_core: 'system',
    trade_journal: 'journal',
    session_log: 'sessions',
    import_data: 'import',
    coach_ops: 'coach',
  };
  const mapped = alias[raw] || raw;
  return DASHBOARD_AGENT_MODULES.has(mapped) ? mapped : null;
}

function inferDashboardModuleFromText(input) {
  const txt = String(input || '').toLowerCase();
  if (!txt) return null;
  if (/\b(command intel|briefing|intel)\b/.test(txt)) return 'briefing';
  if (/\b(dashboard|bridge|main board)\b/.test(txt)) return 'bridge';
  if (/\b(analyst|ai analyst|brain|codex|codex console)\b/.test(txt)) return 'analyst';
  if (/\b(system|system core|health)\b/.test(txt)) return 'system';
  if (/\b(lab|discovery|research)\b/.test(txt)) return 'lab';
  if (/\b(coach|coach ops)\b/.test(txt)) return 'coach';
  if (/\b(portfolio|strategy stack)\b/.test(txt)) return 'portfolio';
  if (/\b(journal|trade journal)\b/.test(txt)) return 'journal';
  if (/\b(session log|sessions)\b/.test(txt)) return 'sessions';
  if (/\b(adversary|risk scan)\b/.test(txt)) return 'adversary';
  if (/\b(conflict|conflicts)\b/.test(txt)) return 'conflicts';
  if (/\b(breakdown|breakdowns)\b/.test(txt)) return 'breakdown';
  if (/\b(import|import data)\b/.test(txt)) return 'import';
  return null;
}

function buildDashboardSiteMap() {
  const map = new Map();
  const entries = Array.isArray(config.discord?.allowedSites) ? config.discord.allowedSites : [];
  for (let i = 0; i < entries.length; i += 1) {
    const token = String(entries[i] || '').trim();
    if (!token) continue;
    const lower = token.toLowerCase();
    if (/^https?:\/\//i.test(token)) {
      map.set(lower, token);
      continue;
    }
    const maybeUrl = String(entries[i + 1] || '').trim();
    if (/^https?:\/\//i.test(maybeUrl)) {
      map.set(lower, maybeUrl);
      i += 1;
      continue;
    }
    if (lower === 'dashboard') map.set('dashboard', 'http://localhost:3131');
    else if (lower === 'youtube') map.set('youtube', 'https://www.youtube.com');
    else if (lower === 'tradingview') map.set('tradingview', 'https://www.tradingview.com');
    else if (lower === 'openai') map.set('openai', 'https://platform.openai.com');
    else if (lower === 'databento') map.set('databento', 'https://databento.com');
  }
  if (!map.has('dashboard')) map.set('dashboard', 'http://localhost:3131');
  return map;
}

function extractJsonObjectFromText(input) {
  const txt = String(input || '').trim();
  if (!txt) return null;
  const fenced = txt.match(/```json\s*([\s\S]*?)```/i) || txt.match(/```\s*([\s\S]*?)```/i);
  const candidate = fenced ? fenced[1].trim() : txt;
  try {
    return JSON.parse(candidate);
  } catch {}
  const first = candidate.indexOf('{');
  const last = candidate.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try {
      return JSON.parse(candidate.slice(first, last + 1));
    } catch {}
  }
  return null;
}

function normalizeOutcomeToken(input) {
  const raw = String(input || '').trim().toLowerCase();
  if (!raw) return null;
  if (['win', 'tp', 'won'].includes(raw)) return 'win';
  if (['loss', 'sl', 'lost'].includes(raw)) return 'loss';
  if (['breakeven', 'break_even', 'break-even', 'be', 'flat'].includes(raw)) return 'breakeven';
  return null;
}

function normalizeDecisionSignalLabel(input) {
  const raw = String(input || '').trim().toUpperCase();
  if (raw === 'TRADE' || raw === 'GO') return 'TRADE';
  if (raw === 'WAIT') return 'WAIT';
  if (raw === "DON'T TRADE" || raw === 'NO_TRADE' || raw === 'NO TRADE') return "DON'T TRADE";
  return raw || 'WAIT';
}

function isBlockedDashboardShellCommand(command) {
  const txt = String(command || '').toLowerCase();
  const blocked = [
    'rm -rf /',
    'rm -rf ~',
    'git reset --hard',
    'git checkout --',
    'shutdown',
    'reboot',
    'halt',
    'diskutil erase',
    ':(){:|:&};:',
    'mkfs',
    'dd if=',
    'sudo ',
  ];
  return blocked.some((token) => txt.includes(token));
}

async function runDashboardShellCommand(command) {
  const cmd = String(command || '').trim();
  if (!cmd) throw new Error('terminal command is empty');
  if (isBlockedDashboardShellCommand(cmd)) {
    throw new Error('Blocked dangerous command. Request a safer equivalent.');
  }
  return new Promise((resolve, reject) => {
    execFile('zsh', ['-lc', cmd], {
      cwd: path.join(__dirname, '..'),
      timeout: DASHBOARD_AGENT_SHELL_TIMEOUT_MS,
      maxBuffer: 1024 * 1024 * 8,
      env: process.env,
    }, (err, stdout, stderr) => {
      const out = truncateAgentText(String(stdout || '').trim(), DASHBOARD_AGENT_MAX_SHELL_OUTPUT_CHARS);
      const errOut = truncateAgentText(String(stderr || '').trim(), DASHBOARD_AGENT_MAX_SHELL_OUTPUT_CHARS);
      if (err) {
        return reject(new Error(errOut || out || err.message || 'terminal command failed'));
      }
      resolve({ command: cmd, stdout: out, stderr: errOut });
    });
  });
}

function summarizeSnapshotOutlook(cmd) {
  const decision = cmd?.decision || {};
  const signal = normalizeDecisionSignalLabel(decision.signalLabel || decision.signal || decision.verdict);
  const confidence = Number(decision.confidence || 0);
  const top = decision?.topSetups?.[0];
  const blockers = (decision?.blockers || []).slice(0, 3);
  const reason = blockers.length
    ? blockers.join(', ')
    : (top?.name ? `focus ${top.name}` : 'no blockers');
  return `${signal}. Confidence ${confidence}%. ${reason}.`;
}

async function executeDashboardAgentCommand(rawCommand, context = {}) {
  const cmdText = String(rawCommand || '').trim().replace(/\s+/g, ' ');
  if (!cmdText) throw new Error('empty command');
  const [baseRaw, ...restTokens] = cmdText.split(' ');
  const base = String(baseRaw || '').toLowerCase();
  const rest = restTokens.join(' ').trim();
  const strategy = String(context.strategy || 'original') === 'alt' ? 'alt' : 'original';

  if (base === 'help' || base === 'capabilities') {
    return {
      ok: true,
      command: cmdText,
      output: [
        'You can ask naturally for: status, plan, deskstart, tradestate, opportunities, autonomy, mode changes, sync, discovery scan, doctor, outcome logging, and terminal tasks.',
        'Examples: "what is today gameplan", "run topstep sync", "mode live assist", "log outcome win 120".',
      ].join(' '),
    };
  }
  if (base === 'status') {
    const cmd = await buildTradingCommandSnapshot(strategy);
    return { ok: true, command: cmdText, output: buildDiscordStatusFromCommand(cmd) };
  }
  if (base === 'plan') {
    const cmd = await buildTradingCommandSnapshot(strategy);
    return { ok: true, command: cmdText, output: buildDailyPlanTextFromCommand(cmd) };
  }
  if (base === 'deskstart') {
    const cmd = await buildTradingCommandSnapshot(strategy, { forceFresh: true });
    return { ok: true, command: cmdText, output: buildDeskStartSequenceFromCommand(cmd).text };
  }
  if (base === 'tradestate') {
    const state = getLiveTradeState();
    const openLine = state?.inPosition
      ? `In position ${String(state.side || '').toUpperCase()} ${state.qty || 0} ${state.symbol || ''} at ${state.entryPrice || 'n/a'}.`
      : 'Flat. No open position.';
    const pnl = Number(todayRealizedPnlDollars() || 0).toFixed(2);
    return { ok: true, command: cmdText, output: `${openLine} Realized PnL today: $${pnl}.` };
  }
  if (base === 'opps') {
    const cmd = await buildTradingCommandSnapshot(strategy);
    const top = (cmd?.opportunities || []).slice(0, 3);
    if (!top.length) return { ok: true, command: cmdText, output: 'No opportunities available right now.' };
    const lines = top.map((o, i) => `${i + 1}. ${o.name} (${o.probability}% ${o.grade || ''})`.trim());
    return { ok: true, command: cmdText, output: lines.join('\n') };
  }
  if (base === 'system') {
    const health = buildHealthSnapshot();
    const compliance = buildTopstepComplianceSnapshot();
    const parts = [
      `System ${health.status || 'unknown'}.`,
      health?.api?.ok ? 'API online.' : 'API down.',
      health?.database?.ok ? 'Database ready.' : 'Database issue.',
      `Topstep mode ${compliance?.apiMode || 'unknown'}.`,
    ];
    return { ok: true, command: cmdText, output: parts.join(' ') };
  }
  if (base === 'autonomy') {
    if (/\brun\b/i.test(rest)) {
      const out = await runPaperAutonomyCycle({ force: true });
      return { ok: true, command: cmdText, output: `Autonomy cycle: ${out.status || 'done'} (${out.reason || 'no reason'}).` };
    }
    const settings = getExecutionAutonomySettings();
    return {
      ok: true,
      command: cmdText,
      output: `Mode ${settings.mode}. Window ${settings.paperAutoWindowStart}-${settings.paperAutoWindowEnd}. Daily cap ${settings.maxPaperActionsPerDay}.`,
    };
  }
  if (base === 'mode') {
    const nextMode = String(rest || '').toLowerCase();
    if (!['manual', 'paper_auto', 'live_assist'].includes(nextMode)) {
      throw new Error('mode must be manual, paper_auto, or live_assist');
    }
    const next = saveExecutionAutonomySettings({ mode: nextMode, paperAutoEnabled: nextMode === 'paper_auto' ? true : undefined });
    return { ok: true, command: cmdText, output: `Autonomy mode set to ${next.mode}.` };
  }
  if (base === 'halt') {
    const c = saveExecutionControls({ killSwitch: true, enabled: true });
    return { ok: true, command: cmdText, output: `Kill switch activated (enabled=${c.enabled}, killSwitch=${c.killSwitch}).` };
  }
  if (base === 'resume') {
    const c = saveExecutionControls({ killSwitch: false, enabled: true });
    return { ok: true, command: cmdText, output: `Kill switch cleared (enabled=${c.enabled}, killSwitch=${c.killSwitch}).` };
  }
  if (base === 'scan') {
    const mode = /\bfull\b/i.test(rest) ? 'full_scan' : 'two_stage';
    const out = await executeDiscoveryRun({ mode });
    return {
      ok: true,
      command: cmdText,
      output: `Discovery ${mode} completed. Candidates: ${Number(out?.summary?.counts?.total || 0)}.`,
    };
  }
  if (base === 'doctor') {
    const out = await runValidationSweep({ source: 'dashboard_agent', force: true });
    return {
      ok: true,
      command: cmdText,
      output: `Validation sweep: ${out?.status || 'done'} (${out?.details?.interpreter?.passed ? 'interpreter ok' : 'interpreter fail'}).`,
    };
  }
  if (base === 'outcome') {
    const tokens = rest.split(/\s+/).filter(Boolean);
    const outcome = normalizeOutcomeToken(tokens.shift());
    if (!outcome) throw new Error('outcome requires win, loss, or breakeven');
    let pnlDollars = null;
    if (tokens.length && /^[-+]?\$?\d+(\.\d+)?$/.test(tokens[0])) {
      const parsed = Number(String(tokens.shift()).replace('$', ''));
      pnlDollars = Number.isFinite(parsed) ? parsed : null;
    }
    const notes = tokens.join(' ').trim();
    const row = await logTradeOutcomeFromDiscord({
      outcome,
      pnlDollars,
      notes,
      source: 'dashboard_agent',
    });
    return {
      ok: true,
      command: cmdText,
      output: `Logged ${String(row?.outcome || outcome).toUpperCase()} for ${row?.setupName || 'current setup'}${Number.isFinite(row?.pnlDollars) ? ` ($${Number(row.pnlDollars).toFixed(2)})` : ''}.`,
    };
  }
  if (base === 'sync') {
    const out = await runTopstepReadOnlySync({ force: true, triggerSource: 'dashboard_agent_command' });
    return { ok: true, command: cmdText, output: `Topstep sync ${out.status || 'done'} (${out.fillRows || 0} fills).` };
  }
  if (base === 'liveintel' || (base === 'intel' && /\blive\b/i.test(rest))) {
    const snapshot = await buildAssistantIntelligenceSnapshot({ strategy });
    const lines = buildAssistantIntelligenceLines(snapshot);
    return {
      ok: true,
      command: cmdText,
      output: lines.join('\n'),
    };
  }
  if (base === 'terminal') {
    const out = await runDashboardShellCommand(rest);
    return {
      ok: true,
      command: cmdText,
      output: out.stdout || out.stderr || 'terminal command complete',
    };
  }
  throw new Error(`Unsupported command: ${base}`);
}

function dashboardAgentProviderSummary() {
  const openaiConfigured = !!String(process.env.OPENAI_API_KEY || '').trim();
  const anthropicConfigured = !!String(process.env.ANTHROPIC_API_KEY || config.anthropicKey || '').trim();
  const openaiBlocked = Number(dashboardPlannerRuntime.openaiBlockedUntil || 0) > Date.now();
  let active = 'none';
  if (DASHBOARD_AGENT_STRICT_PROVIDER) {
    if (DASHBOARD_AGENT_PROVIDER === 'openai') {
      active = openaiConfigured
        ? (openaiBlocked ? 'openai_blocked' : 'openai')
        : 'none';
    } else if (DASHBOARD_AGENT_PROVIDER === 'anthropic') {
      active = anthropicConfigured ? 'anthropic' : 'none';
    } else {
      active = openaiConfigured
        ? (openaiBlocked ? 'openai_blocked' : 'openai')
        : (anthropicConfigured ? 'anthropic' : 'none');
    }
    return {
      configured: active !== 'none',
      active,
      openaiConfigured,
      anthropicConfigured,
      openaiBlocked,
      openaiBlockReason: dashboardPlannerRuntime.openaiBlockReason || null,
      strictProvider: true,
    };
  }
  if (DASHBOARD_AGENT_PROVIDER === 'openai') {
    if (openaiConfigured && !openaiBlocked) active = 'openai';
    else active = anthropicConfigured ? 'anthropic_fallback' : (openaiConfigured ? 'openai_blocked' : 'none');
  } else if (DASHBOARD_AGENT_PROVIDER === 'anthropic') {
    active = anthropicConfigured ? 'anthropic' : (openaiConfigured ? 'openai_fallback' : 'none');
  } else {
    active = (openaiConfigured && !openaiBlocked) ? 'openai' : (anthropicConfigured ? 'anthropic' : (openaiConfigured ? 'openai_blocked' : 'none'));
  }
  return {
    configured: openaiConfigured || anthropicConfigured,
    active,
    openaiConfigured,
    anthropicConfigured,
    openaiBlocked,
    openaiBlockReason: dashboardPlannerRuntime.openaiBlockReason || null,
    strictProvider: false,
  };
}

function getDashboardAgentProviderOrder() {
  const pref = DASHBOARD_AGENT_PROVIDER;
  if (DASHBOARD_AGENT_STRICT_PROVIDER) {
    if (pref === 'anthropic') return ['anthropic'];
    return ['openai'];
  }
  const base = pref === 'anthropic'
    ? ['anthropic', 'openai']
    : pref === 'openai'
      ? ['openai', 'anthropic']
      : ['openai', 'anthropic'];
  const openaiBlocked = Number(dashboardPlannerRuntime.openaiBlockedUntil || 0) > Date.now();
  if (!openaiBlocked) return base;
  return base.filter((p) => p !== 'openai').concat(base.includes('openai') ? ['openai'] : []);
}

function extractOpenAiMessageText(choiceMessage = {}) {
  const content = choiceMessage?.content;
  if (typeof content === 'string') return content;
  if (Array.isArray(content)) {
    return content
      .map((c) => {
        if (!c || typeof c !== 'object') return '';
        if (typeof c.text === 'string') return c.text;
        if (typeof c.output_text === 'string') return c.output_text;
        return '';
      })
      .join('\n')
      .trim();
  }
  return '';
}

async function runDashboardPlannerOpenAI({ system, convo }) {
  const openaiKey = String(process.env.OPENAI_API_KEY || '').trim();
  if (!openaiKey) throw new Error('openai_api_key_missing');
  const messages = [{ role: 'system', content: system }].concat(
    convo.map((m) => ({
      role: m.role === 'assistant' ? 'assistant' : 'user',
      content: String(m.content || ''),
    }))
  );
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), DASHBOARD_AGENT_API_TIMEOUT_MS);
  let response = null;
  let payload = {};
  try {
    response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${openaiKey}`,
      },
      body: JSON.stringify({
        model: DASHBOARD_AGENT_MODEL_OPENAI,
        temperature: 0.1,
        response_format: { type: 'json_object' },
        messages,
      }),
      signal: controller.signal,
    });
    payload = await response.json().catch(() => ({}));
  } finally {
    clearTimeout(timeout);
  }
  if (!response.ok) {
    const errText = truncateAgentText(
      payload?.error?.message || payload?.error || `openai_http_${response.status}`,
      280
    );
    throw new Error(errText);
  }
  const txt = extractOpenAiMessageText(payload?.choices?.[0]?.message || {});
  if (!txt) throw new Error('openai_empty_response');
  return {
    provider: 'openai',
    model: DASHBOARD_AGENT_MODEL_OPENAI,
    rawText: txt,
  };
}

async function runDashboardPlannerAnthropic({ system, convo }) {
  const apiKey = String(process.env.ANTHROPIC_API_KEY || config.anthropicKey || '').trim();
  if (!apiKey) throw new Error('anthropic_api_key_missing');
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), DASHBOARD_AGENT_API_TIMEOUT_MS);
  let response = null;
  let payload = {};
  try {
    response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: DASHBOARD_AGENT_MODEL_ANTHROPIC,
        max_tokens: 700,
        system,
        messages: convo,
      }),
      signal: controller.signal,
    });
    payload = await response.json().catch(() => ({}));
  } finally {
    clearTimeout(timeout);
  }
  if (!response.ok) {
    const msg = truncateAgentText(payload?.error?.message || payload?.error || `anthropic_http_${response.status}`, 280);
    throw new Error(msg);
  }
  const txt = String(payload?.content?.[0]?.text || '').trim();
  if (!txt) throw new Error('anthropic_empty_response');
  return {
    provider: 'anthropic',
    model: DASHBOARD_AGENT_MODEL_ANTHROPIC,
    rawText: txt,
  };
}

async function runDashboardPlannerWithFallback({ system, convo }) {
  const order = getDashboardAgentProviderOrder();
  const errors = [];
  for (const provider of order) {
    try {
      let out = null;
      if (provider === 'openai') out = await runDashboardPlannerOpenAI({ system, convo });
      else out = await runDashboardPlannerAnthropic({ system, convo });
      dashboardPlannerRuntime = {
        ...dashboardPlannerRuntime,
        lastProvider: out.provider || provider,
        lastModel: out.model || null,
        lastSuccessAt: new Date().toISOString(),
      };
      if ((out.provider || provider) === 'openai') {
        dashboardPlannerRuntime.openaiBlockedUntil = 0;
        dashboardPlannerRuntime.openaiBlockReason = null;
      }
      return out;
    } catch (err) {
      const msg = String(err?.message || 'planner_failed');
      if (provider === 'openai' && /\bquota|429|rate limit|insufficient\b/i.test(msg)) {
        dashboardPlannerRuntime.openaiBlockedUntil = Date.now() + (15 * 60 * 1000);
        dashboardPlannerRuntime.openaiBlockReason = msg.slice(0, 180);
      }
      dashboardPlannerRuntime.lastErrorAt = new Date().toISOString();
      dashboardPlannerRuntime.lastErrors = dashboardPlannerRuntime.lastErrors.concat([`${provider}:${msg}`]).slice(-8);
      errors.push(`${provider}:${msg}`);
    }
  }
  throw new Error(errors.join(' | ') || 'dashboard_planner_unavailable');
}

function normalizeAssistantText(input) {
  return String(input || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ');
}

function formatAssistantClockTime(rawTs, timezone = 'America/New_York') {
  const txt = String(rawTs || '').trim();
  if (!txt) return null;
  let dt = new Date(txt);
  if (!Number.isFinite(dt.getTime())) dt = new Date(txt.replace(' ', 'T'));
  if (!Number.isFinite(dt.getTime())) dt = new Date(txt.replace(' ', 'T') + 'Z');
  if (!Number.isFinite(dt.getTime())) return txt;
  try {
    const timeText = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      hour: 'numeric',
      minute: '2-digit',
      hour12: true,
    }).format(dt);
    const dayIso = dateInTimezone(timezone, dt);
    const todayIso = dateInTimezone(timezone);
    return dayIso === todayIso ? `${timeText} ET` : `${timeText} ET on ${dayIso}`;
  } catch {
    return txt;
  }
}

function humanizeAssistantSyncStatus(status) {
  const s = String(status || '').trim().toLowerCase();
  if (!s) return 'Live feed status is unknown right now.';
  if (s === 'ok' || s === 'noop') return 'Live feed is connected and healthy.';
  if (s === 'partial') return 'Live feed is partially healthy; some components need refresh.';
  if (s === 'error') return 'Live feed has an active error and needs a sync.';
  if (s === 'disabled') return 'Live feed is disabled in current settings.';
  return `Live feed status is ${s}.`;
}

function assistantAccountSubject(rawName) {
  const txt = String(rawName || '').trim();
  if (!txt) return 'Connected account';
  if (/^prac[-_]/i.test(txt)) return 'Paper account';
  if (/^(sim|demo|eval|test|paper)[-_]/i.test(txt)) return 'Simulation account';
  if (/^\d{6,}$/.test(txt) || /-\d{6,}/.test(txt)) return 'Connected account';
  return txt;
}

function isAssistantGreetingOnly(message) {
  const txt = normalizeAssistantText(message);
  if (!txt) return false;
  const hasGreeting = /\b(hi|hey|hello|yo|sup|what'?s up|good morning|good afternoon|good evening|how are you|how'?s it going|how is it going)\b/.test(txt);
  if (!hasGreeting) return false;
  const hasActionOrMarketIntent = /\b(status|plan|outlook|gameplan|sync|refresh|update|trade|setup|signal|market|mnq|price|entry|enter|buy|sell|long|short|position|pnl|opportunit|intel|scan|doctor|system|autonomy|open|close|run|execute)\b/.test(txt);
  return !hasActionOrMarketIntent;
}

function pickFirstFiniteNumber(...values) {
  for (const value of values) {
    const num = Number(value);
    if (Number.isFinite(num)) return num;
  }
  return null;
}

function summarizeTopstepFillsForRisk(sessionDateEt, options = {}) {
  const db = getDB();
  const accountIdFilter = String(options.accountId || '').trim() || null;
  const symbolRootFilter = topstepSymbolRoot(String(options.symbol || '').trim().toUpperCase());
  const lookbackRows = Math.max(200, Math.min(4000, Number(options.lookbackRows || 1200)));
  const rows = db.prepare(`
    SELECT id, external_fill_id, order_id, account_id, symbol, qty, realized_pnl, fill_time, created_at
    FROM topstep_fills
    ORDER BY COALESCE(fill_time, created_at) DESC, id DESC
    LIMIT ?
  `).all(lookbackRows);
  const orderKeys = new Set();
  let fillCount = 0;
  let realizedPnl = 0;
  let lastRealizedTradePnL = null;
  let lastRealizedTradeTimeEt = null;
  let lastRealizedTradeTsMs = null;

  for (const row of rows) {
    if (accountIdFilter && String(row?.account_id || '').trim() !== accountIdFilter) continue;
    const eventDateEt = topstepFillEventDate(row?.fill_time, row?.created_at);
    if (eventDateEt !== sessionDateEt) continue;
    const rowSymbolRoot = topstepSymbolRoot(row?.symbol);
    if (symbolRootFilter && rowSymbolRoot && rowSymbolRoot !== symbolRootFilter) continue;
    fillCount += 1;
    const pnl = Number(row?.realized_pnl);
    if (Number.isFinite(pnl)) realizedPnl += pnl;
    if (
      lastRealizedTradeTsMs == null
      && Number.isFinite(pnl)
      && Math.abs(pnl) > 0
    ) {
      const rawTs = row?.fill_time || row?.created_at || null;
      const parsed = parseAnyTimestamp(rawTs) || parseEtLocalTimestamp(rawTs);
      lastRealizedTradeTsMs = parsed ? parsed.getTime() : null;
      lastRealizedTradeTimeEt = formatEtTimestamp(rawTs) || (rawTs ? String(rawTs) : null);
      lastRealizedTradePnL = round2(pnl);
    }
    const orderKey = String(
      row?.order_id
      || row?.external_fill_id
      || `${row?.symbol || ''}:${row?.qty || ''}:${row?.fill_time || row?.created_at || ''}:${row?.id || ''}`
    ).trim();
    if (orderKey) orderKeys.add(orderKey);
  }
  return {
    tradeCount: orderKeys.size,
    fillCount,
    realizedPnl: round2(realizedPnl),
    lastRealizedTradePnL,
    lastRealizedTradeTimeEt,
    lastRealizedTradeTsMs,
  };
}

function deriveRiskOpenPositionState(options = {}) {
  const symbolRoot = topstepSymbolRoot(String(options.symbol || '').trim().toUpperCase());
  const topstepLive = options.topstepLive || {};
  const liveState = options.liveState || {};
  const positions = Array.isArray(topstepLive?.positions) ? topstepLive.positions : [];
  const openPositions = positions.filter((p) => Number(p?.qty || 0) > 0);
  const primary = openPositions.find((p) => topstepSymbolRoot(p?.symbol) === symbolRoot)
    || openPositions[0]
    || null;

  const primaryQty = Number(primary?.qty);
  const liveQty = Number(liveState?.qty);
  const qty = Number.isFinite(primaryQty) && primaryQty > 0
    ? Math.abs(primaryQty)
    : (Number.isFinite(liveQty) ? Math.abs(liveQty) : 0);

  let side = String(primary?.side || liveState?.side || '').trim().toLowerCase();
  if (side !== 'long' && side !== 'short') side = null;
  if (!(Number.isFinite(qty) && qty > 0)) side = null;

  const avgPrice = pickFirstFiniteNumber(primary?.avgPrice, liveState?.entryPrice);
  const unrealizedPnL = pickFirstFiniteNumber(primary?.unrealizedPnl, liveState?.pnlDollars, topstepLive?.account?.unrealizedPnl);

  return {
    side,
    qty: Number.isFinite(qty) ? qty : 0,
    avgPrice: Number.isFinite(Number(qty)) && Number(qty) > 0 ? avgPrice : null,
    unrealizedPnL: Number.isFinite(Number(qty)) && Number(qty) > 0 ? unrealizedPnL : null,
  };
}

function makeAnalystRiskRuntimeCacheKey(options = {}) {
  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const sessionDateEt = String(options.sessionDateEt || dateInTimezone('America/New_York')).trim().slice(0, 10);
  const symbol = String(options.symbol || config.topstep?.autonomy?.defaultSymbol || 'MNQ').trim().toUpperCase();
  const preferCachedLive = options.preferCachedLive === true ? 'cached' : 'full';
  return `${strategy}|${sessionDateEt}|${symbol}|${preferCachedLive}`;
}

function pruneAnalystRiskRuntimeCache() {
  const now = Date.now();
  for (const [key, row] of analystRiskRuntimeCache.entries()) {
    if (!row || (now - Number(row.cachedAtMs || 0)) > ANALYST_RISK_RUNTIME_CACHE_TTL_MS) {
      analystRiskRuntimeCache.delete(key);
    }
  }
}

async function buildAnalystRiskStateRuntime(options = {}) {
  const activeModule = normalizeDashboardModuleId(options.activeModule) || 'analyst';
  if (activeModule !== 'analyst') {
    return {
      enabled: false,
      riskState: null,
      readiness: null,
      marketDataFreshness: null,
      cmdSnapshot: null,
      intelligenceSnapshot: null,
    };
  }

  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const preferCachedLive = options.preferCachedLive === true;
  const cacheable = preferCachedLive && options.forceFresh !== true;
  const cacheKey = cacheable ? makeAnalystRiskRuntimeCacheKey(options) : null;
  if (cacheKey) {
    const cached = analystRiskRuntimeCache.get(cacheKey);
    if (cached && (Date.now() - Number(cached.cachedAtMs || 0)) <= ANALYST_RISK_RUNTIME_CACHE_TTL_MS) {
      return cached.snapshot;
    }
    const inFlight = analystRiskRuntimeInFlight.get(cacheKey);
    if (inFlight) return inFlight;
  }
  const runtimeTimeoutMs = Math.max(
    2500,
    Number(process.env.ANALYST_RISK_RUNTIME_TIMEOUT_MS || 4000)
  );
  const withRuntimeDeadline = async (promiseLike, label) => Promise.race([
    Promise.resolve().then(() => promiseLike),
    new Promise((_, reject) => {
      const timer = setTimeout(() => reject(new Error(`${String(label || 'risk_runtime')}_timeout_${Math.round(runtimeTimeoutMs)}ms`)), runtimeTimeoutMs);
      if (typeof timer.unref === 'function') timer.unref();
    }),
  ]);
  const nowEt = options.nowEt || nowInTimezone('America/New_York');
  const sessionDateEt = String(options.sessionDateEt || nowEt?.date || dateInTimezone('America/New_York')).trim();
  const symbol = String(options.symbol || config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase();
  const runCore = async () => {
    const controls = getExecutionControls();
    const guardrails = getExecutionGuardrails();
    const topstepLive = options.topstepLive || getTopstepLiveSnapshot({ fillLimit: 40 });
    const liveState = options.liveState || getLiveTradeState();
    const account = topstepLive?.account || {};
    const cmdSnapshot = options.cmdSnapshot || await withRuntimeDeadline(
      buildTradingCommandSnapshot(strategy).catch(() => null),
      'risk_cmd_snapshot'
    ).catch(() => null);
    let intelligenceSnapshot = options.intelligenceSnapshot || null;
    if (!intelligenceSnapshot && !preferCachedLive) {
      intelligenceSnapshot = await withRuntimeDeadline(
        buildAssistantIntelligenceSnapshot({
          strategy,
          cmdSnapshot,
          topstepLive,
          preferCachedLive,
          forceFresh: options.forceFresh === true,
        }).catch(() => null),
        'risk_intelligence_snapshot'
      ).catch(() => null);
    }
    const marketDataFreshness = intelligenceSnapshot?.marketDataFreshness || buildMarketDataFreshnessSnapshot({
      timezone: 'America/New_York',
      topstepLive,
    });
    const readiness = evaluateMarketDataFreshnessGate({
      nowEt,
      marketDataFreshness,
      lastPrice: intelligenceSnapshot?.market?.pattern?.lastPrice,
      staleThresholdMinutes: marketDataFreshness?.staleThresholdMinutes || getAnalystFreshnessLagThresholdMinutes(),
    });

    const orderStats = getRecentConfirmedOrderStats('America/New_York');
    const fillSummary = summarizeTopstepFillsForRisk(sessionDateEt, {
      accountId: account?.accountId || null,
      symbol,
    });
    const openPosition = deriveRiskOpenPositionState({
      symbol,
      topstepLive,
      liveState,
    });
    const hasOpenPosition = !!(
      Number(openPosition?.qty || 0) > 0
      || liveState?.inPosition === true
      || topstepLive?.derived?.hasOpenPositions === true
    );

    const tradesTakenToday = Math.max(
      Number(orderStats?.confirmedToday || 0),
      Number(fillSummary?.tradeCount || 0)
    );

    const envMaxTrades = Number(process.env.ANALYST_MAX_TRADES_PER_DAY);
    const maxTradesPerDayRaw = pickFirstFiniteNumber(
      options.maxTradesPerDay,
      envMaxTrades,
      1
    );
    const maxTradesPerDay = Math.max(1, Math.min(20, Math.round(Number(maxTradesPerDayRaw || 1))));
    const entryWindowStartEt = String(options.entryWindowStartEt || process.env.ANALYST_ENTRY_WINDOW_START_ET || '09:30').trim() || '09:30';
    const entryWindowEndEt = String(options.entryWindowEndEt || process.env.ANALYST_ENTRY_WINDOW_END_ET || '10:59').trim() || '10:59';
    const dailyLossLimit = Math.max(
      50,
      Number(pickFirstFiniteNumber(options.dailyLossLimit, process.env.DAILY_LOSS_LIMIT_USD, controls?.maxDailyLossDollars, 500) || 500)
    );
    const maxContracts = Math.max(1, Number(pickFirstFiniteNumber(options.maxContracts, controls?.maxPositionSize, 1) || 1));
    let trailingDrawdownDistance = pickFirstFiniteNumber(
      options.trailingDrawdownDistance,
      account?.maxDrawdownBuffer
    );
    if (!(Number.isFinite(trailingDrawdownDistance) && trailingDrawdownDistance > 0)) {
      trailingDrawdownDistance = null;
    }
    const minDrawdownBufferDollars = Math.max(
      0,
      Number(pickFirstFiniteNumber(options.minDrawdownBufferDollars, config.topstep?.compliance?.minDrawdownBufferDollars, 250) || 250)
    );
    const lossCooldownEnabled = options.lossCooldownEnabled != null
      ? options.lossCooldownEnabled !== false
      : String(process.env.LOSS_COOLDOWN_ENABLED || 'true').trim().toLowerCase() !== 'false';
    const lossCooldownMinutes = Math.max(
      1,
      Math.min(
        240,
        Number(
          pickFirstFiniteNumber(
            options.lossCooldownMinutes,
            process.env.LOSS_COOLDOWN_MINUTES,
            10
          ) || 10
        )
      )
    );
    let cooldownRemainingMinutes = 0;
    if (
      lossCooldownEnabled
      && Number.isFinite(Number(fillSummary?.lastRealizedTradePnL))
      && Number(fillSummary.lastRealizedTradePnL) < 0
    ) {
      const lastLossMs = Number(fillSummary?.lastRealizedTradeTsMs || 0);
      if (Number.isFinite(lastLossMs) && lastLossMs > 0) {
        const nowEtStamp = parseEtLocalTimestamp(`${nowEt.date} ${nowEt.time}:00`) || new Date();
        const elapsedMinutes = Math.max(0, Math.floor((nowEtStamp.getTime() - lastLossMs) / 60000));
        cooldownRemainingMinutes = Math.max(0, lossCooldownMinutes - elapsedMinutes);
      }
    }

    const riskState = buildRiskStateSnapshot({
      nowEt,
      sessionDateEt,
      entryWindowStartEt,
      entryWindowEndEt,
      orbComplete: marketDataFreshness?.hasORBComplete === true,

      equity: pickFirstFiniteNumber(account?.equity),
      balance: pickFirstFiniteNumber(account?.balance),
      unrealizedPnL: pickFirstFiniteNumber(account?.unrealizedPnl, openPosition?.unrealizedPnL, liveState?.pnlDollars),
      realizedPnLToday: pickFirstFiniteNumber(account?.realizedPnl, fillSummary?.realizedPnl, todayRealizedPnlDollars()),
      dailyPnL: pickFirstFiniteNumber(account?.dailyPnl, fillSummary?.realizedPnl, todayRealizedPnlDollars()),
      maxDrawdownToday: pickFirstFiniteNumber(options.maxDrawdownToday),
      trailingDrawdownDistance,

      openPosition,
      hasOpenPosition,
      tradesTakenToday,
      maxTradesPerDay,
      dailyLossLimit,
      maxContracts,
      minDrawdownBufferDollars,
      lossCooldownEnabled,
      lossCooldownMinutes,
      lastRealizedTradePnL: pickFirstFiniteNumber(fillSummary?.lastRealizedTradePnL),
      lastRealizedTradeTimeEt: fillSummary?.lastRealizedTradeTimeEt || null,
      cooldownRemainingMinutes,
      blockedCooldownAfterLoss: lossCooldownEnabled && cooldownRemainingMinutes > 0,

      blockWhenOpenPosition: options.blockWhenOpenPosition !== false,
      blockedDataStale: readiness?.needsFreshData === true && guardrails?.requireFreshData !== false,
      readinessNeedsFreshData: readiness?.needsFreshData === true,
      marketDataFreshness,
    });

    return {
      enabled: true,
      riskState,
      readiness,
      marketDataFreshness,
      cmdSnapshot,
      intelligenceSnapshot,
      topstepLive,
      liveState,
      orderStats,
      fillSummary,
    };
  };

  if (!cacheKey) {
    return runCore();
  }
  const pending = runCore()
    .then((snapshot) => {
      analystRiskRuntimeCache.set(cacheKey, {
        cachedAtMs: Date.now(),
        snapshot,
      });
      pruneAnalystRiskRuntimeCache();
      return snapshot;
    })
    .finally(() => {
      analystRiskRuntimeInFlight.delete(cacheKey);
    });
  analystRiskRuntimeInFlight.set(cacheKey, pending);
  return pending;
}

function parseAssistantQuickIntents(message) {
  const txt = normalizeAssistantText(message);
  return {
    text: txt,
    wantsExplain: isExplainFollowup(message),
    wantsSync: /\b(sync|refresh|update)\b/.test(txt) && /\b(topstep|live|data|market|feed|conditions?|state|now)\b/.test(txt),
    wantsOutlook: /\b(outlook|gameplan|game plan|plan|how should i trade|how should i trade this morning|what should i do|today stance|today signal|morning outlook|morning gameplan|morning game plan|morning plan|today(?:['’]s)? outlook|today(?:['’]s)? game plan|what(?:['’]s| is) the outlook|what(?:['’]s| is) the gameplan|what(?:['’]s| is) the game plan|gameplan for today|macro synthesis|tactical execution|strategy for today|trade plan|session outlook|good day to not trade|good day not to trade|good day to stay out|was today a good day to not trade|was today a good day not to trade|was it right to stay out|i didn['’]?t take a trade today|was that a good decision|should i not trade|was i right not trading|did i do right not trading|was not trading right|should i stay out today|should i stay out|should i sit out|stay out of the market|sit out|stand down|avoid the market|how(?:['’]s| is)\s+it\s+looking\s+for\s+my\s+trading\s+plan|what should i do right now with my trading|am i trading today)\b/.test(txt),
    wantsTrendRegime: /\b(what trend are we in|trend right now|market trend|regime right now|market regime|bias right now)\b/.test(txt),
    wantsHypotheticalReplay: /\b(if i (?:would|would have|would've|had|had have|could have|could've).*(?:trade|traded|taken|take)|if i would have taken a trade|what would have happened|how would that trade have done|would(?: have)? won if i traded|would have been my results?|if i would of traded|if i would've traded)\b/.test(txt),
    wantsReplayWalkthrough: /\b(replay today|replay session|walk me through what happened|session recap|what did price do after 9:45|how did price move after 9:45)\b/.test(txt),
    wantsTradingReview: /\b(was it good i didn['’]?t trade|did i make the right call staying out|right call to stay out|good decision not trading|was staying out right|was i right not trading)\b/.test(txt),
    wantsSetupScan: /\b(potential setup|potential setups|setups do you see|what setups|what setup|opportunit|top setup|best setup|setups right now)\b/.test(txt),
    wantsTradeDecision: /\b(should i take|take this setup|take this trade|enter now|enter a trade now|close my position|buy or sell|should i enter|is this a good setup|should i long|should i short|long or short|should i trade now|take this now|should i not trade|should i stand down|avoid trading today|should i stay out|should i sit out|should i stand down|should i avoid the market|why can(?:'|’)t i trade|if i would have taken a trade|if i would've taken a trade|what would have happened if i traded)\b/.test(txt),
    wantsTradeState: /\b(in profit|pnl|profit|position|open trade|am i in a trade|trade status|am i green|am i red|how am i doing)\b/.test(txt),
    wantsMarketState: /\b(mnq price|current mnq|market state|price now|pull.*(mnq|market)|live feed|quote now|current price|current price of mnq|where is mnq|what is mnq at|mnq now|mnq currently|where is price|fresh bars|inside the entry window|entry window)\b/.test(txt),
    wantsLiveIntel: /\b(liveintel|live intel|live intelligence|market intelligence|intel snapshot|full intelligence|current conditions)\b/.test(txt),
    wantsCapabilityAudit: /\b(what do you need|what are you missing|better function|better perform|upgrade yourself|capability audit|capability gap|missing capabilities|why are you limited|what access do you need|how can i make you better)\b/.test(txt),
    wantsNextStep: /\b(what should i do next|what do i do next|next step|what now|what's next|whats next)\b/.test(txt),
    wantsConnectivityCheck: /\b(live market|market feed|market data|data connectivity|connectivity|connection status|real[-\s]?time data|live data access|can you access live)\b/.test(txt),
    wantsLiveNow: /\b(live|real time|realtime|right now|current|now)\b/.test(txt),
  };
}

function isAnalystPreambleReply(reply) {
  const txt = normalizeAssistantText(reply);
  if (!txt) return true;
  return /^(let me check|i(?:'|’)ll check|i will check|one moment|hold on|give me a second|let me take a look|let me look|checking now|just a moment)\b/.test(txt);
}

function isAnalystNarrativeDecisive(reply) {
  const txt = normalizeAssistantText(reply);
  if (!txt || txt.length < 25) return false;
  const hasStance = /\b(trade|tradable|wait|stand down|stay out|sit out|do not trade|don't trade|preserv(?:e|ing) capital|hold off|take the trade)\b/.test(txt);
  const hasFactor = /\b(range|blocker|score|confidence|volatility|golden zone|exhaust|risk|setup)\b/.test(txt);
  return hasStance && hasFactor;
}

function buildAnalystBlockerReasonLine(decision = {}) {
  const blockerKeys = Array.isArray(decision.blockers)
    ? decision.blockers.map((b) => String(b || '').toUpperCase()).filter(Boolean)
    : [];
  if (!blockerKeys.length) {
    return 'No major blockers are active right now, so execution depends on trigger quality and discipline.';
  }
  const blockers = blockerKeys.slice(0, 3).map(humanizeDecisionBlocker).filter(Boolean);
  const notes = [];
  if (blockerKeys.some((b) => b === 'RANGE_OVEREXTENDED' || b === 'FRIDAY_VOLATILITY_EXHAUSTION')) {
    notes.push('range expansion historically increases fakeout risk');
  }
  if (blockerKeys.some((b) => b === 'SETUP_QUALITY_BELOW_50' || b === 'WIN_PROB_BELOW_50' || b === 'PROB_GREEN_BELOW_50')) {
    notes.push('historical quality metrics are below threshold');
  }
  if (blockerKeys.some((b) => b === 'INSUFFICIENT_DECISIVE_SAMPLE')) {
    notes.push('recent decisive sample size is still thin');
  }
  if (blockerKeys.some((b) => b === 'OPEN_NEWS_RISK' || b === 'NEWS_LOCKOUT_ACTIVE')) {
    notes.push('news timing can distort follow-through');
  }
  const reasonTail = notes.length > 0 ? ` These risks matter because ${notes.join('; ')}.` : '';
  return `Main blockers right now: ${blockers.join(', ')}.${reasonTail}`;
}

function buildAnalystDecisionChangeLine(decision = {}) {
  const signal = normalizeDecisionSignal(decision.signal || decision.verdict);
  const rangeTicks = Number(decision.orbRangeTicks);
  const blockers = new Set(
    Array.isArray(decision.blockers)
      ? decision.blockers.map((b) => String(b || '').toUpperCase()).filter(Boolean)
      : []
  );

  if (Number.isFinite(rangeTicks) && rangeTicks > 400) {
    return 'This call changes when opening volatility compresses back toward your 70-220 tick zone.';
  }
  if (Number.isFinite(rangeTicks) && rangeTicks > 220) {
    return 'This call improves if range narrows and follow-through confirms before entry.';
  }
  if (
    blockers.has('SETUP_QUALITY_BELOW_50')
    || blockers.has('WIN_PROB_BELOW_50')
    || blockers.has('PROB_GREEN_BELOW_50')
  ) {
    return 'This call changes when setup quality and win-probability readings move back above threshold.';
  }
  if (blockers.has('INSUFFICIENT_DECISIVE_SAMPLE')) {
    return 'This call changes as more live outcomes are logged and confidence stabilizes.';
  }
  if (signal === 'GO') {
    return 'This call flips to caution if new blockers appear or range expands beyond your strong zone.';
  }
  if (signal === 'WAIT') {
    return 'This call changes once structure confirms and blocker pressure eases.';
  }
  return 'This call changes only after a clean setup appears with fewer blockers and better confirmation.';
}

function buildAnalystBestSetupLine(decision = {}, intelligence = null) {
  let top = Array.isArray(decision.topSetups) && decision.topSetups.length > 0
    ? decision.topSetups[0]
    : null;

  if (!top && Array.isArray(intelligence?.memory?.bestSetups) && intelligence.memory.bestSetups.length > 0) {
    top = intelligence.memory.bestSetups[0];
  }
  if (!top) return null;

  const setupName = String(top.name || top.setupName || top.setup_id || top.setupId || '').trim();
  if (!setupName) return null;

  const details = [];
  const prob = Number(top.probability);
  if (Number.isFinite(prob)) details.push(`estimated win rate ${prob.toFixed(1)}%`);
  const pf = Number(top.pf || top.profitFactor);
  if (Number.isFinite(pf) && pf > 0) details.push(`profit factor ${pf.toFixed(2)}`);
  const grade = String(top.grade || '').trim();
  if (grade) details.push(`grade ${grade}`);
  if (details.length > 0) {
    return `Best setup right now is ${setupName} (${details.join(', ')}).`;
  }
  return `Best setup right now is ${setupName}.`;
}

function buildAnalystFreshnessContext(intelligenceSnapshot = null) {
  const market = intelligenceSnapshot?.market || {};
  const pattern = market?.pattern || {};
  const marketDataFreshness = intelligenceSnapshot?.marketDataFreshness || buildMarketDataFreshnessSnapshot({
    timezone: 'America/New_York',
  });
  const nowEt = marketDataFreshness?.nowEt || nowInTimezone('America/New_York');
  const readiness = evaluateMarketDataFreshnessGate({
    nowEt,
    marketDataFreshness,
    lastPrice: pattern?.lastPrice,
    staleThresholdMinutes: marketDataFreshness?.staleThresholdMinutes || getAnalystFreshnessLagThresholdMinutes(),
  });
  return {
    marketDataFreshness,
    readiness,
    lastUpdateText: summarizeAnalystLastUpdate(marketDataFreshness),
  };
}

async function buildAnalystIntelligenceWithFreshnessGuard(options = {}) {
  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const cmdSnapshot = options.cmdSnapshot || null;
  const preferCachedLive = options.preferCachedLive === true;
  let liveSync = options.liveSync || null;
  let syncAttempted = false;
  const commandsExecuted = [];

  let intelligenceSnapshot = await buildAssistantIntelligenceSnapshot({
    strategy,
    cmdSnapshot,
    liveSync,
    preferCachedLive,
    forceFresh: options.forceFresh === true || !!liveSync,
  }).catch(() => null);
  let freshnessCtx = buildAnalystFreshnessContext(intelligenceSnapshot);
  const shouldForceSyncIfStale = options.forceSyncIfStale !== false;
  const alreadySynced = options.alreadySynced === true;
  const needSyncRetry = shouldForceSyncIfStale && freshnessCtx.readiness?.needsFreshData && !alreadySynced;

  if (needSyncRetry) {
    syncAttempted = true;
    try {
      liveSync = await runTopstepReadOnlySync({
        force: true,
        triggerSource: 'assistant_freshness_guard',
      });
      commandsExecuted.push({
        command: 'sync',
        ok: String(liveSync?.status || '').toLowerCase() !== 'error',
        output: liveSync?.status || 'ok',
        error: liveSync?.error || null,
      });
    } catch (err) {
      liveSync = { status: 'error', error: String(err?.message || 'topstep_sync_failed') };
      commandsExecuted.push({
        command: 'sync',
        ok: false,
        output: liveSync.status,
        error: liveSync.error,
      });
    }
    intelligenceSnapshot = await buildAssistantIntelligenceSnapshot({
      strategy,
      cmdSnapshot,
      liveSync,
      preferCachedLive: false,
      forceFresh: true,
    }).catch(() => intelligenceSnapshot);
    freshnessCtx = buildAnalystFreshnessContext(intelligenceSnapshot);
  }

  return {
    intelligenceSnapshot,
    marketDataFreshness: freshnessCtx.marketDataFreshness,
    readiness: freshnessCtx.readiness,
    lastUpdateText: freshnessCtx.lastUpdateText,
    liveSync,
    syncAttempted,
    commandsExecuted,
  };
}

async function synthesizeAnalystOrchestratorReply(options = {}) {
  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  let cmdSnapshot = options.cmdSnapshot || null;
  if (!cmdSnapshot || !cmdSnapshot.decision) {
    cmdSnapshot = await buildTradingCommandSnapshot(strategy).catch(() => null);
  }
  const freshnessBundle = await buildAnalystIntelligenceWithFreshnessGuard({
    strategy,
    cmdSnapshot,
    preferCachedLive: true,
    forceSyncIfStale: true,
    alreadySynced: false,
  });
  const intelligenceSnapshot = options.intelligenceSnapshot || freshnessBundle?.intelligenceSnapshot || null;

  const decision = cmdSnapshot?.decision || intelligenceSnapshot?.decision || {};
  const readiness = freshnessBundle?.readiness || {};
  const marketDataFreshness = freshnessBundle?.marketDataFreshness || intelligenceSnapshot?.marketDataFreshness || null;
  if (readiness?.needsFreshData) {
    const staleReply = buildFreshDataUnavailableReply({
      readiness,
      lastUpdateText: freshnessBundle?.lastUpdateText || summarizeAnalystLastUpdate(marketDataFreshness),
    });
    return [staleReply, assistantVisibilityBoundaryLine()].join('\n').trim();
  }
  const narrative = buildAnalystDecisionNarrative(decision, { marketDataFreshness });
  const lines = [narrative.stance, narrative.rangeLine, buildAnalystBlockerReasonLine(decision)];
  if (narrative.contextLine) lines.push(narrative.contextLine);
  lines.push(buildAnalystDecisionChangeLine(decision));
  const bestSetupLine = buildAnalystBestSetupLine(decision, intelligenceSnapshot);
  if (bestSetupLine) lines.push(bestSetupLine);
  lines.push(assistantVisibilityBoundaryLine());

  const out = lines.filter(Boolean).join('\n').trim();
  if (out) return out;
  return 'I could not load a fresh Analyst snapshot right now. Wait for sync to complete, then ask again.';
}

function isAnalystTrendRegimeReplyDecisive(reply) {
  const txt = String(reply || '').trim();
  if (!txt) return false;
  return /(?:^|\n)\s*Trend:\s+/i.test(txt) || /(?:^|\n)\s*Regime:\s+/i.test(txt);
}

async function synthesizeAnalystTrendRegimeReply(options = {}) {
  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  let cmdSnapshot = options.cmdSnapshot || null;
  if (!cmdSnapshot || !cmdSnapshot.decision) {
    cmdSnapshot = await buildTradingCommandSnapshot(strategy).catch(() => null);
  }
  const freshnessBundle = await buildAnalystIntelligenceWithFreshnessGuard({
    strategy,
    cmdSnapshot,
    preferCachedLive: true,
    forceSyncIfStale: true,
    alreadySynced: false,
  });
  const intelligenceSnapshot = options.intelligenceSnapshot || freshnessBundle?.intelligenceSnapshot || null;
  const decision = cmdSnapshot?.decision || intelligenceSnapshot?.decision || {};
  const reply = buildTrendRegimeReply({
    decision,
    pattern: intelligenceSnapshot?.market?.pattern || {},
    readiness: freshnessBundle?.readiness || {},
    lastUpdateText: freshnessBundle?.lastUpdateText || summarizeAnalystLastUpdate(intelligenceSnapshot?.marketDataFreshness || {}),
  });
  return [reply, assistantVisibilityBoundaryLine()].filter(Boolean).join('\n').trim();
}

async function buildAssistantNaturalFallbackReply(options = {}) {
  const message = String(options.message || '').trim();
  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const activeModule = normalizeDashboardModuleId(options.activeModule) || 'bridge';
  const analystNaturalMode = activeModule === 'analyst';
  if (!message) return 'I am online. Ask me your trading question in one sentence.';

  if (isAssistantGreetingOnly(message)) {
    return "I am online and ready. Ask: \"what is today's stance and why?\"";
  }

  const cmd = await buildTradingCommandSnapshot(strategy).catch(() => null);
  const decision = cmd?.decision || {};
  const hasDecision = !!(
    decision
    && (
      Array.isArray(decision.topSetups)
      || decision.signal
      || decision.signalLabel
      || decision.verdict
    )
  );
  if (hasDecision) {
    const sig = buildDecisionSignalSummary(decision);
    const narrative = buildAnalystDecisionNarrative(decision);
    const top = Array.isArray(decision.topSetups) ? decision.topSetups[0] : null;
    const blockers = Array.isArray(decision.blockers)
      ? decision.blockers.slice(0, 2).map(humanizeDecisionBlocker).filter(Boolean)
      : [];
    const lines = analystNaturalMode
      ? [narrative.stance, narrative.rangeLine, narrative.blockerLine]
      : [sig.line];
    if (analystNaturalMode && narrative.contextLine) lines.push(narrative.contextLine);
    if (top?.name) lines.push(`Best setup now: ${top.name}.`);
    if (!analystNaturalMode) {
      if (blockers.length > 0) lines.push(`Why: ${blockers.join(', ')}.`);
      else lines.push('Why: current structure is acceptable if trigger confirms.');
    }
    lines.push('Ask: "should I take this setup now?" for a direct call.');
    return lines.join('\n');
  }

  if (/\b(today|outlook|gameplan|plan|trade|setup|not trade|good day)\b/.test(normalizeAssistantText(message))) {
    return 'I need one clearer version of your question. Try: "Was not trading today the right call, and why?"';
  }

  return 'I heard you. Ask a direct trading question and I will answer with a clear stance and why.';
}

function isAssistantQueryCacheable(message) {
  const txt = normalizeAssistantText(message);
  if (!txt) return false;
  const intents = parseAssistantQuickIntents(txt);
  if (intents.wantsSync) return false;
  if (/\b(mode|halt|resume|terminal|log outcome|outcome win|outcome loss|outcome breakeven|run doctor|doctor|execute)\b/.test(txt)) {
    return false;
  }
  return true;
}

function makeAssistantQueryCacheKey(input = {}) {
  const message = normalizeAssistantText(input.message || '');
  if (!message) return null;
  const strategy = String(input.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const activeModule = normalizeDashboardModuleId(input.activeModule) || 'analyst';
  const preferCachedLive = input.preferCachedLive === true ? 'fast' : 'full';
  const voiceMode = input.voiceMode === true ? 'voice' : 'text';
  const voiceBriefMode = String(input.voiceBriefMode || '').trim().toLowerCase() || 'default';
  return crypto
    .createHash('sha1')
    .update([message, strategy, activeModule, preferCachedLive, voiceMode, voiceBriefMode].join('::'))
    .digest('hex');
}

function getCachedAssistantQuery(key) {
  const entry = assistantQueryCache.get(key);
  if (!entry) return null;
  if ((Date.now() - Number(entry.cachedAt || 0)) > ASSISTANT_QUERY_CACHE_TTL_MS) {
    assistantQueryCache.delete(key);
    return null;
  }
  entry.lastHitAt = Date.now();
  return entry.payload;
}

function setCachedAssistantQuery(key, payload) {
  if (!key || !payload || typeof payload !== 'object') return;
  assistantQueryCache.set(key, {
    cachedAt: Date.now(),
    lastHitAt: Date.now(),
    payload,
  });
  if (assistantQueryCache.size <= ASSISTANT_QUERY_CACHE_MAX_ITEMS) return;
  const rows = Array.from(assistantQueryCache.entries())
    .sort((a, b) => Number(a[1]?.lastHitAt || 0) - Number(b[1]?.lastHitAt || 0));
  while (rows.length > ASSISTANT_QUERY_CACHE_MAX_ITEMS) {
    const drop = rows.shift();
    if (drop) assistantQueryCache.delete(drop[0]);
  }
}

function normalizeAssistantSessionToken(value) {
  const txt = String(value || '').trim();
  if (!txt) return null;
  return txt.replace(/[^a-zA-Z0-9._:-]+/g, '_').slice(0, 180) || null;
}

function buildAnalystGuardrailSessionKey(req, activeModule = 'analyst') {
  const body = req && typeof req.body === 'object' ? req.body : {};
  const fromBody = normalizeAssistantSessionToken(
    body?.sessionId
    || body?.clientId
    || body?.sessionKey
  );
  if (fromBody) return `${activeModule}:${fromBody}`;
  const fromHeader = normalizeAssistantSessionToken(
    req?.get?.('x-session-id')
    || req?.get?.('x-client-id')
  );
  if (fromHeader) return `${activeModule}:${fromHeader}`;
  const fallback = `${String(req?.ip || '')}|${String(req?.get?.('user-agent') || '').slice(0, 200)}|${activeModule}`;
  const hashed = crypto.createHash('sha1').update(fallback).digest('hex').slice(0, 20);
  return `${activeModule}:fallback:${hashed}`;
}

function pruneAnalystGuardrailExplainCache() {
  const now = Date.now();
  for (const [key, entry] of analystGuardrailExplainCache.entries()) {
    if (!entry || (now - Number(entry.savedAt || 0)) > ANALYST_GUARDRAIL_EXPLAIN_TTL_MS) {
      analystGuardrailExplainCache.delete(key);
    }
  }
  if (analystGuardrailExplainCache.size <= ANALYST_GUARDRAIL_EXPLAIN_MAX_ITEMS) return;
  const rows = Array.from(analystGuardrailExplainCache.entries())
    .sort((a, b) => Number(a[1]?.savedAt || 0) - Number(b[1]?.savedAt || 0));
  while (rows.length > ANALYST_GUARDRAIL_EXPLAIN_MAX_ITEMS) {
    const drop = rows.shift();
    if (drop) analystGuardrailExplainCache.delete(drop[0]);
  }
}

function rememberAnalystGuardrailDecision(req, riskState, options = {}) {
  if (!riskState || typeof riskState !== 'object') return null;
  const key = buildAnalystGuardrailSessionKey(req, 'analyst');
  analystGuardrailExplainCache.set(key, {
    savedAt: Date.now(),
    riskState,
    meta: {
      source: String(options.source || '').trim() || null,
      message: String(options.message || '').trim() || null,
    },
  });
  pruneAnalystGuardrailExplainCache();
  return key;
}

function getRecentAnalystGuardrailDecision(req) {
  pruneAnalystGuardrailExplainCache();
  const key = buildAnalystGuardrailSessionKey(req, 'analyst');
  const entry = analystGuardrailExplainCache.get(key);
  if (!entry) return null;
  const ageMs = Date.now() - Number(entry.savedAt || 0);
  if (ageMs > ANALYST_GUARDRAIL_EXPLAIN_TTL_MS) {
    analystGuardrailExplainCache.delete(key);
    return null;
  }
  return {
    key,
    savedAt: Number(entry.savedAt || 0),
    ageMs,
    riskState: entry.riskState || null,
    meta: entry.meta || null,
  };
}

function buildJarvisSessionKey(input = {}) {
  const bodySession = normalizeAssistantSessionToken(
    input?.sessionId
    || input?.clientId
    || input?.sessionKey
  );
  if (bodySession) return `jarvis:${bodySession}`;
  const req = input?.req || null;
  if (req) {
    const fromHeader = normalizeAssistantSessionToken(
      req?.get?.('x-session-id')
      || req?.get?.('x-client-id')
    );
    if (fromHeader) return `jarvis:${fromHeader}`;
    const fallback = `${String(req?.ip || '')}|${String(req?.get?.('user-agent') || '').slice(0, 200)}|jarvis`;
    const hashed = crypto.createHash('sha1').update(fallback).digest('hex').slice(0, 20);
    return `jarvis:fallback:${hashed}`;
  }
  return 'jarvis:default';
}

function buildJarvisPhoneLink(req, sessionId, clientId) {
  const sid = normalizeAssistantSessionToken(sessionId || clientId);
  if (!sid) return null;
  const cid = normalizeAssistantSessionToken(clientId || sessionId || sid) || sid;
  const explicitBase = String(JARVIS_PHONE_LINK_BASE_URL || '').trim().replace(/\/+$/, '');
  if (explicitBase) {
    const query = `sessionId=${encodeURIComponent(sid)}&clientId=${encodeURIComponent(cid)}`;
    return `${explicitBase}/jarvis/link?${query}`;
  }
  const forwardedProto = String(req?.get?.('x-forwarded-proto') || '').split(',')[0].trim();
  const protocol = (forwardedProto || String(req?.protocol || 'http')).toLowerCase();
  const forwardedHost = String(req?.get?.('x-forwarded-host') || '').split(',')[0].trim();
  const rawHost = forwardedHost || String(req?.get?.('host') || '').trim() || `${config.host}:${config.port}`;
  const localAddress = normalizeIp(req?.socket?.localAddress || '');
  const splitHost = (() => {
    const host = String(rawHost || '').trim();
    if (!host) return { hostname: '', port: '' };
    if (host.startsWith('[')) {
      const end = host.indexOf(']');
      if (end > 1) {
        const hostname = host.slice(1, end);
        const rest = host.slice(end + 1);
        const port = rest.startsWith(':') ? rest.slice(1) : '';
        return { hostname, port };
      }
    }
    const idx = host.lastIndexOf(':');
    if (idx > 0 && host.indexOf(':') === idx) {
      return {
        hostname: host.slice(0, idx),
        port: host.slice(idx + 1),
      };
    }
    return { hostname: host, port: '' };
  })();
  let hostname = String(splitHost.hostname || '').trim();
  let port = String(splitHost.port || '').trim();
  const normalizedHostIp = normalizeIp(hostname);
  const hostLooksLoopback = (
    !hostname
    || hostname.toLowerCase() === 'localhost'
    || normalizedHostIp === '127.0.0.1'
    || normalizedHostIp === '::1'
    || normalizedHostIp === '0.0.0.0'
    || normalizedHostIp === '::'
  );
  const localAddressIsLan = localAddress && !isLoopbackIp(localAddress) && isPrivateIpv4(localAddress);
  if (hostLooksLoopback) {
    hostname = PRIMARY_LAN_IPV4 || (localAddressIsLan ? localAddress : hostname);
  }
  if (!hostname) hostname = String(config.host || 'localhost');
  const configPort = String(config.port || 3131);
  if (!port || port === '3130') {
    port = configPort;
  } else if (hostLooksLoopback) {
    port = configPort;
  }
  const host = hostname.includes(':') ? `[${hostname}]` : hostname;
  const query = `sessionId=${encodeURIComponent(sid)}&clientId=${encodeURIComponent(cid)}`;
  return `${protocol}://${host}${port ? `:${port}` : ''}/jarvis/link?${query}`;
}

function pruneJarvisGuardrailExplainCache() {
  if (jarvisDurableStateStore && typeof jarvisDurableStateStore.removeExpired === 'function') {
    jarvisDurableStateStore.removeExpired(JARVIS_GUARDRAIL_STATE_TYPE);
  }
  const now = Date.now();
  for (const [key, entry] of jarvisGuardrailExplainCache.entries()) {
    if (!entry || (now - Number(entry.savedAt || 0)) > JARVIS_GUARDRAIL_EXPLAIN_TTL_MS) {
      jarvisGuardrailExplainCache.delete(key);
    }
  }
  if (jarvisGuardrailExplainCache.size <= JARVIS_GUARDRAIL_EXPLAIN_MAX_ITEMS) return;
  const rows = Array.from(jarvisGuardrailExplainCache.entries())
    .sort((a, b) => Number(a[1]?.savedAt || 0) - Number(b[1]?.savedAt || 0));
  while (rows.length > JARVIS_GUARDRAIL_EXPLAIN_MAX_ITEMS) {
    const drop = rows.shift();
    if (drop) jarvisGuardrailExplainCache.delete(drop[0]);
  }
}

function rememberJarvisGuardrailDecision(sessionKey, riskState, options = {}) {
  if (!riskState || typeof riskState !== 'object') return null;
  const key = String(sessionKey || '').trim() || 'jarvis:default';
  const savedAt = Date.now();
  const payload = {
    savedAt,
    riskState,
    meta: {
      source: String(options.source || '').trim() || null,
      message: String(options.message || '').trim() || null,
      precedenceMode: String(options.precedenceMode || '').trim() || null,
    },
  };
  jarvisGuardrailExplainCache.set(key, {
    savedAt,
    riskState: payload.riskState,
    meta: payload.meta,
  });
  if (jarvisDurableStateStore && typeof jarvisDurableStateStore.put === 'function') {
    jarvisDurableStateStore.put({
      stateType: JARVIS_GUARDRAIL_STATE_TYPE,
      stateKey: key,
      sessionKey: key,
      sessionId: String(key || '').replace(/^jarvis:/, ''),
      ttlMs: JARVIS_GUARDRAIL_EXPLAIN_TTL_MS,
      payload,
    });
  }
  pruneJarvisGuardrailExplainCache();
  return key;
}

function getRecentJarvisGuardrailDecision(sessionKey) {
  pruneJarvisGuardrailExplainCache();
  const key = String(sessionKey || '').trim() || 'jarvis:default';
  if (jarvisDurableStateStore && typeof jarvisDurableStateStore.get === 'function') {
    const row = jarvisDurableStateStore.get({
      stateType: JARVIS_GUARDRAIL_STATE_TYPE,
      stateKey: key,
    });
    if (row && row.payload && typeof row.payload === 'object') {
      const payload = row.payload;
      const savedAt = Number(payload.savedAt || row.updatedAtMs || 0) || 0;
      return {
        key,
        savedAt,
        ageMs: Date.now() - savedAt,
        riskState: payload.riskState || null,
        meta: payload.meta || null,
      };
    }
  }
  const entry = jarvisGuardrailExplainCache.get(key);
  if (!entry) return null;
  const ageMs = Date.now() - Number(entry.savedAt || 0);
  if (ageMs > JARVIS_GUARDRAIL_EXPLAIN_TTL_MS) {
    jarvisGuardrailExplainCache.delete(key);
    return null;
  }
  return {
    key,
    savedAt: Number(entry.savedAt || 0),
    ageMs,
    riskState: entry.riskState || null,
    meta: entry.meta || null,
  };
}

function recordAssistantQueryRuntime(event = {}) {
  const latency = Number(event.latencyMs);
  assistantQueryRuntime.total += 1;
  if (event.cached) assistantQueryRuntime.cacheHits += 1;
  if (event.inFlightJoin) assistantQueryRuntime.inFlightJoined += 1;
  if (String(event.mode || '').toLowerCase() === 'quick') assistantQueryRuntime.quickHandled += 1;
  if (String(event.mode || '').toLowerCase() === 'orchestrator') assistantQueryRuntime.orchestratorHandled += 1;
  if (event.timeoutFallback) assistantQueryRuntime.timeoutFallbacks += 1;
  if (event.timedOut) assistantQueryRuntime.timeouts += 1;
  if (event.failed) assistantQueryRuntime.failures += 1;
  if (Number.isFinite(latency) && latency >= 0) {
    assistantQueryRuntime.recentLatenciesMs.push(Math.round(latency));
    while (assistantQueryRuntime.recentLatenciesMs.length > ASSISTANT_QUERY_RUNTIME_MAX_SAMPLES) {
      assistantQueryRuntime.recentLatenciesMs.shift();
    }
  }
  if (event.error) {
    assistantQueryRuntime.lastError = truncateAgentText(String(event.error), 220);
    assistantQueryRuntime.lastErrorAt = new Date().toISOString();
  }
}

function getAssistantQueryRuntimeSnapshot() {
  const latencies = Array.isArray(assistantQueryRuntime.recentLatenciesMs)
    ? assistantQueryRuntime.recentLatenciesMs.slice()
    : [];
  const count = latencies.length;
  let avgLatencyMs = null;
  let p95LatencyMs = null;
  if (count > 0) {
    const sum = latencies.reduce((acc, v) => acc + Number(v || 0), 0);
    avgLatencyMs = Math.round(sum / count);
    const sorted = latencies.slice().sort((a, b) => a - b);
    const idx = Math.max(0, Math.min(sorted.length - 1, Math.floor(sorted.length * 0.95) - 1));
    p95LatencyMs = Number(sorted[idx] || sorted[sorted.length - 1] || 0);
  }
  const cacheHitRatePct = assistantQueryRuntime.total > 0
    ? round2((assistantQueryRuntime.cacheHits / Math.max(1, assistantQueryRuntime.total)) * 100)
    : 0;
  return {
    total: assistantQueryRuntime.total,
    cacheHits: assistantQueryRuntime.cacheHits,
    cacheHitRatePct,
    inFlightJoined: assistantQueryRuntime.inFlightJoined,
    quickHandled: assistantQueryRuntime.quickHandled,
    orchestratorHandled: assistantQueryRuntime.orchestratorHandled,
    timeoutFallbacks: assistantQueryRuntime.timeoutFallbacks,
    timeouts: assistantQueryRuntime.timeouts,
    failures: assistantQueryRuntime.failures,
    avgLatencyMs,
    p95LatencyMs,
    sampleCount: count,
    lastError: assistantQueryRuntime.lastError || null,
    lastErrorAt: assistantQueryRuntime.lastErrorAt || null,
  };
}

function isAnalystFastPathIntent(intents = {}) {
  if (!intents || typeof intents !== 'object') return false;
  return !!(
    intents.wantsExplain
    || intents.wantsNextStep
    || intents.wantsCapabilityAudit
    || intents.wantsOutlook
    || intents.wantsTrendRegime
    || intents.wantsSetupScan
    || intents.wantsTradeDecision
    || intents.wantsTradeState
    || intents.wantsMarketState
    || intents.wantsLiveIntel
    || intents.wantsConnectivityCheck
    || intents.wantsSync
  );
}

function isAnalystDecisionQuestionIntent(intents = {}) {
  if (!intents || typeof intents !== 'object') return false;
  return !!(
    intents.wantsOutlook
    || intents.wantsTrendRegime
    || intents.wantsSetupScan
    || intents.wantsTradeDecision
    || intents.wantsTradeState
    || intents.wantsMarketState
    || intents.wantsLiveIntel
    || intents.wantsConnectivityCheck
    || intents.wantsSync
    || intents.wantsLiveNow
  );
}

function buildVoiceHealthBlockedReply(snapshot = {}) {
  const reasonRaw = String(snapshot?.reason || '').trim() || 'Topstep bars are stale or unavailable.';
  const reason = reasonRaw.endsWith('.') ? reasonRaw : `${reasonRaw}.`;
  return [
    "I'd sit out for now - my live market data isn't healthy.",
    reason,
    "I'll re-check automatically; ask again once health is OK.",
  ].join(' ');
}

async function getAnalystVoiceHealthPreflightBlock(input = {}) {
  const activeModule = normalizeDashboardModuleId(input.activeModule) || 'bridge';
  if (activeModule !== 'analyst') return null;
  const preferCachedLive = input.preferCachedLive === true;
  const intents = input.intents && typeof input.intents === 'object'
    ? input.intents
    : parseAssistantQuickIntents(input.message || '');
  if (!isAnalystDecisionQuestionIntent(intents)) {
    return {
      checked: false,
      intents,
      health: null,
      status: null,
      blocked: false,
      reply: null,
    };
  }
  const symbol = String(input.symbol || config.topstep?.autonomy?.defaultSymbol || 'MNQ').trim().toUpperCase();
  const healthRequest = {
    symbol,
    live: false,
    compareLiveModes: true,
    lookbackMinutes: 120,
    forceFresh: false,
    triggerSource: 'assistant_voice_preflight',
  };
  const preflightTimeoutMs = preferCachedLive
    ? ANALYST_HEALTH_PREFLIGHT_TIMEOUT_FAST_MS
    : ANALYST_HEALTH_PREFLIGHT_TIMEOUT_MS;
  const health = await Promise.race([
    getMarketHealthSnapshotCached(healthRequest),
    new Promise((_, reject) => {
      const timer = setTimeout(() => reject(new Error(`market_health_preflight_timeout_${preflightTimeoutMs}ms`)), preflightTimeoutMs);
      if (typeof timer.unref === 'function') timer.unref();
    }),
  ]).catch((err) => {
    const cacheKey = makeMarketHealthEndpointCacheKey(healthRequest);
    const cached = marketHealthEndpointCache.get(cacheKey);
    const cachedSnapshot = cached && cached.snapshot && typeof cached.snapshot === 'object'
      ? cached.snapshot
      : null;
    if (cachedSnapshot) {
      return {
        ...cachedSnapshot,
        cacheHit: true,
        preflightTimeoutFallback: true,
      };
    }
    return {
      status: 'STALE',
      reason: String(err?.message || 'market_health_preflight_failed'),
      preflightTimeoutFallback: true,
    };
  });
  const status = String(health?.status || '').trim().toUpperCase() || 'STALE';
  const blocked = status === 'DEGRADED' || status === 'STALE';
  return {
    checked: true,
    blocked,
    status,
    health,
    reply: blocked ? buildVoiceHealthBlockedReply(health) : null,
    intents,
  };
}

function formatQuickTopSetupLine(setup, idx = 0) {
  if (!setup) return null;
  const prob = Number.isFinite(Number(setup.probability)) ? `${Number(setup.probability).toFixed(1)}%` : 'n/a';
  const grade = String(setup.grade || '').trim();
  const trades = Number.isFinite(Number(setup.annualizedTrades)) ? `~${Math.round(Number(setup.annualizedTrades))}/yr` : null;
  const bits = [
    `${idx + 1}) ${setup.name || setup.setupId || 'Unnamed setup'}`,
    `WR ${prob}`,
    grade ? `grade ${grade}` : null,
    trades,
  ].filter(Boolean);
  return bits.join(' | ');
}

async function runAssistantQuickIntent(input = {}) {
  const message = String(input.message || '').trim();
  if (!message) throw new Error('No message provided.');
  if (isAssistantGreetingOnly(message)) {
    return {
      source: 'assistant_quick',
      handled: true,
      reply: 'Doing well and fully online. If you want market guidance, ask: "what is today\'s stance?"',
      commandsExecuted: [],
      clientActions: [],
    };
  }
  const strategy = String(input.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const preferCachedLive = input.preferCachedLive === true;
  const activeModule = normalizeDashboardModuleId(input.activeModule) || 'bridge';
  const intents = parseAssistantQuickIntents(message);
  logAnalystDebug('assistant.quick.intents', {
    activeModule,
    strategy,
    preferCachedLive,
    message: debugTextPreview(message, 220),
    intents: {
      wantsExplain: intents.wantsExplain,
      wantsSync: intents.wantsSync,
      wantsOutlook: intents.wantsOutlook,
      wantsTrendRegime: intents.wantsTrendRegime,
      wantsSetupScan: intents.wantsSetupScan,
      wantsTradeDecision: intents.wantsTradeDecision,
      wantsTradeState: intents.wantsTradeState,
      wantsMarketState: intents.wantsMarketState,
      wantsLiveIntel: intents.wantsLiveIntel,
      wantsCapabilityAudit: intents.wantsCapabilityAudit,
      wantsNextStep: intents.wantsNextStep,
      wantsConnectivityCheck: intents.wantsConnectivityCheck,
      wantsLiveNow: intents.wantsLiveNow,
    },
  });
  const siteMap = buildDashboardSiteMap();
  const appAllow = new Set((config.discord?.allowedApps || []).map((s) => String(s || '').trim().toLowerCase()).filter(Boolean));
  const parserCtx = { siteMap, appAllow };
  const inferred = discordInterpreterTestTools?.inferPlainEnglishCommand
    ? discordInterpreterTestTools.inferPlainEnglishCommand(message, parserCtx)
    : null;
  const validatedInferred = inferred && discordInterpreterTestTools?.validateInterpretedCommand
    ? discordInterpreterTestTools.validateInterpretedCommand(inferred, parserCtx)
    : null;
  const clientActions = [];
  const inferredModule = inferDashboardModuleFromText(message);
  if (inferredModule && /\b(open|show|go to|switch)\b/i.test(intents.text)) {
    clientActions.push({ type: 'open_module', module: inferredModule });
  }

  if (intents.wantsNextStep) {
    const cmd = await buildTradingCommandSnapshot(strategy).catch(() => null);
    const intelligence = await buildAssistantIntelligenceSnapshot({
      strategy,
      cmdSnapshot: cmd,
      preferCachedLive,
    }).catch(() => null);
    const decision = cmd?.decision || {};
    const narrative = buildAnalystDecisionNarrative(decision);
    const analystNaturalMode = activeModule === 'analyst';
    const sig = buildDecisionSignalSummary(decision);
    const topSetup = decision?.topSetups?.[0]?.name || null;
    const blockers = (decision.blockers || []).slice(0, 2).map(humanizeDecisionBlocker);
    const action = String(intelligence?.execution?.action || '').toUpperCase();
    let nextLine = 'Next step: run a quick sync, then reassess the live setup quality.';
    if (action === 'TRADE') {
      nextLine = `Next step: prepare ${topSetup || 'your top setup'} and execute only on clean trigger confirmation.`;
    } else if (action === 'WAIT') {
      nextLine = 'Next step: wait for cleaner structure and keep risk minimized until confirmation improves.';
    } else if (action === "DON'T TRADE") {
      nextLine = 'Next step: stand down for now and preserve capital until blockers clear.';
    }
    const lines = analystNaturalMode ? [narrative.stance, narrative.rangeLine, narrative.blockerLine] : [sig.line];
    if (analystNaturalMode && narrative.contextLine) lines.push(narrative.contextLine);
    if (topSetup) lines.push(`Top setup: ${topSetup}.`);
    if (blockers.length > 0) lines.push(`Current blockers: ${blockers.join(', ')}.`);
    if (intelligence?.market?.pattern?.guidance) lines.push(`Pattern read: ${intelligence.market.pattern.guidance}`);
    lines.push(nextLine);
    return {
      source: 'assistant_quick',
      handled: true,
      reply: lines.join('\n'),
      commandsExecuted: [],
      clientActions,
    };
  }

  if (intents.wantsCapabilityAudit) {
    let liveSync = null;
    try {
      liveSync = await runTopstepReadOnlySync({ force: true, triggerSource: 'assistant_capability_audit' });
    } catch {}
    let contextRefreshed = false;
    try {
      await ensureAnalystContext({ reason: 'assistant_capability_audit', force: true });
      contextRefreshed = true;
    } catch {}

    const openaiConfigured = !!String(process.env.OPENAI_API_KEY || '').trim();
    const anthropicConfigured = !!String(process.env.ANTHROPIC_API_KEY || config.anthropicKey || '').trim();
    const providerOrder = getAnalystProviderOrder({ openaiConfigured, anthropicConfigured });
    const providerHealth = providerOrder.map((provider) => {
      const cooldownUntil = getAnalystProviderCooldownUntil(provider);
      const cooling = cooldownUntil > Date.now();
      if (!cooling) return `${provider}:ready`;
      const eta = Math.max(0, Math.ceil((cooldownUntil - Date.now()) / 1000));
      return `${provider}:cooldown_${eta}s`;
    });
    const topstepCfg = config.topstep?.api || {};
    const topstepLive = getTopstepLiveSnapshot({ fillLimit: 20 });
    const liveStatus = String(liveSync?.status || topstepLive?.sync?.status || 'unknown').toLowerCase();
    let dataSync = null;
    let freshness = getSessionFreshnessSummary('America/New_York') || {};
    if (freshness?.isStale === true) {
      try {
        dataSync = runAutomatedDataSync({ triggerSource: 'assistant_capability_audit', maxFiles: 8 });
        if (dataSync?.freshnessAfter) freshness = dataSync.freshnessAfter;
      } catch {}
    }
    const cmd = await buildTradingCommandSnapshot(strategy, { forceFresh: !!liveSync }).catch(() => null);
    const feedbackSamples = Number(cmd?.feedback?.totalSamples || 0);
    const chartVisionEnabled = openaiConfigured || anthropicConfigured;
    const chartContext = getAnalystChartContextState();

    const needs = [];
    if (!openaiConfigured && !anthropicConfigured) {
      needs.push('Add at least one working analyst model key so deep reasoning is available.');
    } else if (providerOrder.length > 0 && providerOrder.every((provider) => isAnalystProviderOnCooldown(provider))) {
      needs.push('Resolve model-provider cooldown/errors so planner replies stop falling back.');
    }
    if (!topstepCfg.enabled || !topstepCfg.key) {
      needs.push('Enable Topstep API with a valid key for stable live market/account context.');
    } else if (!['ok', 'noop', 'partial'].includes(liveStatus)) {
      needs.push('Stabilize live sync health so trade guidance is based on fresh state.');
    }
    if (freshness?.isStale === true) {
      needs.push(`Ingest newer session data (currently ${Number(freshness.staleDays || 0)} day(s) stale).`);
    }
    if (!chartVisionEnabled) {
      needs.push('Enable chart-image vision input for candle-by-candle guidance on your exact screen.');
    }
    if (!Number.isFinite(feedbackSamples) || feedbackSamples < 30) {
      needs.push('Log more live outcomes to strengthen personalization and confidence calibration.');
    }

    const lines = [
      'Capability audit complete.',
      `Live feed health: ${String(liveStatus || 'unknown').toUpperCase()}.`,
      `Provider routing: ${providerHealth.length ? providerHealth.join(', ') : 'no_provider_configured'}.`,
      `Data freshness: last session ${freshness?.lastSessionDate || 'unknown'} (${Number(freshness?.staleDays ?? -1) >= 0 ? `${freshness.staleDays} day(s) stale` : 'staleness unknown'}).`,
      `Learning memory: ${feedbackSamples} logged outcome samples.`,
      chartContext
        ? `Latest chart context is active (${Math.max(0, Number(chartContext.ageSeconds || 0))}s old${chartContext.signal ? `, signal ${chartContext.signal}` : ''}).`
        : 'Latest chart context: none loaded yet.',
      needs.length > 0
        ? `Top needs: ${needs.map((n, i) => `${i + 1}) ${n}`).join(' ')}`
        : 'Top needs: none critical; current stack is operational.',
      `Auto-applied now: forced live sync ${liveSync?.status ? `(${String(liveSync.status).toUpperCase()})` : '(unavailable)'}, analyst context refresh ${contextRefreshed ? 'done' : 'skipped'}${dataSync ? `, data sync ${String(dataSync.status || 'noop').toUpperCase()} (${Number(dataSync.sessionsAdded || 0)} sessions)` : ''}.`,
      'I guide from live feed and account state; I do not see your exact chart unless you share it.',
    ];
    return {
      source: 'assistant_quick',
      handled: true,
      reply: lines.join('\n'),
      commandsExecuted: liveSync
        ? [{ command: 'sync', ok: liveSync.status !== 'error', output: liveSync.status || 'ok', error: liveSync.error || null }]
        : [],
      clientActions,
    };
  }

  let liveSync = null;
  if (intents.wantsSync) {
    try {
      liveSync = await runTopstepReadOnlySync({ force: true, triggerSource: 'assistant_quick_sync' });
    } catch (err) {
      liveSync = { status: 'error', error: String(err?.message || 'topstep_sync_failed') };
    }
  } else if (
    !preferCachedLive
    && (
      intents.wantsOutlook
      || intents.wantsTrendRegime
      || intents.wantsSetupScan
      || intents.wantsTradeDecision
      || intents.wantsTradeState
      || intents.wantsMarketState
      || intents.wantsLiveIntel
      || intents.wantsConnectivityCheck
    )
  ) {
    try {
      liveSync = await runTopstepReadOnlySync({ force: false, triggerSource: 'assistant_quick_live_refresh' });
    } catch {}
  }

  if (
    intents.wantsSync
    && !intents.wantsOutlook
    && !intents.wantsTrendRegime
    && !intents.wantsSetupScan
    && !intents.wantsTradeDecision
    && !intents.wantsTradeState
    && !intents.wantsMarketState
    && !intents.wantsConnectivityCheck
  ) {
    const ok = liveSync && liveSync.status !== 'error';
    return {
      source: 'assistant_quick',
      handled: true,
      reply: ok
        ? `Topstep live data sync is ${String(liveSync.status || 'ok').toUpperCase()}.`
        : `Topstep sync failed: ${liveSync?.error || 'unknown error'}.`,
      commandsExecuted: [{
        command: 'sync',
        ok: !!ok,
        output: liveSync?.status || null,
        error: liveSync?.error || null,
      }],
      clientActions,
    };
  }

  if (intents.wantsLiveIntel) {
    if (!liveSync && !preferCachedLive) {
      try {
        liveSync = await runTopstepReadOnlySync({ force: false, triggerSource: 'assistant_quick_liveintel_refresh' });
      } catch {}
    }
    const intelligence = await buildAssistantIntelligenceSnapshot({
      strategy,
      liveSync,
      preferCachedLive,
      forceFresh: !!liveSync,
    });
    const lines = buildAssistantIntelligenceLines(intelligence);
    if (Array.isArray(intelligence?.errors) && intelligence.errors.length > 0) {
      lines.push('Some live components are degraded, so this uses the best available feed.');
    }
    if (liveSync?.status) {
      lines.push(`Live sync: ${String(liveSync.status).toUpperCase()}.`);
    }
    return {
      source: 'assistant_quick',
      handled: true,
      reply: lines.join('\n'),
      commandsExecuted: liveSync ? [{ command: 'sync', ok: liveSync.status !== 'error', output: liveSync.status || 'ok', error: liveSync.error || null }] : [],
      clientActions,
    };
  }

  if (intents.wantsMarketState) {
    const topstepLive = getTopstepLiveSnapshot({ fillLimit: 20 });
    const fastState = getLiveTradeState();
    const account = topstepLive?.account || {};
    const positions = Array.isArray(topstepLive?.positions) ? topstepLive.positions : [];
    const fills = Array.isArray(topstepLive?.fills) ? topstepLive.fills : [];
    const symbol = String(config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase();
    const cachedQuote = getCachedMarketQuote(symbol);
    const liveFlag = inferTopstepLiveFlag(account);
    const topstepCfg = config.topstep?.api || {};
    const timeoutMs = Math.max(2000, Number(topstepCfg.timeoutMs || 10_000));
    const marketQuoteTimeoutMs = preferCachedLive ? Math.min(timeoutMs, 1800) : timeoutMs;
    const baseUrls = [topstepCfg.baseUrl, ...(Array.isArray(topstepCfg.altBaseUrls) ? topstepCfg.altBaseUrls : [])].filter(Boolean);
    let priceLine = `${symbol} live price is unavailable right now.`;
    let barTime = null;
    let priceOk = Number.isFinite(Number(fastState?.lastPrice)) && Number(fastState.lastPrice) > 0;
    if (priceOk) {
      setCachedMarketQuote(symbol, Number(fastState.lastPrice), topstepLive?.sync?.createdAt || null);
      priceLine = `${symbol} is around ${Number(fastState.lastPrice).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} based on the latest trade snapshot.`;
    } else if (cachedQuote && Number.isFinite(Number(cachedQuote.price)) && Number(cachedQuote.price) > 0) {
      priceOk = true;
      barTime = cachedQuote.asOf || null;
      priceLine = `${symbol} is trading around ${Number(cachedQuote.price).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}.`;
    } else {
      const positionMark = positions.find((p) => (
        String(p?.symbol || '').toUpperCase() === symbol
        && Number.isFinite(Number(p?.markPrice))
        && Number(p.markPrice) > 0
      ));
      if (positionMark) {
        priceOk = true;
        barTime = topstepLive?.sync?.createdAt || null;
        setCachedMarketQuote(symbol, Number(positionMark.markPrice), barTime);
        priceLine = `${symbol} is around ${Number(positionMark.markPrice).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} from your live position mark.`;
      }
    }
    if (!priceOk) {
      const fillQuote = fills.find((f) => (
        String(f?.symbol || '').toUpperCase() === symbol
        && Number.isFinite(Number(f?.price))
        && Number(f.price) > 0
      ));
      if (fillQuote) {
        priceOk = true;
        barTime = fillQuote.fillTime || fillQuote.timestamp || topstepLive?.sync?.createdAt || null;
        setCachedMarketQuote(symbol, Number(fillQuote.price), barTime);
        priceLine = `${symbol} is around ${Number(fillQuote.price).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} from the latest fill snapshot.`;
      }
    }
    try {
      if (!preferCachedLive && !priceOk && topstepCfg.enabled && topstepCfg.key) {
        const contract = await topstepResolveContractForSymbol({
          symbol,
          live: liveFlag,
          topstepCfg,
          baseUrls,
          timeoutMs: marketQuoteTimeoutMs,
        });
        if (contract?.ok) {
          const cid = contract.contract?.contractId || contract.contract?.id || contract.contract?.instrumentId || null;
          if (cid) {
            const barsOut = await topstepRetrieveBars({
              contractId: cid,
              live: liveFlag,
              lookbackDays: 1,
              unitNumber: 1,
              includePartialBar: true,
              topstepCfg,
              baseUrls,
              timeoutMs: marketQuoteTimeoutMs,
            });
            if (barsOut?.ok && Array.isArray(barsOut.bars) && barsOut.bars.length > 0) {
              const last = barsOut.bars[barsOut.bars.length - 1];
              const px = Number(last?.c);
              if (Number.isFinite(px)) {
                priceOk = true;
                barTime = String(last?.t || '').trim() || null;
                setCachedMarketQuote(symbol, px, barTime);
                priceLine = `${symbol} is trading around ${px.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}.`;
              }
            }
          }
        }
      }
    } catch {}

    if (!priceOk) {
      if (Number.isFinite(Number(fastState?.lastPrice)) && Number(fastState.lastPrice) > 0) {
        setCachedMarketQuote(symbol, Number(fastState.lastPrice), topstepLive?.sync?.createdAt || null);
        priceLine = `${symbol} is around ${Number(fastState.lastPrice).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} based on the latest trade snapshot.`;
      }
    }
    if (!priceOk) {
      try {
        const lastBar = getDB().prepare(`
          SELECT c.close, c.timestamp
          FROM candles c
          JOIN sessions s ON s.id = c.session_id
          WHERE c.timeframe = '5m'
          ORDER BY s.date DESC, c.timestamp DESC
          LIMIT 1
        `).get();
        const px = Number(lastBar?.close);
        if (Number.isFinite(px) && px > 0) {
          priceOk = true;
          barTime = String(lastBar?.timestamp || '').trim() || null;
          priceLine = `${symbol} last recorded session price was around ${px.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}.`;
        }
      } catch {}
    }

    const accountSubject = assistantAccountSubject(account?.accountName || account?.accountId || '');
    const positionLine = positions.length > 0
      ? `You currently have ${positions.length} open position${positions.length === 1 ? '' : 's'}.`
      : 'You are currently flat with no open positions.';
    const syncStatus = String(liveSync?.status || topstepLive?.sync?.status || '').toLowerCase();
    const feedLine = humanizeAssistantSyncStatus(syncStatus);
    const pnlLine = Number.isFinite(Number(account?.dailyPnl))
      ? `Your daily PnL is ${Number(account.dailyPnl) >= 0 ? 'up' : 'down'} $${Math.abs(Number(account.dailyPnl)).toFixed(2)}.`
      : null;
    const timeLine = barTime ? (() => {
      const t = formatAssistantClockTime(barTime);
      return t ? `Last price update was ${t}.` : null;
    })() : null;
    const accountLine = `${accountSubject} is connected.`;
    const lines = [
      priceLine,
      accountLine,
      positionLine,
      feedLine,
      pnlLine,
      timeLine,
      assistantVisibilityBoundaryLine(),
    ].filter(Boolean);
    return {
      source: 'assistant_quick',
      handled: true,
      reply: lines.join('\n'),
      commandsExecuted: liveSync ? [{ command: 'sync', ok: liveSync.status !== 'error', output: liveSync.status || 'ok', error: liveSync.error || null }] : [],
      clientActions,
    };
  }

  if (intents.wantsConnectivityCheck) {
    const topstepLive = getTopstepLiveSnapshot({ fillLimit: 20 });
    const compliance = buildTopstepComplianceSnapshot();
    const dataFreshness = getSessionFreshnessSummary('America/New_York');
    const sync = topstepLive?.sync || {};
    const account = topstepLive?.account || {};
    const positions = Array.isArray(topstepLive?.positions) ? topstepLive.positions : [];
    const fills = Array.isArray(topstepLive?.fills) ? topstepLive.fills : [];
    const syncStatus = String(liveSync?.status || sync.status || 'unknown').toUpperCase();
    const syncOk = syncStatus === 'OK' || syncStatus === 'NOOP';
    const accountSubject = assistantAccountSubject(account?.accountName || account?.accountId || '');
    const modeRaw = String(compliance?.apiMode || 'unknown').toLowerCase();
    const modeLine = modeRaw === 'execution_assist'
      ? 'Connection mode is execution assist (manual oversight with live sync).'
      : modeRaw === 'read_only'
        ? 'Connection mode is read only (analysis only, no execution).'
        : `Connection mode is ${modeRaw.replace(/_/g, ' ')}.`;
    const lines = [
      syncOk
        ? 'Connection check passed. Live data link is healthy.'
        : 'Connection check found an issue in the live data link.',
      `Sync status is ${syncStatus}.`,
      modeLine,
      `${accountSubject} has ${positions.length} open position${positions.length === 1 ? '' : 's'}.`,
      `Recent fills loaded: ${fills.length}.`,
    ];
    if (sync?.createdAt) {
      const t = formatAssistantClockTime(sync.createdAt);
      if (t) lines.push(`Last sync update was ${t}.`);
    }
    if (Number.isFinite(Number(dataFreshness?.staleDays))) {
      lines.push(`Historical session data is ${dataFreshness.staleDays} day(s) behind.`);
    }
    if (!syncOk) {
      lines.push('Run "sync topstep live data now" and then "show status".');
    }
    return {
      source: 'assistant_quick',
      handled: true,
      reply: lines.join('\n'),
      commandsExecuted: liveSync ? [{ command: 'sync', ok: liveSync.status !== 'error', output: liveSync.status || 'ok', error: liveSync.error || null }] : [],
      clientActions,
    };
  }

  if (intents.wantsTradeState) {
    const liveState = getLiveTradeState();
    const topstepLive = getTopstepLiveSnapshot({ fillLimit: 20 });
    const account = topstepLive?.account || {};
    const openLine = liveState?.inPosition
      ? `Open trade: ${String(liveState.side || '').toUpperCase()} ${liveState.qty || 0} ${liveState.symbol || 'MNQ'} at ${liveState.entryPrice ?? 'n/a'}.`
      : 'No open trade right now.';
    const pnlParts = [];
    if (Number.isFinite(Number(liveState?.pnlDollars))) pnlParts.push(`Current open PnL: $${Number(liveState.pnlDollars).toFixed(2)}.`);
    if (Number.isFinite(Number(liveState?.pnlTicks))) pnlParts.push(`Open PnL ticks: ${Number(liveState.pnlTicks).toFixed(1)}.`);
    if (Number.isFinite(Number(account?.dailyPnl))) pnlParts.push(`Topstep daily PnL: $${Number(account.dailyPnl).toFixed(2)}.`);
    const syncLine = liveSync?.status ? `Live sync: ${String(liveSync.status).toUpperCase()}.` : '';
    const boundaryLine = assistantVisibilityBoundaryLine();
    return {
      source: 'assistant_quick',
      handled: true,
      reply: [openLine, ...pnlParts, syncLine, boundaryLine].filter(Boolean).join(' '),
      commandsExecuted: liveSync ? [{ command: 'sync', ok: liveSync.status !== 'error', output: liveSync.status || 'ok', error: liveSync.error || null }] : [],
      clientActions,
    };
  }

  if (intents.wantsTrendRegime) {
    logAnalystDebug('assistant.quick.branch', {
      branch: 'quick_trend_regime',
      activeModule,
    });
    const cmd = await buildTradingCommandSnapshot(strategy).catch(() => null);
    const freshnessBundle = await buildAnalystIntelligenceWithFreshnessGuard({
      strategy,
      cmdSnapshot: cmd,
      liveSync,
      preferCachedLive,
      forceFresh: !!liveSync,
      forceSyncIfStale: activeModule === 'analyst',
      alreadySynced: !!liveSync,
    });
    const intelligence = freshnessBundle?.intelligenceSnapshot || null;
    const decision = cmd?.decision || intelligence?.decision || {};
    const readiness = freshnessBundle?.readiness || {};
    const trendReply = buildTrendRegimeReply({
      decision,
      pattern: intelligence?.market?.pattern || {},
      readiness,
      lastUpdateText: freshnessBundle?.lastUpdateText || 'not available',
    });
    const lines = [trendReply];
    lines.push(assistantVisibilityBoundaryLine());
    if (freshnessBundle?.liveSync?.status) {
      lines.push(`Live sync: ${String(freshnessBundle.liveSync.status).toUpperCase()}.`);
    }
    return {
      source: 'assistant_quick',
      handled: true,
      reply: lines.filter(Boolean).join('\n'),
      commandsExecuted: (freshnessBundle?.commandsExecuted || []).length > 0
        ? freshnessBundle.commandsExecuted
        : (liveSync ? [{ command: 'sync', ok: liveSync.status !== 'error', output: liveSync.status || 'ok', error: liveSync.error || null }] : []),
      clientActions,
    };
  }

  if (intents.wantsOutlook || intents.wantsSetupScan || intents.wantsTradeDecision) {
    const cmd = await buildTradingCommandSnapshot(strategy);
    if (!cmd) {
      return {
        source: 'assistant_quick',
        handled: true,
        reply: 'No strategy data is loaded yet. Import data first, then ask again.',
        commandsExecuted: [],
        clientActions,
      };
    }
    const plan = cmd.plan || {};
    const decision = cmd.decision || {};
    const analystNaturalMode = activeModule === 'analyst';
    const freshnessBundle = analystNaturalMode
      ? await buildAnalystIntelligenceWithFreshnessGuard({
        strategy,
        cmdSnapshot: cmd,
        liveSync,
        preferCachedLive,
        forceFresh: !!liveSync,
        forceSyncIfStale: true,
        alreadySynced: !!liveSync,
      })
      : null;
    const intelligence = freshnessBundle?.intelligenceSnapshot
      || await buildAssistantIntelligenceSnapshot({
        strategy,
        cmdSnapshot: cmd,
        liveSync,
        preferCachedLive,
        forceFresh: !!liveSync,
      });
    const marketDataFreshness = freshnessBundle?.marketDataFreshness || intelligence?.marketDataFreshness || null;
    const readiness = freshnessBundle?.readiness || null;
    logAnalystDebug('assistant.quick.branch', {
      branch: analystNaturalMode ? 'quick_intent_narrative' : 'quick_intent_structured',
      activeModule,
      wantsOutlook: intents.wantsOutlook,
      wantsTrendRegime: intents.wantsTrendRegime,
      wantsSetupScan: intents.wantsSetupScan,
      wantsTradeDecision: intents.wantsTradeDecision,
    });
    if (analystNaturalMode && readiness?.needsFreshData) {
      const guardedReply = buildFreshDataUnavailableReply({
        readiness,
        lastUpdateText: freshnessBundle?.lastUpdateText || summarizeAnalystLastUpdate(marketDataFreshness),
      });
      const lines = [guardedReply, assistantVisibilityBoundaryLine()];
      if (freshnessBundle?.liveSync?.status) {
        lines.push(`Live sync: ${String(freshnessBundle.liveSync.status).toUpperCase()}.`);
      }
      return {
        source: 'assistant_quick',
        handled: true,
        reply: lines.filter(Boolean).join('\n'),
        commandsExecuted: (freshnessBundle?.commandsExecuted || []).length > 0
          ? freshnessBundle.commandsExecuted
          : (liveSync ? [{ command: 'sync', ok: liveSync.status !== 'error', output: liveSync.status || 'ok', error: liveSync.error || null }] : []),
        clientActions,
      };
    }
    const narrative = buildAnalystDecisionNarrative(decision, { marketDataFreshness });
    const sig = buildDecisionSignalSummary(decision);
    const topSetups = Array.isArray(decision.topSetups) ? decision.topSetups.slice(0, 3) : [];
    const blockers = (decision.blockers || []).slice(0, 3).map(humanizeDecisionBlocker);
    const replyLines = analystNaturalMode
      ? [narrative.stance, narrative.rangeLine, narrative.blockerLine]
      : [sig.line];
    if (analystNaturalMode && narrative.contextLine) replyLines.push(narrative.contextLine);
    const chartContextLine = buildAnalystChartContextLine();

    if (intents.wantsTradeDecision) {
      if (!analystNaturalMode) {
        replyLines.push(`Stance now: ${plan.action || 'CONTROLLED EXECUTION'}.`);
      }
      if (topSetups[0]) replyLines.push(`Best current setup: ${topSetups[0].name}.`);
      if (Number.isFinite(Number(topSetups?.[0]?.probability))) {
        replyLines.push(`Estimated win chance on top setup: ${Number(topSetups[0].probability).toFixed(1)}%.`);
      }
      if (!analystNaturalMode) {
        if (blockers.length > 0) replyLines.push(`Reason to hold: ${blockers.join(', ')}.`);
        else replyLines.push('No active blockers detected.');
      }
      if (chartContextLine) replyLines.push(chartContextLine);
    } else if (intents.wantsSetupScan) {
      if (topSetups.length > 0) {
        replyLines.push('Top setups right now:');
        for (let i = 0; i < topSetups.length; i += 1) {
          const line = formatQuickTopSetupLine(topSetups[i], i);
          if (line) replyLines.push(line);
        }
      } else {
        replyLines.push('No ranked setup list is available right now.');
      }
      if (!analystNaturalMode && blockers.length > 0) replyLines.push(`Main blockers: ${blockers.join(', ')}.`);
      if (chartContextLine) replyLines.push(chartContextLine);
    } else {
      if (!analystNaturalMode) {
        replyLines.push(`Today stance: ${plan.action || 'CONTROLLED EXECUTION'}.`);
        replyLines.push(`Risk mode: ${String(plan?.riskPlan?.mode || 'normal').toLowerCase()} with max ${plan?.riskPlan?.maxTrades ?? 2} trades.`);
      } else {
        replyLines.push(`Today's risk plan is ${String(plan?.riskPlan?.mode || 'normal').toLowerCase()} with up to ${plan?.riskPlan?.maxTrades ?? 2} trades.`);
      }
      if (topSetups[0]) replyLines.push(`Primary setup focus: ${topSetups[0].name}.`);
      if (!analystNaturalMode && blockers.length > 0) replyLines.push(`Main blockers: ${blockers.join(', ')}.`);
      if (chartContextLine) replyLines.push(chartContextLine);
    }

    if (intelligence) {
      const intelLines = buildAssistantIntelligenceLines(intelligence);
      const naturalIntelLines = analystNaturalMode
        ? intelLines
          .filter((l) => !/^(GO|WAIT|DON'T TRADE)\s*:/i.test(String(l || '').trim()))
          .slice(0, 3)
        : intelLines.slice(0, 3);
      for (const l of naturalIntelLines) replyLines.push(l);
      if (analystNaturalMode && intelligence?.execution?.reason) {
        replyLines.push(`Execution context: ${String(intelligence.execution.reason).trim()}`);
      }
      if (Array.isArray(intelligence?.errors) && intelligence.errors.length > 0) {
        replyLines.push('Some live components are degraded, so this uses the best available feed.');
      }
    }

    if (liveSync?.status) replyLines.push(`Live sync: ${String(liveSync.status).toUpperCase()}.`);
    if (freshnessBundle?.liveSync?.status && (!liveSync || freshnessBundle.liveSync.status !== liveSync.status)) {
      replyLines.push(`Live sync: ${String(freshnessBundle.liveSync.status).toUpperCase()}.`);
    }
    replyLines.push(assistantVisibilityBoundaryLine());
    return {
      source: 'assistant_quick',
      handled: true,
      reply: replyLines.join('\n'),
      commandsExecuted: (freshnessBundle?.commandsExecuted || []).length > 0
        ? freshnessBundle.commandsExecuted
        : (liveSync ? [{ command: 'sync', ok: liveSync.status !== 'error', output: liveSync.status || 'ok', error: liveSync.error || null }] : []),
      clientActions,
    };
  }

  if (validatedInferred) {
    logAnalystDebug('assistant.quick.branch', {
      branch: 'quick_intent_validated_inferred_command',
      activeModule,
    });
    const execOut = await executeDashboardAgentCommand(validatedInferred, { strategy, activeModule });
    return {
      source: 'assistant_quick',
      handled: true,
      reply: execOut.output,
      commandsExecuted: [{ command: validatedInferred, ok: true, output: truncateAgentText(execOut.output, 400) }],
      clientActions,
    };
  }

  if (clientActions.length > 0) {
    logAnalystDebug('assistant.quick.branch', {
      branch: 'quick_intent_client_action_only',
      activeModule,
      actionCount: clientActions.length,
    });
    const label = clientActions[0]?.module || 'module';
    return {
      source: 'assistant_quick',
      handled: true,
      reply: `Opening ${label}.`,
      commandsExecuted: [],
      clientActions,
    };
  }

  logAnalystDebug('assistant.quick.branch', {
    branch: 'quick_intent_unhandled',
    activeModule,
  });
  return {
    source: 'assistant_quick',
    handled: false,
    reply: '',
    commandsExecuted: [],
    clientActions: [],
  };
}

async function buildPlannerlessStrategicReply(options = {}) {
  const message = String(options.message || '').trim();
  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const plannerError = String(options.plannerError || '').trim();

  const cmd = await buildTradingCommandSnapshot(strategy).catch(() => null);
  const intelligence = await buildAssistantIntelligenceSnapshot({
    strategy,
    cmdSnapshot: cmd,
    preferCachedLive: true,
  }).catch(() => null);

  if (!cmd && !intelligence) {
    return plannerError
      ? `Planner is limited right now (${truncateAgentText(plannerError, 120)}), and local strategy context is unavailable. Try "sync" then "status".`
      : 'Planner is limited and local strategy context is unavailable. Try "sync" then "status".';
  }

  const decision = cmd?.decision || {};
  const sig = buildDecisionSignalSummary(decision);
  const topSetup = decision?.topSetups?.[0] || null;
  const blockers = (decision.blockers || []).slice(0, 3).map(humanizeDecisionBlocker);
  const pattern = intelligence?.market?.pattern || {};
  const execution = intelligence?.execution || {};
  const risk = intelligence?.risk || {};
  const lines = [sig.line];
  const lastPrice = Number(pattern?.lastPrice);

  if (topSetup?.name) {
    const prob = Number.isFinite(Number(topSetup.probability)) ? `${Number(topSetup.probability).toFixed(1)}%` : 'n/a';
    lines.push(`Best setup focus: ${topSetup.name} (estimated WR ${prob}).`);
  }
  if (Number.isFinite(lastPrice) && lastPrice > 0) {
    lines.push(`MNQ is around ${lastPrice.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} with ${String(pattern.volatilityRegime || 'unknown')} volatility.`);
  } else {
    lines.push('MNQ live price is unavailable right now; run sync for a fresh market snapshot.');
  }
  if (execution?.reason) lines.push(`Execution stance: ${execution.reason}`);
  if (risk?.guidance) lines.push(`Risk guidance: ${risk.guidance}`);
  if (blockers.length > 0) lines.push(`Main blockers: ${blockers.join(', ')}.`);

  if (/next step|what now|what should i do next/i.test(message)) {
    const action = String(execution.action || '').toUpperCase();
    if (action === 'TRADE') lines.push('Next step: execute only if trigger confirms and no new blocker appears.');
    else if (action === 'WAIT') lines.push('Next step: wait and reassess after structure confirms.');
    else lines.push('Next step: do not trade until blockers clear.');
  }

  if (DASHBOARD_AGENT_ALLOW_WORKAROUND && plannerError) {
    lines.push('Operating in fallback command mode while planner intelligence is limited.');
  }
  return lines.join('\n');
}

async function runDashboardAgentOrchestrator(input = {}) {
  const message = String(input.message || '').trim();
  if (!message) throw new Error('No message provided.');
  const strategy = String(input.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const activeModule = normalizeDashboardModuleId(input.activeModule) || 'bridge';
  const traceId = String(input.traceId || '').trim() || null;
  const quickIntents = parseAssistantQuickIntents(message);
  logAnalystDebug('assistant.orchestrator.start', {
    traceId,
    activeModule,
    strategy,
    message: debugTextPreview(message, 220),
    intents: {
      wantsOutlook: quickIntents.wantsOutlook,
      wantsTrendRegime: quickIntents.wantsTrendRegime,
      wantsTradeDecision: quickIntents.wantsTradeDecision,
      wantsSetupScan: quickIntents.wantsSetupScan,
      wantsSync: quickIntents.wantsSync,
    },
  });
  const providerState = dashboardAgentProviderSummary();
  const siteMap = buildDashboardSiteMap();
  const appAllow = new Set((config.discord?.allowedApps || []).map((s) => String(s || '').trim().toLowerCase()).filter(Boolean));
  const parserCtx = { siteMap, appAllow };

  const inferred = discordInterpreterTestTools?.inferPlainEnglishCommand
    ? discordInterpreterTestTools.inferPlainEnglishCommand(message, parserCtx)
    : null;
  const validatedInferred = inferred && discordInterpreterTestTools?.validateInterpretedCommand
    ? discordInterpreterTestTools.validateInterpretedCommand(inferred, parserCtx)
    : null;

  const cmdSnapshot = await buildTradingCommandSnapshot(strategy).catch(() => null);
  const chartContextLine = buildAnalystChartContextLine();
  const contextLine = [
    `Active module: ${activeModule}.`,
    `Strategy view: ${strategy}.`,
    `Outlook: ${summarizeSnapshotOutlook(cmdSnapshot)}`,
    chartContextLine ? `Chart: ${chartContextLine}` : 'Chart: no recent chart context loaded.',
  ].join(' ');

  if (!providerState.configured) {
    if (!validatedInferred) {
      return {
        source: 'dashboard_agent',
        reply: 'No AI key is configured. Add OPENAI_API_KEY (preferred for Codex brain) or ANTHROPIC_API_KEY.',
        commandsExecuted: [],
        clientActions: [],
      };
    }
    const execOut = await executeDashboardAgentCommand(validatedInferred, { strategy, activeModule });
    return {
      source: 'dashboard_agent',
      reply: execOut.output,
      commandsExecuted: [{ command: validatedInferred, ok: true, output: truncateAgentText(execOut.output, 400) }],
      clientActions: [],
    };
  }

  const system = [
    'You are 3130 Dashboard Agent, a Codex-style execution copilot.',
    'Convert plain English into actionable dashboard commands and concise spoken feedback.',
    'Return strict JSON only with this exact shape:',
    '{"reply":"string","commands":["..."],"clientActions":[{"type":"open_module","module":"bridge|briefing|analyst|system|lab|coach|portfolio|journal|sessions|adversary|conflicts|breakdown|import"}],"terminalCommand":"optional shell command or empty string"}',
    'Rules:',
    '- Use plain English in reply.',
    '- Keep reply under 120 words.',
    '- commands must use this allowlist:',
    'status, plan, deskstart, tradestate, opps, system, autonomy, autonomy run, mode manual|paper_auto|live_assist, halt, resume, scan two_stage|full_scan, doctor, outcome win|loss|breakeven [pnl] [notes], sync, liveintel, terminal <command>.',
    '- Use terminalCommand only when the user explicitly asks for coding/file/terminal operations.',
    '- If the user asks to navigate the dashboard, add clientActions open_module.',
    '- Never claim you cannot access live data. You can access live trading snapshots via sync/status/tradestate/system commands.',
    '- For live data or connectivity questions, run sync + status (or tradestate/system) and answer with concrete current state.',
    `Context: ${contextLine}`,
  ].join('\n');

  const memory = dashboardAgentHistory.slice(-14);
  const convo = memory.concat([{ role: 'user', content: message }]).map((m) => ({
    role: m.role === 'assistant' ? 'assistant' : 'user',
    content: String(m.content || ''),
  }));

  let parsed = null;
  let plannerProvider = null;
  let plannerModel = null;
  let plannerError = null;
  try {
    const planOut = await runDashboardPlannerWithFallback({ system, convo });
    plannerProvider = planOut.provider || null;
    plannerModel = planOut.model || null;
    parsed = extractJsonObjectFromText(planOut.rawText);
    logAnalystDebug('assistant.orchestrator.planner', {
      traceId,
      provider: plannerProvider,
      model: plannerModel,
      parsedReplyPreview: debugTextPreview(parsed?.reply || '', 220),
      parsedCommandCount: Array.isArray(parsed?.commands) ? parsed.commands.length : 0,
    });
  } catch (err) {
    plannerError = String(err?.message || 'planner_unavailable');
    logAnalystDebug('assistant.orchestrator.planner_error', {
      traceId,
      plannerError,
      activeModule,
    });
    if (validatedInferred) {
      parsed = null;
    } else {
      const quickFallback = await runAssistantQuickIntent({
        message,
        strategy,
        activeModule,
      }).catch(() => null);
      if (quickFallback?.handled) {
        logAnalystDebug('assistant.orchestrator.branch', {
          traceId,
          branch: 'planner_error_quick_fallback',
          activeModule,
          replyPreview: debugTextPreview(quickFallback.reply || '', 220),
        });
        return {
          source: 'dashboard_agent',
          planner: {
            provider: null,
            model: null,
            preferredProvider: DASHBOARD_AGENT_PROVIDER,
          },
          reply: String(quickFallback.reply || ''),
          commandsExecuted: Array.isArray(quickFallback.commandsExecuted) ? quickFallback.commandsExecuted : [],
          clientActions: Array.isArray(quickFallback.clientActions) ? quickFallback.clientActions : [],
          terminal: null,
        };
      }
      const strategicFallback = await buildPlannerlessStrategicReply({
        message,
        strategy,
        plannerError,
      }).catch(() => null);
      if (strategicFallback) {
        logAnalystDebug('assistant.orchestrator.branch', {
          traceId,
          branch: 'planner_error_strategic_fallback',
          activeModule,
          replyPreview: debugTextPreview(strategicFallback, 220),
        });
        return {
          source: 'dashboard_agent',
          planner: {
            provider: null,
            model: null,
            preferredProvider: DASHBOARD_AGENT_PROVIDER,
          },
          reply: String(strategicFallback),
          commandsExecuted: [],
          clientActions: [],
          terminal: null,
        };
      }
    }
  }

  const liveDataQuestion = /\b(live|real[-\s]?time|market feed|market data|connectivity|data connection|can you access)\b/i.test(message);
  const refusalLike = /\b(i cannot|can't|unable|limited)\b[\s\S]{0,120}\b(live|real[-\s]?time|market|data)\b/i.test(String(parsed?.reply || ''));

  let commands = Array.isArray(parsed?.commands)
    ? parsed.commands.map((c) => String(c || '').trim()).filter(Boolean).slice(0, DASHBOARD_AGENT_MAX_COMMANDS)
    : [];
  if (liveDataQuestion) {
    const normalized = new Set(commands.map((c) => c.toLowerCase()));
    if (!normalized.has('sync')) commands.unshift('sync');
    if (!normalized.has('status')) commands.push('status');
    commands = commands.slice(0, DASHBOARD_AGENT_MAX_COMMANDS);
  }
  if (!commands.length && validatedInferred) commands.push(validatedInferred);

  const clientActions = (Array.isArray(parsed?.clientActions) ? parsed.clientActions : [])
    .map((a) => {
      if (!a || typeof a !== 'object') return null;
      if (String(a.type || '').toLowerCase() !== 'open_module') return null;
      const moduleId = normalizeDashboardModuleId(a.module);
      if (!moduleId) return null;
      return { type: 'open_module', module: moduleId };
    })
    .filter(Boolean)
    .slice(0, 3);
  const inferredModule = inferDashboardModuleFromText(message);
  if (inferredModule && !clientActions.some((a) => a.type === 'open_module' && a.module === inferredModule)) {
    if (/\b(open|show|go to|switch)\b/i.test(message) || clientActions.length === 0) {
      clientActions.unshift({ type: 'open_module', module: inferredModule });
    }
  }

  const terminalCommand = String(parsed?.terminalCommand || '').trim();
  const commandsExecuted = [];
  for (const cmd of commands) {
    try {
      const out = await executeDashboardAgentCommand(cmd, { strategy, activeModule });
      commandsExecuted.push({ command: cmd, ok: true, output: truncateAgentText(out.output, 320) });
    } catch (err) {
      commandsExecuted.push({ command: cmd, ok: false, error: String(err?.message || 'command_failed') });
    }
  }

  let terminal = null;
  if (terminalCommand) {
    try {
      const out = await runDashboardShellCommand(terminalCommand);
      terminal = {
        ok: true,
        command: terminalCommand,
        output: truncateAgentText(out.stdout || out.stderr || 'terminal command complete', 500),
      };
    } catch (err) {
      terminal = {
        ok: false,
        command: terminalCommand,
        error: String(err?.message || 'terminal_failed'),
      };
    }
  }

  let reply = String(parsed?.reply || '').trim();
  if (liveDataQuestion && refusalLike) {
    reply = 'Live connectivity check running now. I will report your current sync and decision status.';
  }
  if (!reply) {
    if (commandsExecuted.length > 0) reply = commandsExecuted[0].ok ? commandsExecuted[0].output : `I could not run ${commandsExecuted[0].command}: ${commandsExecuted[0].error}`;
    else if (terminal?.ok) reply = terminal.output;
    else if (terminal && !terminal.ok) reply = `Terminal command failed: ${terminal.error}`;
    else if (plannerError) {
      if (DASHBOARD_AGENT_ALLOW_WORKAROUND) {
        reply = 'Planner intelligence is temporarily limited, so I switched to direct runtime command mode. You can still ask for status, plan, sync, liveintel, tradestate, and system checks.';
      } else if (/\bquota|429|rate limit|insufficient\b/i.test(plannerError)) {
        reply = 'Codex routing is active, but your OpenAI quota is currently exhausted. Add credits and retry. Direct commands like "status", "plan", and "sync" still work.';
      } else {
        reply = `Codex planner is temporarily unavailable: ${truncateAgentText(plannerError, 180)}.`;
      }
    }
    else reply = 'I could not map that phrasing to a safe action yet. Try one clear intent like: "status", "plan", "show live intelligence", "sync", or "what should I do next?"';
  }

  const analystModule = activeModule === 'analyst';
  const analystTrendIntent = analystModule && quickIntents.wantsTrendRegime;
  const analystDecisionIntent = analystModule && (
    quickIntents.wantsOutlook
    || quickIntents.wantsTrendRegime
    || quickIntents.wantsTradeDecision
    || quickIntents.wantsSetupScan
    || /\b(outlook|gameplan|game plan|trade|market|setup|trend|regime|bias|stay out|sit out|stand down|avoid the market)\b/i.test(message)
  );
  if (analystDecisionIntent) {
    const preambleLike = isAnalystPreambleReply(reply);
    const decisive = analystTrendIntent ? isAnalystTrendRegimeReplyDecisive(reply) : isAnalystNarrativeDecisive(reply);
    const tooShort = String(reply || '').trim().length < 25;
    if (preambleLike || !decisive || tooShort) {
      const reasonFlags = [
        preambleLike ? 'preamble_like' : null,
        !decisive ? 'non_decisive' : null,
        tooShort ? 'too_short' : null,
      ].filter(Boolean);
      const synthesized = analystTrendIntent
        ? await synthesizeAnalystTrendRegimeReply({
          strategy,
          cmdSnapshot,
        }).catch(() => '')
        : await synthesizeAnalystOrchestratorReply({
          strategy,
          cmdSnapshot,
        }).catch(() => '');
      if (synthesized) {
        reply = synthesized;
        logAnalystDebug('assistant.orchestrator.branch', {
          traceId,
          branch: analystTrendIntent
            ? 'analyst_trend_post_orchestrator_synthesized'
            : 'analyst_post_orchestrator_synthesized',
          reasons: reasonFlags,
          activeModule,
          replyPreview: debugTextPreview(reply, 240),
        });
      }
    }
  }

  if (DASHBOARD_AGENT_APPEND_COMPLETION_LOG) {
    const completionLines = [];
    for (const row of commandsExecuted) {
      completionLines.push(row.ok ? `${row.command}: done` : `${row.command}: failed (${row.error})`);
    }
    if (terminal) completionLines.push(terminal.ok ? `terminal: done` : `terminal: failed (${terminal.error})`);
    if (completionLines.length > 0) {
      reply = `${reply}\n\nCompleted:\n- ${completionLines.join('\n- ')}`;
    }
  }

  dashboardAgentHistory.push({ role: 'user', content: message });
  dashboardAgentHistory.push({ role: 'assistant', content: reply });
  while (dashboardAgentHistory.length > 40) dashboardAgentHistory.shift();

  logAnalystDebug('assistant.orchestrator.reply', {
    traceId,
    activeModule,
    plannerProvider: plannerProvider || null,
    plannerModel: plannerModel || null,
    commandsExecuted: commandsExecuted.length,
    terminalUsed: !!terminal,
    replyPreview: debugTextPreview(reply, 240),
  });

  return {
    source: 'dashboard_agent',
    planner: {
      provider: plannerProvider,
      model: plannerModel,
      preferredProvider: DASHBOARD_AGENT_PROVIDER,
    },
    reply,
    commandsExecuted,
    clientActions,
    terminal,
  };
}

async function runAssistantUnifiedQuery(input = {}) {
  const message = String(input.message || '').trim();
  if (!message) throw new Error('No message provided.');
  const strategy = String(input.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const activeModule = normalizeDashboardModuleId(input.activeModule) || 'analyst';
  const traceId = String(input.traceId || '').trim() || null;
  const voiceMode = input.voiceMode === true;
  const voiceBriefMode = String(input.voiceBriefMode || '').trim().toLowerCase() || null;
  const preferCachedLive = input.preferCachedLive === true;
  const forceOrchestrator = input.forceOrchestrator === true;
  logAnalystDebug('assistant.unified.start', {
    traceId,
    activeModule,
    strategy,
    voiceMode,
    voiceBriefMode,
    preferCachedLive,
    forceOrchestrator,
    message: debugTextPreview(message, 220),
  });
  const cacheable = !forceOrchestrator && isAssistantQueryCacheable(message);
  const cacheKey = cacheable ? makeAssistantQueryCacheKey({
    message,
    strategy,
    activeModule,
    preferCachedLive,
    voiceMode,
    voiceBriefMode,
  }) : null;

  if (cacheKey) {
    const cached = getCachedAssistantQuery(cacheKey);
    if (cached) {
      return {
        ...cached,
        cached: true,
      };
    }
    const inFlight = assistantQueryInFlight.get(cacheKey);
    if (inFlight) {
      const joined = await inFlight;
      return {
        ...joined,
        inFlightJoined: true,
      };
    }
  }

  const runCore = async () => {
    if (!forceOrchestrator) {
      const quickOut = await runAssistantQuickIntent({
        message,
        strategy,
        activeModule,
        preferCachedLive,
      }).catch(() => null);

      if (quickOut?.handled) {
        logAnalystDebug('assistant.unified.branch', {
          traceId,
          branch: 'quick_intent_handled',
          activeModule,
          source: quickOut.source || 'assistant_quick',
        });
        const result = {
          source: quickOut.source || 'assistant_quick',
          mode: 'quick',
          handled: true,
          reply: normalizeAssistantModuleReply(String(quickOut.reply || ''), {
            stripCompletion: voiceMode,
            voiceMode,
            activeModule,
          }),
          commandsExecuted: Array.isArray(quickOut.commandsExecuted) ? quickOut.commandsExecuted : [],
          clientActions: Array.isArray(quickOut.clientActions) ? quickOut.clientActions : [],
          planner: null,
          terminal: null,
        };
        if (cacheKey) {
          setCachedAssistantQuery(cacheKey, {
            ...result,
            cached: false,
          });
        }
        return result;
      }
    } else {
      logAnalystDebug('assistant.unified.branch', {
        traceId,
        branch: 'force_orchestrator',
        activeModule,
      });
    }

    const orchestrated = await runDashboardAgentOrchestrator({
      message,
      strategy,
      activeModule,
      traceId,
    });
    logAnalystDebug('assistant.unified.branch', {
      traceId,
      branch: 'orchestrator',
      activeModule,
      plannerProvider: orchestrated?.planner?.provider || null,
      source: orchestrated?.source || 'dashboard_agent',
      replyPreview: debugTextPreview(orchestrated?.reply || '', 220),
    });
    const result = {
      ...orchestrated,
      mode: 'orchestrator',
      handled: true,
      reply: normalizeAssistantModuleReply(String(orchestrated.reply || ''), {
        stripCompletion: voiceMode,
        voiceMode,
        activeModule,
      }),
    };
    if (cacheKey && !orchestrated?.terminal) {
      setCachedAssistantQuery(cacheKey, {
        ...result,
        cached: false,
      });
    }
    return result;
  };

  if (!cacheKey) return runCore();
  const pending = runCore().finally(() => {
    assistantQueryInFlight.delete(cacheKey);
  });
  assistantQueryInFlight.set(cacheKey, pending);
  return pending;
}

function summarizePrimaryRiskReason(riskState = {}) {
  const code = String((riskState?.riskReasonCodes || [])[0] || '').trim().toLowerCase();
  const label = String((riskState?.riskReasons || [])[0] || '').trim() || 'risk guardrail active';
  return { code, label };
}

function resolveDecisionBlockedBy(precedenceMode) {
  const mode = String(precedenceMode || '').trim().toLowerCase();
  if (mode === 'health_block') return 'health';
  if (mode === 'risk_block') return 'risk';
  return 'none';
}

function buildVoiceSessionMeta(input = {}) {
  const session = (input.session && typeof input.session === 'object') ? input.session : null;
  const fallbackMinutes = Number.isFinite(Number(input.nowMinutesEt)) ? Number(input.nowMinutesEt) : null;
  const phaseFallback = resolveVoiceTradingTimePhase({ etMinutes: fallbackMinutes });
  const timePhase = String(
    session?.timePhase
    || input.timePhase
    || phaseFallback.timePhase
    || 'postWindow'
  ).trim() || 'postWindow';
  const lastHealthAgeSeconds = Number.isFinite(Number(session?.lastHealthAgeSeconds))
    ? Number(session.lastHealthAgeSeconds)
    : (Number.isFinite(Number(input.lastHealthAgeSeconds)) ? Number(input.lastHealthAgeSeconds) : null);
  const healthStatusUsed = String(
    session?.healthStatusUsed
    || input.healthStatusUsed
    || input.healthStatus
    || ''
  ).trim().toUpperCase() || null;
  return {
    voiceSessionModeActive: session?.voiceSessionModeActive === true,
    lastHealthAgeSeconds,
    healthStatusUsed,
    timePhase,
  };
}

function buildJarvisStatusEarbudReply(context = {}) {
  const hasOpenPosition = context.hasOpenPosition === true;
  if (hasOpenPosition) {
    const side = String(context.positionSide || '').trim().toLowerCase();
    const sideLine = side === 'long' || side === 'short'
      ? `You're currently ${side} in a position, so this is management mode.`
      : "You're currently in a position, so this is management mode.";
    return [
      sideLine,
      "Let's focus on protecting structure and avoiding added risk.",
      'If structure breaks against the position on a close, we flatten.',
    ].join(' ');
  }

  const trend = String(context.trend || '').trim().toLowerCase();
  const regime = String(context.regime || '').trim().toLowerCase();
  const volatility = String(context.volatility || '').trim().toLowerCase();
  let reason = 'trend and regime are mixed right now';
  if (trend && regime) reason = `trend is ${trend} while regime is ${regime}`;
  else if (trend) reason = `trend is ${trend} right now`;
  else if (regime) reason = `regime is ${regime} right now`;
  if (volatility && volatility !== 'unknown') reason = `${reason} with ${volatility} volatility`;
  return [
    `I'd stay selective for now because ${reason}.`,
    "Let's focus on the next momentum checkpoint and retest quality.",
    'If trend and retest structure align cleanly, we can engage.',
  ].join(' ');
}

function buildJarvisMockRiskState(auditMock = {}) {
  const nowEt = (auditMock.nowEt && typeof auditMock.nowEt === 'object')
    ? {
      date: String(auditMock.nowEt.date || dateInTimezone('America/New_York')).slice(0, 10),
      time: normalizeHHMM(auditMock.nowEt.time || nowInTimezone('America/New_York').time, nowInTimezone('America/New_York').time),
    }
    : nowInTimezone('America/New_York');
  const riskInputs = auditMock.riskInputs && typeof auditMock.riskInputs === 'object' ? auditMock.riskInputs : {};
  const openPosition = riskInputs.openPosition && typeof riskInputs.openPosition === 'object'
    ? riskInputs.openPosition
    : null;
  const hasOpenPosition = riskInputs.hasOpenPosition === true
    || Number(openPosition?.qty || 0) > 0;
  return buildRiskStateSnapshot({
    nowEt,
    sessionDateEt: String(riskInputs.sessionDateEt || nowEt.date).slice(0, 10),
    entryWindowStartEt: String(riskInputs.entryWindowStartEt || '09:30'),
    entryWindowEndEt: String(riskInputs.entryWindowEndEt || '10:59'),
    orbComplete: riskInputs.orbComplete === true,
    equity: pickFirstFiniteNumber(riskInputs.equity, 0),
    balance: pickFirstFiniteNumber(riskInputs.balance, 0),
    unrealizedPnL: pickFirstFiniteNumber(riskInputs.unrealizedPnL, 0),
    realizedPnLToday: pickFirstFiniteNumber(riskInputs.realizedPnLToday, riskInputs.dailyPnL, 0),
    dailyPnL: pickFirstFiniteNumber(riskInputs.dailyPnL, 0),
    openPosition: openPosition || { side: null, qty: 0, avgPrice: null, unrealizedPnL: null },
    hasOpenPosition,
    tradesTakenToday: Math.max(0, Number(riskInputs.tradesTakenToday || 0)),
    maxTradesPerDay: Math.max(1, Number(riskInputs.maxTradesPerDay || 1)),
    maxContracts: Math.max(1, Number(riskInputs.maxContracts || 1)),
    dailyLossLimit: Math.max(50, Number(riskInputs.dailyLossLimit || 500)),
    minDrawdownBufferDollars: Math.max(0, Number(riskInputs.minDrawdownBufferDollars || 250)),
    trailingDrawdownDistance: pickFirstFiniteNumber(riskInputs.trailingDrawdownDistance, null),
    lossCooldownEnabled: riskInputs.lossCooldownEnabled !== false,
    lossCooldownMinutes: Math.max(1, Number(riskInputs.lossCooldownMinutes || 10)),
    lastRealizedTradePnL: pickFirstFiniteNumber(riskInputs.lastRealizedTradePnL, null),
    lastRealizedTradeTimeEt: riskInputs.lastRealizedTradeTimeEt || null,
    cooldownRemainingMinutes: Math.max(0, Number(riskInputs.cooldownRemainingMinutes || 0)),
    blockedCooldownAfterLoss: riskInputs.blockedCooldownAfterLoss === true,
    blockWhenOpenPosition: riskInputs.blockWhenOpenPosition !== false,
    blockedDataStale: riskInputs.blockedDataStale === true,
    readinessNeedsFreshData: riskInputs.readinessNeedsFreshData === true,
    marketDataFreshness: riskInputs.marketDataFreshness || null,
  });
}

function humanizeReplayMissingReason(reason) {
  const raw = String(reason || '').trim();
  if (!raw) return 'session bars are missing';
  const normalized = raw.toLowerCase();
  if (normalized.includes('requested date has no stored 5-minute candles')) {
    return 'that session has no stored bars yet';
  }
  if (normalized.includes('insufficient bars for replay')) {
    return 'there are not enough bars to compute replay metrics';
  }
  if (normalized.includes('live bars are unavailable')) {
    return 'live bars for that session are unavailable right now';
  }
  if (normalized.includes('live bars returned no 5-minute candles')) {
    return 'live bars did not produce valid 5-minute replay candles';
  }
  return raw.replace(/_/g, ' ');
}

const REPLAY_WORKABLE_ORB_MIN = 70;
const REPLAY_WORKABLE_ORB_MAX = 220;
const REPLAY_FRIDAY_EXHAUSTION_LIMIT = 380;
const REPLAY_GLOBAL_EXHAUSTION_LIMIT = 400;

function replayDayNameEt(dateIso) {
  const src = String(dateIso || '').trim();
  if (!src) return '';
  const d = new Date(`${src}T12:00:00-05:00`);
  if (Number.isNaN(d.getTime())) return '';
  try {
    return new Intl.DateTimeFormat('en-US', {
      timeZone: 'America/New_York',
      weekday: 'long',
    }).format(d).toLowerCase();
  } catch {
    return '';
  }
}

function replayHumanEligibilityReason(code) {
  const key = String(code || '').trim().toLowerCase();
  const map = {
    orb_outside_workable_zone: `ORB is outside your workable ${REPLAY_WORKABLE_ORB_MIN}-${REPLAY_WORKABLE_ORB_MAX} tick zone`,
    orb_global_exhaustion: `ORB exceeded ${REPLAY_GLOBAL_EXHAUSTION_LIMIT} ticks (historical exhaustion risk)`,
    orb_friday_exhaustion: `Friday ORB exceeded ${REPLAY_FRIDAY_EXHAUSTION_LIMIT} ticks (volatility exhaustion risk)`,
    entry_after_max_hour: 'confirmation arrived after your max entry hour',
    retest_not_confirmed: 'retest structure did not complete',
    direction_filter_long_only: 'first breakout was short but strategy is long-only',
    risk_skip_monday: 'Monday is excluded by your active strategy rules',
    no_breakout: 'no valid breakout confirmed after ORB',
    no_confirmation: 'retest never confirmed with entry conditions',
    max_flips_exceeded: 'invalidation flip count exceeded safety limit',
  };
  if (map[key]) return map[key];
  if (!key) return 'setup conditions were not met';
  return key.replace(/_/g, ' ');
}

function deriveReplaySummaryAlignment({ replayDate, replay, orb, alignment, missingReason }) {
  const aligned = alignment && typeof alignment === 'object' ? alignment : {};
  const direction = String(replay?.direction || '').trim().toLowerCase();
  const normalizedNoTrade = String(replay?.noTradeReason || '').trim().toLowerCase();
  const marketOutcome = String(
    aligned?.marketOutcome
    || (replay?.wouldTrade === true ? replay?.result : '')
    || (direction === 'long' ? 'upside_move' : direction === 'short' ? 'downside_move' : 'rangebound')
  ).trim().toLowerCase() || 'unknown';

  const originalPlanEligible = typeof aligned?.originalPlanEligible === 'boolean'
    ? aligned.originalPlanEligible
    : replay?.wouldTrade === true;
  const originalPlanBlockers = Array.isArray(aligned?.originalPlanBlockers)
    ? aligned.originalPlanBlockers.map((s) => String(s || '').trim()).filter(Boolean)
    : [];
  if (!originalPlanEligible && originalPlanBlockers.length === 0 && normalizedNoTrade) {
    originalPlanBlockers.push(replayHumanEligibilityReason(normalizedNoTrade));
  }
  const originalPlanOutcome = String(
    aligned?.originalPlanOutcome
    || (originalPlanEligible ? (replay?.result || 'unknown') : 'no_trade')
  ).trim().toLowerCase() || 'no_trade';

  const dayName = replayDayNameEt(replayDate);
  const orbRangeTicks = Number.isFinite(Number(orb?.rangeTicks)) ? Number(orb.rangeTicks) : null;
  const inferredOverlayBlockers = [];
  if (Number.isFinite(orbRangeTicks)) {
    const rangeBlocked = (
      orbRangeTicks < REPLAY_WORKABLE_ORB_MIN
      || orbRangeTicks > REPLAY_WORKABLE_ORB_MAX
      || orbRangeTicks > REPLAY_GLOBAL_EXHAUSTION_LIMIT
      || (dayName === 'friday' && orbRangeTicks > REPLAY_FRIDAY_EXHAUSTION_LIMIT)
    );
    if (rangeBlocked) inferredOverlayBlockers.push(replayHumanEligibilityReason('orb_outside_workable_zone'));
  }
  if (dayName === 'monday') inferredOverlayBlockers.push(replayHumanEligibilityReason('risk_skip_monday'));

  const overlayEligible = typeof aligned?.overlayEligible === 'boolean'
    ? aligned.overlayEligible
    : (originalPlanEligible && inferredOverlayBlockers.length === 0);
  const overlayBlockers = Array.isArray(aligned?.overlayBlockers) && aligned.overlayBlockers.length > 0
    ? aligned.overlayBlockers.map((s) => String(s || '').trim()).filter(Boolean)
    : inferredOverlayBlockers;
  const overlayOutcome = String(
    aligned?.overlayOutcome
    || (overlayEligible ? originalPlanOutcome : 'no_trade')
  ).trim().toLowerCase() || 'no_trade';
  const overlayAssessment = aligned?.overlayAssessment && typeof aligned.overlayAssessment === 'object'
    ? aligned.overlayAssessment
    : {
      overlayKey: 'overlay_orb_70_220_skip_monday',
      overlayName: 'Learned Overlay: ORB 70-220 + Skip Monday',
      overlayEligible,
      overlayOutcome,
      overlayBlockers,
      rationale: overlayEligible ? 'Learned overlay does not downgrade this setup.' : (overlayBlockers[0] || 'Learned overlay blocked this setup.'),
      changedDecision: originalPlanEligible !== overlayEligible || originalPlanOutcome !== overlayOutcome,
    };

  const blockedByRangeFilter = aligned?.blockedByRangeFilter === true
    || overlayBlockers.some((r) => /\borb\b|\bvolatility exhaustion\b/i.test(String(r)));
  const blockedByTimeWindow = aligned?.blockedByTimeWindow === true
    || originalPlanBlockers.some((r) => /max entry hour|entry hour|cutoff|time window/i.test(String(r)));
  const blockedByRetestRule = aligned?.blockedByRetestRule === true
    || originalPlanBlockers.some((r) => /retest|confirmation/i.test(String(r)));
  const blockedByDirectionRule = aligned?.blockedByDirectionRule === true
    || originalPlanBlockers.some((r) => /short|direction/i.test(String(r)));
  const blockedByRiskRule = aligned?.blockedByRiskRule === true
    || overlayBlockers.some((r) => /monday/i.test(String(r)));

  const strategyEligible = originalPlanEligible;
  const strategyOutcome = originalPlanOutcome;
  const eligibilityReasons = originalPlanBlockers.slice();
  const skipReason = String(
    aligned?.skipReason
    || (!originalPlanEligible ? (originalPlanBlockers[0] || '') : '')
    || (originalPlanEligible && !overlayEligible ? (overlayBlockers[0] || '') : '')
    || missingReason
    || ''
  ).trim() || null;

  return {
    marketOutcome,
    originalPlanEligible,
    originalPlanBlockers,
    originalPlanOutcome,
    overlayEligible,
    overlayBlockers,
    overlayOutcome,
    overlayAssessment,
    // Legacy compatibility
    strategyEligible,
    strategyOutcome,
    eligibilityReasons,
    blockedByRangeFilter,
    blockedByTimeWindow,
    blockedByRetestRule,
    blockedByDirectionRule,
    blockedByRiskRule,
    skipReason,
  };
}

function buildReplayMetricsSummary(replayData = {}, replayWarnings = []) {
  const replay = replayData?.replay && typeof replayData.replay === 'object' ? replayData.replay : {};
  const orb = replayData?.orb && typeof replayData.orb === 'object' ? replayData.orb : {};
  const mechanics = replayData?.mechanics && typeof replayData.mechanics === 'object'
    ? replayData.mechanics
    : replayData;
  const alignment = replayData?.alignment && typeof replayData.alignment === 'object' ? replayData.alignment : {};
  const available = replayData?.available === true;
  const warnings = Array.isArray(replayWarnings) ? replayWarnings.filter(Boolean) : [];
  const alignedSummary = deriveReplaySummaryAlignment({
    replayDate: replayData?.targetDate,
    replay,
    orb,
    alignment,
    missingReason: replayData?.missingReason,
  });
  const defaultMechanicsSummary = {
    comparisonAvailable: false,
    forcedSimulation: false,
    summaryLine: 'Mechanics comparison unavailable.',
    bestTpMode: null,
    originalTpMode: 'Skip 2',
    changedVsOriginal: false,
  };
  const summary = {
    barsSourceUsed: String(replayData?.source || 'none').trim() || 'none',
    replayDate: String(replayData?.targetDate || '').trim() || null,
    orbRangeTicks: Number.isFinite(Number(orb?.rangeTicks)) ? Number(orb.rangeTicks) : null,
    breakDirection: String(replay?.direction || '').trim().toLowerCase() || null,
    retestDetected: !!String(replay?.retestTime || '').trim(),
    mfe: Number.isFinite(Number(replay?.mfeTicks)) ? Number(replay.mfeTicks) : null,
    mae: Number.isFinite(Number(replay?.maeTicks)) ? Number(replay.maeTicks) : null,
    hypotheticalOutcome: alignedSummary.strategyOutcome,
    marketOutcome: alignedSummary.marketOutcome,
    strategyOutcome: alignedSummary.strategyOutcome,
    originalPlanEligible: alignedSummary.originalPlanEligible === true,
    originalPlanBlockers: Array.isArray(alignedSummary.originalPlanBlockers) ? alignedSummary.originalPlanBlockers : [],
    originalPlanOutcome: alignedSummary.originalPlanOutcome || null,
    overlayEligible: alignedSummary.overlayEligible === true,
    overlayBlockers: Array.isArray(alignedSummary.overlayBlockers) ? alignedSummary.overlayBlockers : [],
    overlayOutcome: alignedSummary.overlayOutcome || null,
    overlayAssessment: alignedSummary.overlayAssessment || null,
    strategyEligible: alignedSummary.strategyEligible === true,
    eligibilityReasons: alignedSummary.eligibilityReasons,
    blockedByRangeFilter: alignedSummary.blockedByRangeFilter === true,
    blockedByTimeWindow: alignedSummary.blockedByTimeWindow === true,
    blockedByRetestRule: alignedSummary.blockedByRetestRule === true,
    blockedByDirectionRule: alignedSummary.blockedByDirectionRule === true,
    blockedByRiskRule: alignedSummary.blockedByRiskRule === true,
    skipReason: alignedSummary.skipReason,
    mechanicsVariants: Array.isArray(mechanics?.mechanicsVariants) ? mechanics.mechanicsVariants : [],
    originalPlanMechanicsVariant: mechanics?.originalPlanMechanicsVariant || null,
    bestMechanicsVariant: mechanics?.bestMechanicsVariant || null,
    mechanicsComparisonSummary: mechanics?.mechanicsComparisonSummary || defaultMechanicsSummary,
    warnings,
    available,
    missingReason: String(replayData?.missingReason || '').trim() || null,
  };
  return summary;
}

function buildReplayMechanicsEarbudLine(summary = {}) {
  const comparison = summary?.mechanicsComparisonSummary && typeof summary.mechanicsComparisonSummary === 'object'
    ? summary.mechanicsComparisonSummary
    : null;
  if (!(comparison?.comparisonAvailable)) return null;
  const original = summary?.originalPlanMechanicsVariant || null;
  const best = summary?.bestMechanicsVariant || null;
  if (comparison.changedVsOriginal && best?.tpMode) {
    return `Let's compare exits: ${best.tpMode} resolved best while original ${original?.tpMode || 'Skip 2'} resolved ${original?.outcome || 'unknown'}.`;
  }
  return `Let's compare exits: ${original?.tpMode || 'Original mechanics'} remained best for this setup.`;
}

function normalizeCheckpointClassificationLabel(value = '') {
  const key = String(value || '').trim().toLowerCase();
  if (key === 'correct') return 'correct';
  if (key === 'too_aggressive') return 'too aggressive';
  if (key === 'too_conservative') return 'too conservative';
  if (key === 'insufficient_evidence') return 'insufficient evidence';
  return '';
}

function loadAssistantDecisionOutcomeCheckpointForDate(tradeDate = '') {
  const safeDate = String(tradeDate || '').trim().slice(0, 10);
  if (!safeDate) return null;
  try {
    const db = getDB();
    if (!db || typeof db.prepare !== 'function') return null;
    const row = db.prepare(`
      SELECT realized_outcome_classification, realized_outcome_reason
      FROM jarvis_assistant_decision_outcome_checkpoints
      WHERE trade_date = ?
      LIMIT 1
    `).get(safeDate);
    if (!row) return null;
    return {
      classification: String(row.realized_outcome_classification || '').trim().toLowerCase() || null,
      reason: String(row.realized_outcome_reason || '').trim() || null,
    };
  } catch {
    return null;
  }
}

function buildDirectTradingResultReply(summary = {}, message = '', options = {}) {
  const earbudMode = options.earbudMode === true;
  const replayDate = String(summary?.replayDate || 'today').trim() || 'today';
  if (summary?.available !== true) {
    const reason = humanizeReplayMissingReason(summary?.missingReason || summary?.skipReason || 'replay data is unavailable');
    if (earbudMode) {
      return [
        `I'd hold ${replayDate}'s setup result for now because ${reason}.`,
        "Let's wait for complete replay bars before we call this win or loss.",
        'If you want, I can re-check as soon as that session data is complete.',
      ].join(' ');
    }
    return `I can't confirm ${replayDate}'s setup result yet because ${reason}.`;
  }
  const strategyEligible = summary?.strategyEligible === true;
  const strategyOutcome = String(summary?.strategyOutcome || summary?.originalPlanOutcome || '').trim().toLowerCase();
  let setupSentence = `Today's setup is still unresolved.`;
  if (!strategyEligible) {
    setupSentence = `Today's setup was a no-trade under your plan.`;
  } else if (strategyOutcome === 'win') {
    setupSentence = `Today's setup won.`;
  } else if (strategyOutcome === 'loss') {
    setupSentence = `Today's setup lost.`;
  } else if (strategyOutcome === 'breakeven') {
    setupSentence = `Today's setup finished around break-even.`;
  }

  const checkpoint = loadAssistantDecisionOutcomeCheckpointForDate(replayDate);
  const checkpointLabel = normalizeCheckpointClassificationLabel(checkpoint?.classification || '');
  if (!earbudMode) {
    if (!checkpointLabel) return setupSentence;
    return `${setupSentence} Jarvis was ${checkpointLabel}.`;
  }

  const setupEarbudSentence = setupSentence
    .replace(/^Today's setup won\.$/i, "I'd mark today's setup as a win.")
    .replace(/^Today's setup lost\.$/i, "I'd mark today's setup as a loss.")
    .replace(/^Today's setup was a no-trade under your plan\.$/i, "I'd mark today's setup as a no-trade under your plan.")
    .replace(/^Today's setup finished around break-even\.$/i, "I'd mark today's setup as roughly break-even.")
    .replace(/^Today's setup is still unresolved\.$/i, "I'd mark today's setup as unresolved right now.");
  const jarvisSentence = checkpointLabel
    ? `Let's score Jarvis as ${checkpointLabel} on this day.`
    : "Let's treat Jarvis scoring as pending until the daily checkpoint row lands.";
  const detailSentence = checkpoint?.reason
    ? `If you want detail, the reason was: ${checkpoint.reason}.`
    : 'If you want detail, I can break down entry timing, retest quality, and exit behavior.';
  return [setupEarbudSentence, jarvisSentence, detailSentence].join(' ');
}

function buildReplayEarbudReply(summary = {}) {
  const replayDate = summary.replayDate || 'that session';
  if (!summary.available) {
    const reason = humanizeReplayMissingReason(summary.missingReason || summary.skipReason || '');
    return [
      `I'd hold this replay for now because ${reason}.`,
      "Let's sync that session data before calculating ORB, MFE, and MAE.",
      'If you give me a date with complete bars, then I can compute the exact would-have result.',
    ].join(' ');
  }

  if (summary.strategyEligible !== true) {
    const reason = String((summary.originalPlanBlockers || [])[0] || humanizeReplayMissingReason(summary.skipReason || 'setup conditions were not met'));
    return [
      `I'd mark this as blocked under your original trading plan even though market outcome was ${summary.marketOutcome}.`,
      `Let's note the original-plan blocker: ${reason}.`,
      'If breakout, retest, and confirmation print before your cutoff, then it becomes valid under your original plan.',
    ].join(' ');
  }

  if (summary.overlayEligible !== true) {
    const overlayReason = String((summary.overlayBlockers || [])[0] || 'the learned overlay filtered this setup');
    return [
      `I'd mark this as valid under your original trading plan, and market outcome was ${summary.originalPlanOutcome}.`,
      `Let's note the learned overlay downgrade: ${overlayReason}.`,
      'If overlay conditions line up with your base setup, then both layers agree next time.',
    ].join(' ');
  }

  const outcomeWord = summary.strategyOutcome === 'win'
    ? 'win'
    : summary.strategyOutcome === 'loss'
      ? 'loss'
      : summary.strategyOutcome === 'breakeven'
        ? 'break-even'
        : 'mixed result';
  const directionText = summary.breakDirection || 'unknown';
  const rangeText = Number.isFinite(Number(summary.orbRangeTicks))
    ? `${Math.round(Number(summary.orbRangeTicks))} ticks`
    : 'unconfirmed range';
  const mfeText = Number.isFinite(Number(summary.mfe))
    ? `${Math.round(Number(summary.mfe))} ticks`
    : 'n/a';
  const maeText = Number.isFinite(Number(summary.mae))
    ? `${Math.round(Number(summary.mae))} ticks`
    : 'n/a';
  const mechanicsLine = buildReplayMechanicsEarbudLine(summary);
  return [
    `I'd mark ${replayDate} as valid under your original trading plan, and it finished ${outcomeWord}.`,
    mechanicsLine || `Let's note the key move: ${directionText} break, ${rangeText} ORB, MFE ${mfeText}, and MAE ${maeText}.`,
    'If this same structure repeats with clean confirmation timing, then it remains inside your edge model.',
  ].join(' ');
}

function buildReplayFullReply(summary = {}) {
  const replayDate = summary.replayDate || 'requested session';
  const rangeText = Number.isFinite(Number(summary.orbRangeTicks))
    ? `${Math.round(Number(summary.orbRangeTicks))}`
    : 'n/a';
  const retestText = summary.retestDetected ? 'yes' : 'no';
  const mfeText = Number.isFinite(Number(summary.mfe)) ? `${Math.round(Number(summary.mfe))}` : 'n/a';
  const maeText = Number.isFinite(Number(summary.mae)) ? `${Math.round(Number(summary.mae))}` : 'n/a';
  const skipReason = summary.skipReason ? humanizeReplayMissingReason(summary.skipReason) : 'n/a';
  const warningText = Array.isArray(summary.warnings) && summary.warnings.length > 0
    ? summary.warnings.join(', ')
    : 'none';
  const eligibilityText = Array.isArray(summary.eligibilityReasons) && summary.eligibilityReasons.length > 0
    ? summary.eligibilityReasons.join(' | ')
    : 'none';
  const mechanicsRows = Array.isArray(summary.mechanicsVariants)
    ? summary.mechanicsVariants
      .map((v) => `  - ${v.tpMode || 'Unknown'} (${v.stopMode || 'n/a'}): ${v.outcome || 'unknown'} | hit ${v.hitOrder || 'unknown'} | MFE ${Number.isFinite(Number(v.mfe)) ? Math.round(Number(v.mfe)) : 'n/a'} | MAE ${Number.isFinite(Number(v.mae)) ? Math.round(Number(v.mae)) : 'n/a'} | bars ${Number.isFinite(Number(v.barsToResolution)) ? Number(v.barsToResolution) : 'n/a'}`)
      .join('\n')
    : '';

  if (!summary.available) {
    const reason = humanizeReplayMissingReason(summary.missingReason || summary.skipReason || '');
    return [
      `Replay not computed for ${replayDate}.`,
      `Reason: ${reason}.`,
      `Bars source checked: ${summary.barsSourceUsed || 'none'}.`,
      `Warnings: ${warningText}.`,
      'Next: provide a valid session date or sync session bars, then ask replay again.',
    ].join('\n');
  }

  return [
    `Replay summary for ${replayDate}:`,
    `- Bars source: ${summary.barsSourceUsed || 'unknown'}`,
    `- Original plan eligible: ${summary.originalPlanEligible ? 'yes' : 'no'}`,
    `- Original plan blockers: ${(summary.originalPlanBlockers || []).join(' | ') || 'none'}`,
    `- Overlay eligible: ${summary.overlayEligible ? 'yes' : 'no'}`,
    `- Overlay blockers: ${(summary.overlayBlockers || []).join(' | ') || 'none'}`,
    `- Market outcome: ${summary.marketOutcome || 'unknown'}`,
    `- Original plan outcome: ${summary.originalPlanOutcome || 'unknown'}`,
    `- Overlay outcome: ${summary.overlayOutcome || 'unknown'}`,
    `- ORB range ticks: ${rangeText}`,
    `- Break direction: ${summary.breakDirection || 'n/a'}`,
    `- Retest detected: ${retestText}`,
    `- MFE ticks: ${mfeText}`,
    `- MAE ticks: ${maeText}`,
    `- Blocked by range filter: ${summary.blockedByRangeFilter ? 'yes' : 'no'}`,
    `- Blocked by time window: ${summary.blockedByTimeWindow ? 'yes' : 'no'}`,
    `- Blocked by retest rule: ${summary.blockedByRetestRule ? 'yes' : 'no'}`,
    `- Blocked by direction rule: ${summary.blockedByDirectionRule ? 'yes' : 'no'}`,
    `- Blocked by risk rule: ${summary.blockedByRiskRule ? 'yes' : 'no'}`,
    `- Eligibility reasons: ${eligibilityText}`,
    `- Skip reason: ${skipReason}`,
    `- Overlay assessment: ${summary?.overlayAssessment?.overlayName || 'n/a'} => ${summary?.overlayOutcome || 'n/a'}`,
    `- Variant assessment: ${summary?.variantAssessment?.variantName || 'n/a'} => ${summary?.variantAssessment?.variantOutcome || 'n/a'}`,
    `- Mechanics original variant: ${summary?.originalPlanMechanicsVariant?.tpMode || 'n/a'} => ${summary?.originalPlanMechanicsVariant?.outcome || 'n/a'}`,
    `- Mechanics best variant: ${summary?.bestMechanicsVariant?.tpMode || 'n/a'} => ${summary?.bestMechanicsVariant?.outcome || 'n/a'}`,
    `- Mechanics comparison: ${summary?.mechanicsComparisonSummary?.summaryLine || 'n/a'}`,
    '- Mechanics variants:',
    mechanicsRows || '  - none',
    `- Warnings: ${warningText}`,
  ].join('\n');
}

async function runJarvisTradingReplayTool(input = {}) {
  const trace = typeof input.trace === 'function' ? input.trace : () => {};
  const traceId = String(input.traceId || '').trim() || null;
  const message = String(input.message || '').trim();
  const jarvisIntent = String(input.intent || 'trading_hypothetical').trim().toLowerCase() || 'trading_hypothetical';
  const directTradingResultQuery = isDirectTradingResultQuery(message);
  const healthIndependentReviewQuery = jarvisIntent === 'trading_review' || directTradingResultQuery;
  const strategy = String(input.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const voiceBriefMode = String(input.voiceBriefMode || 'earbud').trim().toLowerCase() || 'earbud';
  const sessionKey = buildJarvisSessionKey(input);
  const auditMock = (JARVIS_AUDIT_ALLOW_MOCKS && input.auditMock && typeof input.auditMock === 'object')
    ? input.auditMock
    : null;
  const voiceSession = (input.voiceSessionState && typeof input.voiceSessionState === 'object')
    ? input.voiceSessionState
    : null;
  const ensureVoiceSessionHealth = typeof input.ensureVoiceSessionHealth === 'function'
    ? input.ensureVoiceSessionHealth
    : null;
  const voiceSessionHealth = healthIndependentReviewQuery
    ? (voiceSession || null)
    : ensureVoiceSessionHealth
      ? await ensureVoiceSessionHealth({
        sessionKey,
        sessionId: input.sessionId,
        clientId: input.clientId,
        symbol: String(config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase(),
        auditMock,
        intent: 'trading_replay',
        forceFresh: false,
        nonBlocking: true,
      }).catch(() => voiceSession)
      : voiceSession;
  const voiceSessionMeta = buildVoiceSessionMeta({
    session: voiceSessionHealth,
    healthStatus: null,
  });
  const replayMock = (auditMock && auditMock.replay && typeof auditMock.replay === 'object')
    ? auditMock.replay
    : null;
  const replayToolOut = replayMock
    ? {
      ok: replayMock.ok !== false && replayMock.data?.available === true,
      data: replayMock.data && typeof replayMock.data === 'object' ? replayMock.data : {},
      warnings: Array.isArray(replayMock.warnings) ? replayMock.warnings : [],
    }
    : await runReplayTool({
      message,
      intent: jarvisIntent,
      traceId,
      strategy,
      symbol: String(config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase(),
      deps: {
        loadAllSessions,
        getLiveBarsSnapshot,
        topstepBarToSessionCandle,
        aggregateOneMinuteCandlesToFiveMinute,
        processSession,
      },
    });
  const replayData = replayToolOut?.data && typeof replayToolOut.data === 'object' ? replayToolOut.data : {};
  const summary = buildReplayMetricsSummary(replayData, replayToolOut?.warnings);
  const layeredReplay = buildReplayVariantAssessment(summary);
  summary.originalPlanEligible = layeredReplay.originalPlanEligible;
  summary.originalPlanOutcome = layeredReplay.originalPlanOutcome;
  summary.variantAssessment = layeredReplay.variantAssessment;
  summary.strategyVariantComparison = layeredReplay.strategyVariantComparison;
  const missingReason = summary.missingReason || '';
  const replayHealthBlocked = (
    summary.available !== true
    && /\b(live bars|stale|fresh|health|unavailable)\b/i.test(String(missingReason))
  );
  const routePath = summary.available === true
    ? 'runJarvisTradingReplayTool.execute'
    : replayHealthBlocked
      ? 'runJarvisTradingReplayTool.health_block'
      : 'runJarvisTradingReplayTool.data_missing';
  const rawReply = voiceBriefMode === 'earbud' || voiceBriefMode === 'earpiece'
    ? (directTradingResultQuery
      ? buildDirectTradingResultReply(summary, message, { earbudMode: true })
      : buildReplayEarbudReply(summary))
    : (directTradingResultQuery
      ? buildDirectTradingResultReply(summary, message, { earbudMode: false })
      : buildReplayFullReply(summary));
  const reply = finalizeAssistantReplyForDelivery(String(rawReply || ''), {
    activeModule: 'analyst',
    voiceMode: true,
    voiceBriefMode,
    skipEarbudBrief: true,
    earbudSnapshot: {
      message,
      source: 'jarvis_replay_tool',
    },
    applyUserFacingNormalize: true,
  });
  const receipt = {
    traceId,
    tool: 'ReplayTool',
    barsSourceUsed: summary.barsSourceUsed,
    replayDate: summary.replayDate,
    strategyEligible: summary.strategyEligible === true,
    eligibilityReasons: summary.eligibilityReasons,
    originalPlanEligible: summary.originalPlanEligible === true,
    originalPlanBlockers: Array.isArray(summary.originalPlanBlockers) ? summary.originalPlanBlockers : [],
    originalPlanOutcome: summary.originalPlanOutcome || null,
    overlayEligible: summary.overlayEligible === true,
    overlayBlockers: Array.isArray(summary.overlayBlockers) ? summary.overlayBlockers : [],
    overlayOutcome: summary.overlayOutcome || null,
    overlayAssessment: summary.overlayAssessment || null,
    blockedByRangeFilter: summary.blockedByRangeFilter === true,
    blockedByTimeWindow: summary.blockedByTimeWindow === true,
    blockedByRetestRule: summary.blockedByRetestRule === true,
    blockedByDirectionRule: summary.blockedByDirectionRule === true,
    blockedByRiskRule: summary.blockedByRiskRule === true,
    marketOutcome: summary.marketOutcome,
    strategyOutcome: summary.strategyOutcome,
    variantAssessment: summary.variantAssessment || null,
    strategyVariantComparison: summary.strategyVariantComparison || null,
    mechanicsVariants: Array.isArray(summary.mechanicsVariants) ? summary.mechanicsVariants : [],
    originalPlanMechanicsVariant: summary.originalPlanMechanicsVariant || null,
    bestMechanicsVariant: summary.bestMechanicsVariant || null,
    mechanicsComparisonSummary: summary.mechanicsComparisonSummary || null,
    orbRangeTicks: summary.orbRangeTicks,
    breakDirection: summary.breakDirection,
    retestDetected: summary.retestDetected,
    mfe: summary.mfe,
    mae: summary.mae,
    hypotheticalOutcome: summary.hypotheticalOutcome,
    skipReason: summary.skipReason,
    warnings: summary.warnings,
    executed: summary.available === true,
  };
  return {
    reply,
    toolsUsed: ['ReplayTool'],
    activeModule: 'analyst',
    source: 'jarvis_replay_tool',
    routePath,
    precedenceMode: summary.available === true ? 'normal' : (replayHealthBlocked ? 'health_block' : 'normal'),
    healthStatus: replayHealthBlocked ? 'STALE' : null,
    riskVerdict: null,
    hasOpenPosition: false,
    nowMinutesEt: parseMinutesFromHHMM(nowInTimezone('America/New_York').time, null),
    hasORBComplete: Number.isFinite(Number(summary.orbRangeTicks)),
    liveBarsAvailable: String(summary.barsSourceUsed || '').toLowerCase() === 'topstep_live_1m',
    hasTodaySessionBars: null,
    minutesSinceLastBar: null,
    sessionDateOfData: summary.replayDate,
    todayEtDate: nowInTimezone('America/New_York').date,
    staleThresholdMinutes: getAnalystFreshnessLagThresholdMinutes(),
    voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
    lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
    healthStatusUsed: voiceSessionMeta.healthStatusUsed,
    timePhase: voiceSessionMeta.timePhase,
    decisionBlockedBy: replayHealthBlocked ? 'health' : 'none',
    strategyEligible: summary.strategyEligible === true,
    originalPlanEligible: summary.originalPlanEligible === true,
    originalPlanBlockers: Array.isArray(summary.originalPlanBlockers) ? summary.originalPlanBlockers : [],
    originalPlanOutcome: summary.originalPlanOutcome || null,
    overlayEligible: summary.overlayEligible === true,
    overlayBlockers: Array.isArray(summary.overlayBlockers) ? summary.overlayBlockers : [],
    overlayOutcome: summary.overlayOutcome || null,
    overlayAssessment: summary.overlayAssessment || null,
    marketOutcome: summary.marketOutcome,
    strategyOutcome: summary.strategyOutcome,
    eligibilityReasons: summary.eligibilityReasons,
    blockedByRangeFilter: summary.blockedByRangeFilter === true,
    blockedByTimeWindow: summary.blockedByTimeWindow === true,
    blockedByRetestRule: summary.blockedByRetestRule === true,
    blockedByDirectionRule: summary.blockedByDirectionRule === true,
    blockedByRiskRule: summary.blockedByRiskRule === true,
    variantAssessment: summary.variantAssessment || null,
    strategyVariantComparison: summary.strategyVariantComparison || null,
    mechanicsVariants: Array.isArray(summary.mechanicsVariants) ? summary.mechanicsVariants : [],
    originalPlanMechanicsVariant: summary.originalPlanMechanicsVariant || null,
    bestMechanicsVariant: summary.bestMechanicsVariant || null,
    mechanicsComparisonSummary: summary.mechanicsComparisonSummary || null,
    replay: replayData,
    replaySummary: summary,
    toolReceipts: [receipt],
    commandsExecuted: [],
    clientActions: [],
  };
}

async function runJarvisTradingDecisionTool(input = {}) {
  const trace = typeof input.trace === 'function' ? input.trace : () => {};
  const traceId = String(input.traceId || '').trim() || null;
  const message = String(input.message || '').trim();
  const jarvisIntent = String(input.intent || 'trading_decision').trim().toLowerCase() || 'trading_decision';
  const strategy = String(input.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const voiceBriefMode = String(input.voiceBriefMode || 'earbud').trim().toLowerCase() || 'earbud';
  const preferCachedLive = input.preferCachedLive === true;
  const intents = parseAssistantQuickIntents(message);
  const sessionKey = buildJarvisSessionKey(input);
  const auditMock = (JARVIS_AUDIT_ALLOW_MOCKS && input.auditMock && typeof input.auditMock === 'object')
    ? input.auditMock
    : null;
  const voiceSession = (input.voiceSessionState && typeof input.voiceSessionState === 'object')
    ? input.voiceSessionState
    : null;
  const ensureVoiceSessionHealth = typeof input.ensureVoiceSessionHealth === 'function'
    ? input.ensureVoiceSessionHealth
    : null;
  const voiceSessionHealth = ensureVoiceSessionHealth
    ? await ensureVoiceSessionHealth({
      sessionKey,
      sessionId: input.sessionId,
      clientId: input.clientId,
      symbol: String(config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase(),
      auditMock,
      intent: 'trading_decision',
      forceFresh: false,
      nonBlocking: true,
    }).catch(() => voiceSession)
    : voiceSession;
  const marketHealthSnapshotForTool = (voiceSessionHealth && typeof voiceSessionHealth === 'object')
    ? (voiceSessionHealth.snapshotUsed || voiceSessionHealth.lastHealthSnapshot || null)
    : null;

  if (isExplainFollowup(message)) {
    const cachedRiskTool = getRiskExplain(sessionKey);
    const cachedLegacy = getRecentJarvisGuardrailDecision(sessionKey);
    const detailPayload = cachedRiskTool?.payload || null;
    const detailRiskState = detailPayload?.riskState || cachedLegacy?.riskState || null;
    const detailReplyText = String(
      detailPayload?.explainPayload
      || (detailRiskState ? buildAnalystRiskGuardrailReply(detailRiskState, { voiceBriefMode: 'full' }) : '')
    ).trim();
    if (detailRiskState && detailReplyText) {
      trace('jarvis_guardrail_explain_followup', {
        routePath: 'runJarvisTradingDecisionTool.explain_followup',
        source: 'jarvis_risk_guardrail_explain',
      });
      return {
        reply: finalizeAssistantReplyForDelivery(detailReplyText, {
          activeModule: 'analyst',
          voiceMode: true,
          voiceBriefMode: 'full',
          skipEarbudBrief: true,
          applyUserFacingNormalize: true,
        }),
        toolsUsed: ['RiskTool', 'Analyst'],
        activeModule: 'analyst',
        source: 'jarvis_risk_guardrail_explain',
        routePath: 'runJarvisTradingDecisionTool.explain_followup',
        riskState: detailRiskState,
        commandsExecuted: [],
        clientActions: [],
      };
    }
  }

  const finalizeAnalyst = (rawText, options = {}) => finalizeAssistantReplyForDelivery(String(rawText || ''), {
    activeModule: 'analyst',
    voiceMode: true,
    voiceBriefMode,
    skipEarbudBrief: true,
    earbudSnapshot: {
      message,
      source: String(options.source || 'jarvis_orchestrator').trim() || 'jarvis_orchestrator',
    },
    applyUserFacingNormalize: true,
  });

  const healthToolOut = await runHealthTool({
    message,
    strategy,
    activeModule: 'analyst',
    symbol: String(config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase(),
    intents,
    auditMock,
    marketHealthSnapshot: marketHealthSnapshotForTool,
    forceFresh: false,
    deps: {
      parseAssistantQuickIntents,
      getAnalystVoiceHealthPreflightBlock,
      getMarketHealthSnapshotCached,
      buildVoiceHealthBlockedReply,
    },
  });
  const riskToolOut = await runRiskTool({
    message,
    strategy,
    activeModule: 'analyst',
    voiceBriefMode: 'full',
    preferCachedLive,
    sessionId: input.sessionId,
    clientId: input.clientId,
    sessionKey,
    intents,
    healthCtx: healthToolOut?.data?.healthCtx || null,
    auditMock,
    deps: {
      parseAssistantQuickIntents,
      buildAnalystRiskStateRuntime,
      getAnalystVoiceHealthPreflightBlock,
      resolveAnalystPrecedence,
      buildAnalystRiskGuardrailReply,
      buildJarvisMockRiskState,
    },
  });
  const analystRiskCtx = riskToolOut?.data?.analystRiskCtx || null;
  const healthCtx = riskToolOut?.data?.healthCtx || healthToolOut?.data?.healthCtx || null;
  const healthData = healthToolOut?.data || null;
  const riskState = analystRiskCtx?.riskState || riskToolOut?.data?.riskState || null;
  const fallbackNowEt = nowInTimezone('America/New_York');
  const healthFreshness = {
    hasTodaySessionBars: typeof healthData?.hasTodaySessionBars === 'boolean'
      ? healthData.hasTodaySessionBars
      : (riskState?.marketDataFreshness?.hasTodaySessionBars ?? null),
    minutesSinceLastBar: Number.isFinite(Number(healthData?.minutesSinceLastBar))
      ? Number(healthData.minutesSinceLastBar)
      : null,
    sessionDateOfData: String(
      healthData?.sessionDateOfData
      || riskState?.marketDataFreshness?.sessionDateOfData
      || ''
    ).trim() || null,
    todayEtDate: String(
      healthData?.todayEtDate
      || riskState?.marketDataFreshness?.nowEt?.date
      || fallbackNowEt.date
    ).trim() || null,
    staleThresholdMinutes: Number.isFinite(Number(healthData?.staleThresholdMinutes))
      ? Number(healthData.staleThresholdMinutes)
      : getAnalystFreshnessLagThresholdMinutes(),
  };
  const precedence = { mode: String(riskToolOut?.data?.precedenceMode || 'normal') };
  const decisionBlockedBy = resolveDecisionBlockedBy(precedence.mode);
  const voiceSessionMeta = buildVoiceSessionMeta({
    session: voiceSessionHealth,
    healthStatus: healthCtx?.status || null,
  });
  trace('jarvis_precedence_resolved', {
    routePath: 'runJarvisTradingDecisionTool.precedence',
    source: 'jarvis_trading_decision',
    precedenceMode: precedence.mode,
    healthStatus: healthCtx?.status || null,
    riskVerdict: riskState?.riskVerdict || null,
    hasOpenPosition: riskState?.hasOpenPosition === true,
    decisionBlockedBy,
    voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
    lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
    healthStatusUsed: voiceSessionMeta.healthStatusUsed,
    timePhase: voiceSessionMeta.timePhase,
  });

  if (precedence.mode === 'position') {
    const reply = buildAnalystRiskGuardrailReply(riskState || {}, { voiceBriefMode: 'full' });
    rememberJarvisGuardrailDecision(sessionKey, riskState || {}, {
      source: 'jarvis_position_management',
      message,
      precedenceMode: precedence.mode,
    });
    return {
      reply: finalizeAnalyst(reply, { source: 'assistant_position_management' }),
      toolsUsed: ['RiskTool', 'Analyst'],
      activeModule: 'analyst',
      source: 'assistant_position_management',
      routePath: 'runJarvisTradingDecisionTool.position',
      precedenceMode: precedence.mode,
      healthStatus: healthCtx?.status || null,
      riskVerdict: riskState?.riskVerdict || null,
      hasOpenPosition: true,
      riskState: riskState || null,
      hasTodaySessionBars: healthFreshness.hasTodaySessionBars,
      minutesSinceLastBar: healthFreshness.minutesSinceLastBar,
      sessionDateOfData: healthFreshness.sessionDateOfData,
      todayEtDate: healthFreshness.todayEtDate,
      staleThresholdMinutes: healthFreshness.staleThresholdMinutes,
      voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
      lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
      healthStatusUsed: voiceSessionMeta.healthStatusUsed || (healthCtx?.status || null),
      timePhase: voiceSessionMeta.timePhase,
      decisionBlockedBy,
      commandsExecuted: [],
      clientActions: [],
    };
  }

  if (precedence.mode === 'health_block' && healthCtx?.blocked) {
    let canonicalAssistantDecisionBrief = null;
    let canonicalAssistantDecisionBriefText = '';
    try {
      canonicalAssistantDecisionBrief = await buildCanonicalAssistantDecisionBrief({ forceFresh: false });
      canonicalAssistantDecisionBriefText = String(
        canonicalAssistantDecisionBrief?.assistantText
        || canonicalAssistantDecisionBrief?.assistantDecisionBriefText
        || ''
      ).trim();
    } catch {
      canonicalAssistantDecisionBrief = null;
      canonicalAssistantDecisionBriefText = '';
    }
    const mergedHealthBlockedReply = mergeHealthBlockedDecisionReply({
      healthReply: String(healthCtx.reply || ''),
      canonicalBriefText: canonicalAssistantDecisionBriefText,
    });
    return {
      reply: finalizeAnalyst(mergedHealthBlockedReply, { source: 'assistant_voice_health_preflight' }),
      toolsUsed: ['RiskTool', 'Health'],
      activeModule: 'analyst',
      source: 'assistant_voice_health_preflight',
      routePath: 'runJarvisTradingDecisionTool.health_block',
      precedenceMode: precedence.mode,
      healthStatus: healthCtx?.status || null,
      riskVerdict: riskState?.riskVerdict || null,
      hasOpenPosition: riskState?.hasOpenPosition === true,
      marketHealth: healthData?.marketHealthSnapshot || healthCtx.health || null,
      riskState: riskState || null,
      hasTodaySessionBars: healthFreshness.hasTodaySessionBars,
      minutesSinceLastBar: healthFreshness.minutesSinceLastBar,
      sessionDateOfData: healthFreshness.sessionDateOfData,
      todayEtDate: healthFreshness.todayEtDate,
      staleThresholdMinutes: healthFreshness.staleThresholdMinutes,
      voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
      lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
      healthStatusUsed: voiceSessionMeta.healthStatusUsed || (healthCtx?.status || null),
      timePhase: voiceSessionMeta.timePhase,
      decisionBlockedBy,
      assistantDecisionBriefText: canonicalAssistantDecisionBriefText || null,
      assistantDecisionBrief: (
        canonicalAssistantDecisionBrief
        && typeof canonicalAssistantDecisionBrief === 'object'
      ) ? canonicalAssistantDecisionBrief : null,
      commandsExecuted: [],
      clientActions: [],
    };
  }

  if (precedence.mode === 'risk_block') {
    const reply = buildAnalystRiskGuardrailReply(riskState || {}, { voiceBriefMode: 'full' });
    rememberJarvisGuardrailDecision(sessionKey, riskState || {}, {
      source: 'jarvis_risk_guardrail',
      message,
      precedenceMode: precedence.mode,
    });
    return {
      reply: finalizeAnalyst(reply, { source: 'assistant_risk_guardrail' }),
      toolsUsed: ['RiskTool', 'Analyst'],
      activeModule: 'analyst',
      source: 'assistant_risk_guardrail',
      routePath: 'runJarvisTradingDecisionTool.risk_block',
      precedenceMode: precedence.mode,
      healthStatus: healthCtx?.status || null,
      riskVerdict: riskState?.riskVerdict || null,
      hasOpenPosition: riskState?.hasOpenPosition === true,
      riskState: riskState || null,
      hasTodaySessionBars: healthFreshness.hasTodaySessionBars,
      minutesSinceLastBar: healthFreshness.minutesSinceLastBar,
      sessionDateOfData: healthFreshness.sessionDateOfData,
      todayEtDate: healthFreshness.todayEtDate,
      staleThresholdMinutes: healthFreshness.staleThresholdMinutes,
      voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
      lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
      healthStatusUsed: voiceSessionMeta.healthStatusUsed || (healthCtx?.status || null),
      timePhase: voiceSessionMeta.timePhase,
      decisionBlockedBy,
      commandsExecuted: [],
      clientActions: [],
    };
  }

  const withRiskWaitPrefix = (text) => {
    if (!riskState || riskState.riskVerdict !== 'WAIT') return String(text || '');
    return applyAnalystRiskWaitPrefix(String(text || ''), riskState, { voiceBriefMode });
  };

  const analystToolOut = await runAnalystTool({
    mode: 'decision',
    message,
    strategy,
    activeModule: 'analyst',
    traceId,
    voiceMode: true,
    voiceBriefMode,
    preferCachedLive,
    auditMock,
    deps: {
      runAssistantUnifiedQuery,
      buildTradingCommandSnapshot,
      buildAssistantIntelligenceSnapshot,
      buildCanonicalAssistantDecisionBrief,
      parseMinutesFromHHMM,
    },
  });
  const analystData = analystToolOut?.data || {};
  const out = analystData.unified || {};

  const tools = new Set(['RiskTool', 'AnalystTool', 'Analyst']);
  if (String(analystData?.modeSource || out?.mode || '').toLowerCase() === 'orchestrator') tools.add('Bridge');
  if (Array.isArray(analystData?.commandsExecuted) && analystData.commandsExecuted.length > 0) tools.add('Execution');
  if (analystData?.terminal) tools.add('RepoOps');
  const freshness = analystData?.marketDataFreshness || analystRiskCtx?.marketDataFreshness || riskState?.marketDataFreshness || null;
  const nowMinutesEt = Number.isFinite(analystData?.nowMinutesEt)
    ? analystData.nowMinutesEt
    : parseMinutesFromHHMM(freshness?.nowEt?.time || nowInTimezone('America/New_York').time, null);
  const liveBarsAvailable = analystData?.liveBarsAvailable === true
    || freshness?.usedLiveBars === true
    || (freshness?.hasTodaySessionBars === true && Number(freshness?.minutesSinceLastCandle) <= 5);
  const primaryReason = summarizePrimaryRiskReason(riskState || {});
  const voiceSessionMetaResolved = buildVoiceSessionMeta({
    session: voiceSessionHealth,
    nowMinutesEt,
    healthStatus: healthCtx?.status || null,
  });
  const canonicalBriefReply = String(analystData?.assistantDecisionBriefText || '').trim();
  const baseDecisionReply = canonicalBriefReply || String(analystData?.reply || out?.reply || '');
  const finalDecisionReply = canonicalBriefReply
    ? baseDecisionReply
    : withRiskWaitPrefix(baseDecisionReply);
  return {
    reply: finalizeAnalyst(finalDecisionReply, { source: analystData?.source || out?.source || 'assistant_query' }),
    toolsUsed: Array.from(tools),
    activeModule: 'analyst',
    source: analystData?.source || out?.source || 'assistant_query',
    routePath: 'runJarvisTradingDecisionTool.normal',
    precedenceMode: precedence.mode,
    healthStatus: healthCtx?.status || null,
    riskVerdict: riskState?.riskVerdict || null,
    hasOpenPosition: riskState?.hasOpenPosition === true,
    nowMinutesEt,
    hasORBComplete: freshness?.hasORBComplete === true,
    liveBarsAvailable,
    hasTodaySessionBars: healthFreshness.hasTodaySessionBars,
    minutesSinceLastBar: healthFreshness.minutesSinceLastBar,
    sessionDateOfData: healthFreshness.sessionDateOfData,
    todayEtDate: healthFreshness.todayEtDate,
    staleThresholdMinutes: healthFreshness.staleThresholdMinutes,
    voiceSessionModeActive: voiceSessionMetaResolved.voiceSessionModeActive === true,
    lastHealthAgeSeconds: voiceSessionMetaResolved.lastHealthAgeSeconds,
    healthStatusUsed: voiceSessionMetaResolved.healthStatusUsed || (healthCtx?.status || null),
    timePhase: voiceSessionMetaResolved.timePhase,
    decisionBlockedBy,
    primaryReason: primaryReason.label,
    primaryReasonCode: primaryReason.code,
    cooldownRemainingMinutes: Number(riskState?.cooldownRemainingMinutes || 0),
    riskState: riskState || null,
    commandsExecuted: Array.isArray(analystData?.commandsExecuted) ? analystData.commandsExecuted : (Array.isArray(out?.commandsExecuted) ? out.commandsExecuted : []),
    clientActions: Array.isArray(analystData?.clientActions) ? analystData.clientActions : (Array.isArray(out?.clientActions) ? out.clientActions : []),
    planner: analystData?.planner || out?.planner || null,
    terminal: analystData?.terminal || out?.terminal || null,
  };
}

async function runJarvisTradingStatusTool(input = {}) {
  const trace = typeof input.trace === 'function' ? input.trace : () => {};
  const traceId = String(input.traceId || '').trim() || null;
  const strategy = String(input.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const message = String(input.message || '').trim();
  const voiceBriefMode = String(input.voiceBriefMode || 'earbud').trim().toLowerCase() || 'earbud';
  const preferCachedLive = input.preferCachedLive === true;
  const intents = parseAssistantQuickIntents(message);
  const sessionKey = buildJarvisSessionKey(input);
  const auditMock = (JARVIS_AUDIT_ALLOW_MOCKS && input.auditMock && typeof input.auditMock === 'object')
    ? input.auditMock
    : null;
  const voiceSession = (input.voiceSessionState && typeof input.voiceSessionState === 'object')
    ? input.voiceSessionState
    : null;
  const ensureVoiceSessionHealth = typeof input.ensureVoiceSessionHealth === 'function'
    ? input.ensureVoiceSessionHealth
    : null;
  const voiceSessionHealth = ensureVoiceSessionHealth
    ? await ensureVoiceSessionHealth({
      sessionKey,
      sessionId: input.sessionId,
      clientId: input.clientId,
      symbol: String(config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase(),
      auditMock,
      intent: 'trading_status',
      forceFresh: false,
      nonBlocking: true,
    }).catch(() => voiceSession)
    : voiceSession;
  const marketHealthSnapshotForTool = (voiceSessionHealth && typeof voiceSessionHealth === 'object')
    ? (voiceSessionHealth.snapshotUsed || voiceSessionHealth.lastHealthSnapshot || null)
    : null;

  if (isExplainFollowup(message)) {
    const cachedRiskTool = getRiskExplain(sessionKey);
    const cachedLegacy = getRecentJarvisGuardrailDecision(sessionKey);
    const detailPayload = cachedRiskTool?.payload || null;
    const detailRiskState = detailPayload?.riskState || cachedLegacy?.riskState || null;
    const detailReply = String(
      detailPayload?.explainPayload
      || (detailRiskState ? buildAnalystRiskGuardrailReply(detailRiskState, { voiceBriefMode: 'full' }) : '')
    ).trim();
    if (detailReply) {
      return {
        reply: finalizeAssistantReplyForDelivery(detailReply, {
          activeModule: 'analyst',
          voiceMode: true,
          voiceBriefMode: 'full',
          skipEarbudBrief: true,
          applyUserFacingNormalize: true,
        }),
        toolsUsed: ['RiskTool', 'Analyst'],
        activeModule: 'analyst',
        source: 'jarvis_risk_guardrail_explain',
        routePath: 'runJarvisTradingStatusTool.explain_followup',
        riskState: detailRiskState,
        commandsExecuted: [],
        clientActions: [],
      };
    }
  }

  const healthToolOut = await runHealthTool({
    message,
    strategy,
    activeModule: 'analyst',
    symbol: String(config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase(),
    intents,
    auditMock,
    marketHealthSnapshot: marketHealthSnapshotForTool,
    forceFresh: false,
    deps: {
      parseAssistantQuickIntents,
      getAnalystVoiceHealthPreflightBlock,
      getMarketHealthSnapshotCached,
      buildVoiceHealthBlockedReply,
    },
  });
  const riskToolOut = await runRiskTool({
    message,
    strategy,
    activeModule: 'analyst',
    voiceBriefMode: 'full',
    preferCachedLive,
    sessionId: input.sessionId,
    clientId: input.clientId,
    sessionKey,
    intents,
    healthCtx: healthToolOut?.data?.healthCtx || null,
    auditMock,
    deps: {
      parseAssistantQuickIntents,
      buildAnalystRiskStateRuntime,
      getAnalystVoiceHealthPreflightBlock,
      resolveAnalystPrecedence,
      buildAnalystRiskGuardrailReply,
      buildJarvisMockRiskState,
    },
  });
  const analystRiskCtx = riskToolOut?.data?.analystRiskCtx || null;
  const healthCtx = riskToolOut?.data?.healthCtx || healthToolOut?.data?.healthCtx || null;
  const healthData = healthToolOut?.data || null;
  const riskState = analystRiskCtx?.riskState || riskToolOut?.data?.riskState || null;
  const fallbackNowEt = nowInTimezone('America/New_York');
  const healthFreshness = {
    hasTodaySessionBars: typeof healthData?.hasTodaySessionBars === 'boolean'
      ? healthData.hasTodaySessionBars
      : (riskState?.marketDataFreshness?.hasTodaySessionBars ?? null),
    minutesSinceLastBar: Number.isFinite(Number(healthData?.minutesSinceLastBar))
      ? Number(healthData.minutesSinceLastBar)
      : null,
    sessionDateOfData: String(
      healthData?.sessionDateOfData
      || riskState?.marketDataFreshness?.sessionDateOfData
      || ''
    ).trim() || null,
    todayEtDate: String(
      healthData?.todayEtDate
      || riskState?.marketDataFreshness?.nowEt?.date
      || fallbackNowEt.date
    ).trim() || null,
    staleThresholdMinutes: Number.isFinite(Number(healthData?.staleThresholdMinutes))
      ? Number(healthData.staleThresholdMinutes)
      : getAnalystFreshnessLagThresholdMinutes(),
  };
  const precedence = { mode: String(riskToolOut?.data?.precedenceMode || 'normal') };
  const decisionBlockedBy = resolveDecisionBlockedBy(precedence.mode);
  const voiceSessionMeta = buildVoiceSessionMeta({
    session: voiceSessionHealth,
    healthStatus: healthCtx?.status || null,
  });
  trace('jarvis_precedence_resolved', {
    routePath: 'runJarvisTradingStatusTool.precedence',
    source: 'jarvis_trading_status',
    precedenceMode: precedence.mode,
    healthStatus: healthCtx?.status || null,
    riskVerdict: riskState?.riskVerdict || null,
    hasOpenPosition: riskState?.hasOpenPosition === true,
    decisionBlockedBy,
    voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
    lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
    healthStatusUsed: voiceSessionMeta.healthStatusUsed,
    timePhase: voiceSessionMeta.timePhase,
  });

  const finalize = (rawText, options = {}) => finalizeAssistantReplyForDelivery(String(rawText || ''), {
    activeModule: 'analyst',
    voiceMode: true,
    voiceBriefMode,
    skipEarbudBrief: true,
    earbudSnapshot: {
      message,
      source: String(options.source || 'jarvis_trading_status').trim() || 'jarvis_trading_status',
    },
    applyUserFacingNormalize: true,
  });

  const statusPromptShape = classifyTradingStatusPromptShape(message);
  let canonicalAssistantDecisionBrief = null;
  let canonicalAssistantDecisionBriefText = '';
  let canonicalStatusReply = null;
  if (statusPromptShape && !(riskState?.hasOpenPosition === true)) {
    try {
      canonicalAssistantDecisionBrief = await buildCanonicalAssistantDecisionBrief({ forceFresh: false });
      canonicalAssistantDecisionBriefText = String(
        canonicalAssistantDecisionBrief?.assistantText
        || canonicalAssistantDecisionBrief?.assistantDecisionBriefText
        || ''
      ).trim();
      canonicalStatusReply = buildTradingStatusReplyFromCanonicalBrief({
        shape: statusPromptShape,
        briefObject: canonicalAssistantDecisionBrief,
        briefText: canonicalAssistantDecisionBriefText,
      });
    } catch {
      canonicalAssistantDecisionBrief = null;
      canonicalAssistantDecisionBriefText = '';
      canonicalStatusReply = null;
    }
  }

  if (precedence.mode === 'position') {
    const reply = buildAnalystRiskGuardrailReply(riskState || {}, { voiceBriefMode: 'full' });
    rememberJarvisGuardrailDecision(sessionKey, riskState || {}, {
      source: 'jarvis_position_management',
      message,
      precedenceMode: precedence.mode,
    });
    return {
      reply: finalize(canonicalStatusReply || reply, { source: 'jarvis_position_management' }),
      toolsUsed: ['RiskTool', 'Bridge', 'Analyst'],
      activeModule: 'analyst',
      source: 'jarvis_position_management',
      routePath: 'runJarvisTradingStatusTool.position',
      precedenceMode: precedence.mode,
      healthStatus: healthCtx?.status || null,
      riskVerdict: riskState?.riskVerdict || null,
      hasOpenPosition: true,
      riskState: riskState || null,
      hasTodaySessionBars: healthFreshness.hasTodaySessionBars,
      minutesSinceLastBar: healthFreshness.minutesSinceLastBar,
      sessionDateOfData: healthFreshness.sessionDateOfData,
      todayEtDate: healthFreshness.todayEtDate,
      staleThresholdMinutes: healthFreshness.staleThresholdMinutes,
      voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
      lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
      healthStatusUsed: voiceSessionMeta.healthStatusUsed || (healthCtx?.status || null),
      timePhase: voiceSessionMeta.timePhase,
      decisionBlockedBy,
      assistantDecisionBriefText: canonicalAssistantDecisionBriefText || null,
      assistantDecisionBrief: (
        canonicalAssistantDecisionBrief
        && typeof canonicalAssistantDecisionBrief === 'object'
      ) ? canonicalAssistantDecisionBrief : null,
      commandsExecuted: [],
      clientActions: [],
    };
  }

  if (precedence.mode === 'health_block' && healthCtx?.blocked) {
    return {
      reply: finalize(canonicalStatusReply || healthCtx.reply, { source: 'jarvis_health_block' }),
      toolsUsed: ['RiskTool', 'Health', 'Bridge'],
      activeModule: 'analyst',
      source: 'jarvis_health_block',
      routePath: 'runJarvisTradingStatusTool.health_block',
      precedenceMode: precedence.mode,
      healthStatus: healthCtx?.status || null,
      riskVerdict: riskState?.riskVerdict || null,
      hasOpenPosition: false,
      marketHealth: healthData?.marketHealthSnapshot || healthCtx.health || null,
      riskState: riskState || null,
      hasTodaySessionBars: healthFreshness.hasTodaySessionBars,
      minutesSinceLastBar: healthFreshness.minutesSinceLastBar,
      sessionDateOfData: healthFreshness.sessionDateOfData,
      todayEtDate: healthFreshness.todayEtDate,
      staleThresholdMinutes: healthFreshness.staleThresholdMinutes,
      voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
      lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
      healthStatusUsed: voiceSessionMeta.healthStatusUsed || (healthCtx?.status || null),
      timePhase: voiceSessionMeta.timePhase,
      decisionBlockedBy,
      assistantDecisionBriefText: canonicalAssistantDecisionBriefText || null,
      assistantDecisionBrief: (
        canonicalAssistantDecisionBrief
        && typeof canonicalAssistantDecisionBrief === 'object'
      ) ? canonicalAssistantDecisionBrief : null,
      commandsExecuted: [],
      clientActions: [],
    };
  }

  if (precedence.mode === 'risk_block') {
    const reply = buildAnalystRiskGuardrailReply(riskState || {}, { voiceBriefMode: 'full' });
    rememberJarvisGuardrailDecision(sessionKey, riskState || {}, {
      source: 'jarvis_risk_guardrail',
      message,
      precedenceMode: precedence.mode,
    });
    return {
      reply: finalize(canonicalStatusReply || reply, { source: 'jarvis_risk_guardrail' }),
      toolsUsed: ['RiskTool', 'Bridge', 'Analyst'],
      activeModule: 'analyst',
      source: 'jarvis_risk_guardrail',
      routePath: 'runJarvisTradingStatusTool.risk_block',
      precedenceMode: precedence.mode,
      healthStatus: healthCtx?.status || null,
      riskVerdict: riskState?.riskVerdict || null,
      hasOpenPosition: false,
      riskState: riskState || null,
      hasTodaySessionBars: healthFreshness.hasTodaySessionBars,
      minutesSinceLastBar: healthFreshness.minutesSinceLastBar,
      sessionDateOfData: healthFreshness.sessionDateOfData,
      todayEtDate: healthFreshness.todayEtDate,
      staleThresholdMinutes: healthFreshness.staleThresholdMinutes,
      voiceSessionModeActive: voiceSessionMeta.voiceSessionModeActive === true,
      lastHealthAgeSeconds: voiceSessionMeta.lastHealthAgeSeconds,
      healthStatusUsed: voiceSessionMeta.healthStatusUsed || (healthCtx?.status || null),
      timePhase: voiceSessionMeta.timePhase,
      decisionBlockedBy,
      assistantDecisionBriefText: canonicalAssistantDecisionBriefText || null,
      assistantDecisionBrief: (
        canonicalAssistantDecisionBrief
        && typeof canonicalAssistantDecisionBrief === 'object'
      ) ? canonicalAssistantDecisionBrief : null,
      commandsExecuted: [],
      clientActions: [],
    };
  }

  const analystToolOut = await runAnalystTool({
    mode: 'status',
    message,
    strategy,
    activeModule: 'analyst',
    voiceBriefMode,
    preferCachedLive,
    auditMock,
    hasOpenPosition: riskState?.hasOpenPosition === true,
    positionSide: riskState?.openPosition?.side || null,
    cmdSnapshot: analystRiskCtx?.cmdSnapshot || null,
    intelligenceSnapshot: analystRiskCtx?.intelligenceSnapshot || null,
    deps: {
      runTopstepReadOnlySync,
      buildTradingCommandSnapshot,
      buildAssistantIntelligenceSnapshot,
      parseMinutesFromHHMM,
    },
  });
  const analystData = analystToolOut?.data || {};
  const marketFreshness = analystData?.marketDataFreshness || analystRiskCtx?.marketDataFreshness || riskState?.marketDataFreshness || null;
  const nowMinutesEt = Number.isFinite(analystData?.nowMinutesEt)
    ? analystData.nowMinutesEt
    : parseMinutesFromHHMM(marketFreshness?.nowEt?.time || nowInTimezone('America/New_York').time, null);
  const liveBarsAvailable = analystData?.liveBarsAvailable === true
    || marketFreshness?.usedLiveBars === true
    || (marketFreshness?.hasTodaySessionBars === true && Number(marketFreshness?.minutesSinceLastCandle) <= 5);
  const primaryReason = summarizePrimaryRiskReason(riskState || {});
  const voiceSessionMetaResolved = buildVoiceSessionMeta({
    session: voiceSessionHealth,
    nowMinutesEt,
    healthStatus: healthCtx?.status || null,
  });

  return {
    reply: finalize(canonicalStatusReply || analystData?.reply, { source: analystData?.source || 'jarvis_trading_status' }),
    toolsUsed: ['RiskTool', 'HealthTool', 'Bridge', 'AnalystTool', 'Analyst', 'Health'],
    activeModule: 'analyst',
    source: analystData?.source || 'jarvis_trading_status',
    routePath: 'runJarvisTradingStatusTool.normal',
    precedenceMode: precedence.mode,
    healthStatus: healthCtx?.status || null,
    riskVerdict: riskState?.riskVerdict || null,
    hasOpenPosition: riskState?.hasOpenPosition === true,
    nowMinutesEt,
    hasORBComplete: analystData?.hasORBComplete === true || marketFreshness?.hasORBComplete === true,
    liveBarsAvailable,
    hasTodaySessionBars: healthFreshness.hasTodaySessionBars,
    minutesSinceLastBar: healthFreshness.minutesSinceLastBar,
    sessionDateOfData: healthFreshness.sessionDateOfData,
    todayEtDate: healthFreshness.todayEtDate,
    staleThresholdMinutes: healthFreshness.staleThresholdMinutes,
    voiceSessionModeActive: voiceSessionMetaResolved.voiceSessionModeActive === true,
    lastHealthAgeSeconds: voiceSessionMetaResolved.lastHealthAgeSeconds,
    healthStatusUsed: voiceSessionMetaResolved.healthStatusUsed || (healthCtx?.status || null),
    timePhase: voiceSessionMetaResolved.timePhase,
    decisionBlockedBy,
    primaryReason: primaryReason.label,
    primaryReasonCode: primaryReason.code,
    riskState: riskState || null,
    assistantDecisionBriefText: canonicalAssistantDecisionBriefText || null,
    assistantDecisionBrief: (
      canonicalAssistantDecisionBrief
      && typeof canonicalAssistantDecisionBrief === 'object'
    ) ? canonicalAssistantDecisionBrief : null,
    commandsExecuted: [],
    clientActions: [],
  };
}

async function runJarvisCodeChangeTool(input = {}) {
  const trace = typeof input.trace === 'function' ? input.trace : () => {};
  const strategy = String(input.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const contextHint = normalizeDashboardModuleId(input.contextHint || input.activeModule) || 'bridge';
  trace('jarvis_code_change_start', {
    routePath: 'runJarvisCodeChangeTool.start',
    source: 'jarvis_code_change',
    contextHint,
  });
    const out = await runDashboardAgentOrchestrator({
      message: input.message,
      strategy,
      activeModule: contextHint,
      traceId: String(input.traceId || '').trim() || null,
    });
  trace('jarvis_code_change_end', {
    routePath: 'runJarvisCodeChangeTool.end',
    source: out?.source || 'jarvis_code_change',
  });
  return {
    reply: String(out?.reply || '').trim() || 'Code-change router is online, but no action was executed.',
    toolsUsed: ['Codex', 'RepoOps'],
    activeModule: contextHint,
    source: out?.source || 'dashboard_agent',
    routePath: 'runJarvisCodeChangeTool',
    commandsExecuted: Array.isArray(out?.commandsExecuted) ? out.commandsExecuted : [],
    clientActions: Array.isArray(out?.clientActions) ? out.clientActions : [],
    planner: out?.planner || null,
    terminal: out?.terminal || null,
  };
}

async function runJarvisWebQuestionTool(input = {}) {
  const trace = typeof input.trace === 'function' ? input.trace : () => {};
  const intent = String(input.intent || 'web_question').trim().toLowerCase() || 'web_question';
  const message = String(input.message || '').trim();
  const originalQuery = String(input.originalQuery || message).trim();
  const normalizedQuery = String(input.normalizedQuery || input.queryUsed || message).trim();
  const queryUsed = String(input.queryUsed || message).trim();
  const categoryHint = String(input.categoryHint || '').trim() || null;
  const locationRequired = input.locationRequired === true;
  const userLocationHint = (input.userLocationHint && typeof input.userLocationHint === 'object')
    ? input.userLocationHint
    : null;
  const allowNetwork = JARVIS_WEB_ALLOW_NETWORK;
  const webMode = JARVIS_WEB_TOOL_MODE;
  const webEnabled = JARVIS_WEB_ENABLED;
  const webProvider = JARVIS_WEB_PROVIDER;
  const authorizedWeb = input.authorizedWeb === true;
  const runStartedAt = new Date().toISOString();

  const summarizeProviderAttempts = (attemptsInput = []) => {
    const attempts = Array.isArray(attemptsInput) ? attemptsInput : [];
    const providerAttempts = attempts.map((row) => ({
      name: String(row?.name || row?.provider || 'provider_attempt'),
      provider: String(row?.provider || row?.name || 'provider_attempt'),
      ok: row?.ok === true,
      resultCount: Number.isFinite(Number(row?.resultCount)) ? Number(row.resultCount) : 0,
      warning: row?.warning ? String(row.warning) : null,
    }));
    return {
      providerAttempts,
      providerSucceeded: providerAttempts.filter((row) => row.ok === true).map((row) => row.provider),
      providerFailed: providerAttempts.filter((row) => row.ok !== true).map((row) => row.provider),
    };
  };

  const buildWebReceipt = ({
    executed = false,
    consentGranted = authorizedWeb === true,
    warnings = [],
    query = queryUsed,
    normalized = normalizedQuery,
    original = originalQuery,
    location = userLocationHint,
    attempts = [],
    resultCount = 0,
    mode = webMode,
    provider = webProvider,
  } = {}) => ({
    traceId: String(input.traceId || '').trim() || null,
    intent,
    tool: 'WebTool',
    consent: {
      kind: 'web_search',
      granted: consentGranted === true,
      timestamp: new Date().toISOString(),
    },
    parameters: {
      query: String(query || '').trim(),
      normalizedQuery: String(normalized || '').trim(),
      originalQuery: String(original || '').trim(),
      locationRequired: locationRequired === true,
      locationUsed: location || null,
      attempts: Array.isArray(attempts) ? attempts : [],
      mode,
      provider,
    },
      result: {
        executed: executed === true,
        resultCount: Number(resultCount || 0),
        attempts: Array.isArray(attempts) ? attempts : [],
        ...summarizeProviderAttempts(attempts),
        warnings: Array.isArray(warnings) ? warnings : [],
      },
    startedAt: runStartedAt,
    completedAt: new Date().toISOString(),
  });

  if (!message) {
    return {
      reply: 'Ask a web question and I will route it to search.',
      toolsUsed: ['WebTool'],
      source: 'jarvis_web_stub',
      routePath: 'runJarvisWebQuestionTool.empty',
      activeModule: 'bridge',
      commandsExecuted: [],
      clientActions: [],
      toolReceipts: [buildWebReceipt({ executed: false, consentGranted: false, warnings: ['message_required'] })],
    };
  }

  if (!authorizedWeb) {
    return {
      reply: 'I did not run a web search yet. I need your OK before I execute it.',
      toolsUsed: ['Jarvis'],
      source: 'jarvis_web_authorization_required',
      routePath: 'runJarvisWebQuestionTool.authorization_required',
      activeModule: 'bridge',
      commandsExecuted: [],
      clientActions: [],
      consentPending: true,
      consentKind: 'web_search',
      consentNeedLocation: locationRequired,
      web: null,
      toolReceipts: [buildWebReceipt({ executed: false, consentGranted: false, warnings: ['authorization_required'] })],
    };
  }

  const providerStartedAt = Date.now();
  const out = await runWebTool({
    message,
    queryUsed,
    originalQuery,
    normalizedQuery,
    categoryHint,
    intent,
    traceId: input.traceId || null,
    sessionId: input.sessionId || null,
    clientId: input.clientId || null,
    userLocationHint,
    locationRequired,
    webEnabled,
    allowNetwork,
    webMode,
    webProvider,
    webToolUrl: JARVIS_WEB_TOOL_URL,
    maxSources: JARVIS_WEB_MAX_SOURCES,
  });
  const providerDurationMs = Date.now() - providerStartedAt;

  const warnings = Array.isArray(out?.warnings) ? out.warnings : [];
  const answer = String(out?.data?.answer || out?.narrative?.stance || '').trim();
  const sources = Array.isArray(out?.data?.sources) ? out.data.sources : [];
  const locationUsed = out?.data?.locationUsed || null;
  const attempts = Array.isArray(out?.metrics?.attempts) ? out.metrics.attempts : [];
  const providerSummary = summarizeProviderAttempts(attempts);
  const metricsMode = String(out?.metrics?.mode || webMode || 'stub').trim().toLowerCase();
  const isStubMode = metricsMode === 'stub';
  const webReceipt = buildWebReceipt({
    executed: out?.ok === true && !isStubMode,
    consentGranted: true,
    warnings,
    query: out?.data?.queryUsed || queryUsed,
    normalized: out?.data?.normalizedQuery || normalizedQuery || queryUsed,
    original: out?.data?.originalQuery || originalQuery || message,
    location: locationUsed,
    attempts,
    resultCount: sources.length,
    mode: metricsMode,
    provider: String(out?.metrics?.provider || webProvider || 'unknown'),
  });

  if (out?.ok === true && answer) {
    trace('jarvis_web_tool_success', {
      routePath: 'runJarvisWebQuestionTool.execute',
      source: 'jarvis_web_tool',
      providerUrl: JARVIS_WEB_TOOL_URL || null,
      mode: webMode,
      warnings,
      queryUsed: out?.data?.queryUsed || queryUsed,
      resultCount: sources.length,
      usedLocation: locationUsed != null,
      providerDurationMs,
    });
    return {
      reply: answer,
      toolsUsed: ['WebTool'],
      source: webMode === 'real' ? 'jarvis_web_tool' : 'jarvis_web_stub',
      routePath: 'runJarvisWebQuestionTool.execute',
      activeModule: 'bridge',
      commandsExecuted: [],
      clientActions: [],
      web: {
        queryUsed: out?.data?.queryUsed || queryUsed,
        normalizedQuery: out?.data?.normalizedQuery || normalizedQuery || queryUsed,
        originalQuery: out?.data?.originalQuery || originalQuery || message,
        sources,
        warnings,
        attempts,
        ...providerSummary,
        locationUsed,
      },
      toolReceipts: [webReceipt],
    };
  }

  const warningLabel = warnings[0] || 'web_unavailable';
  const fallback = warningLabel === 'web_disabled'
    ? 'Web search is disabled in configuration right now.'
    : warningLabel === 'location_required'
      ? 'I still need a city or location hint before I can run that lookup.'
      : warningLabel === 'web_request_failed'
        ? 'Web provider request failed. Try again in a moment.'
        : 'Web search is not available right now.';

  return {
    reply: fallback,
    toolsUsed: ['WebTool'],
    source: 'jarvis_web_tool',
    routePath: 'runJarvisWebQuestionTool.error',
    activeModule: 'bridge',
    commandsExecuted: [],
    clientActions: [],
    web: {
      queryUsed,
      normalizedQuery: normalizedQuery || queryUsed,
      originalQuery: originalQuery || message,
      sources: [],
      warnings,
      attempts,
      ...providerSummary,
      locationUsed,
    },
    toolReceipts: [webReceipt],
  };
}

const GENERAL_CHAT_FORBIDDEN_REPLY_PATTERNS = [
  { label: 'orb', pattern: /\borb\b/i },
  { label: 'topstep', pattern: /\btopstep\b/i },
  { label: "don't trade", pattern: /\b(?:don't trade|dont trade|do not trade)\b/i },
  { label: 'best setup', pattern: /\bbest setup\b/i },
  { label: 'momentum 10:15', pattern: /\bmomentum\s*10:15\b/i },
  { label: '10:15', pattern: /\b10:15\b/i },
  { label: 'entry window', pattern: /\bentry window\b/i },
  { label: 'range is too wide', pattern: /\brange is too wide\b/i },
  { label: 'chance of green day', pattern: /\bchance of green day\b/i },
  { label: 'contractId', pattern: /\bcontractid\b/i },
  { label: 'mnq price', pattern: /\bmnq price\b/i },
  { label: 'market pattern', pattern: /\bmarket pattern\b/i },
];

function detectGeneralChatForbiddenTokens(replyText = '') {
  const text = String(replyText || '');
  if (!text) return [];
  return GENERAL_CHAT_FORBIDDEN_REPLY_PATTERNS
    .filter((row) => row.pattern.test(text))
    .map((row) => row.label);
}

function applyGeneralChatReplyContentFirewall(payload = {}) {
  const intent = String(payload.intent || '').trim().toLowerCase();
  const reply = String(payload.reply || '').trim();
  if (intent !== 'general_chat') {
    return {
      reply,
      contentFirewallApplied: false,
      detectedForbiddenTokens: [],
    };
  }
  const detectedForbiddenTokens = detectGeneralChatForbiddenTokens(reply);
  if (detectedForbiddenTokens.length <= 0) {
    return {
      reply,
      contentFirewallApplied: false,
      detectedForbiddenTokens,
    };
  }
  return {
    reply: "Sounds like you're venting - want to talk about trading, or something else?",
    contentFirewallApplied: true,
    detectedForbiddenTokens,
  };
}

function shouldUseEarbudForJarvisIntent(intent, message, voiceMode, voiceBriefMode) {
  if (voiceMode !== true) return false;
  const requestedEarbud = voiceBriefMode === 'earbud' || voiceBriefMode === 'earpiece';
  if (!requestedEarbud) return false;
  const normalizedIntent = String(intent || '').trim().toLowerCase();
  if (
    normalizedIntent === 'trading_decision'
    || normalizedIntent === 'trading_hypothetical'
    || normalizedIntent === 'trading_replay'
    || normalizedIntent === 'trading_review'
    || normalizedIntent === 'trading_plan'
    || normalizedIntent === 'trading_execution_request'
    || normalizedIntent === 'trading_status'
    || normalizedIntent === 'trend_regime'
    || normalizedIntent === 'web_question'
    || normalizedIntent === 'local_search'
    || normalizedIntent === 'web_local_search'
    || normalizedIntent === 'os_action'
    || normalizedIntent === 'device_action'
  ) {
    return true;
  }
  if (normalizedIntent === 'general_chat') {
    return /\b(earbud|earpiece|3 sentences|three sentences|coach terse|short brief)\b/i.test(String(message || ''));
  }
  return false;
}

async function runJarvisGeneralChatTool(input = {}) {
  const trace = typeof input.trace === 'function' ? input.trace : () => {};
  const contextHint = normalizeDashboardModuleId(input.contextHint || input.activeModule) || 'bridge';
  const normalizedMessage = String(input.message || '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();

  const nowEt = nowInTimezone('America/New_York');
  const nowLocal = nowInTimezone();

  if (/(what endpoint are you using|which endpoint are you using|what api endpoint are you using).*(voice|voice requests)/.test(normalizedMessage)) {
    const reply = 'Your voice requests are routed through /api/jarvis/query.';
    trace('jarvis_general_chat_endpoint_disclosure', {
      routePath: 'runJarvisGeneralChatTool.endpoint_disclosure',
      source: 'jarvis_general',
      endpoint: '/api/jarvis/query',
    });
    return {
      reply,
      toolsUsed: ['Jarvis'],
      source: 'jarvis_general',
      routePath: 'runJarvisGeneralChatTool.endpoint_disclosure',
      activeModule: 'bridge',
      commandsExecuted: [],
      clientActions: [],
    };
  }

  if (/\b(what time is it|what(?:'|’)s the time|current time|time right now|tell me the time)\b/.test(normalizedMessage)) {
    const reply = `It is ${nowEt.time} ET on ${nowEt.date}. Your local time is ${nowLocal.time}.`;
    trace('jarvis_general_chat_time', {
      routePath: 'runJarvisGeneralChatTool.time',
      source: 'jarvis_general',
      nowEt,
      nowLocal,
    });
    return {
      reply,
      toolsUsed: ['Jarvis'],
      source: 'jarvis_general',
      routePath: 'runJarvisGeneralChatTool.time',
      activeModule: contextHint,
      commandsExecuted: [],
      clientActions: [],
    };
  }

  if (/\b(what day is it|what(?:'|’)s today|today(?:'|’)s date|what(?:'|’)s the date|current date)\b/.test(normalizedMessage)) {
    const reply = `Today is ${nowEt.date} in ET.`;
    trace('jarvis_general_chat_date', {
      routePath: 'runJarvisGeneralChatTool.date',
      source: 'jarvis_general',
      nowEt,
    });
    return {
      reply,
      toolsUsed: ['Jarvis'],
      source: 'jarvis_general',
      routePath: 'runJarvisGeneralChatTool.date',
      activeModule: contextHint,
      commandsExecuted: [],
      clientActions: [],
    };
  }

  let reply = '';
  if (/(still dumb|just says anything|not working|useless|horrible|frustrating|annoying)/.test(normalizedMessage)) {
    reply = "Sounds like you're venting - want to talk about trading, or something else?";
  } else if (/(help|what can you do|what do you do|what now|what should i do next|how does this work)/.test(normalizedMessage)) {
    reply = 'I can help with trading guidance, web lookups, or desktop actions. Tell me which one you want right now.';
  } else if (/(^|\b)(hi|hello|hey|yo|sup|how'?s it going|hows it going)\b/.test(normalizedMessage)) {
    reply = "I'm online. Tell me one task and I'll route it.";
  } else {
    reply = "I'm not sure what you want yet. Ask for trading help, a web search, the current time, or a desktop task.";
  }
  trace('jarvis_general_chat', {
    routePath: 'runJarvisGeneralChatTool',
    source: 'jarvis_general',
  });
  return {
    reply,
    toolsUsed: ['Jarvis'],
    source: 'jarvis_general',
    routePath: 'runJarvisGeneralChatTool',
    activeModule: contextHint,
    commandsExecuted: [],
    clientActions: [],
  };
}

async function runJarvisSystemDiagTool(input = {}) {
  const trace = typeof input.trace === 'function' ? input.trace : () => {};
  const reqBody = input?.req?.body && typeof input.req.body === 'object'
    ? input.req.body
    : {};
  const traceId = String(input.traceId || '').trim() || null;
  const serverPort = Number(config.port || process.env.PORT || 3131) || 3131;

  const clientSaysLegacy =
    reqBody.legacyFallbackActive === true
    || String(reqBody.voiceRouteMode || '').trim().toLowerCase() === 'legacy'
    || String(reqBody.voiceRoutingState || '').trim().toLowerCase() === 'legacy';
  const clientSaysJarvis =
    reqBody.jarvisOn === true
    || reqBody.jarvisRouteOn === true
    || String(reqBody.voiceRouteMode || '').trim().toLowerCase() === 'jarvis'
    || String(reqBody.voiceRoutingState || '').trim().toLowerCase() === 'jarvis';

  let fallbackLine = 'Legacy fallback is OFF (server voice guard enforces Jarvis-only voice routing).';
  if (clientSaysLegacy && !clientSaysJarvis) {
    fallbackLine = 'Legacy fallback appears ON from client telemetry, but server voice guard still requires /api/jarvis/query.';
  } else if (clientSaysJarvis) {
    fallbackLine = 'Jarvis routing is ON and legacy fallback is OFF.';
  }

  const statusLine = `Server port is ${serverPort} (expected 3131)${traceId ? `, trace ID ${traceId}` : ''}.`;
  const reply = [
    'Voice requests are using /api/jarvis/query.',
    fallbackLine,
    statusLine,
  ].join(' ');

  trace('jarvis_system_diag', {
    routePath: 'jarvis_orchestrator.system_diag',
    source: 'jarvis_diag',
    endpoint: '/api/jarvis/query',
    legacyFallbackActive: clientSaysLegacy,
    jarvisRoutingActive: clientSaysJarvis || !clientSaysLegacy,
    serverPort,
  });

  return {
    reply,
    toolsUsed: ['DiagTool'],
    source: 'jarvis_diag',
    routePath: 'jarvis_orchestrator.system_diag',
    routePathTag: 'jarvis_orchestrator.system_diag',
    activeModule: 'bridge',
    commandsExecuted: [],
    clientActions: [],
    endpoint: '/api/jarvis/query',
    voiceRouteMode: clientSaysLegacy && !clientSaysJarvis ? 'legacy' : 'jarvis',
    serverPort,
    traceId,
  };
}

