// API: INTEL (Strategy Analysis)
// ============================================================

app.get('/api/intel', (req, res) => {
  const sessions = loadAllSessions();
  const dates = Object.keys(sessions).sort();

  if (dates.length === 0) {
    return res.json({ verdict: 'NO DATA', alerts: [{ level: 'info', msg: 'Import data first.' }] });
  }

  // Alt strategy mode
  if (req.query.strategy === 'alt') {
    const alt = getAltData();
    // Build a backtest-like object for generateIntel
    const altBt = {
      metrics: alt.metrics,
      trades: alt.trades,
      drawdown: alt.drawdown,
      sharpe: alt.sharpe,
      sortino: alt.sortino,
      monteCarlo: alt.monteCarlo,
      equityCurve: alt.equityCurve,
      monthly: alt.monthly,
      dayOfWeek: alt.dayOfWeek,
      rolling: alt.rolling,
      decay: alt.decay,
      exitReasons: alt.exitReasons,
    };

    const regimes = loadRegimes(sessions);
    const latestDate = dates[dates.length - 1];
    const intel = generateIntel(altBt, regimes, latestDate);

    // No TP sensitivity needed for alt strategy — it IS the optimized version
    intel.insights.unshift({
      type: 'tp',
      msg: `Viewing CLOSER TP variant. ${alt.changeSummary?.flipped || 0} losses flipped to wins. Net impact: $${alt.changeSummary?.netImpact?.toFixed(0) || '?'}.`,
    });

    return res.json(intel);
  }

  const bt = runBacktestWithResolutions(sessions, {
    startingBalance: config.topstep.startingBalance,
    topstepMaxDD: config.topstep.maxDrawdown,
    topstepTarget: config.topstep.profitTarget,
  });

  const regimes = loadRegimes(sessions);
  const latestDate = dates[dates.length - 1];
  const intel = generateIntel(bt, regimes, latestDate);

  // Add TP sensitivity
  const tp = runTPSensitivity(bt.trades, sessions);
  if (tp.flips_at_one_closer > 0) {
    intel.insights.unshift({
      type: 'tp',
      msg: `${tp.flips_at_one_closer}/${tp.total_losses} losses (${tp.flip_rate}%) become wins at 1 psych level closer. Dollar impact: +$${tp.offset_analysis?.[0]?.total_dollar_impact?.toFixed(0) || '?'}. Ask the AI Analyst for the full breakdown.`,
    });
  }
  intel.tpSensitivity = {
    flips: tp.flips_at_one_closer,
    total_losses: tp.total_losses,
    flip_rate: tp.flip_rate,
    dollar_impact: tp.offset_analysis?.[0]?.total_dollar_impact || 0,
  };

  res.json(intel);
});

// ============================================================
// CONFLICT RESOLUTION SYSTEM
// ============================================================

/**
 * Apply stored conflict resolutions to a trades array.
 * Mutates trades in place — call after backtest.
 */
function applyResolutions(trades) {
  const db = getDB();
  const resolutions = db.prepare('SELECT * FROM conflict_resolutions').all();
  if (resolutions.length === 0) return trades;

  const resMap = {};
  for (const r of resolutions) {
    resMap[`${r.trade_date}|${r.direction}|${r.entry_price}`] = r;
  }

  for (const t of trades) {
    const key = `${t.date}|${t.direction}|${t.entry_price}`;
    const res = resMap[key];
    if (res) {
      t.result = res.resolved_result;
      t.exit_reason = res.resolved_exit;
      t.pnl_ticks = res.resolved_pnl_ticks;
      t.pnl_dollars = res.resolved_pnl_dollars;
      t.exit_price = res.resolved_result === 'win' ? t.tp_price : t.sl_price;
      t._resolved = true;
    }
  }

  return trades;
}

/**
 * Get all ambiguous trades (wick-inferred) and their resolution status.
 * These are trades where both TP and SL were hit in the same candle,
 * and the engine used wick direction to guess which hit first.
 */
app.get('/api/conflicts', (req, res) => {
  const sessions = loadAllSessions();
  const dates = Object.keys(sessions).sort();
  if (dates.length === 0) return res.json({ conflicts: [], resolved: [] });

  const bt = runBacktest(sessions);
  const ambiguous = bt.trades.filter(t => 
    t.exit_reason === 'sl_wick_inferred' || t.exit_reason === 'tp_wick_inferred'
  );

  const db = getDB();
  const resolutions = db.prepare('SELECT * FROM conflict_resolutions').all();
  const resMap = {};
  for (const r of resolutions) {
    resMap[`${r.trade_date}|${r.direction}|${r.entry_price}`] = r;
  }

  const conflicts = ambiguous.map(t => {
    const key = `${t.date}|${t.direction}|${t.entry_price}`;
    const resolution = resMap[key] || null;
    return {
      date: t.date,
      direction: t.direction,
      entry_price: t.entry_price,
      entry_time: t.entry_time,
      tp_price: t.tp_price,
      tp_distance_ticks: t.tp_distance_ticks,
      sl_price: t.sl_price,
      sl_distance_ticks: t.sl_distance_ticks,
      orb_high: t.orb_high,
      orb_low: t.orb_low,
      // Engine's wick inference
      inferred_result: t.result,
      inferred_reason: t.exit_reason,
      inferred_pnl: t.pnl_dollars,
      // The conflicting candle info
      ambiguous_candle: {
        time: t.exit_time,
        hit_both: true,
      },
      // If resolved
      resolved: resolution ? {
        result: resolution.resolved_result,
        exit: resolution.resolved_exit,
        pnl_ticks: resolution.resolved_pnl_ticks,
        pnl_dollars: resolution.resolved_pnl_dollars,
        notes: resolution.notes,
        resolved_at: resolution.created_at,
      } : null,
    };
  });

  // Also include any resolutions for trades no longer in backtest (edge case)
  res.json({
    total: conflicts.length,
    unresolved: conflicts.filter(c => !c.resolved).length,
    conflicts,
  });
});

/**
 * Resolve an ambiguous trade.
 * Body: { result: 'win'|'loss', notes?: string }
 */
app.put('/api/conflicts/resolve', (req, res) => {
  const { date, direction, entry_price, result: resolvedResult, notes } = req.body;

  if (!date || !direction || !entry_price || !resolvedResult) {
    return res.status(400).json({ error: 'Missing required fields: date, direction, entry_price, result' });
  }

  if (!['win', 'loss'].includes(resolvedResult)) {
    return res.status(400).json({ error: 'result must be "win" or "loss"' });
  }

  // Find the original trade to compute correct P&L
  const sessions = loadAllSessions();
  const bt = runBacktest(sessions);
  const trade = bt.trades.find(t =>
    t.date === date && t.direction === direction && t.entry_price === entry_price
  );

  if (!trade) {
    return res.status(404).json({ error: 'Trade not found' });
  }

  // Calculate corrected P&L (must match orb.js: subtract 2 slippage ticks + $4.50 commission)
  let pnlTicks, pnlDollars, resolvedExit;
  if (resolvedResult === 'win') {
    resolvedExit = 'tp';
    pnlTicks = trade.tp_distance_ticks - 2; // subtract slippage
    pnlDollars = (pnlTicks * 0.50) - 4.50;  // $0.50/tick - commission
  } else {
    resolvedExit = 'sl';
    pnlTicks = -trade.sl_distance_ticks - 2; // negative + slippage makes it worse
    pnlDollars = (pnlTicks * 0.50) - 4.50;
  }

  const db = getDB();
  db.prepare(`
    INSERT OR REPLACE INTO conflict_resolutions
    (trade_date, direction, entry_price, resolved_result, resolved_exit,
     resolved_pnl_ticks, resolved_pnl_dollars, notes)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).run(date, direction, entry_price, resolvedResult, resolvedExit, pnlTicks, pnlDollars, notes || null);

  // Also update the stored trade in the trades table
  db.prepare(`
    UPDATE trades SET result = ?, exit_reason = ?, pnl_ticks = ?, pnl_dollars = ?,
      exit_price = ?, notes = COALESCE(notes, '') || ' [RESOLVED: ' || ? || ']'
    WHERE date = ? AND direction = ? AND entry_price = ? AND (exit_reason = 'sl_wick_inferred' OR exit_reason = 'tp_wick_inferred' OR exit_reason = 'sl_conservative')
  `).run(resolvedResult, resolvedExit, pnlTicks, pnlDollars,
    resolvedResult === 'win' ? trade.tp_price : trade.sl_price,
    resolvedResult, date, direction, entry_price);

  invalidateAltCache();
  invalidateDailyPlanCache();
  invalidateSessionControlPanelCache();
  eliteBriefCache.clear();

  res.json({
    success: true,
    resolution: { date, direction, entry_price, result: resolvedResult, exit: resolvedExit, pnl_ticks: pnlTicks, pnl_dollars: pnlDollars },
  });
});

/**
 * Undo a conflict resolution.
 */
app.delete('/api/conflicts/resolve', (req, res) => {
  const { date, direction, entry_price } = req.body;
  const db = getDB();
  db.prepare('DELETE FROM conflict_resolutions WHERE trade_date = ? AND direction = ? AND entry_price = ?')
    .run(date, direction, entry_price);
  invalidateAltCache();
  invalidateDailyPlanCache();
  invalidateSessionControlPanelCache();
  eliteBriefCache.clear();
  res.json({ success: true });
});

