async function sendDailyBriefingOnce(options = {}) {
  const triggerSource = String(options.triggerSource || 'manual_daily_brief');
  const nowEt = nowInTimezone('America/New_York');
  const pushDate = String(options.pushDate || nowEt.date || dateInTimezone('America/New_York'));
  const pushTag = `daily_brief_${pushDate}`;
  const channel = 'discord_dm';
  const db = getDB();

  if (!discordBot?.enabled || typeof discordBot.sendDailyBriefing !== 'function') {
    return { status: 'skip', reason: 'discord_unavailable', pushDate, pushTag, triggerSource };
  }

  const lock = db.prepare(`
    INSERT OR IGNORE INTO assistant_push_log (push_date, push_tag, channel)
    VALUES (?, ?, ?)
  `).run(pushDate, pushTag, channel);
  if (Number(lock.changes || 0) === 0) {
    return { status: 'skip', reason: 'already_sent', pushDate, pushTag, triggerSource };
  }

  try {
    const text = String(options.text || await buildDailyBriefingText());
    await discordBot.sendDailyBriefing(text);
    db.prepare('INSERT INTO activity_log (module, message, severity, data) VALUES (?, ?, ?, ?)')
      .run(
        'assistant',
        `Daily briefing sent (${pushDate}).`,
        'info',
        JSON.stringify({ triggerSource, pushDate, pushTag, channel })
      );
    return { status: 'sent', pushDate, pushTag, triggerSource };
  } catch (err) {
    db.prepare('DELETE FROM assistant_push_log WHERE push_date = ? AND push_tag = ? AND channel = ?')
      .run(pushDate, pushTag, channel);
    const msg = String(err?.message || 'daily_brief_send_failed');
    db.prepare('INSERT INTO activity_log (module, message, severity, data) VALUES (?, ?, ?, ?)')
      .run(
        'assistant',
        'Daily briefing send failed.',
        'warning',
        JSON.stringify({ triggerSource, pushDate, pushTag, channel, error: msg })
      );
    throw err;
  }
}

