function dateInTimezone(timezone = 'America/New_York', dateInput = new Date()) {
  const when = dateInput instanceof Date ? dateInput : new Date(dateInput);
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  const parts = Object.fromEntries(fmt.formatToParts(when).map(p => [p.type, p.value]));
  return `${parts.year}-${parts.month}-${parts.day}`;
}

function toUtcDayMs(isoDate) {
  const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(String(isoDate || '').trim());
  if (!match) return null;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) return null;
  return Date.UTC(year, month - 1, day);
}

function diffIsoDays(startIso, endIso) {
  const startMs = toUtcDayMs(startIso);
  const endMs = toUtcDayMs(endIso);
  if (!Number.isFinite(startMs) || !Number.isFinite(endMs)) return null;
  return Math.floor((endMs - startMs) / 86400000);
}

function getSessionFreshnessSummary(timezone = 'America/New_York') {
  const staleThresholdDays = Math.max(1, Number(process.env.MAX_SESSION_STALENESS_DAYS || 3));
  const out = {
    timezone,
    today: dateInTimezone(timezone),
    lastSessionDate: null,
    staleDays: null,
    staleThresholdDays,
    isStale: true,
    error: null,
  };
  try {
    const db = getDB();
    const row = db.prepare('SELECT MAX(date) as last FROM sessions').get();
    out.lastSessionDate = row?.last || null;
    if (out.lastSessionDate) {
      out.staleDays = diffIsoDays(out.lastSessionDate, out.today);
      out.isStale = !Number.isFinite(out.staleDays) || out.staleDays > staleThresholdDays;
    }
    return out;
  } catch (err) {
    out.error = String(err?.message || 'session_freshness_failed');
    out.isStale = true;
    return out;
  }
}

function priceDiffToMnqTicks(a, b) {
  const x = Number(a);
  const y = Number(b);
  if (!Number.isFinite(x) || !Number.isFinite(y)) return null;
  return round2((x - y) * 4);
}

function classifyVolatilityRegime(rangeTicks60) {
  const t = Number(rangeTicks60);
  if (!Number.isFinite(t)) return 'unknown';
  if (t < 120) return 'low';
  if (t < 240) return 'normal';
  if (t < 380) return 'elevated';
  return 'high';
}

function classifyMomentumLabel(momentumTicks15) {
  const t = Number(momentumTicks15);
  if (!Number.isFinite(t)) return 'neutral';
  if (t >= 24) return 'bullish';
  if (t <= -24) return 'bearish';
  return 'neutral';
}

function derivePatternLabel({ momentumLabel, trendTicks30, rangeTicks20 }) {
  const trend = Number(trendTicks30);
  const range20 = Number(rangeTicks20);
  if (Number.isFinite(range20) && range20 <= 60) return 'compression';
  if (momentumLabel === 'bullish' && Number.isFinite(trend) && trend >= 24) return 'bullish_continuation';
  if (momentumLabel === 'bearish' && Number.isFinite(trend) && trend <= -24) return 'bearish_continuation';
  if (momentumLabel === 'neutral') return 'balance';
  return 'transition';
}

function buildPatternRecognitionFromBars(bars = [], symbol = 'MNQ') {
  const sorted = (Array.isArray(bars) ? bars : [])
    .filter((b) => b && Number.isFinite(Number(b.c)))
    .map((b) => ({
      t: String(b.t || b.timestamp || ''),
      o: Number(b.o),
      h: Number(b.h),
      l: Number(b.l),
      c: Number(b.c),
    }))
    .filter((b) => Number.isFinite(b.h) && Number.isFinite(b.l) && Number.isFinite(b.c))
    .sort((a, b) => String(a.t).localeCompare(String(b.t)));
  if (!sorted.length) {
    return {
      symbol,
      source: 'none',
      lastPrice: null,
      lastBarTime: null,
      momentumTicks15: null,
      trendTicks30: null,
      rangeTicks20: null,
      rangeTicks60: null,
      momentumLabel: 'neutral',
      volatilityRegime: 'unknown',
      patternLabel: 'no_data',
      guidance: 'No live pattern data yet. Run sync and try again.',
    };
  }

  const tail = (n) => sorted.slice(Math.max(0, sorted.length - n));
  const last = sorted[sorted.length - 1];
  const closes = sorted.map((b) => b.c);
  const cNow = closes[closes.length - 1];
  const c15 = closes[Math.max(0, closes.length - 16)];
  const c30 = closes[Math.max(0, closes.length - 31)];
  const b20 = tail(20);
  const b60 = tail(60);
  const high20 = b20.length ? Math.max(...b20.map((b) => b.h)) : null;
  const low20 = b20.length ? Math.min(...b20.map((b) => b.l)) : null;
  const high60 = b60.length ? Math.max(...b60.map((b) => b.h)) : null;
  const low60 = b60.length ? Math.min(...b60.map((b) => b.l)) : null;
  const momentumTicks15 = priceDiffToMnqTicks(cNow, c15);
  const trendTicks30 = priceDiffToMnqTicks(cNow, c30);
  const rangeTicks20 = priceDiffToMnqTicks(high20, low20);
  const rangeTicks60 = priceDiffToMnqTicks(high60, low60);
  const momentumLabel = classifyMomentumLabel(momentumTicks15);
  const volatilityRegime = classifyVolatilityRegime(rangeTicks60);
  const patternLabel = derivePatternLabel({ momentumLabel, trendTicks30, rangeTicks20 });
  let guidance = 'Market is mixed. Wait for clean structure before entry.';
  if (patternLabel === 'compression') guidance = 'Compression detected. Wait for breakout, then retest confirmation.';
  else if (patternLabel === 'bullish_continuation') guidance = 'Bullish continuation conditions are active; favor pullback long entries.';
  else if (patternLabel === 'bearish_continuation') guidance = 'Bearish continuation conditions are active; favor pullback short entries.';
  else if (patternLabel === 'balance') guidance = 'Balanced tape. Prefer patience until directional conviction improves.';

  return {
    symbol,
    source: 'topstep_bars',
    lastPrice: cNow,
    lastBarTime: last.t || null,
    momentumTicks15,
    trendTicks30,
    rangeTicks20,
    rangeTicks60,
    momentumLabel,
    volatilityRegime,
    patternLabel,
    guidance,
  };
}

function buildStrategyMemoryProfile(options = {}) {
  const limit = Math.max(80, Math.min(1200, Number(options.limit || 420)));
  const rows = getDB().prepare(`
    SELECT setup_id, setup_name, outcome, pnl_dollars, source, created_at
    FROM trade_outcome_feedback
    ORDER BY id DESC
    LIMIT ?
  `).all(limit).filter((r) => !isSyntheticFeedback({ source: r.source, setupId: r.setup_id }));

  if (!rows.length) {
    return {
      samples: 0,
      totalWinRate: null,
      bestSetups: [],
      weakSetups: [],
      personalizationLine: 'I need more logged outcomes to personalize recommendations.',
    };
  }

  const bySetup = new Map();
  let wins = 0;
  let losses = 0;
  for (const r of rows) {
    const sid = normalizeSetupKey(r.setup_id || r.setup_name || 'setup_unknown');
    if (!bySetup.has(sid)) {
      bySetup.set(sid, {
        setupId: sid,
        setupName: r.setup_name || sid,
        samples: 0,
        wins: 0,
        losses: 0,
        breakeven: 0,
        pnlDollars: 0,
      });
    }
    const item = bySetup.get(sid);
    item.samples += 1;
    const outcome = String(r.outcome || '').toLowerCase();
    if (outcome === 'win') {
      item.wins += 1;
      wins += 1;
    } else if (outcome === 'loss') {
      item.losses += 1;
      losses += 1;
    } else item.breakeven += 1;
    if (Number.isFinite(Number(r.pnl_dollars))) item.pnlDollars += Number(r.pnl_dollars);
  }

  const enriched = Array.from(bySetup.values()).map((s) => {
    const winRate = round2((s.wins / Math.max(1, s.samples)) * 100);
    const avgPnl = round2(s.pnlDollars / Math.max(1, s.samples));
    const sampleScore = clampNumber((Math.min(40, s.samples) / 40) * 20, 0, 20);
    const score = round2(clampNumber((winRate * 0.65) + (avgPnl > 0 ? 15 : avgPnl < 0 ? 5 : 10) + sampleScore, 0, 100));
    return {
      ...s,
      winRate,
      avgPnl,
      score,
    };
  });
  enriched.sort((a, b) => b.score - a.score);
  const bestSetups = enriched.slice(0, 3);
  const weakSetups = enriched.filter((s) => s.samples >= 6).sort((a, b) => a.score - b.score).slice(0, 2);
  const totalWinRate = round2((wins / Math.max(1, wins + losses)) * 100);
  const top = bestSetups[0];
  const personalizationLine = top
    ? `Your strongest learned edge is ${top.setupName} (${top.winRate}% over ${top.samples} logged outcomes).`
    : 'Personalized memory is still calibrating.';
  return {
    samples: rows.length,
    totalWinRate,
    bestSetups,
    weakSetups,
    personalizationLine,
  };
}

async function buildRealtimeMarketIntegration(options = {}) {
  const symbol = String(options.symbol || config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase();
  const topstepCfg = config.topstep?.api || {};
  const topstepLive = options.topstepLive || getTopstepLiveSnapshot({ fillLimit: 20 });
  const account = options.account || topstepLive?.account || {};
  const liveFlag = inferTopstepLiveFlag(account);
  const timeoutMs = Math.max(2000, Number(topstepCfg.timeoutMs || 10_000));
  const baseUrls = [topstepCfg.baseUrl, ...(Array.isArray(topstepCfg.altBaseUrls) ? topstepCfg.altBaseUrls : [])].filter(Boolean);

  let bars = [];
  let source = 'none';
  let error = null;
  let liveBarsSnapshot = null;
  try {
    liveBarsSnapshot = await getLiveBarsSnapshot({
      symbol,
      live: liveFlag,
      topstepCfg,
      baseUrls,
      timeoutMs,
      lookbackMinutes: 240,
      unitNumber: 1,
      includePartialBar: true,
      persistToDb: true,
      persistFiveMinute: true,
      forceFresh: options.forceFreshLiveBars === true,
      topstepLive,
      account,
    });
  } catch (err) {
    error = String(err?.message || 'live_bars_snapshot_failed');
  }
  if (liveBarsSnapshot?.ok && Array.isArray(liveBarsSnapshot.bars) && liveBarsSnapshot.bars.length > 0) {
    bars = liveBarsSnapshot.bars;
    source = 'topstep_live_bars';
  } else if (!error && liveBarsSnapshot && !liveBarsSnapshot.ok) {
    error = String(liveBarsSnapshot.error || 'retrieve_bars_failed');
  }

  const pattern = buildPatternRecognitionFromBars(bars, symbol);
  if (!Number.isFinite(Number(pattern.lastPrice))) {
    const state = getLiveTradeState();
    if (String(state.symbol || '').toUpperCase() === symbol && Number.isFinite(Number(state.lastPrice))) {
      pattern.lastPrice = Number(state.lastPrice);
      pattern.source = 'live_trade_state';
      source = source === 'none' ? 'live_trade_state' : source;
    }
  }
  const todayEt = dateInTimezone('America/New_York');
  let todayBarCount = 0;
  let todayOrbBarsCount = 0;
  for (const b of (Array.isArray(bars) ? bars : [])) {
    const candle = topstepBarToSessionCandle(b);
    if (String(candle.date || '') !== todayEt) continue;
    todayBarCount += 1;
    const hhmm = String(candle.time || '').slice(0, 5);
    if (hhmm >= '09:30' && hhmm < '09:45') todayOrbBarsCount += 1;
  }
  return {
    symbol,
    source,
    error,
    pattern,
    account: {
      accountId: account?.accountId || null,
      accountName: account?.accountName || null,
      dailyPnl: Number.isFinite(Number(account?.dailyPnl)) ? Number(account.dailyPnl) : null,
    },
    openPositions: Array.isArray(topstepLive?.positions) ? topstepLive.positions.length : 0,
    syncStatus: String(options.liveSync?.status || topstepLive?.sync?.status || '').toUpperCase() || 'UNKNOWN',
    liveBarCount: Array.isArray(bars) ? bars.length : 0,
    todayBarCount,
    todayOrbBarsCount,
    liveBarsSnapshot,
  };
}

function buildRealtimeMarketSnapshotFromState(options = {}) {
  const symbol = String(options.symbol || config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase();
  const topstepLive = options.topstepLive || getTopstepLiveSnapshot({ fillLimit: 20 });
  const account = options.account || topstepLive?.account || {};
  const positions = Array.isArray(topstepLive?.positions) ? topstepLive.positions : [];
  const fills = Array.isArray(topstepLive?.fills) ? topstepLive.fills : [];
  const tradeState = getLiveTradeState();
  const cachedQuote = getCachedMarketQuote(symbol);

  let lastPrice = null;
  let lastBarTime = null;
  let source = 'local_state';

  const tsPrice = Number(tradeState?.lastPrice);
  if (String(tradeState?.symbol || '').toUpperCase() === symbol && Number.isFinite(tsPrice) && tsPrice > 0) {
    lastPrice = tsPrice;
    lastBarTime = topstepLive?.sync?.createdAt || null;
    source = 'live_trade_state';
  }
  if (!Number.isFinite(lastPrice) && cachedQuote && Number.isFinite(Number(cachedQuote.price)) && Number(cachedQuote.price) > 0) {
    lastPrice = Number(cachedQuote.price);
    lastBarTime = cachedQuote.asOf || null;
    source = 'quote_cache';
  }
  if (!Number.isFinite(lastPrice)) {
    const pos = positions.find((p) => String(p?.symbol || '').toUpperCase() === symbol && Number.isFinite(Number(p?.markPrice)));
    if (pos) {
      lastPrice = Number(pos.markPrice);
      lastBarTime = topstepLive?.sync?.createdAt || null;
      source = 'topstep_position_mark';
    }
  }
  if (!Number.isFinite(lastPrice)) {
    const fill = fills.find((f) => String(f?.symbol || '').toUpperCase() === symbol && Number.isFinite(Number(f?.price)));
    if (fill) {
      lastPrice = Number(fill.price);
      lastBarTime = fill?.fillTime || fill?.timestamp || topstepLive?.sync?.createdAt || null;
      source = 'topstep_fill';
    }
  }

  const pattern = {
    symbol,
    source,
    lastPrice: Number.isFinite(lastPrice) ? lastPrice : null,
    lastBarTime: lastBarTime || null,
    momentumTicks15: null,
    trendTicks30: null,
    rangeTicks20: null,
    rangeTicks60: null,
    momentumLabel: 'neutral',
    volatilityRegime: 'unknown',
    patternLabel: Number.isFinite(lastPrice) ? 'snapshot' : 'no_data',
    guidance: Number.isFinite(lastPrice)
      ? 'Fast snapshot mode is active for speed. Ask for a full live refresh when needed.'
      : 'Live snapshot has no price yet. Run sync for a deeper refresh.',
  };
  const todayEt = dateInTimezone('America/New_York');
  let todayBarCount = 0;
  let todayOrbBarsCount = 0;
  const lastDt = parseAnyTimestamp(pattern.lastBarTime);
  if (lastDt && dateInTimezone('America/New_York', lastDt) === todayEt) {
    todayBarCount = 1;
    const et = formatEtDateTimeParts(lastDt);
    const hhmm = String(et.hhmm || '');
    if (hhmm >= '09:30' && hhmm < '09:45') todayOrbBarsCount = 1;
  }

  return {
    symbol,
    source,
    error: null,
    pattern,
    account: {
      accountId: account?.accountId || null,
      accountName: account?.accountName || null,
      dailyPnl: Number.isFinite(Number(account?.dailyPnl)) ? Number(account.dailyPnl) : null,
    },
    openPositions: positions.length,
    syncStatus: String(options.liveSync?.status || topstepLive?.sync?.status || '').toUpperCase() || 'UNKNOWN',
    liveBarCount: null,
    todayBarCount,
    todayOrbBarsCount,
    liveBarsSnapshot: null,
  };
}

function getAnalystFreshnessLagThresholdMinutes() {
  const raw = Number(process.env.ANALYST_STALE_MINUTES || process.env.ASSISTANT_STALE_MINUTES || 5);
  if (!Number.isFinite(raw)) return 5;
  return Math.max(3, Math.min(15, Math.round(raw)));
}

function buildMarketDataFreshnessSnapshot(options = {}) {
  const timezone = String(options.timezone || 'America/New_York');
  const nowEt = options.nowEt || nowInTimezone(timezone);
  const todayDate = nowEt.date || dateInTimezone(timezone);
  const staleThresholdMinutes = getAnalystFreshnessLagThresholdMinutes();
  let lastCandleTimestamp = null;
  let sessionDateOfData = null;
  let hasTodaySessionBars = false;
  let orbBarsCount = 0;
  let orbBarsRequired = 3;
  let usedLiveBars = false;
  try {
    const db = getDB();
    const latest = db.prepare(`
      SELECT s.date AS session_date, c.timestamp
      FROM candles c
      JOIN sessions s ON s.id = c.session_id
      WHERE c.timeframe = '5m'
      ORDER BY s.date DESC, c.timestamp DESC
      LIMIT 1
    `).get();
    if (latest?.timestamp) {
      lastCandleTimestamp = String(latest.timestamp);
      sessionDateOfData = String(latest.session_date || '').trim() || null;
    }

    const todayAgg = db.prepare(`
      SELECT
        COUNT(*) AS bar_count,
        MAX(c.timestamp) AS last_ts,
        SUM(CASE
          WHEN substr(c.timestamp, 12, 5) >= '09:30' AND substr(c.timestamp, 12, 5) < '09:45'
          THEN 1 ELSE 0
        END) AS orb_count
      FROM candles c
      JOIN sessions s ON s.id = c.session_id
      WHERE c.timeframe = '5m'
        AND s.date = ?
    `).get(todayDate);
    const barCount = Number(todayAgg?.bar_count || 0);
    hasTodaySessionBars = barCount > 0;
    orbBarsCount = Number(todayAgg?.orb_count || 0);
    if (hasTodaySessionBars) {
      sessionDateOfData = todayDate;
      if (todayAgg?.last_ts) lastCandleTimestamp = String(todayAgg.last_ts);
    }
  } catch {}

  const liveBarsSnapshot = options.liveBarsSnapshot || options.market?.liveBarsSnapshot || null;
  try {
    const bars = Array.isArray(liveBarsSnapshot?.bars) ? liveBarsSnapshot.bars : [];
    if (liveBarsSnapshot?.ok && bars.length > 0) {
      let liveTodayBarCount = 0;
      let liveOrbBarsCount = 0;
      let latestLiveBarMs = -1;
      let latestLiveBarTs = null;
      let latestLiveDateEt = null;
      for (const b of bars) {
        const rawTs = b?.t || b?.time || b?.timestamp || null;
        const dt = parseAnyTimestamp(rawTs);
        if (!dt) continue;
        const ms = dt.getTime();
        if (ms > latestLiveBarMs) {
          latestLiveBarMs = ms;
          latestLiveBarTs = rawTs || dt.toISOString();
          latestLiveDateEt = dateInTimezone(timezone, dt);
        }
        const et = formatEtDateTimeParts(dt);
        const hhmm = String(et.hhmm || '').trim();
        if (et.date === todayDate) {
          liveTodayBarCount += 1;
          if (hhmm >= '09:30' && hhmm < '09:45') liveOrbBarsCount += 1;
        }
      }
      const unitNumber = Math.max(1, Number(liveBarsSnapshot?.unitNumber || 1));
      orbBarsRequired = Math.max(1, Math.ceil(15 / unitNumber));
      hasTodaySessionBars = liveTodayBarCount > 0;
      orbBarsCount = liveOrbBarsCount;
      if (latestLiveDateEt) sessionDateOfData = hasTodaySessionBars ? todayDate : latestLiveDateEt;
      if (latestLiveBarTs) lastCandleTimestamp = String(latestLiveBarTs);
      if (!lastCandleTimestamp) {
        const syncTs = options.liveSync?.snapshot?.sync?.createdAt
          || options.topstepLive?.sync?.createdAt
          || null;
        if (syncTs) lastCandleTimestamp = String(syncTs);
      }
      usedLiveBars = true;
    }
  } catch {}
  // Topstep-first fallback when bars snapshot is unavailable.
  if (!usedLiveBars) {
    try {
      const market = options.market || {};
      const pattern = market?.pattern || {};
      const patternSource = String(pattern?.source || market?.source || '').toLowerCase();
      const trustedLiveSource = (
        patternSource === 'topstep_bars'
        || patternSource === 'topstep_live_bars'
        || patternSource === 'live_trade_state'
        || patternSource === 'quote_cache'
        || patternSource === 'topstep_position_mark'
      );
      const livePrice = Number(pattern?.lastPrice);
      const livePriceValid = Number.isFinite(livePrice) && livePrice > 0;
      const liveBarTsRaw = pattern?.lastBarTime || null;
      const liveBarDt = parseAnyTimestamp(liveBarTsRaw);
      const liveBarDateEt = liveBarDt ? dateInTimezone(timezone, liveBarDt) : null;
      const liveTodayBarCount = Number(market?.todayBarCount);
      const liveOrbBarsCount = Number(market?.todayOrbBarsCount);
      const liveHasTodayBars = (
        trustedLiveSource
        && livePriceValid
        && (
          (Number.isFinite(liveTodayBarCount) && liveTodayBarCount > 0)
          || (liveBarDateEt === todayDate)
        )
      );
      if (liveHasTodayBars) {
        hasTodaySessionBars = true;
        sessionDateOfData = todayDate;
        if (liveBarTsRaw) {
          lastCandleTimestamp = String(liveBarTsRaw);
        } else if (!lastCandleTimestamp) {
          const syncTs = options.liveSync?.snapshot?.sync?.createdAt
            || options.topstepLive?.sync?.createdAt
            || null;
          if (syncTs) lastCandleTimestamp = String(syncTs);
        }
      }
      if (Number.isFinite(liveOrbBarsCount) && liveOrbBarsCount > orbBarsCount) {
        orbBarsCount = liveOrbBarsCount;
      }
    } catch {}
  }

  let minutesSinceLastCandle = null;
  const dt = parseAnyTimestamp(lastCandleTimestamp);
  if (dt) {
    minutesSinceLastCandle = Math.max(0, Math.floor((Date.now() - dt.getTime()) / 60000));
  }
  const nowMinutes = parseMinutesFromHHMM(nowEt.time, null);
  const hasORBComplete = Number.isFinite(nowMinutes) && nowMinutes >= 585 && orbBarsCount >= orbBarsRequired;
  return {
    lastCandleTimestamp: lastCandleTimestamp || null,
    minutesSinceLastCandle: Number.isFinite(minutesSinceLastCandle) ? minutesSinceLastCandle : null,
    sessionDateOfData: sessionDateOfData || null,
    hasTodaySessionBars,
    hasORBComplete,
    orbBarsCount,
    orbBarsRequired,
    usedLiveBars,
    staleThresholdMinutes,
    nowEt,
  };
}

function summarizeAnalystLastUpdate(freshness = {}) {
  const stamp = formatAssistantClockTime(freshness?.lastCandleTimestamp || null);
  if (stamp) return stamp;
  const fallbackDate = String(freshness?.sessionDateOfData || '').trim();
  if (fallbackDate) return `session ${fallbackDate}`;
  return 'not available';
}

function makeAssistantIntelCacheKey(options = {}) {
  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const symbol = String(options.symbol || config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase();
  const marketDate = dateInTimezone('America/New_York');
  const mode = options.preferCachedLive === true ? 'fast' : 'full';
  return `${strategy}:${symbol}:${marketDate}:${mode}`;
}

function pruneAssistantIntelCache(cacheKey) {
  if (assistantIntelCache.size <= 14) return;
  for (const [k] of assistantIntelCache.entries()) {
    if (k !== cacheKey) {
      assistantIntelCache.delete(k);
      if (assistantIntelCache.size <= 10) break;
    }
  }
}

function buildExecutionTimingIntelligence({ cmd, market }) {
  const decision = cmd?.decision || {};
  const guardrails = getExecutionGuardrails();
  const news = evaluateNewsLockoutNow(guardrails, 'America/New_York');
  const now = nowInTimezone('America/New_York');
  const nowMinutes = parseMinutesFromHHMM(now.time, null);
  const inCoreEntryWindow = Number.isFinite(nowMinutes) && nowMinutes >= 570 && nowMinutes < 660;
  const signal = normalizeDecisionSignal(decision.signal || decision.verdict);
  const label = decisionSignalLabel(signal);
  const blockers = (decision.blockers || []).map((b) => String(b || '').toUpperCase());
  let action = "DON'T TRADE";
  let reason = 'Core decision gate is defensive right now.';

  if (news?.blocked) {
    action = 'WAIT';
    reason = 'High-impact news lockout is active right now.';
  } else if (!inCoreEntryWindow) {
    action = 'WAIT';
    reason = 'Outside your primary 9:30 to 10:59 entry window.';
  } else if (signal === 'GO' && blockers.length === 0) {
    action = 'TRADE';
    reason = 'Decision gate is clear and timing window is open.';
  } else if (signal === 'WAIT') {
    action = 'WAIT';
    reason = 'Decision gate says wait for cleaner confirmation.';
  } else if (blockers.includes('RANGE_OVEREXTENDED') || blockers.includes('FRIDAY_VOLATILITY_EXHAUSTION')) {
    action = "DON'T TRADE";
    reason = 'Volatility exhaustion blocker is active.';
  }

  const patternNudge = market?.pattern?.guidance ? `Pattern read: ${market.pattern.guidance}` : null;
  return {
    nowEt: now,
    inCoreEntryWindow,
    decisionLabel: label,
    action,
    reason,
    confidencePct: Number(decision.confidence || 0),
    blockers: (decision.blockers || []).slice(0, 3).map(humanizeDecisionBlocker),
    newsBlocked: !!news?.blocked,
    newsEvent: news?.activeEvent || null,
    patternNudge,
  };
}

function buildRiskModelIntelligence({ cmd, market }) {
  const plan = cmd?.plan || {};
  const decision = cmd?.decision || {};
  const controls = getExecutionControls();
  const riskPlan = plan?.riskPlan || {};
  const dailyPnl = Number(market?.account?.dailyPnl);
  const hasDailyPnl = Number.isFinite(dailyPnl);
  const maxDailyLoss = Number(controls.maxDailyLossDollars || 500);
  const blockerUpper = (decision.blockers || []).map((b) => String(b || '').toUpperCase());
  const volatilityRegime = String(market?.pattern?.volatilityRegime || 'unknown').toLowerCase();

  let riskTier = 'controlled';
  if (blockerUpper.includes('RANGE_OVEREXTENDED') || blockerUpper.includes('FRIDAY_VOLATILITY_EXHAUSTION') || volatilityRegime === 'high') {
    riskTier = 'defensive';
  } else if (volatilityRegime === 'low' && !blockerUpper.length && String(riskPlan.mode || '').toUpperCase() === 'AGGRESSIVE') {
    riskTier = 'normal';
  }
  if (hasDailyPnl && dailyPnl <= -(maxDailyLoss * 0.5)) riskTier = 'defensive';

  const contractCap = riskTier === 'defensive'
    ? 1
    : Math.max(1, Math.min(Number(controls.maxPositionSize || 1), String(riskPlan.sizeGuidance || '').toLowerCase().includes('half') ? 1 : 2));
  const stopAfterLosses = Math.max(1, Number(riskPlan.stopAfterConsecutiveLosses || 2));
  const guidance = riskTier === 'defensive'
    ? 'Use minimum size, one clean attempt, and stand down quickly if wrong.'
    : riskTier === 'controlled'
      ? 'Use controlled size and respect stop-after-loss guardrails.'
      : 'Conditions allow normal risk, but keep execution discipline strict.';

  return {
    riskTier,
    contractCap,
    stopAfterLosses,
    maxDailyLoss,
    dailyPnl: hasDailyPnl ? dailyPnl : null,
    guidance,
  };
}

async function buildAssistantIntelligenceSnapshot(options = {}) {
  const strategy = String(options.strategy || 'original') === 'alt' ? 'alt' : 'original';
  const symbol = String(options.symbol || config.topstep?.autonomy?.defaultSymbol || 'MNQ').toUpperCase();
  const preferCachedLive = options.preferCachedLive === true;
  const forceFresh = options.forceFresh === true;
  const cacheKey = makeAssistantIntelCacheKey({
    strategy,
    symbol,
    preferCachedLive,
  });
  const now = Date.now();
  if (!forceFresh) {
    const cached = assistantIntelCache.get(cacheKey);
    if (cached && (now - Number(cached.fetchedAt || 0)) < ASSISTANT_INTEL_TTL_MS) {
      return cached.snapshot;
    }
    const inFlight = assistantIntelInFlight.get(cacheKey);
    if (inFlight) return inFlight;
  }

  const pending = (async () => {
    const errors = [];
    let cmd = options.cmdSnapshot || null;
    if (!cmd) {
      try {
        cmd = await buildTradingCommandSnapshot(strategy);
      } catch (err) {
        errors.push(`command_snapshot:${String(err?.message || 'failed')}`);
      }
    }
    const topstepLive = options.topstepLive || getTopstepLiveSnapshot({ fillLimit: 20 });
    const account = topstepLive?.account || {};
    let market = {
      symbol,
      source: 'none',
      error: null,
      pattern: {
        symbol,
        source: 'none',
        lastPrice: null,
        lastBarTime: null,
        momentumTicks15: null,
        trendTicks30: null,
        rangeTicks20: null,
        rangeTicks60: null,
        momentumLabel: 'neutral',
        volatilityRegime: 'unknown',
        patternLabel: 'no_data',
        guidance: 'Live pattern data is not available yet.',
      },
      account: {
        accountId: account?.accountId || null,
        accountName: account?.accountName || null,
        dailyPnl: Number.isFinite(Number(account?.dailyPnl)) ? Number(account.dailyPnl) : null,
      },
      openPositions: Array.isArray(topstepLive?.positions) ? topstepLive.positions.length : 0,
      syncStatus: String(options.liveSync?.status || topstepLive?.sync?.status || '').toUpperCase() || 'UNKNOWN',
    };
    try {
      if (preferCachedLive) {
        market = buildRealtimeMarketSnapshotFromState({
          symbol,
          topstepLive,
          liveSync: options.liveSync || null,
        });
      } else {
        const liveMarket = await buildRealtimeMarketIntegration({
          symbol,
          topstepLive,
          liveSync: options.liveSync || null,
        });
        if (liveMarket && typeof liveMarket === 'object') market = liveMarket;
      }
    } catch (err) {
      market.error = String(err?.message || 'live_market_fetch_failed');
      errors.push(`market:${market.error}`);
    }
    let liveBarsSnapshot = market?.liveBarsSnapshot || null;
    const marketPrice = Number(market?.pattern?.lastPrice);
    const marketPriceInvalid = !Number.isFinite(marketPrice) || marketPrice <= 0;
    const marketBarDt = parseAnyTimestamp(market?.pattern?.lastBarTime || null);
    const marketMinutesSince = marketBarDt ? Math.max(0, Math.floor((Date.now() - marketBarDt.getTime()) / 60000)) : null;
    const marketStale = Number.isFinite(marketMinutesSince) && marketMinutesSince > getAnalystFreshnessLagThresholdMinutes();
    if (
      (marketPriceInvalid || marketStale || !(liveBarsSnapshot?.ok && Array.isArray(liveBarsSnapshot?.bars) && liveBarsSnapshot.bars.length > 0))
      && config.topstep?.api?.enabled
      && config.topstep?.api?.key
    ) {
      try {
        liveBarsSnapshot = await getLiveBarsSnapshot({
          symbol,
          topstepLive,
          account,
          live: inferTopstepLiveFlag(account),
          lookbackMinutes: 240,
          unitNumber: 1,
          includePartialBar: true,
          persistToDb: true,
          persistFiveMinute: true,
          forceFresh: marketPriceInvalid || marketStale,
        });
      } catch {}
    }
    if (liveBarsSnapshot?.ok && Array.isArray(liveBarsSnapshot.bars) && liveBarsSnapshot.bars.length > 0) {
      market.liveBarsSnapshot = liveBarsSnapshot;
      const lastBar = liveBarsSnapshot.bars[liveBarsSnapshot.bars.length - 1] || null;
      const liveClose = Number(lastBar?.c);
      const liveTs = String(lastBar?.t || '').trim() || null;
      if (marketPriceInvalid || marketStale) {
        if (Number.isFinite(liveClose) && liveClose > 0) market.pattern.lastPrice = liveClose;
        if (liveTs) market.pattern.lastBarTime = liveTs;
        market.pattern.source = 'topstep_live_bars';
        if (!market.source || market.source === 'none') market.source = 'topstep_live_bars';
      }
      if (!Number.isFinite(Number(market?.todayBarCount)) || Number(market.todayBarCount) <= 0) {
        const today = dateInTimezone('America/New_York');
        let todayCount = 0;
        let orbCount = 0;
        for (const b of liveBarsSnapshot.bars) {
          const c = topstepBarToSessionCandle(b);
          if (String(c.date || '') !== today) continue;
          todayCount += 1;
          const hhmm = String(c.time || '').slice(0, 5);
          if (hhmm >= '09:30' && hhmm < '09:45') orbCount += 1;
        }
        market.todayBarCount = todayCount;
        market.todayOrbBarsCount = orbCount;
      }
    }
    const marketDataFreshness = buildMarketDataFreshnessSnapshot({
      timezone: 'America/New_York',
      market,
      liveBarsSnapshot: liveBarsSnapshot || market?.liveBarsSnapshot || options.liveBarsSnapshot || null,
      topstepLive,
      liveSync: options.liveSync || null,
    });

    let memory = {
      samples: 0,
      totalWinRate: null,
      bestSetups: [],
      weakSetups: [],
      personalizationLine: 'I need more logged outcomes to personalize recommendations.',
    };
    try {
      memory = buildStrategyMemoryProfile({ limit: 520 });
    } catch (err) {
      errors.push(`memory:${String(err?.message || 'failed')}`);
    }

    let execution = {
      nowEt: nowInTimezone('America/New_York'),
      inCoreEntryWindow: false,
      decisionLabel: 'WAIT',
      action: 'WAIT',
      reason: 'Execution timing is unavailable right now.',
      confidencePct: Number(cmd?.decision?.confidence || 0),
      blockers: (cmd?.decision?.blockers || []).slice(0, 3).map(humanizeDecisionBlocker),
      newsBlocked: false,
      newsEvent: null,
      patternNudge: null,
    };
    try {
      execution = buildExecutionTimingIntelligence({ cmd, market });
    } catch (err) {
      errors.push(`execution:${String(err?.message || 'failed')}`);
    }

    let risk = {
      riskTier: 'controlled',
      contractCap: 1,
      stopAfterLosses: 2,
      maxDailyLoss: Number(getExecutionControls()?.maxDailyLossDollars || 500),
      dailyPnl: Number.isFinite(Number(market?.account?.dailyPnl)) ? Number(market.account.dailyPnl) : null,
      guidance: 'Use controlled size and follow your risk limits.',
    };
    try {
      risk = buildRiskModelIntelligence({ cmd, market });
    } catch (err) {
      errors.push(`risk:${String(err?.message || 'failed')}`);
    }

    const snapshot = {
      generatedAt: new Date().toISOString(),
      strategy,
      errors,
      market,
      memory,
      execution,
      risk,
      marketDataFreshness,
      chartContext: getAnalystChartContextState(),
      decision: cmd?.decision || null,
      plan: cmd?.plan || null,
    };
    assistantIntelCache.set(cacheKey, { fetchedAt: Date.now(), snapshot });
    pruneAssistantIntelCache(cacheKey);
    return snapshot;
  })();

  assistantIntelInFlight.set(cacheKey, pending);
  try {
    return await pending;
  } finally {
    assistantIntelInFlight.delete(cacheKey);
  }
}

async function buildCanonicalAssistantDecisionBrief(options = {}) {
  const forceFresh = options.forceFresh === true;
  let payload = null;
  try {
    payload = await buildStrategyLayerSnapshotCached({
      forceFresh,
      includeDiscovery: false,
      includePerDate: false,
      trackingIncludeContext: false,
      performanceSource: 'all',
    });
  } catch {
    payload = null;
  }
  const commandCenter = payload?.commandCenter && typeof payload.commandCenter === 'object'
    ? payload.commandCenter
    : null;
  const brief = commandCenter?.assistantDecisionBrief
    && typeof commandCenter.assistantDecisionBrief === 'object'
    ? commandCenter.assistantDecisionBrief
    : (commandCenter?.todayRecommendation?.assistantDecisionBrief
      && typeof commandCenter.todayRecommendation.assistantDecisionBrief === 'object'
      ? commandCenter.todayRecommendation.assistantDecisionBrief
      : null);
  const assistantText = String(
    brief?.assistantText
    || commandCenter?.assistantDecisionBriefText
    || commandCenter?.todayRecommendation?.assistantDecisionBriefText
    || ''
  ).trim();
  if (!brief && !assistantText) return null;
  return {
    ...(brief && typeof brief === 'object' ? brief : {}),
    assistantText: assistantText || null,
  };
}

function buildAssistantIntelligenceLines(snapshot = {}) {
  const market = snapshot.market || {};
  const pattern = market.pattern || {};
  const execution = snapshot.execution || {};
  const risk = snapshot.risk || {};
  const memory = snapshot.memory || {};
  const chartContext = snapshot.chartContext || null;
  const symbol = String(market.symbol || 'MNQ');
  const fastSnapshot = String(pattern.patternLabel || '').toLowerCase() === 'snapshot';
  const priceLine = Number.isFinite(Number(pattern.lastPrice)) && Number(pattern.lastPrice) > 0
    ? fastSnapshot
      ? `${symbol} is around ${Number(pattern.lastPrice).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} from the latest live snapshot.`
      : `${symbol} is around ${Number(pattern.lastPrice).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}; market pattern is ${String(pattern.patternLabel || 'unknown').replace(/_/g, ' ')} with ${pattern.volatilityRegime || 'unknown'} volatility.`
    : `${symbol} live price is currently unavailable, but feed status is ${String(market.syncStatus || 'UNKNOWN').toLowerCase()}.`;
  const execLine = `${String(execution.action || 'WAIT').toUpperCase()}: ${execution.reason || 'Wait for a cleaner trigger.'}`;
  const memoryLine = memory.personalizationLine || 'Personalized setup memory is still calibrating.';
  const riskLine = `Risk posture is ${risk.riskTier || 'controlled'}: max ${risk.contractCap || 1} contract${Number(risk.contractCap || 1) === 1 ? '' : 's'}, stop after ${risk.stopAfterLosses || 2} losses.`;
  const chartLine = chartContext
    ? `Latest chart context: ${chartContext.signal || 'signal pending'}${chartContext.why ? ` | ${chartContext.why}` : ''}.`
    : null;
  return [priceLine, execLine, memoryLine, riskLine, chartLine].filter(Boolean);
}

