async function runDailyVerdictSummary(options = {}) {
  let payload = await buildDailyVerdictPayload({ forceFresh: true });
  if (!payload) {
    const fallbackSignal = await runMcnairDailySignalsInitialization().catch(() => null);
    if (!fallbackSignal) return null;
    payload = {
      generatedAt: new Date().toISOString(),
      tradeDate: fallbackSignal.marketDate || dateInTimezone('America/New_York'),
      signal: fallbackSignal.signal,
      signalLabel: fallbackSignal.signalLabel,
      why10Words: fallbackSignal.why10Words,
      signalLine: fallbackSignal.signalLine,
      performanceLine: 'Performance: no logged outcomes yet.',
      finalResultLine: 'Final result so far: no trade outcome has been logged yet today.',
      feedback: summarizeFeedbackForDate(fallbackSignal.marketDate || dateInTimezone('America/New_York')),
      decision: {
        verdict: normalizeDecisionSignal(fallbackSignal.signal),
        confidence: 0,
        blockers: fallbackSignal.blockers || [],
        topSetup: fallbackSignal.topSetup || null,
      },
    };
  }
  writeDailyVerdictPayload(payload);
  getDB().prepare('INSERT INTO activity_log (module, message, severity, data) VALUES (?, ?, ?, ?)')
    .run('assistant', `Daily verdict generated (${payload.tradeDate})`, 'info', JSON.stringify(payload));
  if (options.pushDiscord && discordBot?.enabled && typeof discordBot.sendMessageToAllowedUsers === 'function') {
    discordBot.sendMessageToAllowedUsers(buildDailyVerdictText(payload)).catch((err) => {
      console.error('[Daily Verdict] Discord send failed:', err.message);
    });
  }
  if (options.pushDiscord) {
    const pushDate = payload.tradeDate || dateInTimezone('America/New_York');
    const pushTag = `daily_verdict_${pushDate}`;
    if (shouldSendProactivePush(pushDate, pushTag, 'discord_webhook')) {
      enqueueAssistantAlert(
        'Daily Verdict',
        buildDailyVerdictText(payload),
        {
          category: 'reminder',
          severity: payload.signal === 'TRADE' ? 'info' : 'warning',
        }
      );
    }
  }
  return payload;
}

function weekdayNameFromIso(isoDate) {
  const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(String(isoDate || '').trim());
  if (!match) return 'Unknown';
  const dt = new Date(Date.UTC(Number(match[1]), Number(match[2]) - 1, Number(match[3])));
  return ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'][dt.getUTCDay()] || 'Unknown';
}

function classifyOrbRangeBucket(rangeTicks) {
  const ticks = Number(rangeTicks);
  if (!Number.isFinite(ticks)) return 'unknown';
  if (ticks < 70) return 'too_tight';
  if (ticks <= 220) return 'golden_zone';
  if (ticks <= 380) return 'elevated';
  if (ticks <= 400) return 'high';
  return 'overextended';
}

