app.get('/api/assistant/discord/status', (req, res) => {
  const missing = [];
  if (!config.discord?.botToken) missing.push('DISCORD_BOT_TOKEN');
  if (!Array.isArray(config.discord?.allowedUserIds) || config.discord.allowedUserIds.length === 0) {
    missing.push('DISCORD_ALLOWED_USER_IDS');
  }
  if (!Array.isArray(config.discord?.allowedChannelIds) || config.discord.allowedChannelIds.length === 0) {
    missing.push('DISCORD_ALLOWED_CHANNEL_IDS');
  }
  res.json({
    enabled: !!config.discord?.botToken,
    prefix: config.discord?.commandPrefix || '!3130',
    plainEnglishMode: config.discord?.plainEnglishMode !== false,
    allowedUsersCount: Array.isArray(config.discord?.allowedUserIds) ? config.discord.allowedUserIds.length : 0,
    allowedChannelsCount: Array.isArray(config.discord?.allowedChannelIds) ? config.discord.allowedChannelIds.length : 0,
    adminUsersCount: Array.isArray(config.discord?.adminUserIds) ? config.discord.adminUserIds.length : 0,
    missing,
    ready: missing.length === 0,
  });
});

