app.post('/api/execution/order-intent', (req, res) => {
  try {
    const side = String(req.body?.side || '').toLowerCase();
    const qty = Number(req.body?.qty || 0);
    const symbol = String(req.body?.symbol || 'MNQ').toUpperCase();
    if (!['buy', 'sell'].includes(side)) return res.status(400).json({ error: 'side must be buy/sell.' });
    if (!qty || qty <= 0) return res.status(400).json({ error: 'qty must be > 0.' });
    const out = createOrderIntent({
      side,
      qty,
      symbol,
      source: req.body?.source || 'api',
      requestedBy: req.body?.requestedBy || 'owner',
      meta: req.body?.meta || {},
    });
    res.json({ success: true, intent: out.intent, gate: out.gate, topstepCompliance: buildTopstepComplianceSnapshot() });
  } catch (err) {
    if (err.statusCode === 403) return res.status(403).json({ error: err.message, blocked: err.blocked || [] });
    return res.status(400).json({ error: err.message || 'Could not create order intent.' });
  }
});

app.post('/api/execution/order-confirm/:id', (req, res) => {
  try {
    const id = Number(req.params.id);
    if (!id) return res.status(400).json({ error: 'invalid intent id.' });
    const out = confirmOrderIntent(id, req.body?.confirmedBy || 'owner');
    res.json({ success: true, intent: out.intent, gate: out.gate, topstepCompliance: buildTopstepComplianceSnapshot() });
  } catch (err) {
    if (err.statusCode === 404) return res.status(404).json({ error: err.message });
    if (err.statusCode === 409) return res.status(409).json({ error: err.message });
    if (err.statusCode === 403) return res.status(403).json({ error: err.message, blocked: err.blocked || [] });
    return res.status(400).json({ error: err.message || 'Could not confirm order.' });
  }
});

