app.post('/api/coach/proposals/generate', (req, res) => {
  const strategy = req.body?.strategy === 'alt' ? 'alt' : 'original';
  const snapshot = buildCoachSnapshot(strategy);
  if (!snapshot) {
    return res.status(400).json({
      error: 'No strategy data is available yet. Import your data in the Import module and run sync first.',
    });
  }

  const opportunities = deriveStrategyOpportunities(snapshot);
  const db = getDB();
  const insert = db.prepare(`
    INSERT INTO strategy_proposals (title, category, rationale, proposed_filter, expected_impact, confidence, source, status)
    VALUES (?, ?, ?, ?, ?, ?, 'coach', 'pending_approval')
  `);

  let created = 0;
  db.transaction(() => {
    for (const op of opportunities) {
      insert.run(op.title, op.category, op.rationale, JSON.stringify(op.proposedFilter || {}), op.expectedImpact || 0, op.confidence || 'moderate');
      created++;
    }
    db.prepare('INSERT INTO activity_log (module, message, severity, data) VALUES (?, ?, ?, ?)')
      .run('coach', `Generated ${created} strategy proposal(s).`, 'info', JSON.stringify({ strategy, created }));
  })();

  res.json({ success: true, created });
});

app.get('/api/coach/proposals', (req, res) => {
  const status = req.query.status;
  const db = getDB();
  const proposals = status
    ? db.prepare(`
      SELECT p.*, v.status as validation_status, v.target_trades, v.sample_size, v.win_rate as validation_wr,
             v.profit_factor as validation_pf, v.pnl_dollars as validation_pnl
      FROM strategy_proposals p
      LEFT JOIN proposal_validations v ON v.proposal_id = p.id
      WHERE p.status = ?
      ORDER BY datetime(p.created_at) DESC
    `).all(status)
    : db.prepare(`
      SELECT p.*, v.status as validation_status, v.target_trades, v.sample_size, v.win_rate as validation_wr,
             v.profit_factor as validation_pf, v.pnl_dollars as validation_pnl
      FROM strategy_proposals p
      LEFT JOIN proposal_validations v ON v.proposal_id = p.id
      ORDER BY datetime(p.created_at) DESC
      LIMIT 100
    `).all();
  res.json({ proposals });
});

