function buildHealthSnapshot() {
  const providerState = dashboardAgentProviderSummary();
  const runtimeFreshness = detectRuntimeFreshnessSnapshot();
  const runtimeFreshnessFields = buildRuntimeFreshnessResponseFields({
    runtimeFreshnessStatus: runtimeFreshness.staleCodeDetected ? 'stale' : 'current',
    runtimeStaleCodeDetected: runtimeFreshness.staleCodeDetected === true,
    runtimeProcessStartedAt: runtimeFreshness.processStartedAt,
    runtimeLatestCodeMtimeAt: runtimeFreshness.latestCodeMtimeAt,
    runtimeLatestCodePath: runtimeFreshness.latestCodePath,
    runtimeStaleReason: runtimeFreshness.staleReason || null,
    runtimeBuildFingerprintAtBoot: runtimeFreshness.buildFingerprintAtBoot || null,
    runtimeBuildFingerprintCurrent: runtimeFreshness.buildFingerprintCurrent || null,
    runtimeFingerprintMismatchDetected: runtimeFreshness.fingerprintMismatchDetected === true,
    runtimeBuildGitSha: runtimeFreshness.buildGitSha || null,
    runtimeAutoRepairStatus: 'none',
    runtimeAutoRepairTriggered: false,
    runtimeAutoRepairSuppressed: false,
    runtimeAutoRepairReason: null,
  });
  const health = {
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptimeSeconds: Math.floor(process.uptime()),
    version: '7.1.0',
    api: { ok: true },
    database: { ok: false, sessions: 0, trades: 0 },
    analyst: {
      configured: providerState.configured,
      provider: providerState.active === 'openai'
        ? 'codex-openai'
        : providerState.active === 'openai_blocked'
          ? 'codex-openai-blocked'
        : providerState.active === 'anthropic'
          ? 'anthropic'
          : providerState.active === 'anthropic_fallback'
            ? 'anthropic-fallback'
            : providerState.active === 'openai_fallback'
              ? 'openai-fallback'
              : 'local-only',
      historyLength: analystHistory.filter(m => m.role).length,
      interpreterModel: process.env.DISCORD_INTERPRETER_MODEL || 'gpt-5.3-codex',
      contextBuiltAt: analystContextState.builtAt > 0 ? new Date(analystContextState.builtAt).toISOString() : null,
      contextAgeSeconds: analystContextState.builtAt > 0 ? Math.floor((Date.now() - analystContextState.builtAt) / 1000) : null,
      contextLastReason: analystContextState.lastReason,
      contextRefreshCount: analystContextState.refreshCount,
    },
    runtimeFreshness: runtimeFreshnessFields.runtimeFreshness,
    runtimeFreshnessStatus: runtimeFreshnessFields.runtimeFreshnessStatus,
    runtimeStaleCodeDetected: runtimeFreshnessFields.runtimeStaleCodeDetected,
  };

  try {
    const db = getDB();
    health.database.sessions = db.prepare('SELECT COUNT(*) as count FROM sessions').get().count;
    health.database.trades = db.prepare('SELECT COUNT(*) as count FROM trades').get().count;
    health.database.ok = true;
  } catch (err) {
    health.status = 'degraded';
    health.database.error = err.message;
  }

  return health;
}

async function buildSystemStatus(strategy = 'original') {
  const safeStrategy = strategy === 'alt' ? 'alt' : 'original';
  const health = buildHealthSnapshot();
  const dataFreshness = getSessionFreshnessSummary('America/New_York');
  const notifications = getAssistantNotificationSettings();
  const discordRuntime = typeof discordBot?.getStatus === 'function'
    ? discordBot.getStatus()
    : {
      connected: false,
      ready: false,
      lastReadyAt: null,
      lastStartAt: null,
      lastStopAt: null,
      lastError: null,
      loginAttempts: 0,
      reconnects: 0,
    };

  const discord = {
    enabled: !!discordBot?.enabled,
    configured: !!config.discord?.botToken,
    prefix: config.discord?.commandPrefix || '!3130',
    plainEnglishMode: config.discord?.plainEnglishMode !== false,
    allowedUsersCount: Array.isArray(config.discord?.allowedUserIds) ? config.discord.allowedUserIds.length : 0,
    allowedChannelsCount: Array.isArray(config.discord?.allowedChannelIds) ? config.discord.allowedChannelIds.length : 0,
    runtime: discordRuntime,
  };

  const cmd = await buildTradingCommandSnapshot(safeStrategy).catch(() => null);
  const elite = cmd?.elite || null;
  const plan = cmd?.plan || null;
  const decision = cmd?.decision || null;

  const newsEvents = elite?.news?.events || [];
  const topstepLive = getTopstepLiveSnapshot({ fillLimit: 20 });
  const nowEt = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }));
  const nowEtMinutes = (nowEt.getHours() * 60) + nowEt.getMinutes();
  const released = newsEvents.filter((e) => Number.isFinite(e?.minutes) && e.minutes <= nowEtMinutes);
  const upcoming = newsEvents.filter((e) => !Number.isFinite(e?.minutes) || e.minutes > nowEtMinutes);
  const nextEvent = upcoming[0] || null;

  let pendingIntents = 0;
  let stalePendingIntents = 0;
  let latestDataSync = null;
  let latestModelEval = null;
  try {
    const db = getDB();
    pendingIntents = Number(db.prepare(
      "SELECT COUNT(*) as count FROM execution_order_intents WHERE status = 'pending'"
    ).get().count || 0);
    stalePendingIntents = Number(db.prepare(
      "SELECT COUNT(*) as count FROM execution_order_intents WHERE status = 'pending' AND datetime(expires_at) <= datetime('now')"
    ).get().count || 0);
    latestDataSync = db.prepare('SELECT id, status, created_at, imported_files, sessions_added, stale_after FROM data_sync_runs ORDER BY id DESC LIMIT 1').get() || null;
    latestModelEval = db.prepare('SELECT id, status, created_at, interpreter_passed, decision_passed FROM model_eval_runs ORDER BY id DESC LIMIT 1').get() || null;
  } catch {}

  const nowMs = Date.now();
  const rgLastMs = runtimeGuard.lastTriggerAt ? Date.parse(runtimeGuard.lastTriggerAt) : 0;
  const runtimeGuardSnapshot = {
    ...runtimeGuard,
    cooldownRemainingMs: rgLastMs > 0 ? Math.max(0, runtimeGuard.cooldownMs - (nowMs - rgLastMs)) : 0,
    autoHealScript: AUTO_HEAL_SCRIPT,
  };
  const cacheStats = {
    sessionData: {
      ttlMs: SESSION_DATA_CACHE_TTL_MS,
      ageMs: sessionDataCache.fetchedAt ? Math.max(0, nowMs - sessionDataCache.fetchedAt) : null,
      sessionCount: sessionDataCache.sessionCount || 0,
      candleCount: sessionDataCache.candleCount || 0,
      warm: !!sessionDataCache.sessions,
    },
    coachSnapshotEntries: coachSnapshotCache.size,
    commandSnapshotEntries: commandSnapshotCache.size,
    assistantIntelEntries: assistantIntelCache.size,
    assistantIntelInFlight: assistantIntelInFlight.size,
    assistantQueryEntries: assistantQueryCache.size,
    assistantQueryInFlight: assistantQueryInFlight.size,
    assistantQueryRuntime: getAssistantQueryRuntimeSnapshot(),
    assistantVoiceEntries: assistantVoiceCache.size,
    analystReplyEntries: analystReplyCache.size,
    dailyPlanEntries: dailyPlanCache.size,
    panelEntries: sessionControlPanelCache.size,
  };

  return {
    generatedAt: new Date().toISOString(),
    strategy: safeStrategy,
    health,
    discord,
    notifications: {
      active: notifications.active,
      webhookConfigured: notifications.webhookConfigured,
      webhookMasked: notifications.webhookMasked,
      source: notifications.source,
      opportunityAlerts: notifications.opportunityAlerts,
      approvalAlerts: notifications.approvalAlerts,
      reminderAlerts: notifications.reminderAlerts,
    },
    news: {
      source: elite?.news?.source || 'none',
      error: elite?.news?.error || null,
      timezone: elite?.news?.timezone || 'America/New_York',
      eventCount: elite?.news?.eventCount ?? newsEvents.length,
      focusEventCount: elite?.news?.focusEventCount ?? (elite?.news?.focusEvents || []).length,
      releasedCount: released.length,
      upcomingCount: upcoming.length,
      nextEvent: nextEvent ? {
        time: nextEvent.time,
        country: nextEvent.country,
        impact: nextEvent.impact,
        title: nextEvent.title,
      } : null,
    },
    brain: {
      configured: health.analyst.configured,
      provider: health.analyst.provider,
      interpreterModel: health.analyst.interpreterModel,
      historyLength: health.analyst.historyLength,
      modelVersion: elite?.modelVersion || null,
      planner: {
        preferredProvider: DASHBOARD_AGENT_PROVIDER,
        lastProvider: dashboardPlannerRuntime.lastProvider,
        lastModel: dashboardPlannerRuntime.lastModel,
        lastSuccessAt: dashboardPlannerRuntime.lastSuccessAt,
        openaiBlockedUntil: dashboardPlannerRuntime.openaiBlockedUntil
          ? new Date(dashboardPlannerRuntime.openaiBlockedUntil).toISOString()
          : null,
        openaiBlockReason: dashboardPlannerRuntime.openaiBlockReason || null,
      },
    },
    tradePlan: plan ? {
      dayName: plan.dayName,
      action: plan.action,
      setupScore: plan.setupQuality?.score ?? 0,
      setupGrade: plan.setupQuality?.grade || 'D',
      winChance: elite?.winModel?.point ?? null,
      confidenceLevel: elite?.winModel?.confidenceLevel || null,
      probGreen: elite?.outcome?.distribution?.probGreen ?? null,
      riskMode: plan.riskPlan?.mode || 'NORMAL',
      maxTrades: plan.riskPlan?.maxTrades ?? 2,
      sizeGuidance: plan.riskPlan?.sizeGuidance || 'half-size',
      topSetup: decision?.topSetups?.[0] || null,
      decision: decision ? {
        verdict: decision.verdict,
        confidence: decision.confidence,
        blockers: decision.blockers || [],
      } : null,
    } : null,
    locks: {
      pendingOrderIntents: pendingIntents,
      stalePendingOrderIntents: stalePendingIntents,
    },
    operations: {
      topstepSync: topstepLive?.sync ? {
        id: topstepLive.sync.id,
        status: topstepLive.sync.status,
        accountId: topstepLive.sync.accountId,
        positionRows: topstepLive.sync.positionRows,
        fillRows: topstepLive.sync.fillRows,
        errorMessage: topstepLive.sync.errorMessage,
        createdAt: topstepLive.sync.createdAt,
      } : null,
      dataSync: latestDataSync ? {
        id: latestDataSync.id,
        status: latestDataSync.status,
        importedFiles: Number(latestDataSync.imported_files || 0),
        sessionsAdded: Number(latestDataSync.sessions_added || 0),
        staleAfter: !!latestDataSync.stale_after,
        createdAt: latestDataSync.created_at,
      } : null,
      modelEval: latestModelEval ? {
        id: latestModelEval.id,
        status: latestModelEval.status,
        interpreterPassed: !!latestModelEval.interpreter_passed,
        decisionPassed: !!latestModelEval.decision_passed,
        createdAt: latestModelEval.created_at,
      } : null,
    },
    dataFreshness,
    runtimeGuard: runtimeGuardSnapshot,
    cacheStats,
  };
}

async function runSystemRecovery(options = {}) {
  const strategy = options.strategy === 'alt' ? 'alt' : 'original';
  const warnings = [];
  const backup = createRuntimeBackup('system_recovery');
  if (!backup.ok) warnings.push(`backup_failed:${backup.error || 'unknown'}`);

  invalidateSessionDataCache();
  invalidateAltCache();
  invalidateDailyPlanCache();
  invalidateSessionControlPanelCache();
  eliteBriefCache.clear();
  invalidateCommandSnapshotCache();
  dailyPlanCache.clear();
  sessionControlPanelCache.clear();
  econCalendarCache = { fetchedAt: 0, events: [], source: 'manual_reset', error: null };

  let expiredIntents = 0;
  let expiredAgedIntents = 0;
  try {
    const db = getDB();
    expiredIntents = db.prepare(
      "UPDATE execution_order_intents SET status = 'expired' WHERE status = 'pending' AND datetime(expires_at) <= datetime('now')"
    ).run().changes;
    expiredAgedIntents = db.prepare(
      "UPDATE execution_order_intents SET status = 'expired' WHERE status = 'pending' AND datetime(created_at) <= datetime('now', '-20 minutes')"
    ).run().changes;
  } catch (err) {
    warnings.push(`intent_cleanup_failed:${err.message}`);
  }

  let preflight = null;
  try {
    preflight = runPreflight({ strict: false, log: false });
  } catch (err) {
    warnings.push(`preflight_exception:${err.message}`);
  }

  try {
    await fetchEconomicCalendarEvents();
  } catch (err) {
    warnings.push(`news_refresh_failed:${err.message}`);
  }

  try {
    await buildTradingCommandSnapshot(strategy, { forceFresh: true });
  } catch (err) {
    warnings.push(`snapshot_rebuild_failed:${err.message}`);
  }

  let discordRecovery = { attempted: false, ok: null, error: null };
  if (discordBot?.enabled) {
    discordRecovery = { attempted: true, ok: false, error: null };
    try {
      if (typeof discordBot.restart === 'function') {
        await discordBot.restart();
      } else {
        if (typeof discordBot.stop === 'function') await discordBot.stop();
        if (typeof discordBot.start === 'function') await discordBot.start();
      }
      discordRecovery.ok = true;
    } catch (err) {
      discordRecovery.error = err.message;
      warnings.push(`discord_restart_failed:${err.message}`);
    }
  }

  const system = await buildSystemStatus(strategy).catch(() => null);
  return {
    status: warnings.length > 0 ? 'degraded' : 'ok',
    recoveredAt: new Date().toISOString(),
    actions: {
      backup,
      cacheReset: true,
      expiredIntents,
      expiredAgedIntents,
      preflightOk: !!preflight?.ok,
      discordRecovery,
    },
    warnings,
    system,
  };
}

