app.get(['/api/market/health', '/api/topstep/bars/health'], async (req, res) => {
  const parseBool = (value) => {
    if (value == null) return null;
    const t = String(value).trim().toLowerCase();
    if (!t) return null;
    if (['1', 'true', 'yes', 'y', 'on'].includes(t)) return true;
    if (['0', 'false', 'no', 'n', 'off'].includes(t)) return false;
    return null;
  };
  const parsePositiveInt = (value, fallback) => {
    const n = Number(value);
    if (!Number.isFinite(n)) return fallback;
    return Math.max(1, Math.floor(n));
  };

  const live = parseBool(req.query.live);
  const compareLiveA = parseBool(req.query.compareLive);
  const compareLiveB = parseBool(req.query.compare);
  const forceFresh = parseBool(req.query.forceFresh) === true;
  const forceError = parseBool(req.query.forceError) === true;
  const lookbackMinutes = parsePositiveInt(req.query.lookbackMinutes ?? req.query.lookback, 120);
  const timeoutMs = parsePositiveInt(req.query.timeoutMs, (compareLiveA === true || compareLiveB === true) ? 6500 : 8500);
  const symbol = String(req.query.symbol || config.topstep?.autonomy?.defaultSymbol || 'MNQ').trim().toUpperCase();

  try {
    const snapshot = await getMarketHealthSnapshotCached({
      symbol,
      ...(live == null ? {} : { live }),
      compareLiveModes: compareLiveA === true || compareLiveB === true,
      forceFresh,
      forceError,
      lookbackMinutes,
      timeoutMs,
    });
    return res.json(snapshot);
  } catch (err) {
    const nowEt = nowInTimezone('America/New_York');
    return res.status(500).json({
      now_et: `${nowEt.date} ${nowEt.time} ET`,
      contractId_in_use: null,
      contract_roll_status: 'STALE',
      selected_contract_reason: null,
      topstep_bars: {
        ok: false,
        bars_returned: 0,
        last_bar_ts_utc: null,
        last_bar_ts_et: null,
        minutes_since_last_bar: null,
        last_close: null,
      },
      db_persist: {
        sessions_last_date: null,
        candles_1m_last_ts: null,
        candles_5m_last_ts: null,
        minutes_since_db_last_candle: null,
      },
      orb_state: {
        hasORBComplete: false,
        orbWindow: '09:30-09:45 ET',
        orbBarsRequired: 3,
      },
      status: 'STALE',
      reason: String(err?.message || 'market_health_failed'),
    });
  }
});

