app.get('/api/diagnostics', (req, res) => {
  const sessions = loadAllSessions();
  const bt = runBacktestWithResolutions(sessions);
  const dates = Object.keys(sessions).sort();
  const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

  // Map all sessions by day of week
  const sessionsByDay = {};
  for (const date of dates) {
    const [y, m, d] = date.split('-').map(Number);
    const dt = new Date(Date.UTC(y, m - 1, d));
    const dayName = dayNames[dt.getUTCDay()];
    if (!sessionsByDay[dayName]) sessionsByDay[dayName] = [];
    sessionsByDay[dayName].push(date);
  }

  // Map all backtest trades by day of week
  const tradesByDay = {};
  const wickInferred = [];
  for (const t of bt.trades) {
    const [y, m, d] = t.date.split('-').map(Number);
    const dt = new Date(Date.UTC(y, m - 1, d));
    const dayName = dayNames[dt.getUTCDay()];
    if (!tradesByDay[dayName]) tradesByDay[dayName] = [];
    tradesByDay[dayName].push({
      date: t.date,
      direction: t.direction,
      result: t.result,
      exit_reason: t.exit_reason,
      pnl: t.pnl_dollars,
    });
    if (t.exit_reason === 'tp_wick_inferred' || t.exit_reason === 'sl_wick_inferred') {
      wickInferred.push({
        date: t.date,
        direction: t.direction,
        result: t.result,
        exit_reason: t.exit_reason,
        pnl: t.pnl_dollars,
      });
    }
  }

  // Sessions that should have trades but don't
  const noTradeByDay = {};
  for (const date of dates) {
    const [y, m, d] = date.split('-').map(Number);
    const dt = new Date(Date.UTC(y, m - 1, d));
    const dayName = dayNames[dt.getUTCDay()];
    const hasTrade = bt.trades.some(t => t.date === date);
    if (!hasTrade) {
      const result = processSession(sessions[date]);
      if (!noTradeByDay[dayName]) noTradeByDay[dayName] = [];
      noTradeByDay[dayName].push({
        date,
        reason: result.no_trade_reason || 'unknown',
        processSessionHadTrade: !!result.trade,
      });
    }
  }

  // dayOfWeekBreakdown from stats
  const dowBreakdown = bt.dayOfWeek;

  res.json({
    totalSessions: dates.length,
    totalBacktestTrades: bt.trades.length,
    sessionsByDay: Object.entries(sessionsByDay).map(([d, dates_]) => ({ day: d, count: dates_.length })),
    tradesByDay: Object.entries(tradesByDay).map(([d, trades_]) => ({
      day: d,
      count: trades_.length,
      wins: trades_.filter(t => t.result === 'win').length,
      losses: trades_.filter(t => t.result === 'loss').length,
    })),
    noTradeByDay: Object.entries(noTradeByDay).map(([d, items]) => ({
      day: d,
      count: items.length,
      reasons: items.map(i => ({ date: i.date, reason: i.reason, processSessionHadTrade: i.processSessionHadTrade })),
    })),
    wickInferred,
    dowBreakdown: dowBreakdown.map(d => ({
      dayName: d.dayName,
      totalTrades: d.totalTrades,
      winRate: d.winRate,
    })),
  });
});

