async function runDatabentoIngestionJob(options = {}) {
  const cfg = config.databento?.api || {};
  if (cfg.enabled === false) return { status: 'disabled', reason: 'databento_ingestion_disabled' };
  if (!String(cfg.key || '').trim()) return { status: 'disabled', reason: 'databento_api_key_missing' };
  const db = getDB();
  ensureDataFoundationTables(db);
  const result = await runDatabentoIngestion({
    db,
    apiKey: cfg.key,
    mode: String(options.mode || 'auto').trim().toLowerCase() || 'auto',
    dataset: cfg.dataset || DEFAULT_DATABENTO_DATASET,
    schemaName: cfg.schemaName || DEFAULT_DATABENTO_SCHEMA,
    stypeIn: cfg.stypeIn || DEFAULT_DATABENTO_STYPE_IN,
    symbols: normalizeDataCoverageSymbolInput(cfg.symbols || DEFAULT_DATABENTO_SYMBOLS),
    startDate: options.startDate || undefined,
    endDate: options.endDate || dateInTimezone('America/New_York'),
    lookbackDays: Number(options.lookbackDays || cfg.lookbackDays || DEFAULT_DATABENTO_LOOKBACK_DAYS),
    gapLookbackDays: Number(options.gapLookbackDays || cfg.gapLookbackDays || DEFAULT_DATABENTO_GAP_LOOKBACK_DAYS),
    maxRangeDays: Number(options.maxRangeDays || cfg.maxRangeDays || DEFAULT_DATABENTO_MAX_RANGE_DAYS),
    recentClampDays: Number(options.recentClampDays || cfg.recentClampDays || DEFAULT_DATABENTO_RECENT_CLAMP_DAYS),
    nowDate: options.nowDate || dateInTimezone('America/New_York'),
    timeoutMs: Number(options.timeoutMs || cfg.timeoutMs || 30_000),
    force: options.force === true,
  });
  invalidateDataFoundationCaches();
  strategyLayerCache.clear();
  strategyLayerInFlight.clear();
  commandSnapshotCache.clear();
  commandSnapshotInFlight.clear();
  assistantIntelCache.clear();
  assistantIntelInFlight.clear();
  return result;
}

async function runDailyEvidenceScoringJob(options = {}) {
  if (config.dataFoundation?.autoDailyScoringEnabled === false) {
    return { status: 'disabled', reason: 'daily_evidence_scoring_disabled', advisoryOnly: true };
  }
  const out = await runDailyEvidenceScoringPass({
    mode: String(options.mode || 'auto').trim() || 'auto',
    nowDate: options.nowDate || dateInTimezone('America/New_York'),
    windowDays: Number(options.windowDays || config.dataFoundation?.dailyScoringWindowDays || 3),
    force: options.force === true,
    finalizationOnly: options.finalizationOnly === true,
    liveBridgeLookbackDays: Number(options.liveBridgeLookbackDays || 0) || undefined,
    runOrigin: 'natural',
    runtimeTriggered: true,
  });
  return out;
}

async function runLiveOutcomeFinalizationJob(options = {}) {
  if (config.dataFoundation?.autoDailyScoringEnabled === false) {
    return { status: 'disabled', reason: 'daily_evidence_scoring_disabled', advisoryOnly: true };
  }
  const normalizedSweepSource = String(options.sweepSource || '').trim().toLowerCase();
  const out = await runDailyEvidenceScoringPass({
    mode: String(options.mode || 'live_finalization_auto').trim() || 'live_finalization_auto',
    nowDate: options.nowDate || dateInTimezone('America/New_York'),
    nowTime: options.nowTime || options.nowEt?.time || null,
    windowDays: Number(options.windowDays || Math.max(5, Number(config.dataFoundation?.dailyScoringWindowDays || 3))),
    force: options.force === true,
    finalizationOnly: true,
    liveBridgeLookbackDays: Number(options.liveBridgeLookbackDays || 21),
    checkpointTargetTradingDay: options.checkpointTargetTradingDay || null,
    sweepSource: normalizedSweepSource || null,
    performanceSource: String(options.performanceSource || 'all').trim().toLowerCase() || 'all',
    runOrigin: 'natural',
    runtimeTriggered: true,
  });
  return out;
}

async function runLiveRecommendationContextCaptureJob(options = {}) {
  const db = getDB();
  ensureDataFoundationTables(db);
  const targetDate = String(options.nowDate || dateInTimezone('America/New_York')).trim().slice(0, 10);
  const existing = getRecommendationContextRow(db, {
    recDate: targetDate,
    sourceType: 'live',
    reconstructionPhase: 'live_intraday',
  });
  if (existing && options.force !== true) {
    return {
      status: 'ok',
      reason: 'already_present',
      recDate: targetDate,
      contextCaptured: false,
      advisoryOnly: true,
    };
  }
  const nowEt = options.nowEt && typeof options.nowEt === 'object'
    ? options.nowEt
    : nowInTimezone('America/New_York');
  const nowEtOverride = `${targetDate} ${nowEt.date === targetDate ? String(nowEt.time || '16:00') : '16:00'}`;
  await buildStrategyLayerSnapshotCached({
    forceFresh: options.force === true,
    includeDiscovery: false,
    includePerDate: false,
    windowTrades: 120,
    segmentWeekday: true,
    segmentTimeBucket: true,
    segmentRegime: false,
    performanceWindow: Math.max(120, Number(options.performanceWindow || 120)),
    performanceSource: String(options.performanceSource || 'all').trim().toLowerCase() || 'all',
    trackingWindowSessions: Math.max(120, Number(options.windowSessions || 120)),
    trackingIncludeContext: true,
    nowEtOverride,
  });
  const after = getRecommendationContextRow(db, {
    recDate: targetDate,
    sourceType: 'live',
    reconstructionPhase: 'live_intraday',
  });
  return {
    status: after ? 'ok' : 'warning',
    reason: after ? (existing ? 'updated' : 'captured') : 'capture_missing_after_snapshot',
    recDate: targetDate,
    contextCaptured: !existing && !!after,
    advisoryOnly: true,
  };
}

