cron.schedule('25 9 * * 1-5', async () => {
  try {
    const out = await runWeekdayOperatingLoop('signals_init', { triggerSource: 'weekday_signals_init_loop' });
    if (String(out?.status || '').toLowerCase() !== 'ok') {
      triggerAutoHeal('daily_signals_init_not_ok', { out });
      setTimeout(() => {
        runWeekdayOperatingLoop('signals_init', { triggerSource: 'weekday_signals_init_retry' }).catch((err) => {
          console.error('[mcnair_daily_signals] Retry job error:', err.message);
        });
      }, 45_000);
    }
  } catch (err) {
    console.error('[mcnair_daily_signals] Init job error:', err.message);
    triggerAutoHeal('daily_signals_init_failed', { error: err.message || 'daily_signals_init_failed' });
  }
}, { timezone: 'America/New_York' });
cron.schedule('40 9 * * 1-5', async () => {
  try {
    const out = await sendDailyBriefingOnce({ triggerSource: 'weekday_daily_brief_0940' });
    if (String(out?.status || '').toLowerCase() === 'sent') return;
    const reason = String(out?.reason || '').toLowerCase();
    if (reason && reason !== 'already_sent') {
      console.log('[Discord Bot] Daily briefing 09:40 job skipped:', out?.reason || 'unknown');
    }
  } catch (err) {
    console.error('[Discord Bot] Daily briefing job error:', err.message);
    triggerAutoHeal('daily_brief_job_failed', { error: err.message || 'daily_brief_job_failed' });
  }
}, { timezone: 'America/New_York' });
