discordBot = createDiscordControlBot({
  config: { ...config.discord, anthropicKey: config.anthropicKey },
  projectRoot: path.join(__dirname, '..'),
  handlers: {
    getStatusSummary: async () => {
      const cmd = await buildTradingCommandSnapshot('original');
      return buildDiscordStatusFromCommand(cmd);
    },
    getDailyPlanText: async (strategy) => {
      const cmd = await buildTradingCommandSnapshot(strategy || 'original');
      return buildDailyPlanTextFromCommand(cmd);
    },
    getTradeState: async () => ({ state: getLiveTradeState(), realizedPnlDollars: todayRealizedPnlDollars() }),
    getSessionControlPanel: async () => {
      const cmd = await buildTradingCommandSnapshot('original');
      return { panel: cmd?.panel || buildSessionControlPanel({ strategy: 'original' }) };
    },
    getAutonomyState: async () => ({
      settings: getExecutionAutonomySettings(),
      recentEvents: getDB().prepare(`
        SELECT id, event_date, event_time, event_type, status, payload, created_at
        FROM autonomy_events
        ORDER BY id DESC
        LIMIT 10
      `).all().map((r) => {
        let payload = {};
        try { payload = JSON.parse(r.payload || '{}'); } catch {}
        return {
          id: r.id,
          eventDate: r.event_date,
          eventTime: r.event_time,
          eventType: r.event_type,
          status: r.status,
          payload,
          createdAt: r.created_at,
        };
      }),
    }),
    updateAutonomySettings: async (input) => saveExecutionAutonomySettings(input || {}),
    runAutonomyCycle: async (input) => runPaperAutonomyCycle({ force: !!input?.force }),
    updateExecutionControls: async (input) => saveExecutionControls(input || {}),
    createOrderIntent: async (input) => createOrderIntent(input || {}),
    confirmOrderIntent: async (intentId, confirmedBy) => confirmOrderIntent(Number(intentId), confirmedBy || 'owner'),
    runDiscovery: async (mode) => executeDiscoveryRun({ mode }),
    getOpportunities: async () => {
      const cmd = await buildTradingCommandSnapshot('original');
      return (cmd?.opportunities || []).slice(0, 5);
    },
    promoteCandidate: async (candidateId, reviewedBy) => promoteDiscoveryCandidate(Number(candidateId), reviewedBy),
    rejectCandidate: async (candidateId, reviewedBy, notes) => rejectDiscoveryCandidate(Number(candidateId), reviewedBy, notes),
    getDeskStartSequenceText: async (strategy) => {
      const cmd = await buildTradingCommandSnapshot(strategy || 'original', { forceFresh: true });
      return buildDeskStartSequenceFromCommand(cmd).text;
    },
  },
});

if (discordBot.enabled) {
  discordBot.start()
    .then(() => {
      console.log('[Discord Bot] Command agent enabled.');
      setTimeout(() => {
        runDailyBriefingCatchupOnStartup({ triggerSource: 'discord_startup_catchup' })
          .then((out) => {
            if (String(out?.status || '').toLowerCase() === 'sent') {
              console.log(`[Discord Bot] Startup daily brief catch-up sent (${out.pushDate}).`);
            }
          })
          .catch((err) => {
            console.error('[Discord Bot] Startup daily brief catch-up failed:', err.message);
          });
      }, 3000);
      setTimeout(() => {
        runPreOpenFreshnessGuardrailCatchupOnStartup({ triggerSource: 'discord_startup_preopen_guardrail' })
          .then((out) => {
            if (String(out?.status || '').toLowerCase() === 'blocked') {
              console.log(`[Pre-open Guardrail] Startup catch-up blocked (${out.nowEt?.date || 'today'}).`);
            }
          })
          .catch((err) => {
            console.error('[Pre-open Guardrail] Startup catch-up failed:', err.message);
          });
      }, 4500);
    })
    .catch((err) => {
      console.error('[Discord Bot] Failed to start:', err.message);
      triggerAutoHeal('discord_bot_start_failed', { error: err.message || 'discord_bot_start_failed' });
    });
} else {
  console.log('[Discord Bot] Disabled (set DISCORD_BOT_TOKEN to enable).');
}

setTimeout(() => {
  runDailySignalsCatchupOnStartup({ triggerSource: 'startup_signals_catchup' })
    .then((out) => {
      if (String(out?.status || '').toLowerCase() === 'ok') {
        console.log(`[mcnair_daily_signals] Startup catch-up refreshed (${out.marketDate}).`);
      }
    })
    .catch((err) => {
      console.error('[mcnair_daily_signals] Startup catch-up failed:', err.message);
    });
}, 2000);

let fatalExitScheduled = false;
process.on('unhandledRejection', (reason) => {
  const message = reason instanceof Error ? reason.message : String(reason || 'unknown_unhandled_rejection');
  console.error('[3130] Unhandled rejection:', message);
  triggerAutoHeal('unhandled_rejection', { error: message });
});

process.on('uncaughtException', (err) => {
  const message = String(err?.message || 'unknown_uncaught_exception');
  console.error('[3130] Uncaught exception:', message);
  triggerAutoHeal('uncaught_exception', { error: message });
  if (fatalExitScheduled) return;
  fatalExitScheduled = true;
  setTimeout(() => {
    try { closeDB(); } catch {}
    process.exit(1);
  }, 2000);
});

process.on('SIGINT', () => {
  console.log('\n[3130] Shutting down...');
  if (discordBot.enabled) {
    discordBot.stop().catch(() => {});
  }
  closeDB();
  server.close();
  process.exit(0);
});
